moderation_guard_recent_messages = defaultdict(lambda: deque(maxlen=30))
# Wall-clock UTC time the bot process started. Used by the ADM age guard
# to ONLY filter "old" events during a short cold-start window — after
# that, the hash dedupe on its own is sufficient to prevent replay, and
# the age guard would falsely drop live events when the DayZ server logs
# in a non-UTC timezone (e.g. CEST/CET/EST Nitrado nodes).
BOT_PROCESS_START_TIME = datetime.now(UTC)
# How long after process start the ADM age guard stays active. 90s is
# enough to filter out yesterday's 250 tail lines on a cold container,
# but short enough that the first real-world player connect after start
# always dispatches.
ADM_AGE_GUARD_COLD_START_WINDOW_SECONDS = 90
# Per-guild asyncio.Lock so two ADM scans for the same guild can never
# overlap (which used to cause the same log line to be posted twice).
adm_scan_locks = {}
# Per-guild backoff after Nitrado/Cloudflare 429s. Without this the ADM loop
# retries every 30s across many paths and can keep the service rate-limited.
adm_rate_limit_backoff_until = {}
# Runtime-only source metadata for the ADM file currently being parsed.
# This lets the parser tell the difference between the latest live log and
# an intentional cold-start history sweep.
adm_parse_context = {}
# Tracks which guilds have already had their last-24h ADM history swept
# on this process boot. Reset every time the Railway container recycles
# so a fresh restart re-ingests the previous day's events into the
# dedupe store (the hash file is the canonical "already broadcast" gate).
_adm_history_swept = {}
# Maximum number of recently-seen ADM line hashes to keep per guild.
# Must be high enough that lines still inside the `lines[-250:]` parse
# window remain in cache between scans, even on a quiet server where
# the same lines linger in that window for a long time.
PROCESSED_ADM_CACHE_LIMIT = 5000
PROCESSED_ADM_EVENT_CACHE_LIMIT = 10000
PROCESSED_KILL_EVENT_CACHE_LIMIT = 10000
