def guild_heatmap_mode(guild_id):
    mode = guild_configs.get(str(guild_id), {}).get("heatmap_mode", "all")
    return mode if mode in HEATMAP_MODES else "all"


def heat_counts_for_mode(guild_id, mode):
    heat_data = territory_heat.get(str(guild_id), {})

    if mode == "pvp":
        return {
            key: value
            for key, value in heat_data.items()
            if not str(key).startswith("__") and isinstance(value, int)
        }

    if mode == "all":
        combined = {}
        for mode_counts in heat_data.get("__modes__", {}).values():
            for zone, count in mode_counts.items():
                combined[zone] = combined.get(zone, 0) + count
        return combined

    return heat_data.get("__modes__", {}).get(mode, {})


def server_map_key(guild_id):
    config = guild_configs.get(str(guild_id), {})
    configured = config.get("server_map")
    if not configured:
        guild_name_key = normalize_discord_name(config.get("guild_name", ""))
        if any(term in guild_name_key for term in ["livonia", "livo", "enoch"]):
            configured = "livonia"
        elif any(term in guild_name_key for term in ["sakhal", "sakhalplus"]):
            configured = "sakhal"
        else:
            configured = "chernarus"

    key = normalize_discord_name(configured)

    if key in ["livonia", "enoch"]:
        return "livonia"

    if key in ["sakhal", "sakhalplus"]:
        return "sakhal"

    return "chernarus"


SERVER_PLATFORM_VALUES = {"xbox", "playstation", "pc"}


def normalize_server_platform(value):
    text = normalize_discord_name(value or "")
    if text in {"ps", "ps4", "ps5", "playstation", "dayzps"}:
        return "playstation"
    if text in {"pc", "steam", "windows", "dayzpc"}:
        return "pc"
    if text in {"xb", "xbox", "xboxone", "seriesx", "seriess", "dayzxb"}:
        return "xbox"
    return "xbox"


def server_platform_key(guild_id):
    config = guild_configs.get(str(guild_id), {})
    return normalize_server_platform(config.get("server_platform") or config.get("platform"))


def mission_root_candidates_for_platform(platform_key, include_fallback=True):
    platform_key = normalize_server_platform(platform_key)
    if platform_key == "playstation":
        preferred = [
            "/dayzps_missions",
            "/dayzps_missions/mpmissions",
            "/dayzps/mpmissions",
        ]
    elif platform_key == "pc":
        preferred = [
            "/dayz_missions",
            "/dayz_missions/mpmissions",
            "/dayz/mpmissions",
            "/dayzserver/mpmissions",
            "/mpmissions",
        ]
    else:
        preferred = [
            "/dayzxb_missions",
            "/dayzxb_missions/mpmissions",
            "/dayzxb/mpmissions",
            "/dayzxbserver/mpmissions",
        ]
    fallback = [
        "/dayzxb_missions",
        "/dayzxb_missions/mpmissions",
        "/dayzxb/mpmissions",
        "/dayzps_missions",
        "/dayzps_missions/mpmissions",
        "/dayzps/mpmissions",
        "/dayz_missions",
        "/dayz_missions/mpmissions",
        "/dayz/mpmissions",
        "/dayzserver/mpmissions",
        "/dayzxbserver/mpmissions",
        "/mpmissions",
    ]
    out = []
    roots = [*preferred, *fallback] if include_fallback else preferred
    for root in roots:
        if root not in out:
            out.append(root)
    return out


def config_has_explicit_server_platform(config):
    if not isinstance(config, dict):
        return False
    return bool(str(config.get("server_platform") or config.get("platform") or "").strip())


def mission_root_candidates_for_config(config, guild_id):
    return mission_root_candidates_for_platform(
        server_platform_key(guild_id),
        include_fallback=not config_has_explicit_server_platform(config),
    )


def server_map_size(guild_id):
    map_key = server_map_key(guild_id)

    if map_key == "livonia":
        return 12800, 12800

    if map_key == "sakhal":
        return 15360, 15360

    return 15360, 15360


def map_coords_to_pixel(coords, guild_id=None, width=512, height=384):
    try:
        x_text, y_text = coords.split(",")[:2]
        x = float(x_text.strip())
        y = float(y_text.strip())
    except Exception:
        return None

    map_width, map_height = server_map_size(guild_id) if guild_id else (15360, 15360)
    px = int(max(0, min(width - 1, (x / map_width) * width)))
    py = int(max(0, min(height - 1, height - ((y / map_height) * height))))
    return px, py


def heat_points_for_mode(guild_id, mode):
    heat_data = territory_heat.get(str(guild_id), {})
    points = heat_data.get("__points__", {})

    if mode == "all":
        merged = []
        for mode_points in points.values():
            merged.extend(mode_points)
        return merged[-300:]

    return points.get(mode, [])[-300:]


async def get_or_create_feed_channel(guild, config, key, name, private=False, force=False):
    channels = config.setdefault("channels", {})
    if is_channel_key_disabled(config, key) and not force:
        return None

    if force:
        set_channel_key_disabled(config, key, False)

    existing_id = channels.get(key)
    category = await ensure_bot_category(guild, BOT_CHANNEL_CATEGORY_BY_KEY.get(key, "live_feeds"))

    if existing_id:
        existing = guild.get_channel(existing_id)
        if existing:
            if existing.name != name or (category and existing.category_id != category.id):
                try:
                    await existing.edit(name=name, category=category)
                except Exception:
                    pass
            return existing

    for channel in guild.text_channels:
        if channel_matches_bot_default_name(channel, key):
            channels[key] = channel.id
            if category and channel.category_id != category.id:
                try:
                    await channel.edit(category=category)
                except Exception:
                    pass
            save_guild_configs()
            return channel

    overwrites = {}
    if private:
        overwrites = {
            guild.default_role: discord.PermissionOverwrite(read_messages=False)
        }
        for role in guild.roles:
            if role.permissions.administrator or role.name in config.get("admin_roles", DEFAULT_ADMIN_ROLES):
                overwrites[role] = discord.PermissionOverwrite(read_messages=True, send_messages=True)

    channel = await guild.create_text_channel(name, overwrites=overwrites, category=category)
    channels[key] = channel.id
    save_guild_configs()
    return channel


def split_adm_coords(coords):
    if not coords:
        return None, None, None

    parts = [part.strip() for part in str(coords).split(",")]
    x = parts[0] if len(parts) > 0 else None
    z = parts[1] if len(parts) > 1 else None
    y = parts[2] if len(parts) > 2 else None
    return x, z, y


def nearest_named_location_for_coords(guild_id, x, z):
    try:
        x_value = float(str(x).replace(",", ""))
        z_value = float(str(z).replace(",", ""))
    except Exception:
        return ""

    try:
        presets = scenario_location_presets_for_map(server_map_key(guild_id))
    except Exception:
        return ""

    best_name = ""
    best_distance = None
    for key, location in presets.items():
        if key == "custom" or not isinstance(location, dict):
            continue
        loc_x = location.get("x")
        loc_z = location.get("z")
        if loc_x is None or loc_z is None:
            continue
        distance = ((float(loc_x) - x_value) ** 2 + (float(loc_z) - z_value) ** 2) ** 0.5
        if best_distance is None or distance < best_distance:
            best_distance = distance
            best_name = str(location.get("name") or key)
    if best_name and best_distance is not None:
        return f"{best_name} area ({int(best_distance)}m away)"
    return ""


def extract_flag_base_name(line, guild_id, x=None, z=None):
    patterns = [
        r'flag of (?:base )?"([^"]+)"',
        r'(?:territory\s*)?flag (?:at|in|inside|for) "([^"]+)"',
        r'base "([^"]+)"',
        r'territory "([^"]+)"',
    ]
    for pattern in patterns:
        match = re.search(pattern, line, re.IGNORECASE)
        if match:
            return match.group(1).strip()

    nearest = nearest_named_location_for_coords(guild_id, x, z) if x and z else ""
    return nearest or "Unregistered flag"


def extract_flag_class_name(line):
    match = re.search(r"\b(TerritoryFlag[A-Za-z0-9_]*)\b", line)
    return match.group(1) if match else "TerritoryFlag"


def extract_flag_cloth_class_name(line):
    patterns = [
        r"\bhas\s+raised\s+(Flag_[A-Za-z0-9_]+)\s+on\s+TerritoryFlag\b",
        r"\bhas\s+lowered\s+(Flag_[A-Za-z0-9_]+)\s+on\s+TerritoryFlag\b",
        r"\b(Flag_[A-Za-z0-9_]+)\s+on\s+TerritoryFlag\b",
    ]
    for pattern in patterns:
        match = re.search(pattern, line, re.IGNORECASE)
        if match:
            return match.group(1)
    return ""


def friendly_flag_name(flag_class):
    if not flag_class:
        return "Unknown flag cloth"
    return str(flag_class).replace("Flag_", "").replace("_", " ").strip() or str(flag_class)


def dayz_db_item_image_url(class_name):
    class_name = str(class_name or "").strip()
    if not class_name:
        return ""
    return f"https://db.mydayz.eu/wp-content/uploads/2025/08/{urllib.parse.quote(class_name)}.png.webp"


def extract_placed_object(line):
    angle_match = re.search(r"\bplaced\s+.*?<([^>]+)>", line, re.IGNORECASE)
    if angle_match:
        return angle_match.group(1).strip().replace("_", " ")
    match = re.search(r"\bplaced\s+([^<]+)", line, re.IGNORECASE)
    if match:
        return match.group(1).strip().replace("_", " ")
    return "Unknown item"


def extract_packed_object(line):
    match = re.search(r"\bpacked\s+([^<]+)", line, re.IGNORECASE)
    if match:
        return match.group(1).strip().replace("_", " ")
    return "Unknown item"


def extract_pvp_kill_details(line):
    direct = re.search(r'Player "([^"]+)" killed Player "([^"]+)" with ([^ ]+)', line)
    reverse = re.search(r'Player "([^"]+)".* killed by Player "([^"]+)".* with ([^ ]+)', line)
    hit_death = re.search(
        r'"([^"]+)"\s+\(DEAD\).*?hit by Player "([^"]+)".*?for ([0-9]+\.?[0-9]*) damage \(([^)]+)\) with ([^ ]+) from ([0-9]+\.?[0-9]*) meters?',
        line,
        re.IGNORECASE
    )

    details = None
    if direct:
        details = {
            "killer": direct.group(1),
            "victim": direct.group(2),
            "weapon": direct.group(3),
        }
    elif reverse:
        details = {
            "victim": reverse.group(1),
            "killer": reverse.group(2),
            "weapon": reverse.group(3),
        }
    elif hit_death:
        details = {
            "victim": hit_death.group(1),
            "killer": hit_death.group(2),
            "damage": hit_death.group(3),
            "ammo": hit_death.group(4),
            "weapon": hit_death.group(5),
            "distance": float(hit_death.group(6)),
        }

    if not details:
        return None

    distance_match = re.search(r'from ([0-9]+\.?[0-9]*)\s*m(?:eters?)?', line, re.IGNORECASE)
    if distance_match:
        details["distance"] = float(distance_match.group(1))
    else:
        details.setdefault("distance", 0)

    coords = extract_adm_coords(line)
    if coords:
        details["coords"] = coords

    # Headshot detection — DayZ ADM exposes both the hit-zone
    # ("into Head(0)") and the damage type ("(Brain)"). Either is
    # enough to flag a headshot.
    headshot = False
    hit_location_match = re.search(r'into\s+([A-Za-z]+)', line)
    if hit_location_match and hit_location_match.group(1).lower() in HEADSHOT_HIT_LOCATIONS:
        headshot = True
        details["hit_location"] = hit_location_match.group(1)
    ammo_value = (details.get("ammo") or "").strip().lower()
    if ammo_value in HEADSHOT_DAMAGE_TYPES:
        headshot = True
    details["headshot"] = headshot

    return details


def extract_vehicle_kill_details(line):
    """Parse vehicle kill events like:
       Player "X" (DEAD) (pos=<...>) hit by Transport_PickupTruck for 250 damage
       Player "X" (DEAD) (pos=<...>) hit by Vehicle Sedan_01 from ..."""
    if "(dead)" not in line.lower():
        return None
    victim_match = re.search(r'"([^"]+)"\s+\(DEAD\)', line)
    vehicle_match = re.search(
        r'hit by (?:Vehicle\s+([A-Za-z0-9_\-]+)|(Transport[A-Za-z0-9_\-]*))',
        line,
        re.IGNORECASE,
    )
    if not victim_match:
        return None
    vehicle_name = "Vehicle"
    if vehicle_match:
        vehicle_name = vehicle_match.group(1) or vehicle_match.group(2) or "Vehicle"
    vehicle_clean = re.sub(r'^Transport_?', '', vehicle_name).replace("_", " ") or vehicle_name
    details = {
        "victim": victim_match.group(1),
        "vehicle": vehicle_clean,
    }
    coords = extract_adm_coords(line)
    if coords:
        details["coords"] = coords
    distance_match = re.search(r'from ([0-9]+\.?[0-9]*)\s*m', line, re.IGNORECASE)
    if distance_match:
        try:
            details["distance"] = float(distance_match.group(1))
        except Exception:
            pass
    return details


def pvp_kill_signature(guild_id, details):
    distance = int(round(float(details.get("distance", 0) or 0)))
    return (
        str(guild_id),
        normalize_discord_name(details.get("killer", "")),
        normalize_discord_name(details.get("victim", "")),
        normalize_discord_name(details.get("weapon", "")),
        distance,
    )


def pvp_kill_event_fingerprint(guild_id, details, line=None, event_time=None):
    """Stable kill-event fingerprint used to stop ADM replay duplicates.

    The raw ADM line hash is still useful, but Nitrado can expose the same
    event through a different log/download path. This key anchors on the
    actual kill facts and ADM clock, so replayed events cannot inflate stats.
    """
    clock = ""
    if event_time:
        try:
            clock = event_time.strftime("%Y-%m-%dT%H:%M:%S")
        except Exception:
            clock = ""
    if not clock and line:
        match = _ADM_TIME_PREFIX_RE.match(line)
        if match:
            clock = f"{int(match.group(1)):02d}:{match.group(2)}:{match.group(3)}"

    parts = [
        str(guild_id),
        clock,
        normalize_discord_name(details.get("killer", "")),
        normalize_discord_name(details.get("victim", "")),
        normalize_discord_name(details.get("weapon", "")),
        normalize_discord_name(details.get("ammo", "")),
    ]
    return hashlib.sha256("|".join(parts).encode("utf-8", errors="ignore")).hexdigest()


def adm_event_fingerprint(guild_id, event_type, line, event_time=None):
    clock = ""
    if event_time:
        try:
            clock = event_time.strftime("%Y-%m-%dT%H:%M:%S")
        except Exception:
            clock = ""
    player = extract_player_name(line)
    coords = extract_adm_coords(line) or ""
    compact_line = re.sub(r"\bid=[^) ]+", "id=", str(line or ""), flags=re.IGNORECASE)
    compact_line = re.sub(r"\s+", " ", compact_line).strip().lower()
    parts = [
        str(guild_id),
        str(event_type or ""),
        clock,
        normalize_discord_name(player),
        str(coords).strip(),
        hashlib.sha1(compact_line.encode("utf-8", errors="ignore")).hexdigest()[:16],
    ]
    return hashlib.sha256("|".join(parts).encode("utf-8", errors="ignore")).hexdigest()


def is_duplicate_pvp_kill(guild_id, details, ttl_seconds=45):
    signature = pvp_kill_signature(guild_id, details)
    now_ts = datetime.now(UTC).timestamp()
    last_seen = recent_pvp_kill_signatures.get(signature, 0)
    recent_pvp_kill_signatures[signature] = now_ts

    for key, seen_ts in list(recent_pvp_kill_signatures.items()):
        if now_ts - seen_ts > ttl_seconds:
            recent_pvp_kill_signatures.pop(key, None)

    return now_ts - last_seen < ttl_seconds


CHEAT_WEAPON_LIMITS = {
    "Pistol": 400,
    "SMG": 600,
    "Shotgun": 600,
    "Rifle": 1000,
    "Sniper": 1300,
}

CHEAT_SNAP_RULES = [
    {"kills": 2, "span": 1.5, "angle": 85, "distance": 350},
    {"kills": 3, "span": 4.0, "angle": 60, "distance": 250},
    {"kills": 4, "span": 7.0, "angle": 40, "distance": 175},
]

# ──────────────────────────────────────────────────────────────────────
# NEW (PR #49): close-cluster multi-kill detector. Catches the OPPOSITE
# pattern from the snap rules above — same killer drops 3+ victims that
# are all geographically close to each other (within a tight radius)
# inside a short minutes-long window. That is the textbook signature of
# wallhacks / aimbots / room-clearing — multiple people dying in the
# same building/courtyard without realistic spacing or time between
# kills. The snap rules above intentionally REQUIRE big inter-victim
# distance (>=175m) so they never fire on this pattern; we add a
# dedicated rule that demands SMALL inter-victim distance instead.
# ──────────────────────────────────────────────────────────────────────
CHEAT_CLUSTER_RULES = [
    # 3 kills inside 90s, all victims within a 50m circle of each other.
    {"kills": 3, "span": 90.0, "max_victim_radius": 50.0},
    # 4+ kills inside 180s, victims within a 100m circle.
    {"kills": 4, "span": 180.0, "max_victim_radius": 100.0},
]


def cheat_check_config(config):
    settings = config.setdefault("cheat_check", {})
    settings.setdefault("enabled", True)
    settings.setdefault("auto_ban", False)
    settings.setdefault("clear_chain_on_teleport", True)
    # Bumped from 8s → 200s (PR #49). The legacy snap-kill rules clip
    # their own span (1.5/4/7s) so they still fire on the same true
    # snap kills, but the longer chain window now also feeds the new
    # close-cluster detector which scans up to 3 minutes of recent
    # kills by the same player.
    settings.setdefault("chain_window_seconds", 200)
    # New close-cluster detector tunables — admins can override per guild.
    settings.setdefault("cluster_window_seconds", 180)
    settings.setdefault("cluster_min_kills", 3)
    settings.setdefault("cluster_max_radius", 50)
    return settings


def classify_cheat_weapon(weapon):
    weapon_key = normalize_discord_name(weapon)
    if any(term in weapon_key for term in ["mosin", "svd", "vss", "vs89", "m70", "winchester", "cz550", "ssg", "lrs", "sniper"]):
        return "Sniper"
    if any(term in weapon_key for term in ["ij70", "makarov", "mkii", "fx45", "colt", "deagle", "p1", "pistol", "derringer"]):
        return "Pistol"
    if any(term in weapon_key for term in ["ump", "mp5", "sg5", "ak74u", "scorpion", "vikhr", "smg"]):
        return "SMG"
    if any(term in weapon_key for term in ["bk12", "bk133", "saiga", "vaiga", "shotgun"]):
        return "Shotgun"
    return "Rifle"


def parse_coord_tuple(coords):
    try:
        x, z, y = split_adm_coords(coords)
        return float(x), float(z), float(y or 0)
    except Exception:
        return None


def coord_distance(a, b):
    if not a or not b:
        return 0
    return ((a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2) ** 0.5


def angle_between_vectors(a, b):
    import math
    mag_a = (a[0] ** 2 + a[1] ** 2) ** 0.5
    mag_b = (b[0] ** 2 + b[1] ** 2) ** 0.5
    if mag_a <= 0 or mag_b <= 0:
        return 0
    dot = a[0] * b[0] + a[1] * b[1]
    cosine = max(-1, min(1, dot / (mag_a * mag_b)))
    return math.degrees(math.acos(cosine))


def extract_all_adm_coords(line):
    return re.findall(r"pos=<([^>]+)>", str(line))


def enrich_kill_coords(guild_id, kill_details, line):
    coords = extract_all_adm_coords(line)
    if coords:
        kill_details.setdefault("coords", coords[-1])
        if len(coords) >= 2:
            kill_details["killer_coords"] = coords[0]
            kill_details["victim_coords"] = coords[-1]
        else:
            kill_details["victim_coords"] = coords[0]

    killer = kill_details.get("killer")
    if killer and not kill_details.get("killer_coords"):
        last_seen = player_last_coords.get(str(guild_id), {}).get(killer, {})
        if isinstance(last_seen, dict) and last_seen.get("coords"):
            kill_details["killer_coords"] = last_seen["coords"]

    if not kill_details.get("victim_coords") and kill_details.get("coords"):
        kill_details["victim_coords"] = kill_details.get("coords")

    return kill_details


async def ensure_cheat_check_channel(guild, config, force=False):
    channels = config.setdefault("channels", {})
    if is_channel_key_disabled(config, "cheat_checks") and not force:
        return None

    if force:
        set_channel_key_disabled(config, "cheat_checks", False)

    channel = bot.get_channel(channels.get("cheat_checks"))
    if channel:
        return channel

    overwrites = {
        guild.default_role: discord.PermissionOverwrite(view_channel=False),
        guild.me: discord.PermissionOverwrite(view_channel=True, send_messages=True, read_message_history=True),
    }
    for role in guild.roles:
        if role.permissions.administrator or role.name in config.get("admin_roles", DEFAULT_ADMIN_ROLES):
            overwrites[role] = discord.PermissionOverwrite(view_channel=True, send_messages=True, read_message_history=True)

    category_name = "🕵️🚫┃PRIVATE CHEAT CHECK┃🚫🕵️"
    category = discord.utils.get(guild.categories, name=category_name)
    if not category:
        category = await guild.create_category(category_name, overwrites=overwrites)

    channel = await guild.create_text_channel(
        DEFAULT_CHANNEL_NAMES["cheat_checks"],
        overwrites=overwrites,
        category=category
    )
    channels["cheat_checks"] = channel.id
    save_guild_configs()
    return channel


