def parse_saved_datetime(value):
    if not value:
        return None

    try:
        parsed = datetime.fromisoformat(str(value).replace("Z", "+00:00"))
        return parsed if parsed.tzinfo else parsed.replace(tzinfo=UTC)
    except Exception:
        return None


def edit_distance(left, right):
    left = str(left)
    right = str(right)

    if left == right:
        return 0

    distances = [
        [0 for _ in range(len(right) + 1)]
        for _ in range(len(left) + 1)
    ]

    for left_index in range(len(left) + 1):
        distances[left_index][0] = left_index

    for right_index in range(len(right) + 1):
        distances[0][right_index] = right_index

    for left_index, left_char in enumerate(left, start=1):
        for right_index, right_char in enumerate(right, start=1):
            replace_cost = 0 if left_char == right_char else 1
            distances[left_index][right_index] = min(
                distances[left_index - 1][right_index] + 1,
                distances[left_index][right_index - 1] + 1,
                distances[left_index - 1][right_index - 1] + replace_cost,
            )

            if (
                left_index > 1
                and right_index > 1
                and left[left_index - 1] == right[right_index - 2]
                and left[left_index - 2] == right[right_index - 1]
            ):
                distances[left_index][right_index] = min(
                    distances[left_index][right_index],
                    distances[left_index - 2][right_index - 2] + 1,
                )

    return distances[-1][-1]


def closest_adm_player_name(guild_id, typed_name):
    wanted = normalize_discord_name(typed_name)
    if not wanted:
        return None

    best_name = None
    best_distance = None

    for player_name, stats in player_stats.items():
        if str(stats.get("guild_id", "")) != str(guild_id):
            continue

        candidate = normalize_discord_name(player_name)
        if not candidate:
            continue

        distance = edit_distance(wanted, candidate)
        allowed_distance = 1 if len(candidate) <= 5 else 2 if len(candidate) <= 12 else 3
        if distance > allowed_distance:
            continue

        if best_distance is None or distance < best_distance:
            best_name = player_name
            best_distance = distance

    return best_name


def find_live_or_enforcement_player_name(guild_id, typed_name):
    wanted = normalize_discord_name(typed_name)
    if not wanted:
        return ""

    ensure_guild_runtime(str(guild_id))
    for player_name in online_players.get(str(guild_id), set()):
        if normalize_discord_name(player_name) == wanted:
            return str(player_name)

    config = guild_configs.get(str(guild_id), {})
    pending = {}
    try:
        pending = link_enforcement_pending_bucket(config)
    except Exception:
        pending = {}
    if isinstance(pending, dict):
        for record in pending.values():
            if not isinstance(record, dict):
                continue
            player_name = str(record.get("gamertag") or "").strip()
            if player_name and normalize_discord_name(player_name) == wanted:
                return player_name

    return ""


def learn_recent_adm_players_for_linking(guild_id, config, hours=168, max_logs=40):
    ensure_guild_runtime(str(guild_id))

    adm_logs = list_adm_logs(config, hours)
    if not adm_logs:
        latest_log = ping_latest_adm_log(config)
        adm_logs = [latest_log] if latest_log else []

    adm_logs = [adm_log for adm_log in adm_logs if adm_log][:max(1, int(max_logs or 40))]

    learned = 0
    scanned_logs = 0

    for adm_log in adm_logs:
        if not adm_log:
            continue

        if not download_latest_adm(guild_id, config, adm_log):
            continue

        adm_path = os.path.join(GUILD_DATA_FOLDER, f"{guild_id}.ADM")
        if not os.path.exists(adm_path):
            continue

        scanned_logs += 1
        log_seen_at = parse_saved_datetime(adm_log.get("_adm_datetime")) or adm_log_datetime(adm_log)
        log_seen_text = str(log_seen_at or (datetime.now(UTC) - timedelta(hours=hours)))

        with open(adm_path, "r", encoding="utf-8", errors="ignore") as f:
            lines = [line.strip() for line in f.readlines() if line.strip()]

        for line in lines:
            for player_name in extract_adm_player_names(line):
                if not player_name or player_name == "Unknown":
                    continue

                stats = ensure_player_stats_record(guild_id, player_name)
                if not stats:
                    continue

                existing_first_seen = parse_saved_datetime(stats.get("first_adm_seen"))
                if not existing_first_seen or (log_seen_at and log_seen_at < existing_first_seen):
                    stats["first_adm_seen"] = log_seen_text

                stats["last_adm_seen"] = log_seen_text
                learned += 1

            remember_player_location_from_adm(guild_id, line)

    if learned:
        save_player_stats()

    return learned, scanned_logs


def find_adm_verified_player(guild_id, typed_name, minimum_age_seconds=300):
    wanted = normalize_discord_name(typed_name)
    if not wanted:
        return None, "Type the exact gamertag that appears in the server ADM logs."

    matches = []
    for player_name, stats in player_stats.items():
        if str(stats.get("guild_id", "")) != str(guild_id):
            continue

        if normalize_discord_name(player_name) == wanted:
            matches.append((player_name, stats))

    if not matches:
        live_name = find_live_or_enforcement_player_name(guild_id, typed_name)
        if live_name:
            stats = ensure_player_stats_record(guild_id, live_name)
            if stats:
                stats["verified_from_live_link_enforcement"] = str(datetime.now(UTC))
                save_player_stats()
            return live_name, None

        suggestion = closest_adm_player_name(guild_id, typed_name)
        if suggestion:
            return None, f"That gamertag has not appeared exactly in ADM. Did you mean `{suggestion}`? Try `/linkgamer gamertag:{suggestion}`."

        return None, "That gamertag has not appeared in this server's ADM logs yet. Join the server first, wait at least 5 minutes, then try again."

    player_name, stats = matches[0]
    first_seen = parse_saved_datetime(stats.get("first_adm_seen") or stats.get("last_adm_seen") or stats.get("last_seen"))
    if not first_seen:
        return None, "That gamertag was found, but its ADM timestamp is missing. Wait for the next ADM scan, then try again."

    age_seconds = (datetime.now(UTC) - first_seen).total_seconds()
    if age_seconds < minimum_age_seconds:
        wait_minutes = max(1, int((minimum_age_seconds - age_seconds + 59) // 60))
        return None, f"That gamertag was just seen in ADM. Wait about `{wait_minutes}` more minute(s), then try again."

    return player_name, None


def linked_player_gamertags(data):
    names = []
    seen = set()

    def add(value):
        name = str(value or "").strip()
        key = normalize_discord_name(name)
        if name and key and key not in seen:
            seen.add(key)
            names.append(name)

    if isinstance(data, dict):
        add(data.get("gamertag") or data.get("player_name"))
        alt_values = data.get("alt_gamertags")
        if alt_values is None:
            alt_values = data.get("alts") or data.get("alt_gamertag")
        if isinstance(alt_values, (list, tuple, set)):
            for value in alt_values:
                add(value)
        else:
            add(alt_values)
    return names[:2]


def linked_player_alt_gamertags(data):
    return linked_player_gamertags(data)[1:2]


def linked_player_matches_gamertag(data, gamertag):
    wanted = normalize_discord_name(gamertag)
    if not wanted:
        return False
    return any(normalize_discord_name(name) == wanted for name in linked_player_gamertags(data))


def linked_player_primary_gamertag(data):
    names = linked_player_gamertags(data)
    return names[0] if names else ""


def linked_player_gamertag_summary(data):
    names = linked_player_gamertags(data)
    if not names:
        return "`Not linked`"
    lines = [f"Primary: `{names[0]}`"]
    if len(names) > 1:
        lines.append(f"Alt: `{names[1]}`")
    return "\n".join(lines)


def linked_player_claim_key(gamertag):
    return normalize_discord_name(gamertag)


def linked_player_claim_owner_id(claim):
    if not isinstance(claim, dict):
        return ""
    return str(
        claim.get("current_user_id")
        or claim.get("owner_user_id")
        or claim.get("first_user_id")
        or claim.get("discord_id")
        or ""
    )


def linked_player_claim_owner_label(claim):
    if not isinstance(claim, dict):
        return ""
    return str(
        claim.get("current_discord_name")
        or claim.get("owner_discord_name")
        or claim.get("first_discord_name")
        or linked_player_claim_owner_id(claim)
        or "that Discord account"
    )


def linked_player_claim_history(claim):
    if not isinstance(claim, dict):
        return []
    history = claim.setdefault("history", [])
    if not isinstance(history, list):
        history = []
        claim["history"] = history
    return history


def record_linked_player_claim(guild_id, user_id, discord_name, gamertag, *, source="linkgamer", account_type="primary", override=False):
    key = linked_player_claim_key(gamertag)
    if not key:
        return None
    now_text = datetime.now(UTC).isoformat()
    user_id = str(user_id)
    claim = linked_player_claims.setdefault(key, {})
    previous_owner = linked_player_claim_owner_id(claim)
    if previous_owner and previous_owner != user_id and override:
        linked_player_claim_history(claim).append({
            "action": "admin_override",
            "previous_user_id": previous_owner,
            "previous_discord_name": linked_player_claim_owner_label(claim),
            "new_user_id": user_id,
            "new_discord_name": str(discord_name),
            "source": source,
            "at": now_text,
        })
    claim.setdefault("first_user_id", user_id)
    claim.setdefault("first_discord_name", str(discord_name))
    claim.setdefault("first_claimed_at", now_text)
    claim["current_user_id"] = user_id
    claim["current_discord_name"] = str(discord_name)
    claim["guild_id"] = str(guild_id)
    claim["gamertag"] = str(gamertag).strip()
    claim["normalized_gamertag"] = key
    claim["account_type"] = account_type
    claim["status"] = "active"
    claim["source"] = source
    claim["updated_at"] = now_text
    linked_player_claim_history(claim).append({
        "action": "claim",
        "user_id": user_id,
        "discord_name": str(discord_name),
        "guild_id": str(guild_id),
        "gamertag": str(gamertag).strip(),
        "account_type": account_type,
        "source": source,
        "at": now_text,
    })
    return claim


def reserve_removed_linked_player_claim(guild_id, user_id, discord_name, gamertag, *, source="unlinkgamer", reason="removed"):
    key = linked_player_claim_key(gamertag)
    if not key:
        return None
    now_text = datetime.now(UTC).isoformat()
    claim = linked_player_claims.setdefault(key, {})
    claim.setdefault("first_user_id", str(user_id))
    claim.setdefault("first_discord_name", str(discord_name))
    claim.setdefault("first_claimed_at", now_text)
    claim.setdefault("guild_id", str(guild_id))
    claim.setdefault("gamertag", str(gamertag).strip())
    claim["normalized_gamertag"] = key
    if linked_player_claim_owner_id(claim) == str(user_id):
        claim.pop("current_user_id", None)
        claim.pop("current_discord_name", None)
    claim["status"] = f"reserved_{reason}"
    claim["updated_at"] = now_text
    claim["source"] = source
    linked_player_claim_history(claim).append({
        "action": reason,
        "user_id": str(user_id),
        "discord_name": str(discord_name),
        "guild_id": str(guild_id),
        "gamertag": str(gamertag).strip(),
        "source": source,
        "at": now_text,
    })
    return claim


def migrate_linked_player_claims_from_links():
    changed = False
    for user_id, data in list(linked_players.items()):
        if not isinstance(data, dict):
            continue
        guild_id = str(data.get("guild_id") or "")
        discord_name = str(data.get("discord_name") or user_id)
        names = linked_player_gamertags(data)
        for index, gamertag in enumerate(names[:2]):
            key = linked_player_claim_key(gamertag)
            if not key:
                continue
            claim = linked_player_claims.get(key)
            if not isinstance(claim, dict):
                record_linked_player_claim(
                    guild_id,
                    user_id,
                    discord_name,
                    gamertag,
                    source="migration",
                    account_type="primary" if index == 0 else "alt",
                )
                changed = True
                continue
            owner_id = linked_player_claim_owner_id(claim)
            if not owner_id:
                record_linked_player_claim(
                    guild_id,
                    user_id,
                    discord_name,
                    gamertag,
                    source="migration",
                    account_type="primary" if index == 0 else "alt",
                )
                changed = True
            elif owner_id != str(user_id):
                linked_player_claim_history(claim).append({
                    "action": "duplicate_detected_on_migration",
                    "existing_owner_id": owner_id,
                    "duplicate_user_id": str(user_id),
                    "duplicate_discord_name": discord_name,
                    "guild_id": guild_id,
                    "gamertag": str(gamertag).strip(),
                    "at": datetime.now(UTC).isoformat(),
                })
                claim["duplicate_detected"] = True
                claim["updated_at"] = datetime.now(UTC).isoformat()
                changed = True
    return changed


def gamertag_claimed_to_other_user(gamertag, user_id):
    key = linked_player_claim_key(gamertag)
    if not key:
        return None, None
    claim = linked_player_claims.get(key)
    owner_id = linked_player_claim_owner_id(claim)
    if owner_id and owner_id != str(user_id):
        return key, claim
    return None, None


def active_manual_ban_record_for_gamertag(guild_id, gamertag):
    wanted = normalize_discord_name(gamertag)
    if not wanted:
        return None
    config = guild_configs.get(str(guild_id), {})
    for record in config.get("nitrado_perm_bans", []):
        if isinstance(record, dict) and normalize_discord_name(record.get("gamertag")) == wanted:
            return record
    now_ts = datetime.now(UTC).timestamp()
    for record in config.get("nitrado_temp_bans", []):
        if not isinstance(record, dict):
            continue
        if normalize_discord_name(record.get("gamertag")) != wanted:
            continue
        if _temp_ban_record_is_link_enforcement(record):
            continue
        until_ts = float(record.get("until_ts") or 0)
        if not until_ts or until_ts > now_ts:
            return record
    return None


def gamertag_linked_to_other_user(gamertag, user_id):
    wanted = normalize_discord_name(gamertag)
    _claim_key, claim = gamertag_claimed_to_other_user(gamertag, user_id)
    if claim:
        return linked_player_claim_owner_id(claim), {
            "discord_name": linked_player_claim_owner_label(claim),
            "gamertag": claim.get("gamertag") or gamertag,
            "claim": claim,
        }
    for linked_user_id, data in linked_players.items():
        if str(linked_user_id) == str(user_id):
            continue
        if linked_player_matches_gamertag(data, wanted):
            return linked_user_id, data
    return None, None


ONBOARDING_REACTION_OPTIONS = {"✅", "👍", "🟢", "🛡️", "📜"}


def member_onboarding_settings(config):
    saved = config.get("member_onboarding") if isinstance(config, dict) else {}
    saved = saved if isinstance(saved, dict) else {}
    reaction = str(saved.get("reaction_emoji") or "✅").strip() or "✅"
    if reaction not in ONBOARDING_REACTION_OPTIONS:
        reaction = "✅"
    return {
        "enabled": bool(saved.get("enabled")),
        "rules_channel_key": str(saved.get("rules_channel_key") or "").strip(),
        "rules_channel_id": str(saved.get("rules_channel_id") or "").strip(),
        "next_channel_key": str(saved.get("next_channel_key") or "").strip(),
        "next_channel_id": str(saved.get("next_channel_id") or "").strip(),
        "rules_role_id": str(saved.get("rules_role_id") or "").strip(),
        "linked_role_id": str(saved.get("linked_role_id") or "").strip(),
        "pending_role_id": str(saved.get("pending_role_id") or "").strip(),
        "reaction_emoji": reaction,
        "rules_message_id": str(saved.get("rules_message_id") or "").strip(),
        "require_rules_before_linked_role": bool(saved.get("require_rules_before_linked_role", True)),
        "welcome_message": str(saved.get("welcome_message") or "Read the rules, react to accept them, then link your gamertag with /linkgamer.").strip(),
        "accepted_message": str(saved.get("accepted_message") or "Rules accepted. Next step: link your gamertag with /linkgamer.").strip(),
        "linked_message": str(saved.get("linked_message") or "Gamertag linked. Your linked-player role has been applied.").strip(),
    }


def resolve_onboarding_channel(guild, config, settings, prefix, fallback_key="welcome"):
    channels = config.get("channels", {}) if isinstance(config.get("channels"), dict) else {}
    channel_id = str(settings.get(f"{prefix}_channel_id") or "").strip()
    channel_key = str(settings.get(f"{prefix}_channel_key") or "").strip()
    if channel_id.isdigit():
        channel = guild.get_channel(int(channel_id))
        if channel:
            return channel
    if channel_key:
        configured_id = channels.get(channel_key)
        if configured_id:
            channel = guild.get_channel(int(configured_id))
            if channel:
                return channel
        for channel in getattr(guild, "text_channels", []) or []:
            if normalize_discord_name(getattr(channel, "name", "")) == normalize_discord_name(channel_key):
                return channel
    configured_id = channels.get(fallback_key)
    if configured_id:
        return guild.get_channel(int(configured_id))
    return None


def resolve_onboarding_role(guild, role_id):
    text = str(role_id or "").strip()
    if not text.isdigit():
        return None
    return guild.get_role(int(text))


def member_has_role_id(member, role_id):
    wanted = str(role_id or "").strip()
    if not wanted:
        return False
    return any(str(getattr(role, "id", "")) == wanted for role in getattr(member, "roles", []) or [])


async def add_onboarding_role(member, role_id, reason):
    role = resolve_onboarding_role(member.guild, role_id)
    if not role or member_has_role_id(member, role_id):
        return False
    try:
        await member.add_roles(role, reason=reason)
        return True
    except Exception as error:
        print(f"[ONBOARDING] failed to add role {role_id} to {member}: {error}")
        return False


async def remove_onboarding_role(member, role_id, reason):
    role = resolve_onboarding_role(member.guild, role_id)
    if not role or not member_has_role_id(member, role_id):
        return False
    try:
        await member.remove_roles(role, reason=reason)
        return True
    except Exception as error:
        print(f"[ONBOARDING] failed to remove role {role_id} from {member}: {error}")
        return False


def onboarding_message_has_reaction(message, reaction_emoji):
    wanted = str(reaction_emoji or "").strip()
    if not wanted:
        return False
    for reaction in getattr(message, "reactions", []) or []:
        if str(getattr(reaction, "emoji", "")) == wanted:
            return True
    return False


def is_onboarding_bot_prompt_message(message):
    for embed in getattr(message, "embeds", []) or []:
        if str(getattr(embed, "title", "") or "").strip().upper() == "RULES CHECK REQUIRED":
            return True
        footer = getattr(embed, "footer", None)
        footer_text = str(getattr(footer, "text", "") or "")
        if "Member Onboarding" in footer_text:
            return True
    return False


def is_onboarding_rules_message_candidate(message):
    if is_onboarding_bot_prompt_message(message):
        return False
    if (getattr(message, "content", "") or "").strip():
        return True
    return bool(getattr(message, "embeds", None))


async def fetch_onboarding_rules_message(channel, message_id):
    message_text = str(message_id or "").strip()
    if not message_text.isdigit():
        return None
    try:
        message = await channel.fetch_message(int(message_text))
        if is_onboarding_rules_message_candidate(message):
            return message
    except Exception as error:
        print(f"[ONBOARDING] could not fetch configured rules message {message_text}: {error}")
    return None


async def find_existing_onboarding_rules_message(channel, reaction_emoji):
    pinned_candidates = []
    try:
        pinned_candidates = [
            message
            for message in await channel.pins()
            if is_onboarding_rules_message_candidate(message)
        ]
    except Exception as error:
        print(f"[ONBOARDING] could not inspect pinned rules messages in #{getattr(channel, 'name', channel)}: {error}")

    for message in pinned_candidates:
        if onboarding_message_has_reaction(message, reaction_emoji):
            return message
    if pinned_candidates:
        return pinned_candidates[0]

    fallback = None
    try:
        async for message in channel.history(limit=100, oldest_first=False):
            if not is_onboarding_rules_message_candidate(message):
                continue
            if onboarding_message_has_reaction(message, reaction_emoji):
                return message
            content = (getattr(message, "content", "") or "").strip()
            if fallback is None and (len(content) >= 80 or getattr(message, "embeds", None)):
                fallback = message
    except Exception as error:
        print(f"[ONBOARDING] could not inspect rules channel history in #{getattr(channel, 'name', channel)}: {error}")
    return fallback


def remember_onboarding_rules_message(config, settings, message_id):
    if not isinstance(config, dict):
        return
    onboarding = config.get("member_onboarding")
    if not isinstance(onboarding, dict):
        onboarding = {}
        config["member_onboarding"] = onboarding
    message_text = str(message_id or "").strip()
    if not message_text or str(onboarding.get("rules_message_id") or "").strip() == message_text:
        return
    onboarding["rules_message_id"] = message_text
    settings["rules_message_id"] = message_text
    try:
        save_guild_configs()
    except Exception as error:
        print(f"[ONBOARDING] could not save discovered rules message {message_text}: {error}")


async def send_member_onboarding_join_prompt(member, config, settings):
    channel = resolve_onboarding_channel(member.guild, config, settings, "rules", "welcome")
    if not channel:
        return False
    reaction_emoji = settings["reaction_emoji"]
    target_message = await fetch_onboarding_rules_message(channel, settings.get("rules_message_id"))
    if not target_message:
        target_message = await find_existing_onboarding_rules_message(channel, reaction_emoji)
        if target_message:
            remember_onboarding_rules_message(config, settings, getattr(target_message, "id", ""))
    if not target_message:
        print(f"[ONBOARDING] no real rules message target found in #{getattr(channel, 'name', channel)}; refusing to create a second reaction target")
        return False
    try:
        await target_message.add_reaction(reaction_emoji)
    except Exception as error:
        print(f"[ONBOARDING] could not add rules reaction to message {getattr(target_message, 'id', '')}: {error}")
    try:
        await member.send(
            f"Please read and react to the server rules here: {target_message.jump_url}\n"
            f"React with {reaction_emoji} to unlock the next step, then use /linkgamer."
        )
        return True
    except Exception as error:
        print(f"[ONBOARDING] could not DM rules link to {member}: {error}")
        return True


async def apply_member_onboarding_rules_acceptance(guild, config, member):
    settings = member_onboarding_settings(config)
    if not settings["enabled"]:
        return False
    await add_onboarding_role(member, settings.get("rules_role_id"), "Wandering Bot rules accepted")
    await remove_onboarding_role(member, settings.get("pending_role_id"), "Wandering Bot rules accepted")
    linked_data = linked_players.get(str(member.id), {}) if isinstance(linked_players.get(str(member.id)), dict) else {}
    if linked_player_primary_gamertag(linked_data):
        await add_onboarding_role(member, settings.get("linked_role_id"), "Wandering Bot gamertag already linked when rules were accepted")
    channel = resolve_onboarding_channel(guild, config, settings, "next", "general_chat") or resolve_onboarding_channel(guild, config, settings, "rules", "welcome")
    if channel:
        embed = discord.Embed(
            title="RULES ACCEPTED",
            description=f"{member.mention}\n\n{settings['accepted_message']}",
            color=0x2ECC71,
        )
        embed.set_thumbnail(url=BOT_IMAGE)
        embed.set_footer(text="Wandering Bot Alpha - Member Onboarding")
        try:
            await channel.send(embed=style_embed(embed), allowed_mentions=discord.AllowedMentions(users=True, roles=False, everyone=False))
        except Exception as error:
            print(f"[ONBOARDING] accepted notice failed for {member}: {error}")
    return True


async def apply_member_onboarding_link_role(guild, config, member):
    settings = member_onboarding_settings(config)
    if not settings["enabled"] or not settings.get("linked_role_id"):
        return False
    if settings.get("require_rules_before_linked_role") and settings.get("rules_role_id") and not member_has_role_id(member, settings.get("rules_role_id")):
        return False
    changed = await add_onboarding_role(member, settings.get("linked_role_id"), "Wandering Bot gamertag linked")
    await remove_onboarding_role(member, settings.get("pending_role_id"), "Wandering Bot gamertag linked")
    if changed:
        channel = resolve_onboarding_channel(guild, config, settings, "next", "general_chat") or resolve_onboarding_channel(guild, config, settings, "rules", "welcome")
        if channel:
            embed = discord.Embed(
                title="GAMERTAG LINK COMPLETE",
                description=f"{member.mention}\n\n{settings['linked_message']}",
                color=0x00D1B2,
            )
            embed.set_thumbnail(url=BOT_IMAGE)
            embed.set_footer(text="Wandering Bot Alpha - Member Onboarding")
            try:
                await channel.send(embed=style_embed(embed), allowed_mentions=discord.AllowedMentions(users=True, roles=False, everyone=False))
            except Exception as error:
                print(f"[ONBOARDING] linked notice failed for {member}: {error}")
    return changed


async def announce_verified_gamer_link(guild, config, member, gamertag, account_label="Primary gamertag"):
    channel = await get_or_create_feed_channel(
        guild,
        config,
        "linked_players",
        DEFAULT_CHANNEL_NAMES["linked_players"],
        private=False
    )

    embed = discord.Embed(
        title="VERIFIED GAMERTAG LINKED",
        description=f"{member.mention} is now verified as `{gamertag}`.",
        color=0x2ECC71
    )
    embed.add_field(name="Discord", value=str(member), inline=True)
    embed.add_field(name="Account", value=account_label, inline=True)
    embed.add_field(name="ADM Verified Gamertag", value=gamertag, inline=True)
    embed.add_field(name="Recognition", value="Identity confirmed from ADM history and ready for economy rewards.", inline=False)
    embed.set_thumbnail(url=BOT_IMAGE)
    embed.set_footer(text="Wandering Bot Alpha - Verified Identity")
    await channel.send(embed=style_embed(embed))

    audit_channel = await get_or_create_feed_channel(
        guild,
        config,
        "link_audit",
        DEFAULT_CHANNEL_NAMES["link_audit"],
        private=True
    )
    if audit_channel:
        audit = discord.Embed(
            title="GAMERTAG LINK AUDIT",
            description="A Discord account has linked to an ADM verified survivor name.",
            color=0x3498DB
        )
        audit.add_field(name="Discord", value=f"{member.mention}\n`{member}`", inline=False)
        audit.add_field(name="Discord ID", value=f"`{member.id}`", inline=True)
        audit.add_field(name="Account", value=account_label, inline=True)
        audit.add_field(name="Gamertag", value=f"`{gamertag}`", inline=True)
        audit.add_field(name="Guild", value=f"{guild.name}\n`{guild.id}`", inline=False)
        audit.set_thumbnail(url=BOT_IMAGE)
        audit.set_footer(text="Wandering Bot Alpha - Private Identity Audit")
        await audit_channel.send(embed=style_embed(audit))


