BOT_CATEGORY_SPECS_BY_KEY = {
    key: (name, aliases)
    for key, name, aliases in CATEGORY_REPAIR_SPECS
}


def category_matches_bot_spec(category, category_key):
    spec = BOT_CATEGORY_SPECS_BY_KEY.get(category_key)
    if not spec:
        return False

    desired_name, aliases = spec
    normalized = normalize_discord_name(category.name)
    strict_names = {normalize_discord_name(desired_name)}
    strict_names.update(normalize_discord_name(alias) for alias in aliases)
    return normalized in strict_names


async def ensure_bot_category(guild, category_key):
    spec = BOT_CATEGORY_SPECS_BY_KEY.get(category_key)
    if not spec:
        return None

    desired_name, _ = spec
    for category in guild.categories:
        if category_matches_bot_spec(category, category_key):
            if category.name != desired_name:
                try:
                    await category.edit(name=desired_name)
                except Exception:
                    pass
            return category

    return await guild.create_category(desired_name)


def channel_matches_bot_default_name(channel, key):
    desired = DEFAULT_CHANNEL_NAMES.get(key)
    if not desired:
        return False
    return normalize_discord_name(channel.name) == normalize_discord_name(desired)


def channel_matches_saved_key(channel, key):
    return channel_matches_bot_default_name(channel, key)


MOJIBAKE_MARKERS = ("đ", "Đ", "â", "ă", "Ă", "ď", "Ď", "\x83", "\x90", "\x9f")


def reverse_cp1250_mojibake(text):
    text = str(text or "")
    if not text or not any(marker in text for marker in MOJIBAKE_MARKERS):
        return text

    reverse = {}
    for byte_value in range(256):
        try:
            reverse[bytes([byte_value]).decode("cp1250")] = byte_value
        except UnicodeDecodeError:
            pass

    for byte_value in range(0x80, 0xA0):
        reverse[chr(byte_value)] = byte_value

    raw = bytearray()
    for char in text:
        if ord(char) < 128:
            raw.append(ord(char))
        elif char in reverse:
            raw.append(reverse[char])
        else:
            return text

    try:
        return bytes(raw).decode("utf-8")
    except UnicodeDecodeError:
        return text


def default_channel_key_for_name(name):
    normalized = normalize_discord_name(name)
    if not normalized:
        return None

    for key, desired_name in DEFAULT_CHANNEL_NAMES.items():
        if normalized == normalize_discord_name(desired_name):
            return key

    return None


def disabled_channel_keys(config):
    disabled = config.setdefault("disabled_channels", [])
    if not isinstance(disabled, list):
        disabled = []
        config["disabled_channels"] = disabled
    return disabled


def is_channel_key_disabled(config, key):
    return key in set(disabled_channel_keys(config))


def _feed_route_should_log(guild_id, key, reason, seconds=300):
    now_ts = time.time()
    route_key = (str(guild_id), str(key), str(reason))
    last_ts = feed_route_log_time.get(route_key, 0)
    if now_ts - last_ts < seconds:
        return False
    feed_route_log_time[route_key] = now_ts
    return True


def _safe_channel_id(value):
    try:
        if value is None or value == "":
            return None
        return int(value)
    except Exception:
        return None


def resolve_feed_channel(guild_id, config, key, *, required=False, allow_name_repair=True):
    channels = config.setdefault("channels", {})
    if not isinstance(channels, dict):
        channels = {}
        config["channels"] = channels

    if is_channel_key_disabled(config, key):
        if required and _feed_route_should_log(guild_id, key, "disabled"):
            print(f"[FEED ROUTE] {guild_id} #{DEFAULT_CHANNEL_NAMES.get(key, key)} is disabled in config; not posting feed.")
        return None

    guild = None
    try:
        guild = bot.get_guild(int(guild_id))
    except Exception:
        guild = None

    saved_id = _safe_channel_id(channels.get(key))
    if saved_id:
        channel = bot.get_channel(saved_id)
        if channel:
            return channel
        if guild:
            channel = guild.get_channel(saved_id)
            if channel:
                return channel

    if allow_name_repair and guild:
        for channel in getattr(guild, "text_channels", []):
            if channel_matches_saved_key(channel, key):
                channels[key] = channel.id
                save_guild_configs()
                if _feed_route_should_log(guild_id, key, "repaired"):
                    print(f"[FEED ROUTE] {guild_id} repaired #{DEFAULT_CHANNEL_NAMES.get(key, key)} to channel id {channel.id}.")
                return channel

    if required and _feed_route_should_log(guild_id, key, "missing"):
        if saved_id:
            print(f"[FEED ROUTE] {guild_id} saved #{DEFAULT_CHANNEL_NAMES.get(key, key)} channel id {saved_id} could not be resolved.")
        else:
            print(f"[FEED ROUTE] {guild_id} has no saved channel id for #{DEFAULT_CHANNEL_NAMES.get(key, key)}.")
    return None


def set_channel_key_disabled(config, key, disabled=True):
    disabled_keys = disabled_channel_keys(config)
    if disabled and key not in disabled_keys:
        disabled_keys.append(key)
    elif not disabled and key in disabled_keys:
        disabled_keys.remove(key)


def mark_deleted_bot_channel(guild_id, channel_id):
    config = guild_configs.get(str(guild_id))
    if not config:
        return None

    channels = config.setdefault("channels", {})
    for key, saved_id in list(channels.items()):
        if int(saved_id or 0) != int(channel_id):
            continue
        channels.pop(key, None)
        set_channel_key_disabled(config, key, True)
        save_guild_configs()
        return key

    return None


def discover_existing_guild_channels(guild, config):
    channels = config.setdefault("channels", {})
    changed = False

    for key in DEFAULT_CHANNEL_NAMES:
        if is_channel_key_disabled(config, key):
            continue

        existing_id = channels.get(key)

        existing_channel_id = _safe_channel_id(existing_id)
        if existing_channel_id and guild.get_channel(existing_channel_id):
            continue

        for channel in guild.text_channels:
            if channel_matches_saved_key(channel, key):
                channels[key] = channel.id
                changed = True
                break

    return changed


async def repair_guild_display_names(guild, config):
    channels = config.setdefault("channels", {})
    repaired = 0
    edited_channel_ids = set()

    for category_key, category_name, aliases in CATEGORY_REPAIR_SPECS:
        for category in guild.categories:
            if category_matches_bot_spec(category, category_key):
                if category.name != category_name:
                    try:
                        await category.edit(name=category_name)
                        repaired += 1
                    except Exception:
                        pass
                break

    for category in guild.categories:
        decoded_name = reverse_cp1250_mojibake(category.name)
        if decoded_name != category.name:
            desired_name = decoded_name
            decoded_normalized = normalize_discord_name(decoded_name)
            for _, category_name, aliases in CATEGORY_REPAIR_SPECS:
                wanted = normalize_discord_name(category_name)
                alias_set = {wanted, *aliases}
                if decoded_normalized in alias_set:
                    desired_name = category_name
                    break

            try:
                await category.edit(name=desired_name)
                repaired += 1
            except Exception:
                pass

    for candidate in guild.text_channels:
        decoded_name = reverse_cp1250_mojibake(candidate.name)
        if decoded_name == candidate.name:
            continue

        key = default_channel_key_for_name(decoded_name)
        if key and is_channel_key_disabled(config, key):
            continue

        desired_name = DEFAULT_CHANNEL_NAMES.get(key, decoded_name)
        if candidate.name == desired_name:
            continue

        try:
            await candidate.edit(name=desired_name)
            edited_channel_ids.add(candidate.id)
            if key:
                channels[key] = candidate.id
            repaired += 1
        except Exception:
            pass

    for key, desired_name in DEFAULT_CHANNEL_NAMES.items():
        if is_channel_key_disabled(config, key):
            continue

        channel = None
        existing_id = channels.get(key)

        if existing_id:
            channel = guild.get_channel(int(existing_id))

        if not channel:
            for candidate in guild.text_channels:
                if channel_matches_saved_key(candidate, key):
                    channel = candidate
                    channels[key] = candidate.id
                    break

        category = await ensure_bot_category(guild, BOT_CHANNEL_CATEGORY_BY_KEY.get(key, "live_feeds"))
        needs_name = channel and channel.id not in edited_channel_ids and channel.name != desired_name
        needs_category = channel and category and channel.category_id != category.id
        if needs_name or needs_category:
            try:
                await channel.edit(name=desired_name, category=category)
                repaired += 1
            except Exception:
                pass

    save_guild_configs()
    return repaired


def env_truthy(name, default=""):
    return str(os.getenv(name, default)).strip().lower() in {"1", "true", "yes", "on"}


def startup_display_name_repair_enabled():
    return env_truthy("WANDERING_REPAIR_NAMES_ON_STARTUP", "false")


def startup_display_name_repair_cooldown_seconds():
    try:
        hours = float(os.getenv("WANDERING_REPAIR_NAMES_COOLDOWN_HOURS", "24"))
    except Exception:
        hours = 24
    return max(1, int(hours * 3600))


def should_run_startup_display_name_repair(config, now_ts):
    if not startup_display_name_repair_enabled():
        return False

    try:
        last_repair = float(config.get("last_display_name_repair_ts", 0) or 0)
    except Exception:
        last_repair = 0

    return now_ts - last_repair >= startup_display_name_repair_cooldown_seconds()


async def repair_display_names_for_active_guilds(force=False):
    if not force and not startup_display_name_repair_enabled():
        print("DISPLAY NAME REPAIR SKIPPED: startup repair disabled")
        return

    now_ts = datetime.now(UTC).timestamp()
    changed = False

    for guild in bot.guilds:
        try:
            guild_id = str(guild.id)
            config = guild_configs.setdefault(guild_id, new_guild_config(guild))

            if not force and not should_run_startup_display_name_repair(config, now_ts):
                continue

            repaired = await repair_guild_display_names(guild, config)
            config["last_display_name_repair_ts"] = now_ts
            changed = True
            if repaired:
                print(f"DISPLAY NAME REPAIR {guild.id}: {repaired}")
        except Exception as error:
            print(f"DISPLAY NAME REPAIR ERROR {guild.id}: {error}")

    if changed:
        save_guild_configs()


async def ensure_bot_updates_channel(guild, config, force=False):
    channels = config.setdefault("channels", {})
    if is_channel_key_disabled(config, "bot_updates") and not force:
        return None

    if force:
        set_channel_key_disabled(config, "bot_updates", False)

    category = await ensure_bot_category(guild, "bot_updates")

    channel = bot.get_channel(channels.get("bot_updates"))
    if channel:
        if category and channel.category_id != category.id:
            try:
                await channel.edit(category=category)
            except Exception:
                pass
        return channel

    for existing in guild.text_channels:
        if channel_matches_saved_key(existing, "bot_updates"):
            channels["bot_updates"] = existing.id
            if category and existing.category_id != category.id:
                try:
                    await existing.edit(category=category)
                except Exception:
                    pass
            save_guild_configs()
            return existing

    channel = await guild.create_text_channel(
        DEFAULT_CHANNEL_NAMES["bot_updates"],
        category=category
    )
    channels["bot_updates"] = channel.id
    save_guild_configs()
    return channel


async def publish_bot_update_notes(guild, config, *, force=False):
    channel = await ensure_bot_updates_channel(guild, config, force=force)
    if not channel:
        return 0, None

    posted = set(config.setdefault("posted_bot_update_ids", []))
    sent = 0

    for note in BOT_UPDATE_NOTES:
        note_id = note["id"]
        if not force and note_id in posted:
            continue

        embed = discord.Embed(
            title=f"BOT UPDATE: {note['title']}",
            description=note["summary"],
            color=0xF1C40F
        )
        embed.add_field(name="Commands", value=note.get("commands", "No commands changed."), inline=False)
        embed.add_field(name="Who Uses It", value=note.get("audience", "Everyone"), inline=False)
        embed.add_field(name="Privacy", value="No tokens, passwords, private logs, or sensitive setup details are posted here.", inline=False)
        embed.set_thumbnail(url=BOT_IMAGE)
        embed.set_footer(text=f"Wandering Bot Alpha - Update ID {note_id}")
        embed.timestamp = datetime.now(UTC)
        await channel.send(embed=style_embed(embed))
        posted.add(note_id)
        sent += 1

    config["posted_bot_update_ids"] = sorted(posted)
    save_guild_configs()
    return sent, channel


async def publish_bot_updates_for_active_guilds():
    for guild in bot.guilds:
        try:
            guild_id = str(guild.id)
            config = guild_configs.setdefault(guild_id, new_guild_config(guild))
            await publish_bot_update_notes(guild, config)
        except Exception as error:
            print(f"BOT UPDATE FEED ERROR {guild.id}: {error}")


def resolve_channel_key(text):
    wanted = normalize_discord_name(text)
    if not wanted:
        return None

    for key in DEFAULT_CHANNEL_NAMES:
        if wanted == normalize_discord_name(key):
            return key
        if wanted == normalize_discord_name(DEFAULT_CHANNEL_NAMES.get(key, "")):
            return key
        for alias in CHANNEL_ALIASES.get(key, []):
            if wanted == normalize_discord_name(alias):
                return key

    return None


def format_channel_restore_packs():
    lines = []
    for pack, keys in CHANNEL_RESTORE_PACKS.items():
        if pack == "all":
            continue
        lines.append(f"`{pack}` - {len(keys)} channel(s)")
    lines.append("`all` - every bot channel")
    return "\n".join(lines)


async def restore_disabled_bot_channels(guild, config, channel_key=None, channel_keys=None):
    disabled = list(disabled_channel_keys(config))
    if channel_key:
        resolved = resolve_channel_key(channel_key)
        if not resolved:
            return [], f"`{channel_key}` is not a bot channel key I recognise."
        keys_to_restore = [resolved]
    elif channel_keys is not None:
        keys_to_restore = [key for key in channel_keys if key in DEFAULT_CHANNEL_NAMES]
    else:
        keys_to_restore = disabled

    restored = []
    for key in keys_to_restore:
        if not channel_key_allowed_for_server_mode(key, config):
            continue

        name = DEFAULT_CHANNEL_NAMES.get(key)
        if not name:
            continue

        if key == "bot_updates":
            channel = await ensure_bot_updates_channel(guild, config, force=True)
        elif key == "cheat_checks":
            channel = await ensure_cheat_check_channel(guild, config, force=True)
        elif key == "public_shame":
            channel = await ensure_public_shame_channel(guild, config, force=True)
        else:
            channel = await get_or_create_feed_channel(
                guild,
                config,
                key,
                name,
                private=key in PRIVATE_FEED_CHANNEL_KEYS,
                force=True
            )

        if channel:
            restored.append(f"`{key}` -> {channel.mention}")

    save_guild_configs()
    return restored, None


async def ensure_pve_channels(guild, config, force=False):
    if not server_allows_pve(config):
        return {}

    channels = config.setdefault("channels", {})
    pve_channel_keys = [
        "pve_quests",
        "pve_hunting",
        "pve_collection",
        "pve_fishing",
        "pve_crafting",
        "pve_expeditions",
        "pve_info",
        "pve_help",
        "pve_heatmap",
        "pve_rewards_public",
        "pve_rewards_private",
        "quest_workshop"
    ]

    if not force and all(is_channel_key_disabled(config, key) for key in pve_channel_keys):
        return {}

    pve_category = await ensure_bot_category(guild, "pve")

    async def ensure_channel(key):
        name = DEFAULT_CHANNEL_NAMES[key]
        if is_channel_key_disabled(config, key) and not force:
            return None

        if force:
            set_channel_key_disabled(config, key, False)

        # quest_workshop and pve_rewards_private are admin-only.
        # Hidden from @everyone, allow admins only.
        is_private = key in ("quest_workshop", "pve_rewards_private")
        overwrites = {}
        if is_private:
            overwrites = {
                guild.default_role: discord.PermissionOverwrite(read_messages=False)
            }
            for role in guild.roles:
                if role.permissions.administrator or role.name in config.get("admin_roles", DEFAULT_ADMIN_ROLES):
                    overwrites[role] = discord.PermissionOverwrite(read_messages=True, send_messages=True)

        existing_id = channels.get(key)
        if existing_id:
            existing = guild.get_channel(existing_id)
            if existing:
                needs_name = existing.name != name
                needs_category = pve_category and existing.category_id != pve_category.id
                if needs_name or needs_category:
                    try:
                        await existing.edit(name=name, category=pve_category)
                    except Exception:
                        pass
                # Only re-apply admin-only overwrites if they're actually
                # missing — Discord rate-limits PUT permissions hard, so
                # blasting all of them on every restart triggers 429s.
                if is_private:
                    try:
                        existing_overwrites = existing.overwrites
                        for target, overwrite in overwrites.items():
                            current = existing_overwrites.get(target)
                            if current != overwrite:
                                await existing.set_permissions(target, overwrite=overwrite)
                    except Exception:
                        pass
                return existing

        for channel in guild.text_channels:
            if channel_matches_saved_key(channel, key):
                channels[key] = channel.id
                needs_name = channel.name != name
                needs_category = pve_category and channel.category_id != pve_category.id
                if needs_name or needs_category:
                    try:
                        await channel.edit(name=name, category=pve_category)
                    except Exception:
                        pass
                if is_private:
                    try:
                        existing_overwrites = channel.overwrites
                        for target, overwrite in overwrites.items():
                            current = existing_overwrites.get(target)
                            if current != overwrite:
                                await channel.set_permissions(target, overwrite=overwrite)
                    except Exception:
                        pass
                return channel

        if is_private:
            channel = await guild.create_text_channel(name, category=pve_category, overwrites=overwrites)
        else:
            channel = await guild.create_text_channel(name, category=pve_category)
        channels[key] = channel.id

        # First-time welcome for the quest workshop so admins know what
        # to type. Sent only on creation, never on re-syncs. The public
        # pve-help guides are seeded separately at the end of
        # ensure_pve_channels() so existing guilds also get them.
        if is_private and key == "quest_workshop":
            try:
                welcome = discord.Embed(
                    title="🛠️ Welcome to the AI Quest Workshop",
                    description=(
                        "This is your private admin channel. Talk to me here in plain English "
                        "and I'll design DayZ PVE quests, full storylines, or recurring schedules.\n\n"
                        "**Try things like:**\n"
                        "• `make me 12 winter outbreak quests`\n"
                        "• `write a 6-part storyline about a missing coastal convoy`\n"
                        "• `post one of those convoy quests in pve-expeditions every 12 hours`\n"
                        "• `list my campaigns`\n"
                        "• `cancel schedule sched-1234...`\n\n"
                        "Type `help` any time to see this again."
                    ),
                    color=0x9B59B6,
                )
                welcome.set_thumbnail(url=BOT_IMAGE)
                welcome.set_footer(text="Wandering Bot Alpha - AI Quest Workshop")
                await channel.send(embed=welcome)
            except Exception as error:
                print(f"WORKSHOP WELCOME SEND FAILED: {error}")
        return channel

    created = {}
    for key in pve_channel_keys:
        channel = await ensure_channel(key)
        if channel:
            created[key] = channel

    # Seed pve-help guides ONCE per guild, regardless of whether the
    # quest_workshop channel was newly-created or already existed. The
    # individual seed flags (pve_help_workshop_seeded, pve_help_rewards_seeded)
    # ensure each embed is posted at most once per guild.
    try:
        await _seed_pve_help_guides(guild, config, created.get("pve_help") or guild.get_channel(config.get("channels", {}).get("pve_help")))
    except Exception as error:
        print(f"PVE HELP SEED ERROR {guild.id}: {error}")

    config.setdefault("pve", {"enabled": True, "interval_hours": 12})
    save_guild_configs()
    return created


async def _seed_pve_help_guides(guild, config, pve_help_channel):
    """Post the workshop how-to and the rewards explainer embeds in the
    pve-help channel exactly once per guild. Idempotent — controlled by
    pve_help_workshop_seeded and pve_help_rewards_seeded config flags."""
    if pve_help_channel is None:
        return

    # 1. Workshop how-to guide.
