def merge_guild_config_records(base, override):
    if not isinstance(base, dict):
        return override
    if not isinstance(override, dict):
        return base
    merged = dict(base)
    merged.update(override)
    base_events = base.get("scenario_events")
    override_events = override.get("scenario_events")
    base_tombstones = base.get("scenario_event_tombstones")
    override_tombstones = override.get("scenario_event_tombstones")
    tombstones = {}
    if isinstance(base_tombstones, dict):
        tombstones.update(base_tombstones)
    if isinstance(override_tombstones, dict):
        tombstones.update(override_tombstones)
    if tombstones:
        merged["scenario_event_tombstones"] = tombstones

    def event_is_visible(event):
        if not isinstance(event, dict):
            return False
        event_id = str(event.get("id") or event.get("name") or "").strip()
        return not event_id or event_id not in tombstones

    if isinstance(override_events, list):
        merged["scenario_events"] = [event for event in override_events if event_is_visible(event)]
    elif isinstance(base_events, list):
        merged["scenario_events"] = [event for event in base_events if event_is_visible(event)]
    return merged


def load_guild_configs():
    global guild_configs

    guild_configs = load_json(GUILD_CONFIG_FILE)

    if os.path.isdir(GUILD_CONFIG_FOLDER):
        for config_file in os.listdir(GUILD_CONFIG_FOLDER):
            if not config_file.endswith(".json"):
                continue

            guild_id = config_file[:-5]
            split_config = load_json(
                os.path.join(GUILD_CONFIG_FOLDER, config_file)
            )
            guild_configs[guild_id] = merge_guild_config_records(
                guild_configs.get(guild_id),
                split_config
            )

    changed = False
    for config in guild_configs.values():
        if normalize_server_control_schedules(config):
            changed = True
    if changed:
        save_guild_configs()


def save_guild_config(guild_id):
    guild_id = str(guild_id)
    config = guild_configs.get(guild_id)

    if not config:
        return

    save_json(
        os.path.join(GUILD_CONFIG_FOLDER, f"{guild_id}.json"),
        config
    )


def save_guild_configs():
    save_json(GUILD_CONFIG_FILE, guild_configs)

    for guild_id in guild_configs:
        save_guild_config(guild_id)


