# =========================================================

_AI_ROAST_FALLBACKS = [
    "Map called. Said you forgot to read it.",
    "{killer} just turned {victim} into loot.",
    "{victim}'s last words: 'where's the shot coming from'.",
    "{distance:.0f}m. {weapon}. Cold.",
    "{victim} blinked. {killer} did not.",
    "Inventory: tab → empty.",
    "Server tick ate {victim} before {killer} did.",
    "{killer} sends regards. And one bullet.",
    "{victim} respawned harder than they spawned.",
    "Coastal start incoming for {victim}.",
]


def _format_fallback_roast(killer, victim, weapon, distance):
    template = random.choice(_AI_ROAST_FALLBACKS)
    try:
        return template.format(
            killer=killer or "Unknown",
            victim=victim or "Unknown",
            weapon=weapon or "Unknown",
            distance=float(distance or 0),
        )
    except Exception:
        return template


async def generate_death_roast(killer, victim, weapon, distance, headshot=False, tone=None):
    """Return a short (<= ~22 word) one-liner roast for the killfeed.
    Uses the Emergent Universal LLM key via emergentintegrations. If the
    key is missing or the call fails, returns a deterministic fallback so
    the killfeed never blocks on AI."""
    killer = (killer or "Unknown").strip()
    victim = (victim or "Unknown").strip()
    weapon = (weapon or "Unknown").strip()
    try:
        distance = float(distance or 0)
    except Exception:
        distance = 0.0

    if not EMERGENT_LLM_KEY:
        return _format_fallback_roast(killer, victim, weapon, distance)

    try:
        from emergentintegrations.llm.chat import LlmChat, UserMessage
    except Exception as error:
        print(f"[AI ROAST] emergentintegrations import failed: {error}")
        return _format_fallback_roast(killer, victim, weapon, distance)

    tone_value = (tone or AI_ROAST_TONE or "mixed").lower()
    tone_hint = {
        "edgy": "Tone: dark, edgy DayZ humour. Punchy. No slurs, no real-world tragedies.",
        "pg13": "Tone: PG-13 witty/sarcastic. No swears.",
        "brutal_clean": "Tone: brutal but clean. No swears. Make it sting.",
    }.get(tone_value, "Tone: pick at random between dark/edgy, witty/sarcastic, and brutal-but-clean.")

    headshot_hint = " It was a HEADSHOT — reference that." if headshot else ""
    distance_hint = f" Distance: {distance:.0f}m." if distance >= 50 else ""

    prompt = (
        f"Kill event:\n"
        f"- Killer: {killer}\n"
        f"- Victim: {victim}\n"
        f"- Weapon: {weapon}\n"
        f"- Distance: {distance:.0f}m\n"
        f"- Headshot: {'yes' if headshot else 'no'}\n\n"
        f"{tone_hint}{headshot_hint}{distance_hint}\n"
        f"Return ONLY the one-liner. No prefix, no quotes."
    )

    try:
        chat = LlmChat(
            api_key=EMERGENT_LLM_KEY,
            session_id=f"roast-{hashlib.sha1(f'{killer}{victim}{weapon}{distance}'.encode()).hexdigest()[:12]}",
            system_message=AI_ROAST_SYSTEM_PROMPT,
        ).with_model(AI_ROAST_PROVIDER, AI_ROAST_MODEL)

        response = await asyncio.wait_for(
            chat.send_message(UserMessage(text=prompt)),
            timeout=AI_ROAST_TIMEOUT_SECONDS,
        )
        text = (str(response or "")).strip()
        # Strip any wrapping quotes/backticks the model might add
        text = text.strip('"').strip("'").strip("`").strip()
        # Single line only
        text = text.splitlines()[0] if text else ""
        # Hard cap at 220 chars so it always fits a Discord embed field
        if len(text) > 220:
            text = text[:217].rstrip() + "..."
        return text or _format_fallback_roast(killer, victim, weapon, distance)
    except asyncio.TimeoutError:
        print("[AI ROAST] LLM call timed out — using fallback")
        return _format_fallback_roast(killer, victim, weapon, distance)
    except Exception as error:
        print(f"[AI ROAST] LLM call failed ({error}) — using fallback")
        return _format_fallback_roast(killer, victim, weapon, distance)


def guild_roasts_enabled(guild_id):
    """AI death roasts are OFF by default; admins must opt in."""
    gid = str(guild_id)
    config = guild_configs.get(gid, {})
    return bool(config.get("roasts_enabled", False))


def guild_roast_tone(guild_id):
    gid = str(guild_id)
    config = guild_configs.get(gid, {})
    return (config.get("roast_tone") or AI_ROAST_TONE or "mixed").lower()


# Provider/model used for heavier generative work (quest campaigns, news
# digests). Defaults to Claude Sonnet (better at long-form structured
# JSON), but operators can override via env. Falls back gracefully to
# whatever AI_ROAST_PROVIDER/AI_ROAST_MODEL is configured if these are
# unset, so a single env-key change toggles everything.
AI_CAMPAIGN_PROVIDER = os.getenv("WANDERING_AI_CAMPAIGN_PROVIDER", "anthropic")
AI_CAMPAIGN_MODEL = os.getenv("WANDERING_AI_CAMPAIGN_MODEL", "claude-sonnet-4-6")
AI_CAMPAIGN_TIMEOUT_SECONDS = float(os.getenv("WANDERING_AI_CAMPAIGN_TIMEOUT_SECONDS", "60"))

# When OPENAI_API_KEY is set, the bot uses OpenAI directly (billed via the
# user's OpenAI platform account) for the workshop and campaigns instead
# of going through emergentintegrations / EMERGENT_LLM_KEY. Override the
# model with WANDERING_OPENAI_QUEST_MODEL on Railway.
OPENAI_QUEST_MODEL = os.getenv("WANDERING_OPENAI_QUEST_MODEL", "gpt-4o")
OPENAI_QUEST_TIMEOUT_SECONDS = float(os.getenv("WANDERING_OPENAI_QUEST_TIMEOUT_SECONDS", "120"))


def _call_openai_chat_sync(system_message, user_message, model=None, timeout=None):
    """Direct OpenAI Chat Completions call via REST. Sync — wrap in
    asyncio.to_thread for use from async code. Raises on non-200."""
    api_url = "https://api.openai.com/v1/chat/completions"
    payload = {
        "model": model or OPENAI_QUEST_MODEL,
        "messages": [
            {"role": "system", "content": system_message},
            {"role": "user", "content": user_message},
        ],
        "temperature": 0.85,
        "max_tokens": 8000,
    }
    headers = {
        "Authorization": f"Bearer {OPENAI_API_KEY}",
        "Content-Type": "application/json",
    }
    response = requests.post(
        api_url, json=payload, headers=headers,
        timeout=timeout or OPENAI_QUEST_TIMEOUT_SECONDS,
    )
    if response.status_code != 200:
        raise RuntimeError(f"OpenAI {response.status_code}: {response.text[:300]}")
    data = response.json()
    choices = data.get("choices") or []
    if not choices:
        raise RuntimeError("OpenAI returned no choices")
    content = (choices[0].get("message") or {}).get("content") or ""
    return content


async def call_quest_llm(system_message, user_message, *, session_hint=""):
    """Unified LLM call for the quest workshop and campaign generator.

    Routing rules:
      - If OPENAI_API_KEY is set, call OpenAI directly (billed to the
        user's OpenAI account). Uses OPENAI_QUEST_MODEL.
      - Else if EMERGENT_LLM_KEY is set, fall back to emergentintegrations
        with the configured AI_CAMPAIGN_PROVIDER / AI_CAMPAIGN_MODEL.
      - Else raise RuntimeError so the caller can show a clear setup hint.

    Returns the raw text response from the model.
    """
    if OPENAI_API_KEY:
        return await asyncio.wait_for(
            asyncio.to_thread(_call_openai_chat_sync, system_message, user_message),
            timeout=OPENAI_QUEST_TIMEOUT_SECONDS + 5,
        )

    if EMERGENT_LLM_KEY:
        try:
            from emergentintegrations.llm.chat import LlmChat, UserMessage
        except Exception as error:
            raise RuntimeError(f"emergentintegrations import failed: {error}")

        session_id = f"quest-{hashlib.sha1((session_hint + user_message).encode()).hexdigest()[:12]}"
        chat = LlmChat(
            api_key=EMERGENT_LLM_KEY,
            session_id=session_id,
            system_message=system_message,
        ).with_model(AI_CAMPAIGN_PROVIDER, AI_CAMPAIGN_MODEL)

        return await asyncio.wait_for(
            chat.send_message(UserMessage(text=user_message)),
            timeout=AI_CAMPAIGN_TIMEOUT_SECONDS,
        )

    raise RuntimeError(
        "No LLM key configured. Set OPENAI_API_KEY (recommended) or "
        "EMERGENT_LLM_KEY on Railway."
    )


