async def _deliver_reward_pennies(guild, config, challenge, member, target_channel, dm_channel):
    pennies = int(challenge.get("reward_pennies", 0))
    embed = discord.Embed(
        title="🎁 Quest Reward — Pennies Paid",
        description=f"{member.mention} earned **{pennies} pennies** for completing **{challenge.get('title')}**.",
        color=0xF1C40F,
    )
    embed.add_field(name="Quest", value=f"`{pve_quest_code(challenge)}`", inline=True)
    embed.add_field(name="Difficulty", value=challenge.get("difficulty", "Medium"), inline=True)
    embed.set_thumbnail(url=BOT_IMAGE)
    embed.set_footer(text="Wandering Bot Alpha - PVE Rewards")
    if target_channel:
        await target_channel.send(content=member.mention, embed=style_embed(embed))


async def _deliver_reward_infected_map(guild, config, challenge, member, target_channel, dm_channel):
    guild_id = str(guild.id)
    map_key = server_map_key(guild_id)
    # Try the real map render first; if not configured, fall back to the
    # synthetic heatmap renderer that doesn't need a base image.
    image_path = generate_real_map_heatmap_image(guild_id, "all", map_key, width=900, height=720)
    if not image_path:
        image_path = generate_guild_heatmap_image(guild_id, mode="all")

    embed = discord.Embed(
        title="🗺️ Quest Reward — Infected & Activity Map",
        description=(
            f"{member.mention} earned a live activity map of **{map_key.title()}** "
            f"by completing **{challenge.get('title')}**. Hot zones show recent kills, "
            f"infected sightings, and contested territory. Plan accordingly."
        ),
        color=0xE67E22,
    )
    embed.add_field(name="Quest", value=f"`{pve_quest_code(challenge)}`", inline=True)
    embed.set_footer(text="Wandering Bot Alpha - PVE Rewards")

    if target_channel:
        if image_path and os.path.exists(image_path):
            try:
                file = discord.File(image_path, filename="activity_map.png")
                embed.set_image(url="attachment://activity_map.png")
                await target_channel.send(content=member.mention, embed=style_embed(embed), file=file)
            except Exception as send_error:
                print(f"INFECTED MAP SEND FAILED: {send_error}")
                await target_channel.send(content=member.mention, embed=style_embed(embed))
            finally:
                try:
                    os.remove(image_path)
                except Exception:
                    pass
        else:
            embed.add_field(
                name="Note",
                value="Heatmap data is still building. Run `/heatmap` in a few hours for a denser map.",
                inline=False,
            )
            await target_channel.send(content=member.mention, embed=style_embed(embed))


async def _deliver_reward_intel_brief(guild, config, challenge, member, target_channel, dm_channel):
    guild_id = str(guild.id)
    # Pull the freshest signals the bot already collects.
    longshot_lines = []
    for record in (longshot_records.get(guild_id, [])[-3:] or []):
        longshot_lines.append(
            f"• {record.get('killer', '?')} dropped {record.get('victim', '?')} from "
            f"{int(record.get('distance', 0))}m with {record.get('weapon', '?')}."
        )
    bounty_lines = []
    for bounty in (bounties.get(guild_id, [])[-3:] or []):
        bounty_lines.append(f"• {bounty.get('target', '?')} — {bounty.get('reward', '?')}")
    heat_top = sorted(
        heat_counts_for_mode(guild_id, "pvp").items(),
        key=lambda x: x[1],
        reverse=True
    )[:5]
    heat_lines = [f"• {zone}: {count} engagements" for zone, count in heat_top]

    embed = discord.Embed(
        title="📋 Quest Reward — Server Intel Brief",
        description=(
            f"{member.mention} earned a fresh intel briefing for completing "
            f"**{challenge.get('title')}**. Recon notes below — use them or trade them."
        ),
        color=0x3498DB,
    )
    if heat_lines:
        embed.add_field(name="🔥 Hottest PVP Zones", value="\n".join(heat_lines), inline=False)
    if longshot_lines:
        embed.add_field(name="🎯 Recent Longshots", value="\n".join(longshot_lines), inline=False)
    if bounty_lines:
        embed.add_field(name="💰 Active Bounties", value="\n".join(bounty_lines), inline=False)
    if not (heat_lines or longshot_lines or bounty_lines):
        embed.add_field(
            name="Field Report",
            value="Server is quiet right now — light contacts, no major engagements logged. Move freely but stay paranoid.",
            inline=False,
        )
    embed.add_field(name="Quest", value=f"`{pve_quest_code(challenge)}`", inline=True)
    embed.set_thumbnail(url=BOT_IMAGE)
    embed.set_footer(text="Wandering Bot Alpha - PVE Rewards")
    if target_channel:
        await target_channel.send(content=member.mention, embed=style_embed(embed))


async def _deliver_reward_loot_drop_coords(guild, config, challenge, member, target_channel, dm_channel):
    guild_id = str(guild.id)
    map_key = server_map_key(guild_id)
    pool = {
        "chernarus": CHERNARUS_LOOT_DROPS,
        "livonia": LIVONIA_LOOT_DROPS,
        "sakhal": SAKHAL_LOOT_DROPS,
    }.get(map_key, CHERNARUS_LOOT_DROPS)
    spot_name, coords = random.choice(pool)
    map_link = build_izurvive_link(coords, guild_id) or "(map link unavailable)"

    embed = discord.Embed(
        title="📍 Quest Reward — Loot Drop Coordinates",
        description=(
            f"You completed **{challenge.get('title')}**. Coordinates of a hand-picked stash "
            f"location are below. **Keep this private.** Other survivors who see these coords "
            f"will race you to the spot."
        ),
        color=0x2ECC71,
    )
    embed.add_field(name="Stash Location", value=spot_name, inline=False)
    embed.add_field(name="Coordinates", value=f"`{coords}`", inline=True)
    embed.add_field(name="Map", value=f"[Open iZurvive]({map_link})", inline=True)
    embed.add_field(
        name="Rules",
        value="The spawn isn't guaranteed — admin will drop a stash there during the next restart cycle.",
        inline=False,
    )
    embed.add_field(name="Quest", value=f"`{pve_quest_code(challenge)}`", inline=True)
    embed.set_thumbnail(url=BOT_IMAGE)
    embed.set_footer(text="Wandering Bot Alpha - PVE Rewards (private)")

    delivered_dm = False
    if dm_channel:
        try:
            await dm_channel.send(content=f"🎁 Private reward from your DayZ server:", embed=style_embed(embed))
            delivered_dm = True
        except Exception as dm_error:
            print(f"DM REWARD FAILED: {dm_error}")

    if target_channel:
        # Public-channel notice only — no coords leaked.
        notice = discord.Embed(
            title="📍 Private Reward Delivered",
            description=(
                f"{member.mention} earned a **private loot drop reward** for "
                f"**{challenge.get('title')}**. Coordinates were sent privately."
            ),
            color=0x2ECC71,
        )
        notice.set_footer(text="Wandering Bot Alpha - PVE Rewards")
        try:
            await target_channel.send(embed=style_embed(notice))
        except Exception:
            pass

    return delivered_dm


async def _deliver_reward_role_grant(guild, config, challenge, member, target_channel, dm_channel):
    role_name = (config.get("pve_reward_role")
                 or challenge.get("reward_role_name")
                 or "DayZ Quest Veteran")
    role = discord.utils.get(guild.roles, name=role_name)
    if not role:
        try:
            role = await guild.create_role(
                name=role_name,
                colour=discord.Colour(0x9B59B6),
                reason="PVE quest reward role",
            )
        except Exception as role_error:
            print(f"ROLE CREATE FAILED: {role_error}")
            role = None

    granted = False
    if role:
        try:
            if role not in member.roles:
                await member.add_roles(role, reason=f"PVE quest reward: {challenge.get('title')}")
            granted = True
        except Exception as add_error:
            print(f"ROLE GRANT FAILED: {add_error}")

    embed = discord.Embed(
        title="🎖️ Quest Reward — Role Granted" if granted else "🎖️ Quest Reward — Role (manual)",
        description=(
            f"{member.mention} earned the **{role_name}** role for completing "
            f"**{challenge.get('title')}**." if granted else
            f"{member.mention} earned the **{role_name}** role but the bot couldn't apply it. "
            f"An admin should grant it manually."
        ),
        color=0x9B59B6,
    )
    embed.add_field(name="Quest", value=f"`{pve_quest_code(challenge)}`", inline=True)
    embed.set_footer(text="Wandering Bot Alpha - PVE Rewards")
    if target_channel:
        await target_channel.send(content=member.mention, embed=style_embed(embed))


async def _deliver_reward_custom(guild, config, challenge, member, target_channel, dm_channel):
    embed = discord.Embed(
        title="🎁 Quest Reward — Hand-Issued",
        description=(
            f"{member.mention} completed **{challenge.get('title')}** and earned: "
            f"_{challenge.get('reward', 'Admin-chosen reward')}_\n\n"
            f"An admin will deliver this reward in-game on the next server restart "
            f"or stash drop."
        ),
        color=0x95A5A6,
    )
    embed.add_field(name="Quest", value=f"`{pve_quest_code(challenge)}`", inline=True)
    embed.add_field(name="Pennies Paid", value=str(challenge.get("reward_pennies", 0)), inline=True)
    embed.set_thumbnail(url=BOT_IMAGE)
    embed.set_footer(text="Wandering Bot Alpha - PVE Rewards (admin issues in-game)")
    if target_channel:
        await target_channel.send(content=member.mention, embed=style_embed(embed))


async def deliver_quest_reward(guild, config, challenge, member):
    """Deliver whatever reward this completed quest specified.

    Routes to one of six handlers based on `challenge['reward_type']`:
      pennies | infected_map | intel_brief | loot_drop_coords | role_grant | custom

    Visibility:
      - public  → posts in the public pve-rewards channel, tags the player.
      - private → DMs the player, plus a no-detail audit notice in the
                  public channel and a full copy in the admin-only
                  pve-rewards-private channel for staff records.
    """
    channels = config.setdefault("channels", {})
    public_channel = guild.get_channel(channels.get("pve_rewards_public"))
    private_channel = guild.get_channel(channels.get("pve_rewards_private"))
    if not public_channel:
        if is_channel_key_disabled(config, "pve_rewards_public"):
            return
        # Auto-create on first use.
        await ensure_pve_channels(guild, config)
        public_channel = guild.get_channel(channels.get("pve_rewards_public"))
        private_channel = guild.get_channel(channels.get("pve_rewards_private"))

    visibility = str(challenge.get("reward_visibility") or "public").strip().lower()
    reward_type = str(challenge.get("reward_type") or "pennies").strip().lower()

    # 🎟️ TICKET-CHANNEL ROUTING — if this quest (or its parent campaign)
    # is bound to a player's private ticket channel, route the FULL
    # reward embed there. Post a no-detail confirmation in the public
    # pve-rewards so the community can celebrate the win without seeing
    # spoilers (live maps, intel coords, loot drops).
    ticket_channel = None
    ticket_ch_id = challenge.get("claimed_ticket_channel_id")
    if not ticket_ch_id:
        # Fall through to campaign-level binding.
        camp_id = challenge.get("campaign_id") or challenge.get("ai_campaign_id")
        if camp_id:
            camp = pve_ai_campaigns.get(str(guild.id), {}).get(camp_id) or {}
            ticket_ch_id = camp.get("bound_ticket_channel_id")
    if ticket_ch_id:
        candidate = guild.get_channel(int(ticket_ch_id))
        if candidate:
            ticket_channel = candidate

    # Open a DM channel for private rewards.
    dm_channel = None
    if visibility == "private" and not ticket_channel:
        try:
            dm_channel = member.dm_channel or await member.create_dm()
        except Exception as dm_error:
            print(f"DM OPEN FAILED for {member.id}: {dm_error}")

    # For private rewards, the "target_channel" passed to the handler is
    # the public channel for the no-detail notice (handlers handle DM
    # themselves when needed). For public rewards, the handler posts the
    # full embed there.
    target_channel = public_channel if visibility == "public" else None

    # 🎟️ Override: if a ticket channel exists, ALL reward types route
    # there regardless of visibility — the ticket itself is private
    # so no separate DM is needed.
    if ticket_channel:
        target_channel = ticket_channel
        visibility = "ticket"  # marker so the audit log shows this

    handler_map = {
        "pennies": _deliver_reward_pennies,
        "infected_map": _deliver_reward_infected_map,
        "intel_brief": _deliver_reward_intel_brief,
        "loot_drop_coords": _deliver_reward_loot_drop_coords,
        "role_grant": _deliver_reward_role_grant,
        "custom": _deliver_reward_custom,
    }
    handler = handler_map.get(reward_type, _deliver_reward_custom)

    # Run the per-type handler.
    if visibility == "ticket":
        # Full reward in the private ticket channel; no-detail confirmation
        # in the public pve-rewards so the community can celebrate.
        await handler(guild, config, challenge, member, ticket_channel, None)
        if public_channel:
            try:
                pretty_reward_label = {
                    "pennies": "💰 Pennies",
                    "infected_map": "🗺️ Live infected map",
                    "intel_brief": "📰 Intel briefing",
                    "loot_drop_coords": "📍 Loot drop coordinates",
                    "role_grant": "🏷️ Achievement role",
                    "custom": "🎁 Custom admin reward",
                }.get(reward_type, "🎁 Reward")
                public_notice = discord.Embed(
                    title="🏆 QUEST COMPLETE",
                    description=(
                        f"{member.mention} completed **{challenge.get('title', '?')}** "
                        f"and earned **{pretty_reward_label}**.\n"
                        f"_Full details were delivered privately in their quest ticket._"
                    ),
                    color=0xF1C40F,
                )
                public_notice.set_footer(text=f"Wandering Bot Alpha — Quest {pve_quest_code(challenge)}")
                await public_channel.send(
                    embed=style_embed(public_notice),
                    allowed_mentions=discord.AllowedMentions(users=[member]),
                )
            except Exception as err:
                print(f"[REWARD] public notice failed: {err}")
    elif visibility == "private":
        # All private deliveries route through the same channel pair: the
        # handler decides what (if anything) to post publicly via the
        # `target_channel` arg below. We still pass `public_channel` so
        # the handler can drop a no-coords notice for the rest of the
        # community to celebrate the win.
        await handler(guild, config, challenge, member, public_channel, dm_channel)
    else:
        await handler(guild, config, challenge, member, target_channel, None)

    # Audit log for admins regardless of visibility.
    if private_channel:
        try:
            audit = discord.Embed(
                title=f"🛡️ Reward Delivered: {challenge.get('title', '?')}",
                description=(
                    f"**Player:** {member.mention} (`{member}`)\n"
                    f"**Quest:** `{pve_quest_code(challenge)}`\n"
                    f"**Reward Type:** `{reward_type}`\n"
                    f"**Visibility:** `{visibility}`\n"
                    f"**Pennies:** {challenge.get('reward_pennies', 0)}\n"
                    f"**Reward Text:** {challenge.get('reward', '—')}"
                ),
                color=0x34495E,
            )
            audit.set_footer(text="Wandering Bot Alpha - Reward Audit Log")
            await private_channel.send(embed=audit)
        except Exception as audit_error:
            print(f"REWARD AUDIT FAILED: {audit_error}")


async def workshop_edit_posted_quest(message, config, params):
    """Find an existing posted PVE quest by its PVE-XXXXXX code, update the
    fields the admin asked to change, edit the public embed in place, and
    optionally re-post in a different channel. Returns a string reply for
    the workshop channel."""
    guild = message.guild
    guild_id = str(guild.id)
    params = params or {}

    raw_code = str(params.get("quest_code") or "").strip().upper()
    if raw_code.isdigit():
        raw_code = f"PVE-{raw_code}"
    if not raw_code.startswith("PVE-"):
        m = re.search(r"PVE[-_ ]?(\d{4,8})", str(params.get("quest_code") or ""), re.IGNORECASE)
        if m:
            raw_code = f"PVE-{m.group(1)}"
    if not raw_code or not raw_code.startswith("PVE-"):
        return "❌ I need the quest code (e.g. `PVE-529315`) to edit a posted quest."

    # Find the quest in pve_challenges (any status — admins might be
    # tweaking a quest that was already completed/archived too).
    quest_record = None
    for ch in pve_challenges.get(guild_id, []):
        if pve_quest_code(ch) == raw_code:
            quest_record = ch
            break
    if not quest_record:
        return f"❌ Couldn't find quest `{raw_code}` in this server's PVE board. Use `list my campaigns` or check the `#pve-quests` history."

    # Track what we actually changed so the reply is informative.
    changes = []

    new_delivery = params.get("delivery_target")
    if new_delivery is not None and str(new_delivery).strip():
        quest_record["delivery_target"] = str(new_delivery).strip()[:200]
        changes.append(f"📍 delivery → **{quest_record['delivery_target']}**")
        # Rewrite the final goal sentence so the player's checklist
        # matches the new drop-off, e.g. "Deliver all items to <X>."
        existing_goal = str(quest_record.get("goal") or "")
        # Strip any prior "deliver them to ..." tail and re-stamp it.
        cleaned_goal = re.sub(
            r"(?i)\s*(?:and\s+)?deliver(?:\s+(?:them|it|the\s+\w+))?\s+to\s+.+?(?:\.|$)",
            "", existing_goal,
        ).rstrip(" .,;")
        new_goal = f"{cleaned_goal}. Deliver them to {quest_record['delivery_target']}." if cleaned_goal else f"Deliver the items to {quest_record['delivery_target']}."
        quest_record["goal"] = _sanitize_quest_goal(new_goal[:500])

    new_goal_override = params.get("goal")
    if new_goal_override is not None and str(new_goal_override).strip():
        quest_record["goal"] = _sanitize_quest_goal(str(new_goal_override).strip()[:500])
        changes.append("🎯 goal rewritten")

    new_title = params.get("title")
    if new_title is not None and str(new_title).strip():
        quest_record["title"] = str(new_title).strip()[:120]
        changes.append(f"📜 title → **{quest_record['title']}**")

    new_kind = params.get("kind")
    if new_kind is not None and str(new_kind).strip():
        quest_record["kind"] = _coerce_quest_kind(new_kind)
        changes.append(f"🏷️ kind → **{quest_record['kind']}**")

    new_items = params.get("items_needed")
    if new_items is not None and isinstance(new_items, list) and new_items:
        coerced = _coerce_items_needed(new_items)
        if coerced:
            quest_record["items_needed"] = coerced
            preview = ", ".join(f"{i.get('qty', 1)}x {i.get('item')}" for i in coerced[:4])
            changes.append(f"🎯 items → {preview}")

    new_steps = params.get("steps")
    if new_steps is not None and isinstance(new_steps, list) and new_steps:
        safe_steps = _sanitize_quest_steps([str(s) for s in new_steps if s])
        if safe_steps:
            quest_record["steps"] = safe_steps
            changes.append(f"📋 {len(safe_steps)} step(s) rewritten")

    # Channel move — re-post in the new channel and (best-effort) edit the
    # previous post to point readers at the new location.
    raw_target_key = params.get("target_channel_key")
    new_channel_key = workshop_resolve_target_channel_key(raw_target_key) if raw_target_key else None
    old_channel_key = quest_record.get("channel_key")
    move_channel = new_channel_key and new_channel_key != old_channel_key

    save_pve_challenges()

    if not changes and not move_channel:
        return f"ℹ️ Nothing to change on `{raw_code}` — the params you sent were all empty."

    # Try to edit the original Discord embed in place so the same message
    # in the original channel reflects the new info immediately.
    edited_in_place = False
    for ref in list(quest_record.get("post_message_refs") or []):
        try:
            ch = guild.get_channel(int(ref.get("channel_id"))) if ref.get("channel_id") else None
            if not ch:
                continue
            msg = await ch.fetch_message(int(ref.get("message_id")))
            new_embed = _build_quest_embed_from_record(quest_record)
            if new_embed:
                await msg.edit(embed=style_embed(new_embed))
                edited_in_place = True
        except Exception as edit_err:
            print(f"[WORKSHOP] edit_in_place failed for {raw_code}: {edit_err}")

    move_note = ""
    if move_channel:
        # Repost into the new channel as a fresh message with the updated
        # embed (so the new channel's regular pings/notifications fire).
        quest_record["channel_key"] = new_channel_key
        save_pve_challenges()
        ok, info = await workshop_post_one_quest_to_channel(
            guild, config, new_channel_key, quest_record, campaign=None,
        )
        if ok:
            move_note = f"\n🚚 Re-posted in {info} (new channel: `{new_channel_key}`)."
        else:
            move_note = f"\n⚠️ Couldn't repost in `{new_channel_key}`: {info}"

    summary = ", ".join(changes) if changes else "channel moved"
    place_note = " (edited the original post in place)" if edited_in_place else ""
    return f"✏️ Updated `{raw_code}` — {summary}.{place_note}{move_note}"


def _build_quest_embed_from_record(record):
    """Re-render a saved pve_challenges record back into the same embed
    layout workshop_post_one_quest_to_channel uses, so the in-place edit
    looks identical to a freshly-posted quest with the new fields."""
    if not record:
        return None
    quest_code = pve_quest_code(record)
    kind = record.get("kind", "Survival")
    title = record.get("title", "Untitled Quest")
    summary = record.get("summary") or ""
    goal = record.get("goal") or ""
    epigraph = (record.get("story_epigraph") or "").strip()
    description_parts = []
    if epigraph:
        description_parts.append(f"> _\u201c{epigraph}\u201d_")
    if summary:
        description_parts.append(summary)
    description_parts.append(f"\U0001F3AF **Objective:** {goal}")
    embed = discord.Embed(
        title=f"\U0001F9ED {kind.upper()} QUEST [{quest_code}]: {title}",
        description="\n\n".join(description_parts)[:4000],
        color=0x9B59B6,
    )
    embed.add_field(name="\U0001F194 Quest ID", value=f"`{quest_code}`", inline=True)
    embed.add_field(name="Difficulty", value=record.get("difficulty", "Medium"), inline=True)
    if record.get("estimated_minutes"):
        embed.add_field(name="Est. Time", value=f"~{record['estimated_minutes']} min", inline=True)

    steps = record.get("steps") or []
    if steps:
        numbered = "\n".join(f"**{i+1}.** {step}" for i, step in enumerate(steps[:6]))
        embed.add_field(name="\U0001F4CB Step-by-Step", value=numbered[:1024], inline=False)

    locations = record.get("locations") or []
    if locations:
        embed.add_field(
            name="\U0001F4CD Locations",
            value="\n".join(f"\u2022 {loc}" for loc in locations[:6])[:1024],
            inline=True,
        )

    items_needed = record.get("items_needed") or []
    if items_needed:
        rendered = []
        for it in items_needed[:10]:
            line = format_quest_item_line(it) if isinstance(it, dict) else f"\u2022 {str(it)[:80]}"
            if line:
                rendered.append(line)
        if rendered:
            embed.add_field(
                name="\U0001F3AF Collect / Bring",
                value="\n".join(rendered)[:1024],
                inline=False,
            )

    delivery_target = (record.get("delivery_target") or "").strip()
    if delivery_target:
        embed.add_field(name="\U0001F4CD Delivery / Drop-off", value=delivery_target[:1024], inline=False)

    dangers = record.get("dangers") or []
    if dangers:
        embed.add_field(
            name="\u26A0\uFE0F Watch Out For",
            value="\n".join(f"\u2022 {d}" for d in dangers[:5])[:1024],
            inline=False,
        )

    embed.add_field(name="\U0001F4B0 Reward", value=record.get("reward", "Admin-chosen")[:1024], inline=False)
    embed.set_thumbnail(url=BOT_IMAGE)
    embed.set_footer(text=f"Wandering Bot Alpha - AI Quest Workshop - {quest_code}")
    return embed


async def workshop_execute_action(message, config, action, params):
    """Execute one workshop action and return a string reply for the channel."""
    guild = message.guild
    guild_id = str(guild.id)
    params = params or {}

    if action == "generate_campaign":
        theme = str(params.get("theme") or "").strip()
        count = int(params.get("count") or 12)
        story_mode = bool(params.get("story_mode"))
        if not theme:
            return "I need a theme. Try: `make me 10 winter outbreak quests`."
        prompt_count = max(4, min(count, 40))
        # Tweak the call: pass story_mode by appending a hint to the theme.
        effective_theme = f"{theme} (multi-part storyline, ordered narrative)" if story_mode else theme
        quests, campaign_or_error = await generate_ai_pve_campaign(effective_theme, count=prompt_count)
        if not quests:
            return f"⚠️ Generation failed: {campaign_or_error}"
        campaign_id = save_ai_campaign_for_guild(
            guild.id, theme=theme, campaign_name=campaign_or_error,
            quests=quests, author_id=message.author.id,
        )
        sample = ", ".join(q.get("title", "?") for q in quests[:3])
        more = f" + {len(quests) - 3} more" if len(quests) > 3 else ""
        return (
            f"✅ Campaign **{campaign_or_error}** saved with {len(quests)} quests.\n"
            f"`campaign_id`: `{campaign_id}`\n"
            f"Preview: {sample}{more}\n"
            f"Tell me when/where to post them, e.g. *post one every 12 hours in pve-expeditions*."
        )

    if action == "post_quest_now":
        campaign_id = params.get("campaign_id")
        theme = params.get("theme")
        channel_key = workshop_resolve_target_channel_key(params.get("target_channel_key"))
        campaign = workshop_find_campaign(guild_id, campaign_id, theme=theme)
        # If no campaign — pull from any AI quest pool, else built-in bank.
        if campaign:
            pool = [q for q in campaign.get("quests", []) if isinstance(q, dict)]
        else:
            pool = guild_ai_campaign_quests(guild_id) or PVE_CHALLENGE_BANK
        if not pool:
            return "No quests available — generate a campaign first."
        quest = random.choice(pool)
        ok, info = await workshop_post_one_quest_to_channel(guild, config, channel_key, quest, campaign=campaign)
        if not ok:
            return f"⚠️ Post failed: {info}"
        return f"📜 Posted quest **{quest.get('title', '?')}** in {info}."

    if action == "edit_posted_quest":
        return await workshop_edit_posted_quest(message, config, params)

    if action == "schedule_campaign":
        campaign_id = params.get("campaign_id") or ""
        channel_key = workshop_resolve_target_channel_key(params.get("target_channel_key"))
        try:
            interval_hours = max(1, min(int(params.get("interval_hours") or 12), 168))
        except Exception:
            interval_hours = 12
        occurrences_raw = params.get("occurrences")
        try:
            occurrences = int(occurrences_raw) if occurrences_raw not in (None, "", "null") else None
        except Exception:
            occurrences = None
        story_mode = bool(params.get("story_mode"))

        campaign = workshop_find_campaign(guild_id, campaign_id, theme=params.get("theme"))
        if not campaign:
            return "Couldn't find that campaign. Try `list my campaigns` first."

        sched_id = f"sched-{int(datetime.now(UTC).timestamp())}-{random.randint(1000, 9999)}"
        next_run = datetime.now(UTC) + timedelta(seconds=30)  # first post in 30s
        schedule = {
            "id": sched_id,
            "campaign_id": campaign.get("id"),
            "target_channel_key": channel_key,
            "interval_hours": interval_hours,
            "next_run_iso": next_run.isoformat(),
            "remaining": occurrences,
            "story_mode": story_mode,
            "next_index": 0,
            "created": datetime.now(UTC).isoformat(),
            "created_by": str(message.author.id),
            "active": True,
        }
        guild_workshop_schedules(guild_id).append(schedule)
        save_pve_workshop_schedules()
        occ_text = "unlimited" if occurrences is None else f"{occurrences} occurrence(s)"
        return (
            f"⏱️ Schedule **{sched_id}** active. Posting from **{campaign.get('name', '?')}** "
            f"every **{interval_hours}h** into `{channel_key}` — {occ_text}. "
            f"First post in 30 seconds."
        )

    if action == "list_campaigns":
        block = pve_ai_campaigns.get(guild_id, {})
        if not block:
            return "No campaigns yet. Try `generate me 10 quests about a coastal salvage mission`."
        lines = ["**Campaigns:**"]
        for camp in sorted(block.values(), key=lambda c: c.get("created", ""), reverse=True)[:10]:
            lines.append(
                f"• `{camp.get('id', '?')}` — **{camp.get('name', '?')}** "
                f"({len(camp.get('quests', []))} quests, theme: _{camp.get('theme', '?')}_)"
            )
        return "\n".join(lines)

    if action == "list_schedules":
        scheds = guild_workshop_schedules(guild_id)
        active = [s for s in scheds if s.get("active")]
        if not active:
            return "No active schedules."
        lines = ["**Active schedules:**"]
        for s in active[:10]:
            lines.append(
                f"• `{s['id']}` — campaign `{s.get('campaign_id', '?')}` → "
                f"`{s.get('target_channel_key', '?')}` every **{s.get('interval_hours', '?')}h**, "
                f"remaining: {s.get('remaining', 'unlimited')}"
            )
        return "\n".join(lines)

    if action == "cancel_schedule":
        sched_id = params.get("schedule_id") or ""
        scheds = guild_workshop_schedules(guild_id)
        for s in scheds:
            if s.get("id") == sched_id:
                s["active"] = False
                save_pve_workshop_schedules()
                return f"🛑 Schedule `{sched_id}` cancelled."
        return f"No schedule with id `{sched_id}`."

    if action == "delete_campaign":
        campaign_id = params.get("campaign_id") or ""
        block = pve_ai_campaigns.get(guild_id, {})
        if campaign_id in block:
            removed = block.pop(campaign_id)
            save_pve_ai_campaigns()
            return f"🗑️ Deleted campaign **{removed.get('name', campaign_id)}**."
        return f"No campaign with id `{campaign_id}`."

    # action == "chat" or anything unknown → just echo the LLM's reply.
    return None


async def handle_quest_workshop_message(message):
    """Entry point called from on_message when an admin posts in the
    quest-workshop channel. Routes their message through the LLM and
    executes whichever action it returns."""
    guild = message.guild
    if not guild:
        return
    config = guild_configs.get(str(guild.id))
    if not config:
        return

    # Admin gate — only admins can drive the workshop.
    member = message.author if isinstance(message.author, discord.Member) else guild.get_member(message.author.id)
    if member is None or not (
        member.guild_permissions.administrator
        or any(role.name in config.get("admin_roles", DEFAULT_ADMIN_ROLES) for role in getattr(member, "roles", []))
    ):
        try:
            await message.reply("This channel is for admins only.", mention_author=False, delete_after=8)
        except Exception:
            pass
        return

    text = (message.content or "").strip()
    if not text:
        return

    # Help shortcut.
    if text.lower() in {"help", "?", "/help"}:
        try:
            await message.reply(
                "**🛠️ Quest Workshop**\nTalk to me in plain English. " + workshop_action_help_blurb(),
                mention_author=False,
            )
        except Exception:
            pass
        return

    # Show typing while the LLM thinks.
    try:
        async with message.channel.typing():
            history_pairs = [(m.author.bot and "bot" or "user", m.content)
                             for m in [m async for m in message.channel.history(limit=8, before=message)][::-1]
                             if m.content]
            plan = await call_workshop_llm(history_pairs, text)
    except Exception as error:
        try:
            await message.reply(f"Workshop error: {error}", mention_author=False)
        except Exception:
            pass
        return

    action = str(plan.get("action") or "chat").strip().lower()
    reply_text = str(plan.get("reply") or "").strip()
    params = plan.get("params") or {}

    # 🛡️ Safety net: if the admin's literal message names an existing
    # PVE-XXXXXX quest code but the LLM still decided to do anything
    # OTHER than edit it, force the edit path. Without this the bot keeps
    # spawning brand-new quests instead of updating the one the admin
    # explicitly referenced.
    pve_code_match = re.search(r"PVE[-_ ]?(\d{4,8})", text, re.IGNORECASE)
    if pve_code_match and action in {"generate_campaign", "post_quest_now", "chat"}:
        forced_code = f"PVE-{pve_code_match.group(1)}"
        # Try to find that quest in this guild before overriding — if it
        # doesn't exist, leave the LLM's plan alone so chat can clarify.
        gid_local = str(guild.id)
        exists = any(
            pve_quest_code(ch) == forced_code
            for ch in pve_challenges.get(gid_local, [])
        )
        if exists:
            params = dict(params or {})
            params["quest_code"] = forced_code
            # Heuristic field extraction from the admin's raw text so the
            # edit applies even if the LLM forgot to populate params.
            lower_text = text.lower()
            if "delivery_target" not in params or not params.get("delivery_target"):
                for hint, normalised in [
                    ("black market trader", "Black Market Trader"),
                    ("blackmarket trader", "Black Market Trader"),
                    ("black-market trader", "Black Market Trader"),
                    ("black trader", "Black Market Trader"),
                    ("trader at solnichniy", "Trader at Solnichniy"),
                    ("green mountain", "Green Mountain stash"),
                ]:
                    if hint in lower_text:
                        params["delivery_target"] = normalised
                        break
            if "target_channel_key" not in params or not params.get("target_channel_key"):
                if "hunting" in lower_text or "hunter" in lower_text:
                    params["target_channel_key"] = "pve_hunting"
                elif "fishing" in lower_text or "fish " in lower_text:
                    params["target_channel_key"] = "pve_fishing"
                elif "crafting" in lower_text or "craft " in lower_text:
                    params["target_channel_key"] = "pve_crafting"
                elif "expedition" in lower_text or "exploration" in lower_text:
                    params["target_channel_key"] = "pve_expeditions"
                elif "collection" in lower_text or "collect " in lower_text:
                    params["target_channel_key"] = "pve_collection"
            action = "edit_posted_quest"
            # Add a tiny human-visible nudge so the admin sees the override.
            reply_text = (
                (reply_text + "\n\n" if reply_text else "")
                + f"_(Forwarded as **edit_posted_quest** for `{forced_code}` — that quest already exists, "
                  "so I'm updating it in place instead of creating a new one.)_"
            )

    # First send the LLM's chatty reply (if any) so the admin always sees
    # acknowledgment immediately, then execute the action.
    if reply_text:
        try:
            await message.reply(reply_text[:1900], mention_author=False)
        except Exception:
            pass

    try:
        action_result = await workshop_execute_action(message, config, action, params)
    except Exception as error:
        action_result = f"⚠️ Action failed: {error}"

    if action_result:
        try:
            await message.channel.send(action_result[:1900])
        except Exception:
            pass


