def is_first_time_player(guild_id, gamertag):
    """Return True if this is the first time we've ever seen this
    gamertag in this guild. Marks them as seen as a side-effect."""
    if not gamertag or gamertag == "Unknown":
        return False
    gid = str(guild_id)
    block = seen_players.setdefault(gid, {})
    cleaned = str(gamertag).strip()
    # Case-insensitive existence check.
    for known in block:
        if known.strip().lower() == cleaned.lower():
            return False
    block[cleaned] = datetime.now(UTC).isoformat()
    save_seen_players()
    return True


# =========================================================
# 💀 AI LAST WORDS
# Generate a short dramatic "final transmission" for a player who
# just died. Used on suicide / bleedout / kill embeds. Fails silently
# if no LLM key is available — last words are a flavour bonus, not
# critical functionality.
# =========================================================

async def generate_last_words(player_name, cause="killed", context=""):
    """Return a 1-2 sentence dramatic final transmission as if the
    player wrote it. Returns None if no LLM is configured."""
    if not OPENAI_API_KEY and not EMERGENT_LLM_KEY:
        return None
    if not player_name or player_name == "Unknown":
        return None
    system = (
        "You are a survival horror writer for a DayZ Discord bot. "
        "You write dramatic 1-2 sentence final transmissions from a survivor "
        "who has just died. The tone should match DayZ: gritty, reluctant, "
        "weary, sometimes darkly funny. Never use real-world tragedies. "
        "Reply with just the transmission, no quotes, no preamble."
    )
    prompt = (
        f"Survivor name: {player_name}\n"
        f"Cause of death: {cause}\n"
        f"Context: {context or 'No further details.'}\n\n"
        f"Write their final 1-2 sentence transmission (under 240 chars total)."
    )
    try:
        response = await asyncio.wait_for(
            call_quest_llm(system, prompt, session_hint="last-words"),
            timeout=12,
        )
    except Exception:
        return None
    text = (str(response or "")).strip().strip('"').strip("'")
    return text[:240] or None


def stable_line_hash(line):
    return hashlib.sha256(
        line.encode("utf-8", errors="ignore")
    ).hexdigest()


_ADM_TIME_PREFIX_RE = re.compile(r"^\s*(\d{1,2}):(\d{2}):(\d{2})\b")


def adm_timezone_for_config(config=None):
    timezone_name = ""
    if isinstance(config, dict):
        timezone_name = str(
            config.get("adm_timezone")
            or config.get("timezone")
            or config.get("server_timezone")
            or ""
        ).strip()
    timezone_name = timezone_name or os.getenv("WANDERING_ADM_TIMEZONE", "Europe/Dublin")
    try:
        return ZoneInfo(timezone_name)
    except Exception:
        return UTC


def validate_timezone_name(timezone_name, default="Europe/Dublin"):
    clean = str(timezone_name or default or "UTC").strip()
    try:
        ZoneInfo(clean)
        return clean, ""
    except Exception:
        return "", f"`{clean}` is not a valid IANA timezone. Examples: `Europe/London`, `Europe/Berlin`, `America/New_York`, `America/Chicago`, `UTC`."


def server_timezone_name(config=None, default="Europe/Dublin"):
    if isinstance(config, dict):
        configured = (
            config.get("server_timezone")
            or config.get("timezone")
            or config.get("adm_timezone")
            or default
        )
    else:
        configured = default
    clean, _ = validate_timezone_name(configured, default)
    return clean or "UTC"


def restart_timezone_name(config=None):
    if isinstance(config, dict):
        configured = config.get("restart_timezone") or config.get("server_timezone") or config.get("timezone")
    else:
        configured = ""
    clean, _ = validate_timezone_name(configured, "Europe/Dublin")
    return clean or "UTC"


def restart_timezone_for_config(config=None):
    try:
        return ZoneInfo(restart_timezone_name(config))
    except Exception:
        return UTC


def apply_server_timezone(config, timezone_name):
    clean, error = validate_timezone_name(timezone_name)
    if error:
        return "", error
    if not isinstance(config, dict):
        return "", "Server config is missing."
    config["server_timezone"] = clean
    config["timezone"] = clean
    config["adm_timezone"] = clean
    config["restart_timezone"] = clean
    config.setdefault("damage_timezone", clean)
    config.setdefault("damage_restore_timezone", clean)
    config.setdefault("vehicle_reset_timezone", clean)
    for schedule_key, config_key in (
        ("damage_schedule", "damage_timezone"),
        ("damage_restore_schedule", "damage_restore_timezone"),
        ("vehicle_reset_schedule", "vehicle_reset_timezone"),
    ):
        schedule = config.get(schedule_key)
        if isinstance(schedule, dict):
            schedule.setdefault("timezone", config.get(config_key) or clean)
    return clean, ""


def adm_line_time_parts(line):
    if not line:
        return None
    match = _ADM_TIME_PREFIX_RE.match(line)
    if not match:
        return None
    try:
        hh = int(match.group(1))
        mm = int(match.group(2))
        ss = int(match.group(3))
    except Exception:
        return None
    if not (0 <= hh < 24 and 0 <= mm < 60 and 0 <= ss < 60):
        return None
    return hh, mm, ss


def extract_adm_event_time(line, *, now=None, config=None):
    """Extract the in-game wall-clock time from an ADM log line and return
    a timezone-aware UTC datetime, or None if the line has no recognisable
    `HH:MM:SS` prefix.

    DayZ ADM lines look like:
        01:23:45 | Player "Bob" (id=ABC pos=<x, 0, z>) is connected
    The log only stores HH:MM:SS, never a date — we anchor it to today's
    UTC date (or yesterday's if the parsed time is *more* than 12 hours
    in the future relative to `now`, which handles late-night scans
    where the log line was written just before UTC midnight).
    """
    parts = adm_line_time_parts(line)
    if not parts:
        return None
    hh, mm, ss = parts

    tz = adm_timezone_for_config(config)
    reference_utc = now or datetime.now(UTC)
    if reference_utc.tzinfo is None:
        reference_utc = reference_utc.replace(tzinfo=UTC)
    else:
        reference_utc = reference_utc.astimezone(UTC)
    reference_local = reference_utc.astimezone(tz)
    candidate_local = reference_local.replace(hour=hh, minute=mm, second=ss, microsecond=0)
    # ADM lines only contain wall-clock time. Compare in the server's own
    # timezone so live UK/EU summer-time logs are not mislabelled yesterday.
    # Only roll back across midnight when the parsed time is wildly ahead of
    # the current local time. A few minutes of Nitrado/Railway clock drift is
    # normal and must not turn today's event into yesterday's feed item.
    if candidate_local > reference_local + timedelta(hours=12):
        candidate_local -= timedelta(days=1)
    candidate = candidate_local.astimezone(UTC)
    if candidate > reference_utc + timedelta(hours=12):
        candidate -= timedelta(days=1)
    return candidate


def normalize_live_adm_event_time(line, event_time, *, config=None, now=None):
    """Keep live ADM feed timestamps on the nearest plausible current day."""
    if event_time is None:
        return None
    reference_utc = now or datetime.now(UTC)
    if reference_utc.tzinfo is None:
        reference_utc = reference_utc.replace(tzinfo=UTC)
    else:
        reference_utc = reference_utc.astimezone(UTC)
    try:
        event_time = event_time.astimezone(UTC) if event_time.tzinfo else event_time.replace(tzinfo=UTC)
        if abs((reference_utc - event_time).total_seconds()) <= 12 * 60 * 60:
            return event_time
    except Exception:
        return event_time

    parts = adm_line_time_parts(line)
    if not parts:
        return event_time
    hh, mm, ss = parts
    candidate_timezones = []
    for tz in (adm_timezone_for_config(config), UTC):
        if all(str(tz) != str(existing) for existing in candidate_timezones):
            candidate_timezones.append(tz)
    try:
        dublin = ZoneInfo("Europe/Dublin")
        if all(str(dublin) != str(existing) for existing in candidate_timezones):
            candidate_timezones.append(dublin)
    except Exception:
        pass

    best = event_time
    best_delta = abs((reference_utc - event_time).total_seconds())
    for tz in candidate_timezones:
        reference_local = reference_utc.astimezone(tz)
        for day_offset in (-1, 0, 1):
            local_day = reference_local + timedelta(days=day_offset)
            candidate_local = local_day.replace(hour=hh, minute=mm, second=ss, microsecond=0)
            candidate = candidate_local.astimezone(UTC)
            delta = abs((reference_utc - candidate).total_seconds())
            if delta < best_delta:
                best = candidate
                best_delta = delta
    return best


# How old (in seconds) an ADM event can be before we refuse to dispatch
# Discord feeds for it. This is the critical guard that prevents Railway
# container restarts from spamming the server with yesterday's events
# every time the in-memory + on-disk processed_lines cache gets wiped.
# 2 hours is the sweet spot: long enough to backfill genuine "missed
# events" after a brief outage, short enough to never re-broadcast
# yesterday's killfeed.
ADM_EVENT_MAX_AGE_SECONDS = 2 * 60 * 60


def adm_event_max_age_seconds():
    try:
        return max(300, int(os.getenv("WANDERING_ADM_EVENT_MAX_AGE_SECONDS", ADM_EVENT_MAX_AGE_SECONDS)))
    except Exception:
        return ADM_EVENT_MAX_AGE_SECONDS


def is_adm_event_stale(event_time, *, now=None, max_age_seconds=ADM_EVENT_MAX_AGE_SECONDS):
    """Return True if `event_time` is older than `max_age_seconds` relative
    to `now` (defaults to current UTC). Used to suppress feed dispatch for
    ADM lines that were already logged hours ago (e.g. after a Railway
    container restart wipes the processed-line cache and the bot re-scans
    the entire .ADM file fresh).
    """
    if event_time is None:
        return False
    reference = now or datetime.now(UTC)
    try:
        age = (reference - event_time).total_seconds()
    except Exception:
        return False
    return age > max_age_seconds


def should_guard_stale_adm_events(guild_id):
    context = adm_parse_context.get(str(guild_id), {})
    return bool(context.get("history_sweep"))


def load_processed_adm_lines():
    global processed_lines

    data = load_json(PROCESSED_ADM_FILE)
    processed_lines = {}

    for guild_id, hashes in data.items():
        if isinstance(hashes, list):
            # Use an OrderedDict as an insertion-ordered set so trimming
            # always evicts the oldest entries, never random ones.
            ordered = OrderedDict()
            for item in hashes:
                ordered[str(item)] = None
            processed_lines[str(guild_id)] = ordered


def save_processed_adm_lines():
    data = {}

    for guild_id, hashes in processed_lines.items():
        # `hashes` is an OrderedDict; keep the most recent
        # PROCESSED_ADM_CACHE_LIMIT keys for crash recovery.
        keys = list(hashes.keys()) if isinstance(hashes, OrderedDict) else list(hashes)
        data[guild_id] = keys[-PROCESSED_ADM_CACHE_LIMIT:]

    save_json(PROCESSED_ADM_FILE, data)


def load_processed_adm_events():
    global processed_adm_events

    data = load_json(PROCESSED_ADM_EVENTS_FILE)
    processed_adm_events = {}

    for guild_id, fingerprints in data.items():
        if isinstance(fingerprints, list):
            ordered = OrderedDict()
            for item in fingerprints:
                ordered[str(item)] = None
            processed_adm_events[str(guild_id)] = ordered


def save_processed_adm_events():
    data = {}

    for guild_id, fingerprints in processed_adm_events.items():
        keys = list(fingerprints.keys()) if isinstance(fingerprints, OrderedDict) else list(fingerprints)
        data[guild_id] = keys[-PROCESSED_ADM_EVENT_CACHE_LIMIT:]

