def get_zone_from_line(line):

    lower = line.lower()

    for zone, keywords in zone_keywords.items():

        for keyword in keywords:

            if keyword in lower:
                return zone

    coords = extract_adm_coords(line)
    if coords:
        return zone_from_coords(coords)

    return "Unknown"


def zone_from_coords(coords):
    try:
        x_text, y_text = coords.split(",")[:2]
        x = float(x_text.strip())
        y = float(y_text.strip())
    except Exception:
        return "Unknown"

    east_west = "West" if x < 5120 else "Central" if x < 10240 else "East"
    north_south = "South" if y < 5120 else "Midlands" if y < 10240 else "North"
    return f"{north_south} {east_west}"


def ensure_guild_runtime(guild_id):

    if guild_id not in processed_lines:
        processed_lines[guild_id] = OrderedDict()
    elif not isinstance(processed_lines[guild_id], OrderedDict):
        # Migrate any legacy `set` cache to OrderedDict on the fly.
        legacy = processed_lines[guild_id]
        processed_lines[guild_id] = OrderedDict((str(item), None) for item in legacy)

    if guild_id not in processed_adm_events:
        processed_adm_events[guild_id] = OrderedDict()
    elif not isinstance(processed_adm_events[guild_id], OrderedDict):
        legacy_events = processed_adm_events[guild_id]
        processed_adm_events[guild_id] = OrderedDict((str(item), None) for item in legacy_events)

    if guild_id not in processed_kill_events:
        processed_kill_events[guild_id] = OrderedDict()
    elif not isinstance(processed_kill_events[guild_id], OrderedDict):
        legacy_kills = processed_kill_events[guild_id]
        processed_kill_events[guild_id] = OrderedDict((str(item), None) for item in legacy_kills)

    if guild_id not in online_players:
        online_players[guild_id] = set()

    if guild_id not in player_last_coords:
        player_last_coords[guild_id] = {}

    if guild_id not in player_online_times:
        player_online_times[guild_id] = {}

    if guild_id not in territory_heat:
        territory_heat[guild_id] = {}


def increase_heat(guild_id, zone, mode="pvp", coords=None):

    ensure_guild_runtime(guild_id)

    if mode == "pvp":
        territory_heat[guild_id][zone] = (
            territory_heat[guild_id].get(zone, 0) + 1
        )

    modes = territory_heat[guild_id].setdefault("__modes__", {})
    mode_counts = modes.setdefault(mode, {})
    mode_counts[zone] = mode_counts.get(zone, 0) + 1

    if coords:
        points = territory_heat[guild_id].setdefault("__points__", {})
        mode_points = points.setdefault(mode, [])
        plotted = map_coords_to_pixel(coords, guild_id)
        if plotted:
            mode_points.append(plotted)
            points[mode] = mode_points[-300:]

    save_heatmap()


def remember_player_location_from_adm(guild_id, line):
    player_name = extract_player_name(line)
    coords = extract_adm_coords(line)

    if not coords or not player_name or player_name == "Unknown":
        return

    ensure_guild_runtime(guild_id)
    player_last_coords[str(guild_id)][player_name] = {
        "coords": coords,
        "seen": str(datetime.now(UTC)),
    }


def remember_online_state_from_adm_line(guild_id, line, event_type=None, event_time=None):
    event_type = event_type or classify_event(line)
    if event_type not in {"connect", "disconnect"}:
        return False, event_type, ""

    player_name = extract_player_name(line)
    if not player_name or player_name == "Unknown":
        return False, event_type, ""

    ensure_guild_runtime(guild_id)
    changed = False

    if event_type == "connect":
        changed = player_name not in online_players[guild_id]
        online_players[guild_id].add(player_name)
        player_online_times[guild_id].setdefault(player_name, event_time or datetime.now(UTC))
    else:
        changed = player_name in online_players[guild_id]
        online_players[guild_id].discard(player_name)
        player_online_times[guild_id].pop(player_name, None)

    if changed:
        save_online_players()

    return changed, event_type, player_name


def classify_event(line):

    lower = line.lower()
    zombie_terms = ["infected", "zombie", "zmb"]
    animal_terms = [
        "animal_",
        "deer",
        "stag",
        "doe",
        "boar",
        "pig",
        "cow",
        "sheep",
        "goat",
        "wolf",
        "bear",
        "chicken",
        "hen",
        "rooster",
        "fox",
        "hare"
    ]
    unconscious_terms = [
        "unconscious",
        "unconsciousness",
        "knocked out",
        "passed out"
    ]

    if "disconnected" in lower:
        return "disconnect"

    # Only treat completed joins as connections. "connecting" is ignored
    # to avoid duplicate Discord feed messages for the same player.
    if re.search(r"\bconnected\b", lower) and "connecting" not in lower:
        return "connect"

    if "territoryflag" in lower and "has raised" in lower:
        return "flag_raise"

    if "territoryflag" in lower and "has lowered" in lower:
        return "flag_lower"

    if "performed emotesuicide" in lower or "committed suicide" in lower:
        return "suicide"

    if "is choosing to respawn" in lower:
        return "respawn"

    if "bled out" in lower or "bleed sources" in lower:
        return "bleedout"

    if re.search(r"\bpacked\b", lower):
        return "packed"

    if re.search(r"\bplaced\b", lower):
        return "placed"

    if any(term in lower for term in unconscious_terms):
        return "unconscious"

    if any(term in lower for term in animal_terms) and any(word in lower for word in ["killed", "dead", "died"]):
        return "animal_kill"

    if any(term in lower for term in zombie_terms):

        if any(word in lower for word in ["killed", "died", "dead"]):
            return "zombie_kill"

        if any(word in lower for word in ["hit", "attacked", "damage", "wound"]):
            return "zombie_hit"

    if 'hit by player "' in lower and ("(dead)" in lower or "[hp: 0]" in lower):
        return "kill"

    # Vehicle deaths/hits — DayZ ADM lines look like:
    #   Player "X" (DEAD) ... hit by Transport_PickupTruck for 250 damage
    #   Player "X" (DEAD) ... hit by Vehicle CivilianSedan from ...
    if "(dead)" in lower and (" by transport" in lower or " by vehicle" in lower or "by transporthit" in lower):
        return "vehicle_kill"

    if "hit by" in lower:
        return "cut"

    if "killed by" in lower and 'killed by player "' not in lower:
        if any(term in lower for term in zombie_terms):
            return "zombie_kill"
        return "cut"

    if "killed" in lower:
        return "kill"

    if "built" in lower or "mounted" in lower or "unmounted" in lower:
        return "build"

    if "destroyed" in lower or "dismantled" in lower:
        return "raid"

    return None

# =========================================================
# MULTI GUILD API SEARCH
# =========================================================

ADM_LOG_NAME_PATTERN = re.compile(
    r"^DayZServer_[A-Z0-9]+_x64_(\d{4}-\d{2}-\d{2})_(\d{2}-\d{2}-\d{2})\.ADM$",
    re.IGNORECASE
)


def nitrado_adm_search_paths(config):
    nitrado_user = config.get("nitrado_user")
    if not nitrado_user:
        return []
    platform_key = normalize_server_platform(config.get("server_platform") or config.get("platform"))
    if platform_key == "playstation":
        roots = ("dayzps", "dayzps_missions", "dayzxb", "dayzxb_missions")
    elif platform_key == "pc":
        roots = ("dayz", "mpmissions", "dayzxb", "dayzxb_missions", "dayzps", "dayzps_missions")
    else:
        roots = ("dayzxb", "dayzxb_missions", "dayzps", "dayzps_missions", "dayz")

    mission_names = [
        "dayzOffline.chernarusplus",
        "dayzOffline.enoch",
        "dayzOffline.sakhal",
    ]
    active_mission = str(config.get("active_mission_dir") or config.get("mission_folder") or "").strip().strip("/")
    if active_mission and "/" not in active_mission and active_mission not in mission_names:
        mission_names.insert(0, active_mission)

    paths = []

    def add(path):
        clean = str(path or "").strip()
        if clean and clean not in paths:
            paths.append(clean)

    for remembered_key in ("adm_log_directory", "adm_last_log_directory"):
        remembered = normalize_nitrado_directory_path(config.get(remembered_key))
        if remembered:
            add(remembered)

    remembered_path = str(config.get("adm_last_log_path") or "").strip()
    remembered_dir = nitrado_directory_from_file_path(remembered_path)
    if remembered_dir:
        add(remembered_dir)

    for root in roots:
        base = f"/games/{nitrado_user}/noftp/{root}"
        add(f"{base}/config/")
        add(f"{base}/profiles/")
        add(f"{base}/logs/")
        add(f"{base}/")
        add(f"{base}/mpmissions/")
        for mission in mission_names:
            add(f"{base}/mpmissions/{mission}/")
            add(f"{base}/{mission}/")
    add(f"/games/{nitrado_user}/noftp/")
    return paths


def normalize_nitrado_directory_path(path):
    clean = str(path or "").strip().replace("\\", "/")
    if not clean.startswith("/games/"):
        return ""
    if not clean.endswith("/"):
        clean = f"{clean}/"
    return clean


def nitrado_directory_from_file_path(path):
    clean = str(path or "").strip().replace("\\", "/")
    if not clean.startswith("/games/") or "/" not in clean:
        return ""
    directory = clean.rsplit("/", 1)[0]
    return normalize_nitrado_directory_path(directory)


def remember_adm_log_source(config, latest_log):
    if not isinstance(config, dict) or not isinstance(latest_log, dict):
        return False
    path = str(latest_log.get("path") or "").strip()
    directory = nitrado_directory_from_file_path(path)
    if not path or not directory:
        return False

    changed = False
    if config.get("adm_last_log_path") != path:
        config["adm_last_log_path"] = path
        changed = True
    if config.get("adm_log_directory") != directory:
        config["adm_log_directory"] = directory
        changed = True
    return changed


def parse_nitrado_datetime(value):
    if not value:
        return None

    if isinstance(value, (int, float)):
        try:
            return datetime.fromtimestamp(value, UTC)
        except Exception:
            return None

    text = str(value).strip().replace("Z", "+00:00")
    try:
        parsed = datetime.fromisoformat(text)
        return parsed if parsed.tzinfo else parsed.replace(tzinfo=UTC)
    except Exception:
        return None


def adm_log_datetime(entry):
    name_match = ADM_LOG_NAME_PATTERN.match(entry.get("name", ""))
    if name_match:
        time_text = f"{name_match.group(1)} {name_match.group(2).replace('-', ':')}"
        try:
            return datetime.strptime(time_text, "%Y-%m-%d %H:%M:%S").replace(tzinfo=UTC)
        except Exception:
            pass

    return parse_nitrado_datetime(entry.get("modified_at"))


def adm_debug_enabled():
    return str(os.getenv("WANDERING_ADM_DEBUG", "")).strip().lower() in {"1", "true", "yes", "on"}


def adm_debug_log(message):
    if adm_debug_enabled():
        print(message)


def compact_adm_scan_message(message, limit=220):
    text = re.sub(r"\s+", " ", str(message or "")).strip()
    if "Just a moment" in text or "<!DOCTYPE html" in text:
        text = "Nitrado/Cloudflare returned an HTML rate-limit page."
    return text[:limit]


def adm_scan_failure_summary(diagnostics, limit=5):
    diagnostics = diagnostics if isinstance(diagnostics, list) else []
    if not diagnostics:
        return "No ADM search diagnostics were recorded."
    failures = []
    for item in diagnostics:
        if not isinstance(item, dict):
            continue
        path = str(item.get("path") or "").strip()
        status = str(item.get("status") or "").strip()
        count = int(item.get("count") or 0)
        error = compact_adm_scan_message(item.get("error") or item.get("message") or "")
        if count > 0:
            failures.append(f"{path}: {count} ADM candidate(s)")
        elif error:
            failures.append(f"{path}: {status or 'error'} {error}")
        else:
            failures.append(f"{path}: {status or 'no entries'}")
    return "; ".join(failures[-limit:])[:900]


def adm_scan_diagnostic_is_rate_limited(item):
    if not isinstance(item, dict):
        return False
    status = str(item.get("status") or "").strip()
    text = str(item.get("error") or item.get("message") or "").lower()
    return (
        status == "429"
        or "429" in text
        or "cloudflare" in text
        or "rate-limit" in text
        or "just a moment" in text
        or "<!doctype html" in text
    )


def adm_scan_diagnostics_rate_limited(diagnostics):
    return any(adm_scan_diagnostic_is_rate_limited(item) for item in diagnostics or [])


def adm_rate_limit_backoff_seconds():
    try:
        return max(60, min(900, int(os.getenv("WANDERING_ADM_RATE_LIMIT_BACKOFF_SECONDS", "180"))))
    except Exception:
        return 180


def set_adm_rate_limit_backoff(guild_id):
    seconds = adm_rate_limit_backoff_seconds()
    adm_rate_limit_backoff_until[str(guild_id)] = time.time() + seconds
    return seconds


def adm_rate_limited_message(stage, diagnostics, backoff_seconds=None):
    seconds = int(backoff_seconds if backoff_seconds is not None else adm_rate_limit_backoff_seconds())
    return (
        f"Nitrado/Cloudflare rate-limited ADM {stage} (429). This is not a missing ADM file/path; "
        f"backing off for about {seconds}s. Last checks: {adm_scan_failure_summary(diagnostics)}"
    )


def list_adm_logs(config, lookback_hours=None, diagnostics=None, stop_after_first_match=False):

    token = config.get("nitrado_token")
    service_id = config.get("service_id")

    headers = {
        "Authorization": f"Bearer {token}",
        "Accept": "application/json"
    }

    cutoff = None
    if lookback_hours:
        cutoff = datetime.now(UTC) - timedelta(hours=int(lookback_hours))

    matching_logs = {}

    for search_path in nitrado_adm_search_paths(config):

        try:

            url = (
                f"https://api.nitrado.net/services/"
                f"{service_id}/gameservers/file_server/list"
            )

            params = {
                "dir": search_path,
                "search": "*DayZServer*"
            }

            response = requests.get(
                url,
                headers=headers,
                params=params,
                timeout=20
            )

            adm_debug_log(f"[PING STATUS] {response.status_code}")

            if response.status_code != 200:
                diagnostic = {
                    "path": search_path,
                    "status": response.status_code,
                    "error": response.text[:300],
                    "count": 0,
                }
                if isinstance(diagnostics, list):
                    diagnostics.append(diagnostic)
                if adm_scan_diagnostic_is_rate_limited(diagnostic):
                    break
                continue

            try:
                data = response.json()
            except Exception:
                diagnostic = {
                    "path": search_path,
                    "status": response.status_code,
                    "error": response.text[:300],
                    "count": 0,
                }
                if isinstance(diagnostics, list):
                    diagnostics.append(diagnostic)
                if adm_scan_diagnostic_is_rate_limited(diagnostic):
                    break
                continue

            entries = (
                data
                .get("data", {})
                .get("entries", [])
            )

            adm_debug_log(f"[SEARCH PATH] {search_path}")
            path_matches = 0
            matched_this_path = False

            for entry in entries:
                if not ADM_LOG_NAME_PATTERN.match(entry.get("name", "")):
                    continue

                adm_debug_log(f"FOUND FILE: {entry.get('name')}")
                path_matches += 1

                entry_time = adm_log_datetime(entry)
                if cutoff and entry_time and entry_time < cutoff:
                    continue

                path = entry.get("path")
                if path:
                    entry["_adm_datetime"] = entry_time.isoformat() if entry_time else ""
                    modified_time = parse_nitrado_datetime(entry.get("modified_at"))
                    entry["_modified_datetime"] = modified_time.isoformat() if modified_time else ""
                    matching_logs[path] = entry
                    matched_this_path = True
            if isinstance(diagnostics, list):
                diagnostics.append({
                    "path": search_path,
                    "status": response.status_code,
                    "count": path_matches,
                    "entries": len(entries),
                })
            if stop_after_first_match and matched_this_path:
                break

        except Exception as error:
            print(error)
            if isinstance(diagnostics, list):
                diagnostics.append({
                    "path": search_path,
                    "status": "exception",
                    "error": str(error),
                    "count": 0,
                })

    logs = list(matching_logs.values())
    logs.sort(key=lambda item: item.get("_adm_datetime") or item.get("modified_at", ""), reverse=True)
    return logs


def ping_latest_adm_log(config, diagnostics=None):
    matching_logs = list_adm_logs(config, diagnostics=diagnostics, stop_after_first_match=True)

    if not matching_logs:
        adm_debug_log("NO MATCHING ADM FILES")
        return None

    latest = matching_logs[0]
    adm_debug_log(f"LATEST ADM FOUND: {latest.get('path')}")
    return latest


# ============================================================================
# .RPT LIVE EVENT TRACKER (PR #41 follow-up)
# ----------------------------------------------------------------------------
# Pulls the freshest DayZ .RPT log from Nitrado, parses dynamic-event spawns
# (heli crashes, contaminated zones, convoys, infected hordes, vehicles) with
# world coords, posts/updates a live admin-only embed.
# Events have lifetimes — when the bot stops seeing an event id in subsequent
# pulls AND the time since first_seen exceeds default DayZ lifetime, it's
# marked despawned and removed from the live embed.
# ============================================================================

RPT_EVENT_TRACKER_FILE = data_path("rpt_event_tracker.json")
RPT_LOG_NAME_PATTERN = re.compile(r"DayZServer.*\.RPT$", re.IGNORECASE)
RPT_DEFAULT_EVENT_LIFETIME_SECONDS = 25 * 60
RPT_EVENT_PREFIXES = (
    "Land_Wreck_", "StaticHeliCrash", "ContaminatedArea", "EventConvoy",
    "EventConvoyMilitary", "Static_", "InfectedHorde", "DynamicEvent",
    "PoliceCar", "CivilianSedan", "Hatchback", "Sedan", "Olga",
    "Gunter", "Ada", "Sarka", "Truck", "M3S", "Offroad",
)

rpt_event_tracker = {}


def load_rpt_event_tracker():
    global rpt_event_tracker
    try:
        with open(RPT_EVENT_TRACKER_FILE, "r", encoding="utf-8") as fh:
            rpt_event_tracker = json.load(fh)
    except FileNotFoundError:
        rpt_event_tracker = {}
    except Exception as err:
        print(f"[RPT TRACKER] load error: {err}")
        rpt_event_tracker = {}


def save_rpt_event_tracker():
    try:
        with open(RPT_EVENT_TRACKER_FILE, "w", encoding="utf-8") as fh:
            json.dump(rpt_event_tracker, fh, indent=2, default=str)
    except Exception as err:
        print(f"[RPT TRACKER] save error: {err}")


def nitrado_rpt_search_paths(config):
    nitrado_user = config.get("nitrado_user") or ""
    if not nitrado_user:
        return []
    platform_key = normalize_server_platform(config.get("server_platform") or config.get("platform"))
    if platform_key == "playstation":
        roots = ("dayzps", "dayzps_missions", "dayzxb", "dayzxb_missions")
    elif platform_key == "pc":
        roots = ("dayz", "mpmissions", "dayzxb", "dayzxb_missions")
    else:
        roots = ("dayzxb", "dayzxb_missions", "dayzps", "dayzps_missions")
    candidates = []
    for root in roots:
        candidates.extend([
            f"/games/{nitrado_user}/noftp/{root}/profiles/",
            f"/games/{nitrado_user}/noftp/{root}/config/",
            f"/games/{nitrado_user}/noftp/{root}/logs/",
            f"/games/{nitrado_user}/noftp/{root}/",
        ])
    seen = set()
    deduped = []
    for path in candidates:
        key = path.lower()
        if key not in seen:
            seen.add(key)
            deduped.append(path)
    return deduped


def list_rpt_logs(config):
    token = config.get("nitrado_token")
    service_id = config.get("service_id")
    if not token or not service_id:
        return []
    headers = {"Authorization": f"Bearer {token}", "Accept": "application/json"}
    matching = {}
    for search_path in nitrado_rpt_search_paths(config):
        try:
            response = requests.get(
                f"https://api.nitrado.net/services/{service_id}/gameservers/file_server/list",
                headers=headers,
                params={"dir": search_path, "search": "*DayZServer*"},
                timeout=20,
            )
            if response.status_code != 200:
                continue
            entries = response.json().get("data", {}).get("entries", [])
            for entry in entries:
                if not RPT_LOG_NAME_PATTERN.search(entry.get("name", "")):
                    continue
                path = entry.get("path")
                if path:
                    matching[path] = entry
        except Exception as err:
            print(f"[RPT TRACKER] list_rpt_logs error: {err}")
    logs = list(matching.values())
    logs.sort(key=lambda e: e.get("modified_at", ""), reverse=True)
    return logs


def fetch_latest_rpt_content(config):
    logs = list_rpt_logs(config)
    if not logs:
        return None, None, None
    latest = logs[0]
    token = config.get("nitrado_token")
    service_id = config.get("service_id")
    try:
        dl_resp = requests.get(
            f"https://api.nitrado.net/services/{service_id}/gameservers/file_server/download",
            headers={"Authorization": f"Bearer {token}"},
            params={"file": latest.get("path")},
            timeout=20,
        )
        if dl_resp.status_code != 200:
            return None, None, None
        token_url = dl_resp.json().get("data", {}).get("token", {}).get("url")
        if not token_url:
            return None, None, None
        file_resp = requests.get(token_url, timeout=30)
        text = file_resp.content.decode("utf-8", errors="replace")
        return latest.get("path"), latest.get("modified_at", ""), text
    except Exception as err:
        print(f"[RPT TRACKER] fetch_latest_rpt_content error: {err}")
        return None, None, None


_RPT_COORD_PATTERNS = [
    re.compile(r"<\s*(-?\d+(?:\.\d+)?)[\s,]+(-?\d+(?:\.\d+)?)[\s,]+(-?\d+(?:\.\d+)?)\s*>"),
    re.compile(r'pos\s*=\s*"\s*(-?\d+(?:\.\d+)?)\s+(-?\d+(?:\.\d+)?)\s+(-?\d+(?:\.\d+)?)\s*"'),
    re.compile(r"\[\s*(-?\d+(?:\.\d+)?)[\s,]+(-?\d+(?:\.\d+)?)[\s,]+(-?\d+(?:\.\d+)?)\s*\]"),
]


def _extract_rpt_coords(line):
    for pat in _RPT_COORD_PATTERNS:
        m = pat.search(line)
        if m:
            try:
                return float(m.group(1)), float(m.group(2)), float(m.group(3))
            except (TypeError, ValueError):
                continue
    return None


def _extract_rpt_event_type(line):
    cleaned = line
    for prefix in ("Event spawned", "Spawned event", "CE event", "Event ", "Spawn "):
        if prefix.lower() in cleaned.lower():
            idx = cleaned.lower().index(prefix.lower())
            cleaned = cleaned[idx + len(prefix):]
            break
    for prefix in RPT_EVENT_PREFIXES:
        m = re.search(rf"\b({re.escape(prefix)}\w+)", cleaned)
        if m:
            return m.group(1)[:80]
    return None


def parse_rpt_for_events(rpt_text):
    """Returns (restart_markers, events).
    restart_markers = list of restart banner indexes
    events = list of {id, type, x, y, z, line_index}"""
    if not rpt_text:
        return [], []
    restart_markers = []
    events = []
    seen = set()
    lines = rpt_text.splitlines()
    banner_pattern = re.compile(r"={20,}")
    for i, raw_line in enumerate(lines):
        if banner_pattern.search(raw_line) and i + 5 < len(lines):
            window = "\n".join(lines[i:i + 6]).lower()
            if "dayz" in window or "mission" in window:
                restart_markers.append(str(i))
        lowered = raw_line.lower()
        if not any(t in lowered for t in ("spawn", "event", "ce ", "ce]")):
            continue
        coords = _extract_rpt_coords(raw_line)
        if not coords:
            continue
        event_type = _extract_rpt_event_type(raw_line)
        if not event_type:
            continue
        eid = f"{event_type}@{int(coords[0])}_{int(coords[2])}"
        if eid in seen:
            continue
        seen.add(eid)
        events.append({
            "id": eid, "type": event_type,
            "x": coords[0], "y": coords[1], "z": coords[2],
            "line_index": i,
        })
    return restart_markers, events


def parse_rpt_diagnostics(rpt_text, limit=16):
    if not rpt_text:
        return []
    diagnostics = []
    seen = set()

    def add(kind, name, message, line_index):
        if len(diagnostics) >= limit:
            return
        key = (kind, name, message)
        if key in seen:
            return
        seen.add(key)
        diagnostics.append({
            "kind": str(kind or "Warning")[:60],
            "name": str(name or "RPT")[:120],
            "message": str(message or "")[:240],
            "line_index": int(line_index or 0),
        })

    lines = rpt_text.splitlines()
    managed_event_hits = 0
    for i, raw_line in enumerate(lines):
        m = re.search(r'\[\d+\]\s+((?:Animal|Infected|Vehicle|Static)WanderingBot_[A-Za-z0-9_]+)', raw_line)
        if not m:
            continue
        next_line = lines[i + 1].strip() if i + 1 < len(lines) else ""
        if "primary spawner" not in next_line.lower() or "active: yes" not in next_line.lower():
            continue
        add(
            "Managed event loaded",
            m.group(1),
            f"CE loaded this Wandering Bot definition ({next_line}); startup RPT lists do not include runtime spawn coordinates",
            i,
        )
        managed_event_hits += 1
        if managed_event_hits >= 4:
            break

    for i, raw_line in enumerate(lines):
        line = raw_line.strip()
        if not line:
            continue
        m = re.search(r'DynamicEvent\s+"([^"]+)"\s+setup is invalid, event will be disabled', line, re.I)
        if m:
            add("Disabled event", m.group(1), "setup is invalid; DayZ disabled this event", i)
            continue
        m = re.search(r'\[DynEvent\]\s+"([^"]+)"\s+will be ignored\s+::\s+(.+)', line, re.I)
        if m:
            add("Ignored event", m.group(1), m.group(2), i)
            continue
        m = re.search(r'\[DynEvent\]\s+"([^"]+)"\s+failed to initialize spawner\s+-\s+(.+)', line, re.I)
        if m:
            add("Spawner failed", m.group(1), m.group(2), i)
            continue
        m = re.search(r"Skipping entry for non-existing event '([^']+)'", line, re.I)
        if m:
            add("Missing event", m.group(1), "cfgeventspawns.xml references an event not present in events.xml", i)
            continue
        m = re.search(r'File\s+"([^"]+)"\s+does not exist', line, re.I)
        if m:
            missing_path = m.group(1)
            if "wanderingbot" in normalize_discord_name(missing_path) and "territor" in missing_path.lower():
                add("Missing animal territory XML", missing_path, "cfgenvironment.xml references this Wandering Bot animal territory file, but DayZ could not open it", i)
            else:
                add("Missing file", missing_path, "required CE/XML file is missing", i)
            continue
        m = re.search(r'\[ERROR\]\[XML\]\s+::\s+(.+)', line, re.I)
        if m:
            add("XML error", "XML", m.group(1), i)
            continue
        m = re.search(r"Failed to open file\s+\"?([^\"\s]+)\"?", line, re.I)
        if m:
            add("Missing XML file", m.group(1), "DayZ tried to load this file but it was not present at restart", i)
            continue
        m = re.search(r"Type '([^']+)'\s+will be ignored\.\s+\((.+)\)", line, re.I)
        if m:
            add("Ignored type", m.group(1), m.group(2), i)
            continue
        m = re.search(r"Spawnable type\s+'?([^']+)'?\s+could not load preset item\s+'?([^']+?)'?\s+because it is ignored", line, re.I)
        if m:
            add("Ignored preset item", m.group(2), f"spawnabletypes preset `{m.group(1)}` references an ignored item; remove it from cargo/attachments", i)
            continue
        m = re.search(r'PRESET LOAD ERROR:\s+(.+)', line, re.I)
        if m:
            add("Preset error", "spawnabletypes", m.group(1), i)
            continue
        m = re.search(r"Preset \([^)]+\) with name '([^']+)'\s+was not found", line, re.I)
        if m:
            add("Missing preset", m.group(1), "referenced loot preset was not found", i)
            continue
        m = re.search(r"Unknown value:\s+'([^']+)'", line, re.I)
        if m:
            add("Unknown value", m.group(1), "DayZ CE does not recognise this value/tag", i)
            continue
        m = re.search(r"Type 'ManType' must be inherited from class 'DayZAnimalType'", line, re.I)
        if m:
            add("Animal error", "animal storage", "saved animal/entity data is not matching DayZAnimalType", i)
            continue
        m = re.search(r'groups failed:\s*([1-9]\d*)', line, re.I)
        if m:
            add("Map group failures", "mapgrouppos/mapgroupproto", f"{m.group(1)} group(s) failed to load", i)
            continue
        m = re.search(r'No group configured for \'([^\']+)\', failed to spawn loot', line, re.I)
        if m:
            add("No loot group", m.group(1), "object spawned but CE has no loot group for it", i)
            continue
        m = re.search(r'Object spawner failed to spawn\s+(.+)', line, re.I)
        if m:
            add("Object spawn failed", m.group(1), "object path/class failed in object spawner", i)
            continue
        if len(diagnostics) >= limit:
            break
    return diagnostics


async def get_or_create_rpt_admin_channel(guild, config):
    channels = config.setdefault("channels", {})
    existing_id = channels.get("rpt_admin")
    if existing_id:
        ch = guild.get_channel(int(existing_id))
        if ch:
            return ch
    overwrites = {
        guild.default_role: discord.PermissionOverwrite(read_messages=False),
        guild.me: discord.PermissionOverwrite(read_messages=True, send_messages=True, manage_messages=True, embed_links=True),
    }
    admin_role_names = {str(r).lower() for r in (config.get("admin_roles") or DEFAULT_ADMIN_ROLES)}
    for role in guild.roles:
        if role.permissions.administrator or role.name.lower() in admin_role_names:
            overwrites[role] = discord.PermissionOverwrite(read_messages=True, send_messages=True, embed_links=True)
    try:
        ch = await guild.create_text_channel(
            "🔧-server-spawns",
            overwrites=overwrites,
            topic="Live RPT event tracker — auto-updated each server restart.",
        )
        channels["rpt_admin"] = ch.id
        save_guild_configs()
        return ch
    except Exception as err:
        print(f"[RPT TRACKER] could not create admin channel: {err}")
        return None


def _rpt_world_link(x, z, guild_id):
    try:
        return build_izurvive_link(f"{int(x)},{int(z)}", guild_id=int(guild_id))
    except Exception:
        return None


def _build_rpt_event_embed(guild_id, state):
    events = state.get("events", [])
    now_ts = datetime.now(UTC).timestamp()
    last_restart = float(state.get("last_restart_ts") or 0)
    last_restart_text = f"<t:{int(last_restart)}:R>" if last_restart else "—"
    buckets = {}
    for ev in events:
        buckets.setdefault(ev.get("type", "Unknown"), []).append(ev)
    embed = discord.Embed(
        title="🔧 LIVE SERVER SPAWN TRACKER",
        description=(
            f"Last detected server restart: {last_restart_text}\n"
            f"Tracking **{len(events)}** active event/vehicle spawn(s) parsed from `.RPT`.\n"
            f"Entries auto-expire when their DayZ lifetime passes or the next pull no longer sees them."
        ),
        color=0xE67E22,
    )
    if not events:
        embed.add_field(name="No active spawns detected", value="The next RPT pull will populate this.", inline=False)
    else:
        hidden_events = 0
        max_fields = 8
        max_per_type = 5
        for kind, evs in sorted(buckets.items()):
            if len(embed.fields) >= max_fields:
                hidden_events += len(evs)
                continue
            lines = []
            for ev in evs[:max_per_type]:
                link = _rpt_world_link(ev["x"], ev["z"], guild_id)
                first_seen_ts = int(float(ev.get("first_seen_ts", now_ts)))
                age_s = int(now_ts - first_seen_ts)
                lifetime = int(ev.get("lifetime_s", RPT_DEFAULT_EVENT_LIFETIME_SECONDS))
                remaining = max(0, lifetime - age_s)
                coord_text = f"({int(ev['x'])}, {int(ev['z'])})"
                if link:
                    coord_text = f"[{coord_text}]({link})"
                lines.append(f"- {coord_text} | seen <t:{first_seen_ts}:R> | age {format_duration_seconds(age_s)} | expires in {format_duration_seconds(remaining)}")
            if len(evs) > max_per_type:
                hidden_events += len(evs) - max_per_type
                lines.append(f"- +{len(evs) - max_per_type} more {kind} spawn(s)")
            embed.add_field(name=f"{kind} ({len(evs)})", value="\n".join(lines)[:1024], inline=False)
        if hidden_events:
            embed.add_field(
                name="More Spawns Hidden",
                value=f"`{hidden_events}` extra spawn(s) are tracked but hidden to stay under Discord embed limits. Use `/server liveevents list` for the full list.",
                inline=False,
            )
    diagnostics = state.get("diagnostics") or []
    if diagnostics:
        lines = []
        for item in diagnostics[:8]:
            kind = str(item.get("kind") or "Warning")
            name = str(item.get("name") or "RPT")
            message = str(item.get("message") or "Check the latest RPT.")
            lines.append(f"- **{kind}** `{name}`: {message}"[:240])
        if len(diagnostics) > 8:
            lines.append(f"- +{len(diagnostics) - 8} more warning(s) in the latest RPT pull")
        embed.add_field(name="Spawn / XML status", value="\n".join(lines)[:1024], inline=False)
    embed.set_footer(text=f"Wandering Bot Alpha — refresh every 5 min · Updated {datetime.now(UTC).strftime('%Y-%m-%d %H:%M UTC')}")
    return embed


async def _post_or_update_rpt_embed(guild, state):
    channel = guild.get_channel(int(state.get("channel_id", 0)))
    if not channel:
        return False
    embed = _build_rpt_event_embed(guild.id, state)
    msg_id = state.get("embed_message_id")
    try:
        if msg_id:
            try:
                msg = await channel.fetch_message(int(msg_id))
                await msg.edit(embed=style_embed(embed))
                return True
            except discord.NotFound:
                pass
        msg = await channel.send(embed=style_embed(embed))
        state["embed_message_id"] = msg.id
        try:
            await msg.pin(reason="Live RPT spawn tracker")
        except Exception:
            pass
        return True
    except Exception as err:
        print(f"[RPT TRACKER] post/update embed failed: {err}")
        return False


async def _post_rpt_restart_report(guild, state, new_events, diagnostics=None):
    channel = guild.get_channel(int(state.get("channel_id", 0)))
    if not channel:
        return
    embed = discord.Embed(
        title="🛑 SERVER RESTART DETECTED",
        description=(
            f"<t:{int(datetime.now(UTC).timestamp())}:F> — fresh mission started.\n"
            f"**{len(new_events)}** dynamic-event spawns located in the first `.RPT` pull."
        ),
        color=0xE74C3C,
    )
    if new_events:
        lines = []
        for ev in new_events[:10]:
            link = _rpt_world_link(ev["x"], ev["z"], guild.id)
            ct = f"({int(ev['x'])}, {int(ev['z'])})"
            if link:
                ct = f"[{ct}]({link})"
            first_seen_ts = int(float(ev.get("first_seen_ts", datetime.now(UTC).timestamp())))
            lines.append(f"- **{ev['type']}** at {ct} | seen <t:{first_seen_ts}:R>")
        embed.add_field(name="First spawns of the cycle", value="\n".join(lines)[:1024], inline=False)
    if diagnostics:
        lines = []
        for item in diagnostics[:8]:
            kind = str(item.get("kind") or "Warning")
            name = str(item.get("name") or "RPT")
            message = str(item.get("message") or "Check the latest RPT.")
            lines.append(f"- **{kind}** `{name}`: {message}"[:240])
        embed.add_field(name="Warnings found in startup RPT", value="\n".join(lines)[:1024], inline=False)
    try:
        await channel.send(embed=style_embed(embed))
    except Exception as err:
        print(f"[RPT TRACKER] restart report failed: {err}")


async def refresh_rpt_event_tracker(guild_id, config, force_restart_post=False):
    state = rpt_event_tracker.setdefault(str(guild_id), {
        "events": [], "last_restart_ts": 0, "last_rpt_size": 0,
        "enabled": True, "embed_message_id": None, "channel_id": None,
        "restart_marker_count": 0,
    })
    if not state.get("enabled", True):
        return "Tracker is disabled for this guild."
    guild = bot.get_guild(int(guild_id))
    if not guild:
        return "Guild not found."

    channel = guild.get_channel(int(state.get("channel_id") or 0))
    if not channel:
        channel = await get_or_create_rpt_admin_channel(guild, config)
        if not channel:
            return "Could not create the admin channel."
        state["channel_id"] = channel.id

    path, modified_at, text = await asyncio.to_thread(fetch_latest_rpt_content, config)
    now_ts = datetime.now(UTC).timestamp()
    state["last_rpt_path"] = path or ""
    state["last_rpt_modified_at"] = modified_at or ""
    state["last_rpt_checked_ts"] = now_ts
    if not text:
        return "XML uploaded, but the tracker could not pull the latest .RPT yet. If this server recently changed map/platform, confirm `/server setplatform` is correct and restart once so Nitrado creates a fresh log."

    new_size = len(text)
    if not force_restart_post and new_size == int(state.get("last_rpt_size") or 0):
        save_rpt_event_tracker()
        return "Latest RPT checked; file unchanged since last tracker pull."
    state["last_rpt_size"] = new_size

    restart_markers, events = parse_rpt_for_events(text)
    diagnostics = parse_rpt_diagnostics(text)
    state["diagnostics"] = diagnostics
    state["diagnostics_updated_ts"] = now_ts

    saw_new_restart = force_restart_post
    restart_history_record = None
    last_known = int(state.get("restart_marker_count") or 0)
    new_restart_marker_detected = len(restart_markers) > last_known
    if new_restart_marker_detected:
        saw_new_restart = True
        state["restart_marker_count"] = len(restart_markers)
        state["last_restart_ts"] = now_ts
        details = f"Fresh mission marker detected in latest RPT. Total restart markers now {len(restart_markers)}."
        if last_known > 0 and mark_one_time_scenario_events_uploaded(config, require_native_upload=True):
            details += " Dashboard native CE event run counters advanced."
        restart_history_record = append_restart_history(
            guild_id,
            config,
            "rpt_detected",
            "detected",
            details,
            "RPT tracker",
        )

    existing_by_id = {e["id"]: e for e in state.get("events", [])}
    fresh_ids = set()
    new_events_this_cycle = []
    for ev in events:
        fresh_ids.add(ev["id"])
        if ev["id"] in existing_by_id:
            existing_by_id[ev["id"]]["last_seen_ts"] = now_ts
        else:
            record = {**ev, "first_seen_ts": now_ts, "last_seen_ts": now_ts,
                      "lifetime_s": RPT_DEFAULT_EVENT_LIFETIME_SECONDS}
            existing_by_id[ev["id"]] = record
            new_events_this_cycle.append(record)

    kept = []
    for record in existing_by_id.values():
        age = now_ts - float(record.get("first_seen_ts", now_ts))
        gone_for = now_ts - float(record.get("last_seen_ts", now_ts))
        if age > float(record.get("lifetime_s", RPT_DEFAULT_EVENT_LIFETIME_SECONDS)):
            continue
        if record["id"] not in fresh_ids and gone_for > 30 * 60:
            continue
        kept.append(record)
    state["events"] = kept

    save_rpt_event_tracker()
    await _post_or_update_rpt_embed(guild, state)

    if saw_new_restart:
        await _post_rpt_restart_report(guild, state, new_events_this_cycle or kept, diagnostics)
        if restart_history_record:
            save_guild_configs()
            await publish_restart_history(guild_id, config, restart_history_record)
        save_rpt_event_tracker()

    return f"OK — {len(kept)} live event(s), restart={saw_new_restart}, restarts_total={state.get('restart_marker_count', 0)}"


@tasks.loop(minutes=5)
async def rpt_event_tracker_loop():
    for guild_id, config in list(guild_configs.items()):
        try:
            if not config.get("rpt_tracker_enabled", True):
                continue
            if not config.get("nitrado_token") or not config.get("service_id"):
                continue
            await refresh_rpt_event_tracker(guild_id, config)
        except Exception as err:
            print(f"[RPT TRACKER LOOP] {guild_id} error: {err}")


load_rpt_event_tracker()


