@tasks.loop(minutes=1)
async def dashboard_member_action_loop():
    changed = False
    for guild_id, config in active_guild_config_items():
        actions = config.get("dashboard_member_actions", [])
        if not isinstance(actions, list):
            continue
        for action in actions:
            if not isinstance(action, dict) or action.get("status") != "queued":
                continue
            action_type = str(action.get("action") or "").lower()
            player_name = str(action.get("player_name") or "").strip()
            if action_type not in {"dayz_temp_ban", "dayz_perm_ban"} or not player_name:
                continue
            try:
                minutes = max(1, int(action.get("minutes") or 1440)) if action_type == "dayz_temp_ban" else None
                reason = str(action.get("reason") or ("Dashboard temp ban" if action_type == "dayz_temp_ban" else "Dashboard perm ban"))
                ok, message = await add_player_to_nitrado_banlist_async(
                    guild_id,
                    config,
                    player_name,
                    ban_type="temp" if action_type == "dayz_temp_ban" else "perm",
                    reason=reason,
                    source="dashboard_members",
                    minutes=minutes,
                )
                action["status"] = "done" if ok else "failed"
                action["result"] = message
                action["processed_at"] = datetime.now(UTC).isoformat()
                if ok and action_type == "dayz_temp_ban":
                    clean_name = normalize_nitrado_banlist_name(player_name)
                    now_dt = datetime.now(UTC)
                    now_ts = now_dt.timestamp()
                    wanted = normalize_discord_name(clean_name)
                    matched = None
                    for record in config.setdefault("nitrado_temp_bans", []):
                        if normalize_discord_name(record.get("gamertag", "")) == wanted:
                            matched = record
                            break
                    if matched:
                        base_until = max(now_ts, float(matched.get("until_ts") or 0))
                        matched["gamertag"] = clean_name
                        matched["until_ts"] = base_until + minutes * 60
                        matched["expires_at"] = datetime.fromtimestamp(matched["until_ts"], UTC).isoformat()
                        matched["reason"] = reason
                        matched["source"] = "dashboard_members"
                        matched["extended_at"] = now_dt.isoformat()
                    else:
                        until_dt = now_dt + timedelta(minutes=minutes)
                        config.setdefault("nitrado_temp_bans", []).append(
                            {
                                "gamertag": clean_name,
                                "expires_at": until_dt.isoformat(),
                                "until_ts": until_dt.timestamp(),
                                "reason": reason,
                                "source": "dashboard_members",
                            }
                        )
                elif ok and action_type == "dayz_perm_ban":
                    config.setdefault("nitrado_perm_bans", []).append(
                        {
                            "gamertag": player_name,
                            "reason": reason,
                            "source": "dashboard",
                            "created_at": datetime.now(UTC).isoformat(),
                        }
                    )
                changed = True
            except Exception as error:
                action["status"] = "failed"
                action["result"] = str(error)
                action["processed_at"] = datetime.now(UTC).isoformat()
                changed = True
                print(f"[DASHBOARD MEMBER ACTION] {guild_id} failed for {player_name}: {error}")
    if changed:
        save_guild_configs()


def load_dashboard_audit_queue():
    try:
        loaded = load_json(DASHBOARD_AUDIT_QUEUE_FILE)
    except Exception as error:
        print(f"[DASHBOARD AUDIT] load failed: {error}")
        return []
    if isinstance(loaded, list):
        return loaded
    if isinstance(loaded, dict) and isinstance(loaded.get("items"), list):
        return loaded.get("items", [])
    return []


def save_dashboard_audit_queue(queue):
    try:
        save_json(DASHBOARD_AUDIT_QUEUE_FILE, list(queue or []))
    except Exception as error:
        print(f"[DASHBOARD AUDIT] save failed: {error}")


def dashboard_audit_timestamp(value):
    try:
        text = str(value or "").replace("Z", "+00:00")
        parsed = datetime.fromisoformat(text)
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=UTC)
        return int(parsed.timestamp())
    except Exception:
        return int(datetime.now(UTC).timestamp())


def dashboard_audit_line_value(value, limit=150):
    if isinstance(value, (dict, list)):
        try:
            value = json.dumps(value, ensure_ascii=False)
        except Exception:
            value = str(value)
    text = discord.utils.escape_mentions(str(value or ""))
    text = text.replace("\n", " ").strip()
    if len(text) > limit:
        text = text[: max(0, limit - 3)].rstrip() + "..."
    return text or "blank"


def format_dashboard_audit_details(payload):
    if not isinstance(payload, dict) or not payload:
        return "No extra details were supplied."
    ignored = {"dashboard_mode", "return_to", "_scope_denied", "csrf", "csrf_token"}
    lines = []
    for key, value in payload.items():
        if key in ignored or value in (None, ""):
            continue
        label = str(key).replace("_", " ").title()
        lines.append(f"**{label}:** {dashboard_audit_line_value(value)}")
        if len(lines) >= 10:
            break
    return "\n".join(lines) if lines else "No extra details were supplied."


def money_event_value(value, limit=260):
    text = discord.utils.escape_mentions(str(value or ""))
    text = text.replace("\n", " ").strip()
    if len(text) > limit:
        text = text[: max(0, limit - 3)].rstrip() + "..."
    return text or "blank"


async def send_money_feed(guild, config, title, description="", fields=None, *, color=0xF1C40F, footer="Money Feed"):
    if not guild:
        return None
    config = config if isinstance(config, dict) else guild_configs.setdefault(str(guild.id), {"guild_name": guild.name, "channels": {}})
    try:
        channel = await get_or_create_feed_channel(
            guild,
            config,
            "money_feed",
            DEFAULT_CHANNEL_NAMES["money_feed"],
            private=True,
            force=True,
        )
        if not channel:
            return None
        embed = discord.Embed(
            title=money_event_value(title, 256),
            description=discord_safe_content(discord.utils.escape_mentions(str(description or "")), 900) if description else "",
            color=color,
        )
        for field in fields or []:
            if not isinstance(field, dict):
                continue
            embed.add_field(
                name=money_event_value(field.get("name"), 256),
                value=discord_safe_content(money_event_value(field.get("value"), 1024), 1024),
                inline=bool(field.get("inline", True)),
            )
        embed.set_thumbnail(url=BOT_IMAGE)
        embed.set_footer(text=f"Wandering Bot Alpha - {footer}")
        await channel.send(embed=trim_embed_field_values(style_embed(embed)), allowed_mentions=discord.AllowedMentions.none())
        return channel
    except Exception as error:
        print(f"[MONEY FEED] send failed for {getattr(guild, 'id', '?')}: {error}")
        return None


MONEY_DASHBOARD_ROUTES = {
    "/api/admin/wage",
    "/api/admin/wallet-adjustment",
    "/api/admin/economy-rule",
    "/api/admin/shop-item",
    "/api/admin/shop-bundle",
}


def build_dashboard_audit_embed(event, guild):
    title = discord.utils.escape_mentions(str(event.get("title") or "Dashboard change confirmed"))
    summary = discord.utils.escape_mentions(str(event.get("summary") or "").strip())
    created_ts = dashboard_audit_timestamp(event.get("created_at"))
    embed = discord.Embed(
        title="🛡️ DASHBOARD CHANGE CONFIRMED",
        description=f"**{title}**" + (f"\n{summary}" if summary else ""),
        color=0xFF5AA5,
    )
    embed.add_field(name="Server", value=discord.utils.escape_mentions(guild.name), inline=True)
    embed.add_field(name="By", value=dashboard_audit_line_value(event.get("actor"), 220), inline=True)
    embed.add_field(name="When", value=f"<t:{created_ts}:F>\n<t:{created_ts}:R>", inline=True)
    embed.add_field(
        name="Dashboard Route",
        value=f"`{dashboard_audit_line_value(event.get('method'), 12)} {dashboard_audit_line_value(event.get('route'), 120)}`",
        inline=False,
    )
    embed.add_field(name="What Changed", value=format_dashboard_audit_details(event.get("payload")), inline=False)
    embed.set_thumbnail(url=BOT_IMAGE)
    embed.set_footer(text=f"Wandering Bot Alpha - Dashboard Audit - {event.get('id', 'queued')}")
    return trim_embed_field_values(style_embed(embed))


@tasks.loop(seconds=20)
async def dashboard_audit_loop():
    queue = load_dashboard_audit_queue()
    if not queue:
        return

    sent_ids = set()
    failed_attempts = {}
    processed = 0

    for event in queue:
        if processed >= 20:
            break
        if not isinstance(event, dict):
            continue
        event_id = str(event.get("id") or "")
        guild_id = str(event.get("guild_id") or "").strip()
        if not event_id or not guild_id or not guild_id.isdigit():
            sent_ids.add(event_id)
            continue
        guild = bot.get_guild(int(guild_id))
        if not guild:
            failed_attempts[event_id] = int(event.get("attempts") or 0) + 1
            continue
        config = guild_configs.setdefault(guild_id, {"guild_name": guild.name, "channels": {}})
        try:
            channel = await get_or_create_feed_channel(
                guild,
                config,
                "dashboard_audit",
                DEFAULT_CHANNEL_NAMES["dashboard_audit"],
                private=True,
                force=True,
            )
            if not channel:
                failed_attempts[event_id] = int(event.get("attempts") or 0) + 1
                continue
            await channel.send(
                embed=build_dashboard_audit_embed(event, guild),
                allowed_mentions=discord.AllowedMentions.none(),
            )
            if str(event.get("route") or "") in MONEY_DASHBOARD_ROUTES:
                await send_money_feed(
                    guild,
                    config,
                    "🧾 DASHBOARD MONEY CHANGE",
                    event.get("title") or "Dashboard money setting updated.",
                    [
                        {"name": "By", "value": event.get("actor"), "inline": True},
                        {"name": "Route", "value": f"{event.get('method', 'POST')} {event.get('route', '')}", "inline": True},
                        {"name": "Details", "value": format_dashboard_audit_details(event.get("payload")), "inline": False},
                    ],
                    color=0xD5B45F,
                    footer="Money Feed - Dashboard",
                )
            sent_ids.add(event_id)
            processed += 1
        except Exception as error:
            failed_attempts[event_id] = int(event.get("attempts") or 0) + 1
            print(f"[DASHBOARD AUDIT] send failed for {guild_id}: {error}")

    if sent_ids or failed_attempts:
        latest = load_dashboard_audit_queue()
        remaining = []
        for event in latest:
            if not isinstance(event, dict):
                continue
            event_id = str(event.get("id") or "")
            if event_id in sent_ids:
                continue
            if event_id in failed_attempts:
                event["attempts"] = failed_attempts[event_id]
                if event["attempts"] > 10:
                    print(f"[DASHBOARD AUDIT] dropping stuck event {event_id}")
                    continue
            remaining.append(event)
        save_dashboard_audit_queue(remaining)

