@bot.event
async def on_member_join(member):

    guild_id = str(member.guild.id)

    config = guild_configs.get(guild_id, {})

    channels = config.get("channels", {})

    # ── Autonomous showcase welcome ──────────────────────
    if is_showcase_guild(guild_id):
        showcase_welcome_channel = None
        for key in ("general_chat", "welcome"):
            ch_id = channels.get(key)
            if ch_id:
                showcase_welcome_channel = bot.get_channel(ch_id)
                if showcase_welcome_channel:
                    break

        if not showcase_welcome_channel:
            for ch in member.guild.text_channels:
                if ch.permissions_for(member.guild.me).send_messages:
                    showcase_welcome_channel = ch
                    break

        if showcase_welcome_channel:
            welcome_text = random.choice(SHOWCASE_WELCOME_MESSAGES_EXTENDED)
            embed = discord.Embed(
                title="🤖 NEW ARRIVAL DETECTED",
                description=(
                    f"{member.mention}\n\n{welcome_text}\n\n"
                    "💬 Say `hi` to get started. Ask me to generate an image, explain a feature, or just chat.\n"
                    "📻 This server is run by the bot. The owner is here as backup only."
                ),
                color=0x9B59B6
            )
            embed.set_thumbnail(url=BOT_IMAGE)
            embed.set_footer(text="Wandering Bot • Autonomous Showcase • Fully bot-managed server")
            await showcase_welcome_channel.send(embed=style_embed(embed))

            # Generate a welcome image if OpenAI is available
            if OPENAI_API_KEY:
                await asyncio.sleep(2)
                await showcase_generate_and_post_image(
                    showcase_welcome_channel,
                    "gritty",
                    caption_prefix="Welcome postcard for the new arrival — "
                )
        return
    # ── Standard welcome ─────────────────────────────────

    onboarding = member_onboarding_settings(config)
    if onboarding["enabled"]:
        await add_onboarding_role(member, onboarding.get("pending_role_id"), "Wandering Bot onboarding pending")
        sent = await send_member_onboarding_join_prompt(member, config, onboarding)
        if sent:
            return

    welcome_channel = bot.get_channel(
        channels.get("welcome")
    )

    if not welcome_channel:
        return

    welcome_text = random.choice(WELCOME_MESSAGES)

    embed = discord.Embed(
        title="👋 NEW SURVIVOR ARRIVED",
        description=(
            f"{member.mention}\n\n{welcome_text}\n\n"
            "🔗 Please link your gamertag with `/linkgamer` in the required channel.\n"
            "Example: `/linkgamer gamertag: YourXboxName`"
        ),
        color=0x1ABC9C
    )

    embed.set_thumbnail(url=BOT_IMAGE)

    embed.set_footer(
        text="Wandering Bot Alpha • Welcome System"
    )

    await welcome_channel.send(embed=style_embed(embed))


@bot.event
async def on_raw_reaction_add(payload):
    if not payload.guild_id or not payload.user_id:
        return
    if bot.user and int(payload.user_id) == int(bot.user.id):
        return
    guild = bot.get_guild(int(payload.guild_id))
    if not guild:
        return
    guild_id = str(guild.id)
    config = guild_configs.get(guild_id, {})
    settings = member_onboarding_settings(config)
    if not settings["enabled"]:
        return
    rules_channel = resolve_onboarding_channel(guild, config, settings, "rules", "welcome")
    if not rules_channel or int(payload.channel_id) != int(rules_channel.id):
        return
    rules_message_id = str(settings.get("rules_message_id") or "").strip()
    if not rules_message_id:
        return
    if str(payload.message_id) != rules_message_id:
        return
    if str(payload.emoji) != settings.get("reaction_emoji"):
        return
    member = guild.get_member(int(payload.user_id))
    if not member:
        try:
            member = await guild.fetch_member(int(payload.user_id))
        except Exception:
            return
    if getattr(member, "bot", False):
        return
    await apply_member_onboarding_rules_acceptance(guild, config, member)


WANDERING_MASTER_GUILD_ID = os.environ.get("WANDERING_MASTER_GUILD_ID", "").strip()
_company_announce_dedupe = {}


async def maybe_broadcast_company_announcement(message):
    """If `message` was posted in the master guild's
    #wandering-company-announcements (or matches the legacy '📢🎊・UPDATES &
    NEWS・🎊📢' naming), fan it out to every other guild's
    company_announcements channel. Best-effort: each delivery failure
    is logged and skipped. Set WANDERING_MASTER_GUILD_ID env var to
    enable; otherwise this function silently no-ops."""
    if not WANDERING_MASTER_GUILD_ID:
        return
    if not message.guild or str(message.guild.id) != WANDERING_MASTER_GUILD_ID:
        return

    # Only broadcast from the configured channel.
    master_config = guild_configs.get(str(message.guild.id), {})
    master_channel_id = master_config.get("channels", {}).get("company_announcements")
    if master_channel_id and message.channel.id != int(master_channel_id):
        return
    # Fallback name match if channels-config isn't initialised yet.
    if not master_channel_id:
        ch_name_lower = (message.channel.name or "").lower()
        if "company-announcement" not in ch_name_lower and "updates" not in ch_name_lower:
            return

    if not message.content and not message.attachments and not message.embeds:
        return

    # 1-minute dedupe so we don't double-broadcast on Discord edits.
    now_ts = datetime.now(UTC).timestamp()
    if now_ts - _company_announce_dedupe.get(message.id, 0) < 60:
        return
    _company_announce_dedupe[message.id] = now_ts

    attachments_payload = []
    for att in message.attachments[:5]:
        try:
            attachments_payload.append(await att.to_file())
        except Exception:
            pass

    delivered = 0
    failed = 0
    for guild in bot.guilds:
        if str(guild.id) == WANDERING_MASTER_GUILD_ID:
            continue
        target_config = guild_configs.get(str(guild.id), {})
        target_id = target_config.get("channels", {}).get("company_announcements")
        target_channel = None
        if target_id:
            target_channel = guild.get_channel(int(target_id))
        # Fallback: any channel whose name contains 'company-announcement'.
        if not target_channel:
            for ch in guild.text_channels:
                if "company-announcement" in (ch.name or "").lower():
                    target_channel = ch
                    break
        if not target_channel:
            failed += 1
            continue

        outbound = discord.Embed(
            title="📢 Wandering Bot — Company Announcement",
            description=message.content[:4000] if message.content else "_(see attachments)_",
            color=0xE67E22,
        )
        outbound.set_footer(text=f"Broadcast from {message.guild.name} by {message.author.display_name}")
        try:
            files_clone = []
            for att in message.attachments[:5]:
                try:
                    files_clone.append(await att.to_file())
                except Exception:
                    pass
            await target_channel.send(embed=style_embed(outbound), files=files_clone or None)
            delivered += 1
        except Exception as err:
            failed += 1
            print(f"[COMPANY ANNOUNCE] {guild.name}: {err}")

    # Acknowledge to the announcer in the master channel.
    try:
        await message.add_reaction("📡")
        if delivered:
            await message.channel.send(
                f"📡 Broadcast delivered to **{delivered}** guild(s) (failed {failed}).",
                delete_after=60,
            )
    except Exception:
        pass


