DEFAULT_RESTART_INTERVAL_HOURS = 4

last_restart_hour = {}
restart_warning_tracker = {}


def schedule_bool(value, default=False):
    if isinstance(value, bool):
        return value
    if value is None:
        return default
    text = str(value).strip().lower()
    if text in {"1", "true", "yes", "on", "enabled"}:
        return True
    if text in {"0", "false", "no", "off", "disabled"}:
        return False
    return default


def set_config_value_if_changed(target, key, value):
    if target.get(key) == value:
        return False
    target[key] = value
    return True


def normalize_schedule_pair(config, flag_key, schedule_key, defaults):
    if not isinstance(config, dict):
        return False
    changed = False
    schedule = config.get(schedule_key)
    if not isinstance(schedule, dict):
        schedule = {}
        config[schedule_key] = schedule
        changed = True

    top_enabled = schedule_bool(config.get(flag_key), False)
    nested_enabled = schedule_bool(schedule.get("enabled"), top_enabled)
    enabled = top_enabled or nested_enabled
    changed |= set_config_value_if_changed(config, flag_key, enabled)
    changed |= set_config_value_if_changed(schedule, "enabled", enabled)

    for key, default in defaults.items():
        config_key = f"{schedule_key.removesuffix('_schedule')}_{key}"
        existing = schedule.get(key)
        mirror = config.get(config_key)
        if existing in (None, "") and mirror not in (None, ""):
            changed |= set_config_value_if_changed(schedule, key, mirror)
        elif mirror in (None, "") and existing not in (None, ""):
            changed |= set_config_value_if_changed(config, config_key, existing)
        elif existing in (None, "") and mirror in (None, ""):
            changed |= set_config_value_if_changed(schedule, key, default)
            changed |= set_config_value_if_changed(config, config_key, default)

    return changed


def normalize_server_control_schedules(config):
    if not isinstance(config, dict):
        return False
    changed = False

    restart_enabled = schedule_bool(config.get("restart_schedule_enabled"), False)
    restart_confirmed = schedule_bool(config.get("restart_schedule_confirmed"), restart_enabled)
    if restart_enabled and not restart_confirmed:
        restart_confirmed = True
    changed |= set_config_value_if_changed(config, "restart_schedule_enabled", restart_enabled)
    changed |= set_config_value_if_changed(config, "restart_schedule_confirmed", restart_confirmed)
    changed |= set_config_value_if_changed(
        config,
        "restart_interval_hours",
        max(1, min(24, safe_int(config.get("restart_interval_hours"), DEFAULT_RESTART_INTERVAL_HOURS))),
    )
    changed |= set_config_value_if_changed(
        config,
        "restart_start_hour",
        max(0, min(23, safe_int(config.get("restart_start_hour"), 0))),
    )
    warnings = []
    for item in config.get("restart_warning_minutes") or [30, 15, 10, 5, 1]:
        minute = safe_int(item, 0)
        if minute > 0 and minute not in warnings:
            warnings.append(minute)
    changed |= set_config_value_if_changed(config, "restart_warning_minutes", warnings or [30, 15, 10, 5, 1])
    timezone_name = server_timezone_name(config)
    restart_timezone = restart_timezone_name(config)
    changed |= set_config_value_if_changed(config, "server_timezone", timezone_name)
    changed |= set_config_value_if_changed(config, "adm_timezone", config.get("adm_timezone") or timezone_name)
    changed |= set_config_value_if_changed(config, "restart_timezone", restart_timezone or timezone_name)

    changed |= normalize_schedule_pair(config, "damage_schedule_enabled", "damage_schedule", {
        "first_date": "",
        "time": "04:00",
        "timezone": timezone_name,
        "interval_value": 7,
        "interval_unit": "days",
        "day_of_week": "",
        "day_of_month": 0,
    })
    changed |= normalize_schedule_pair(config, "damage_restore_schedule_enabled", "damage_restore_schedule", {
        "first_date": "",
        "time": "04:00",
        "timezone": timezone_name,
        "interval_value": 14,
        "interval_unit": "days",
        "day_of_week": "",
        "day_of_month": 0,
    })
    changed |= normalize_schedule_pair(config, "vehicle_reset_schedule_enabled", "vehicle_reset_schedule", {
        "method": "cfgignorelist",
        "first_date": "",
        "time": "04:00",
        "timezone": timezone_name,
        "interval_value": 7,
        "interval_unit": "days",
        "day_of_week": "",
        "day_of_month": 0,
    })
    return changed


def append_restart_history(guild_id, config, source, status, details="", actor=""):
    if not isinstance(config, dict):
        return {}
    history = config.setdefault("restart_history", [])
    if not isinstance(history, list):
        history = []
        config["restart_history"] = history
    record = {
        "id": f"restart-{datetime.now(UTC).strftime('%Y%m%d%H%M%S')}-{secrets.token_hex(3)}",
        "created_at": datetime.now(UTC).isoformat(),
        "source": str(source or "unknown")[:80],
        "status": str(status or "detected")[:80],
        "details": str(details or "")[:500],
        "actor": str(actor or "")[:160],
    }
    history.insert(0, record)
    del history[60:]
    return record


async def publish_restart_history(guild_id, config, record):
    if not record or not isinstance(config, dict):
        return
    channels = config.get("channels", {}) if isinstance(config.get("channels"), dict) else {}
    log_key = config.get("restart_log_channel_key") or "restart_logs"
    channel_id = (
        config.get("restart_log_channel_id")
        or channels.get(log_key)
        or channels.get("restart_logs")
        or channels.get("restart_alerts")
        or channels.get("admin_logs")
    )
    if not channel_id:
        return
    try:
        channel = bot.get_channel(int(channel_id))
    except Exception:
        channel = None
    if not channel:
        return
    embed = discord.Embed(
        title="Server Restart Log",
        description=str(record.get("details") or "Restart activity recorded.")[:1500],
        color=0x94B4FF if str(record.get("status")) in {"requested", "detected"} else 0xE74C3C,
    )
    embed.add_field(name="Source", value=str(record.get("source") or "unknown").replace("_", " ").title(), inline=True)
    embed.add_field(name="Status", value=str(record.get("status") or "detected").replace("_", " ").title(), inline=True)
    if record.get("actor"):
        embed.add_field(name="Actor", value=str(record.get("actor"))[:1000], inline=False)
    embed.timestamp = datetime.now(UTC)
    try:
        await channel.send(embed=style_embed(embed))
    except Exception as error:
        print(f"[RESTART LOG] failed for {guild_id}: {error}")


