def _minutes_until_next_restart(now, restart_offset, restart_interval):
    """Return minutes until the next scheduled restart hour."""
    try:
        restart_offset = int(restart_offset or 0) % 24
        restart_interval = int(restart_interval or 0)
    except Exception:
        return None

    if restart_interval <= 0:
        return None

    restart_hours = [
        h for h in range(24)
        if h >= restart_offset and ((h - restart_offset) % restart_interval == 0)
    ]
    if not restart_hours:
        return None

    current_minutes = now.hour * 60 + now.minute
    candidates = []
    for h in restart_hours:
        candidate = h * 60
        delta = candidate - current_minutes
        if delta <= 0:
            delta += 24 * 60
        candidates.append(delta)

    return min(candidates) if candidates else None


@tasks.loop(minutes=1)
async def scheduled_restart_loop():

    global last_restart_hour

    now = datetime.now(UTC)

    # ────────────────────────────────────────────────────────────────
    # PRE-RESTART COUNTDOWN WARNINGS in general_chat
    # Fires once for each configured warning minute before each scheduled restart.
    # The warning is deleted when the restart triggers so chat does not
    # fill up with old restart notices.
    # ────────────────────────────────────────────────────────────────
    for guild_id, config in active_guild_config_items():
        try:
            if config.get("restart_schedule_enabled") is not True or config.get("restart_schedule_confirmed") is not True:
                continue

            restart_interval = max(1, min(24, safe_int(
                config.get("restart_interval_hours"),
                DEFAULT_RESTART_INTERVAL_HOURS,
            )))
            restart_offset = max(0, min(23, safe_int(config.get("restart_start_hour"), 0)))
            if restart_interval <= 0:
                continue

            local_tz = restart_timezone_for_config(config)
            local_now = now.astimezone(local_tz)
            current_hour = local_now.hour
            minutes_until = _minutes_until_next_restart(local_now, restart_offset, restart_interval)
            if minutes_until is None:
                continue

            configured_warnings = []
            for raw_warning in config.get("restart_warning_minutes") or [30, 15, 10, 5, 1]:
                try:
                    warning_minute = int(raw_warning)
                except Exception:
                    continue
                if warning_minute > 0 and warning_minute not in configured_warnings:
                    configured_warnings.append(warning_minute)
            if minutes_until not in configured_warnings:
                continue

            warning = RESTART_COUNTDOWN_WARNINGS.get(minutes_until) or {
                "title": f"RESTART IN {minutes_until} MINUTES",
                "body": "Scheduled restart warning. Finish up and get somewhere safe.",
                "color": 0xF39C12,
            }

            channels = config.get("channels", {})
            # Honour per-guild override: admins can set the countdown to
            # post in a dedicated channel via /extra setcountdownchannel.
            # Falls back to general_chat if no override is configured.
            countdown_channel_id = (
                config.get("restart_channel_id")
                or channels.get(config.get("restart_channel_key") or "")
                or channels.get("restart_countdown")
                or channels.get("general_chat")
            )
            try:
                countdown_channel_id = int(countdown_channel_id)
            except Exception:
                countdown_channel_id = None
            chat_channel = bot.get_channel(countdown_channel_id)
            if not chat_channel:
                continue

            fired = restart_warning_tracker.setdefault(guild_id, {})
            cycle_date = (local_now + timedelta(minutes=minutes_until)).date().isoformat()
            cycle_key = ((current_hour * 60) + local_now.minute + minutes_until) // 60 % 24
            cycle_marker = f"{cycle_date}-{cycle_key:02d}-{restart_timezone_name(config)}"
            already_fired = fired.setdefault(cycle_marker, set())
            if minutes_until in already_fired:
                continue
            already_fired.add(minutes_until)

            today_marker = local_now.date().isoformat()
            yesterday_marker = (local_now - timedelta(days=1)).date().isoformat()
            for stale_key in [k for k in fired if not (k.startswith(today_marker) or k.startswith(yesterday_marker))]:
                fired.pop(stale_key, None)

            embed = discord.Embed(
                title=warning["title"],
                description=warning["body"],
                color=warning["color"]
            )
            embed.set_thumbnail(url=BOT_IMAGE)
            embed.set_footer(text="Wandering Bot Alpha — Pre-Restart Warning")
            embed.timestamp = now

            previous_id = last_restart_countdown_message_ids.get(guild_id)
            if previous_id:
                try:
                    previous_msg = await chat_channel.fetch_message(previous_id)
                    await previous_msg.delete()
                except Exception:
                    pass

            sent = await chat_channel.send(embed=style_embed(embed))
            last_restart_countdown_message_ids[guild_id] = sent.id

        except Exception as countdown_error:
            print(f"RESTART COUNTDOWN ERROR {guild_id}: {countdown_error}")

    for guild_id, config in active_guild_config_items():

        if config.get("restart_schedule_enabled") is not True or config.get("restart_schedule_confirmed") is not True:
            continue

        restart_interval = max(1, min(24, safe_int(
            config.get("restart_interval_hours"),
            DEFAULT_RESTART_INTERVAL_HOURS,
        )))

        restart_offset = max(0, min(23, safe_int(config.get("restart_start_hour"), 0)))
        local_tz = restart_timezone_for_config(config)
        local_now = now.astimezone(local_tz)
        current_hour = local_now.hour
        current_minute = local_now.minute

        should_restart = (
            current_hour >= restart_offset
            and ((current_hour - restart_offset) % restart_interval == 0)
            and current_minute == 0
        )

        if not should_restart:
            continue

        trigger_marker = f"{local_now.date().isoformat()}-{current_hour:02d}-{restart_timezone_name(config)}"
        if last_restart_hour.get(guild_id) == trigger_marker:
            continue

        last_restart_hour[guild_id] = trigger_marker

        print(f"SCHEDULED RESTART TRIGGERED {guild_id} @ {current_hour}:00 {restart_timezone_name(config)}")

        try:

            channels = config.get("channels", {})

            announce_channel_id = (
                config.get("restart_channel_id")
                or channels.get(config.get("restart_channel_key") or "")
                or channels.get("restart_alerts")
            )
            try:
                announce_channel_id = int(announce_channel_id)
            except Exception:
                announce_channel_id = None
            announce_channel = bot.get_channel(announce_channel_id)

            if announce_channel:

                embed = discord.Embed(
                    title="⚠️ SCHEDULED RESTART",
                    description=(
                        f"Automatic restart triggered.\n\n"
                        f"⏰ Interval: Every {restart_interval} hours\n"
                        f"🕒 Current Restart: {current_hour}:00 {restart_timezone_name(config)}"
                    ),
                    color=0xE74C3C
                )

                embed.set_thumbnail(url=BOT_IMAGE)

                # Self-clean: delete previous restart-alerts message so
                # at most one is ever visible in the channel.
                previous_alert_id = last_restart_message_ids.get(guild_id)
                if previous_alert_id:
                    try:
                        previous_alert = await announce_channel.fetch_message(previous_alert_id)
                        await previous_alert.delete()
                    except Exception:
                        pass

                last_restart_message_ids.pop(guild_id, None)

                # Post the "go touch grass" follow-up to the same channel
                # the countdown was using (honours the per-guild override).
                countdown_channel_id = (
                    config.get("restart_channel_id")
                    or channels.get(config.get("restart_channel_key") or "")
                    or channels.get("restart_countdown")
                    or channels.get("general_chat")
                )
                try:
                    countdown_channel_id = int(countdown_channel_id)
                except Exception:
                    countdown_channel_id = None
                chat_channel = bot.get_channel(countdown_channel_id)
                if chat_channel:
                    final_embed = discord.Embed(
                        title="💥 SERVER IS RESTARTING NOW",
                        description=random.choice(RESTART_DOWN_FUNNIES),
                        color=0x95A5A6
                    )
                    final_embed.set_thumbnail(url=BOT_IMAGE)
                    final_embed.set_footer(text="Wandering Bot Alpha — Restart Notice")
                    final_embed.timestamp = now

                    previous_countdown_id = last_restart_countdown_message_ids.pop(guild_id, None)
                    if previous_countdown_id:
                        try:
                            previous_countdown = await chat_channel.fetch_message(previous_countdown_id)
                            await previous_countdown.delete()
                        except Exception:
                            pass

                    # The 30-minute warning is self-cleaned above. Do not
                    # send extra restart messages into Discord.

                restart_warning_tracker[guild_id] = {}

                token = config.get("nitrado_token")
                service_id = config.get("service_id")

                if token and service_id:

                    try:
                        queued_reset = queue_due_vehicle_reset_schedule(guild_id, config, now)
                        if queued_reset:
                            print(f"SCHEDULED VEHICLE RESET QUEUED BEFORE RESTART {guild_id}: {queued_reset.get('id')}")

                        cfgignorelist_events_before = list(active_cfgignorelist_vehicle_reset_events(config))
                        cfgignorelist_has_immediate_cycle = any(
                            not is_scheduled_cfgignorelist_vehicle_reset(event)
                            for event in cfgignorelist_events_before
                        )
                        cfgignorelist_results = await process_cfgignorelist_vehicle_reset_events(guild_id, config)
                        if cfgignorelist_results:
                            for ok, message in cfgignorelist_results:
                                print(f"CFGIGNORELIST VEHICLE RESET {guild_id}: ok={ok} {message}")
                            if cfgignorelist_has_immediate_cycle:
                                continue

                        economy_results = await process_economy_vehicle_reset_events(guild_id, config)
                        if economy_results:
                            for ok, message in economy_results:
                                print(f"ECONOMY VEHICLE RESET {guild_id}: ok={ok} {message}")
                            continue

                        normal_scenario_events = bridge_scenario_events(config)
                        delivery_scenario_events = delivery_bridge_scenario_events(config)
                        native_scenario_events = native_ce_scenario_events(config)
                        console_ce_enabled = console_ce_event_config(config).get("enabled")
                        has_delivery_work = queue_entries_for_guild(delivery_queue, guild_id) or queue_entries_for_guild(vehicle_rentals_queue, guild_id)
                        if has_delivery_work or (normal_scenario_events and not console_ce_enabled) or (delivery_scenario_events and console_ce_enabled):
                            upload_success, _ = await asyncio.to_thread(
                                write_and_upload_delivery_xml,
                                guild_id,
                                config,
                                now,
                                delivery_scenario_events if console_ce_enabled else None,
                                not console_ce_enabled,
                            )
                            print(f"PRE-RESTART DELIVERY XML UPLOAD {guild_id}: {upload_success}")

                        if native_scenario_events and console_ce_enabled:
                            success, _, messages = await asyncio.to_thread(
                                upload_console_ce_event_files,
                                guild_id,
                                config,
                                "",
                                "",
                                "",
                                True,
                            )
                            print(f"PRE-RESTART NATIVE CE XML UPLOAD {guild_id}: {success} {' | '.join(messages[-4:])}")

                        url = (
                            f"https://api.nitrado.net/services/"
                            f"{service_id}/gameservers/restart"
                        )

                        headers = {
                            "Authorization": f"Bearer {token}"
                        }

                        restart_response = requests.post(
                            url,
                            headers=headers,
                            timeout=30
                        )

                        print(f"AUTO RESTART STATUS: {restart_response.status_code}")
                        restart_ok = restart_response.status_code in {200, 201, 202, 204}
                        record = append_restart_history(
                            guild_id,
                            config,
                            "bot_schedule",
                            "requested" if restart_ok else "failed",
                            f"Scheduled restart at {current_hour:02d}:00 {restart_timezone_name(config)} ({now.strftime('%Y-%m-%d %H:%M UTC')}). Nitrado status {restart_response.status_code}.",
                            "scheduled_restart_loop",
                        )
                        save_guild_configs()
                        await publish_restart_history(guild_id, config, record)

                    except Exception as restart_error:
                        print(restart_error)
                        record = append_restart_history(
                            guild_id,
                            config,
                            "bot_schedule",
                            "failed",
                            f"Scheduled restart exception: {restart_error}",
                            "scheduled_restart_loop",
                        )
                        save_guild_configs()
                        await publish_restart_history(guild_id, config, record)
                else:
                    record = append_restart_history(
                        guild_id,
                        config,
                        "bot_schedule",
                        "blocked",
                        "Scheduled restart reached its time, but Nitrado token or service id is missing.",
                        "scheduled_restart_loop",
                    )
                    save_guild_configs()
                    await publish_restart_history(guild_id, config, record)

        except Exception as error:

            print(error)

