def pve_active_quest_for_channel(guild_id, channel_key, difficulty=None):
    wanted_difficulty = str(difficulty).title() if difficulty else None
    for challenge in reversed(pve_challenges.get(str(guild_id), [])):
        if challenge.get("status") != "active" or challenge.get("channel_key") != channel_key:
            continue
        if wanted_difficulty and str(challenge.get("difficulty", "")).title() != wanted_difficulty:
            continue
        return challenge
    return None


def has_active_pve_kind(guild_id, kind):
    wanted = str(kind).lower()
    for challenge in pve_challenges.get(str(guild_id), []):
        if challenge.get("status") == "active" and str(challenge.get("kind", "")).lower() == wanted:
            return True
    return False


def linked_user_id_for_player(player_name):
    wanted = normalize_discord_name(player_name)
    for user_id, data in linked_players.items():
        if data.get("verified_by") != "ADM":
            continue
        if linked_player_matches_gamertag(data, wanted):
            return str(user_id)
    return None


def award_pve_pennies(guild_id, player_name, challenge):
    user_id = linked_user_id_for_player(player_name)
    if not user_id:
        return False, "No linked Discord member found"

    wallet = guild_wallet(guild_id, user_id, linked_players.get(user_id, {}).get("discord_name", player_name))
    reward = int(challenge.get("reward_pennies", 0))
    wallet_credit(wallet, reward, "cash")
    save_wallets()
    return True, f"{reward} pennies paid"


def pve_progress_text(challenge):
    target_count = int(challenge.get("target_count", 0) or 0)
    if not target_count:
        return "Manual approval"

    progress = challenge.get("progress", {})
    if not progress:
        return f"0/{target_count}"

    leader, amount = max(progress.items(), key=lambda row: row[1])
    return f"{leader}: {amount}/{target_count}"


async def get_or_create_pve_ticket_category(guild, config):
    """Find or create the category that houses PVE quest tickets.

    Stored under `config["channels"]["pve_ticket_category"]` so it survives
    restarts. Falls back to creating a new category if the stored ID no
    longer resolves (e.g. admin manually deleted it).
    """
    channels = config.setdefault("channels", {})
    existing_id = channels.get("pve_ticket_category")
    if existing_id:
        existing = guild.get_channel(existing_id)
        if existing and isinstance(existing, discord.CategoryChannel):
            return existing
    try:
        category = await guild.create_category("🎟️ PVE Quest Tickets")
    except discord.Forbidden:
        return None
    except Exception as err:
        print(f"[PVE TICKET] could not create category: {err}")
        return None
    channels["pve_ticket_category"] = category.id
    save_guild_configs()
    return category


def next_quest_ticket_number(guild_id):
    """Return a per-guild monotonically increasing ticket number, persisting
    the counter to guild_configs so channel names stay sequential across
    bot restarts (matches the `12-username-questslug` style users expect)."""
    gid = str(guild_id)
    config = guild_configs.setdefault(gid, {"channels": {}, "admin_roles": DEFAULT_ADMIN_ROLES.copy()})
    current = int(config.get("pve_ticket_counter") or 0)
    current += 1
    config["pve_ticket_counter"] = current
    save_guild_configs()
    return current


def is_quest_claimed(challenge):
    return bool(challenge and challenge.get("claimed_by_player_id"))


def mark_quest_claimed(challenge, *, player_id, ticket_channel_id, ticket_number):
    """Lock a quest to one player so no one else can open a ticket on it.
    Idempotent — if already claimed, returns False without overwriting."""
    if not challenge:
        return False
    if challenge.get("claimed_by_player_id") and str(challenge["claimed_by_player_id"]) != str(player_id):
        return False
    challenge["claimed_by_player_id"] = str(player_id)
    challenge["claimed_ticket_channel_id"] = int(ticket_channel_id) if ticket_channel_id else None
    challenge["claimed_ticket_number"] = int(ticket_number) if ticket_number else None
    challenge["claimed_at"] = datetime.now(UTC).isoformat()
    save_pve_challenges()
    return True


def release_quest_claim(challenge):
    """Release a quest lock — used when a ticket is Deleted without
    completion so another player can pick it up."""
    if not challenge:
        return
    challenge.pop("claimed_by_player_id", None)
    challenge.pop("claimed_ticket_channel_id", None)
    challenge.pop("claimed_ticket_number", None)
    challenge.pop("claimed_at", None)
    save_pve_challenges()


def remember_quest_post_message(challenge, channel_id, message_id):
    """Track every public Discord message that displays this quest so we
    can edit them later (e.g. to add a 🔒 CLAIMED banner)."""
    if not challenge:
        return
    refs = challenge.setdefault("post_message_refs", [])
    entry = {"channel_id": int(channel_id), "message_id": int(message_id)}
    if entry not in refs:
        refs.append(entry)
        save_pve_challenges()


async def update_public_quest_posts_with_claim(guild, challenge):
    """Edit every previously-posted public quest embed to show a 🔒 CLAIMED
    banner and disable the Start button. Best-effort — never raises."""
    if not guild or not challenge:
        return
    player_id = challenge.get("claimed_by_player_id")
    if not player_id:
        return
    claimer = None
    try:
        claimer = guild.get_member(int(player_id))
    except Exception:
        claimer = None
    claimer_label = claimer.mention if claimer else f"<@{player_id}>"
    refs = list(challenge.get("post_message_refs") or [])
    quest_code = pve_quest_code(challenge)
    for ref in refs:
        try:
            channel = guild.get_channel(int(ref.get("channel_id", 0)))
            if not channel:
                continue
            message = await channel.fetch_message(int(ref.get("message_id", 0)))
            if not message or not message.embeds:
                continue
            embed = message.embeds[0]
            # Prefix the title with 🔒 CLAIMED if not already.
            if embed.title and not embed.title.startswith("🔒"):
                embed.title = f"🔒 CLAIMED — {embed.title}"
            # Add / refresh a Claimed-By field.
            claimed_field_idx = None
            for i, f in enumerate(embed.fields):
                if f.name and f.name.startswith("🔒 Claimed By"):
                    claimed_field_idx = i
                    break
            if claimed_field_idx is not None:
                embed.set_field_at(
                    claimed_field_idx,
                    name="🔒 Claimed By",
                    value=f"{claimer_label} — others must pick a different quest.",
                    inline=False,
                )
            else:
                embed.add_field(
                    name="🔒 Claimed By",
                    value=f"{claimer_label} — others must pick a different quest.",
                    inline=False,
                )
            # Disable the Start button by attaching a fresh disabled View.
            disabled_view = PVEQuestCompletionView(quest_code, disabled=True)
            try:
                await message.edit(embed=embed, view=disabled_view)
            except Exception:
                # Some message edits may still succeed without the view.
                try:
                    await message.edit(embed=embed)
                except Exception:
                    pass
        except Exception as err:
            print(f"[PVE TICKET] update_public_quest_posts edit failed: {err}")


def default_items_for_quest(challenge):
    """Return a sensible structured items_needed kit ({item, qty, spawn_zones})
    inferred from the quest's kind + title keywords. Used to auto-enrich
    legacy hardcoded bank quests (PVE_CHALLENGE_BANK) that were written
    before the structured-items schema existed, so every quest — AI or
    bank — surfaces a meaty multi-item collection list in its embed.

    Order matters: title-keyword matches win over kind matches so a
    'Medical Run' Collection quest still gets the medical kit."""
    if not isinstance(challenge, dict):
        return []
    title = str(challenge.get("title") or "").lower()
    kind = str(challenge.get("kind") or "").lower()
    goal = str(challenge.get("goal") or "").lower()
    blob = f"{title} {goal}"

    def kit(*entries):
        return [{"item": name, "qty": qty, "spawn_zones": list(zones)} for name, qty, *zones in entries]

    # --- Title / goal keyword routing ---
    if any(w in blob for w in ["medic", "medical", "doctor", "hospital", "outbreak", "viral", "infect", "clinic"]):
        return kit(
            ("Bandage", 6, "Residential", "Hospital"),
            ("Rag", 8, "Residential"),
            ("Tetracycline Pills", 3, "Hospital", "Police"),
            ("Charcoal Tablets", 4, "Hospital", "Residential"),
            ("Saline Bag IV", 2, "Hospital", "Military"),
            ("Morphine Auto-Injector", 1, "Hospital", "Military"),
            ("Epinephrine", 2, "Hospital"),
            ("Disinfectant Spray", 2, "Residential", "Hospital"),
        )
    if any(w in blob for w in ["pantry", "food", "feast", "supper", "ration"]):
        return kit(
            ("Canned Beans", 5, "Residential"),
            ("Canned Spaghetti", 4, "Residential"),
            ("Sardines", 4, "Residential", "Coastal"),
            ("Powdered Milk", 3, "Residential"),
            ("Rice", 3, "Residential"),
            ("Pumpkin", 2, "Farm", "Hunting"),
            ("Canteen", 1, "Residential", "Hunting"),
        )
    if any(w in blob for w in ["builder", "build", "carpenter", "construct", "fence", "base"]):
        return kit(
            ("Nail", 30, "Industrial", "Residential"),
            ("Wooden Plank", 10, "Industrial"),
            ("Wooden Log", 6, "Forest", "Industrial"),
            ("Rope", 3, "Residential", "Hunting"),
            ("Combination Lock", 2, "Industrial"),
            ("Hammer", 1, "Industrial"),
            ("Hand Saw", 1, "Industrial"),
        )
    if any(w in blob for w in ["tool", "mechanic", "garage", "wrench", "spark", "battery", "fuel", "vehicle", "roadside"]):
        return kit(
            ("Spark Plug", 2, "Industrial"),
            ("Car Battery", 1, "Industrial"),
            ("Radiator", 1, "Industrial"),
            ("Glow Plug", 2, "Industrial"),
            ("Jerry Can (full)", 2, "Industrial", "Residential"),
            ("Pipe Wrench", 1, "Industrial"),
            ("Pliers", 1, "Industrial"),
            ("Duct Tape", 2, "Residential", "Industrial"),
        )
    if any(w in blob for w in ["radio", "signal", "transceiver", "antenna", "comm", "broadcast"]):
        return kit(
            ("Portable Transceiver", 2, "Military", "Police"),
            ("Battery 9V", 4, "Residential", "Police"),
            ("Cassette Tape", 1, "Residential"),
            ("Duct Tape", 1, "Residential"),
            ("Electrical Repair Kit", 1, "Industrial", "Military"),
            ("Headtorch", 1, "Industrial", "Residential"),
        )
    if any(w in blob for w in ["hunt", "predator", "wolf", "bear", "deer", "boar"]):
        return kit(
            ("Hunting Knife", 1, "Hunting", "Residential"),
            ("Compound Bow", 1, "Hunting"),
            ("Mosin 9130", 1, "Hunting", "Military"),
            ("Mosin Ammo Box", 1, "Hunting", "Military"),
            ("Steak Knife", 1, "Residential"),
            ("Cooking Pot", 1, "Residential"),
            ("Cooking Tripod", 1, "Residential", "Hunting"),
        )
    if any(w in blob for w in ["fish", "angler", "lake", "river"]):
        return kit(
            ("Improvised Fishing Rod", 1, "Coastal", "Residential"),
            ("Bone Hook", 5, "Coastal", "Residential"),
            ("Worm", 4, "Forest", "Farm"),
            ("Long Wooden Stick", 2, "Forest"),
            ("Rope", 2, "Residential"),
            ("Cooking Pot", 1, "Residential"),
        )
    if any(w in blob for w in ["military", "tisy", "nwaf", "armory", "soldier", "convoy"]):
        return kit(
            ("Plate Carrier Vest", 1, "Military"),
            ("Ballistic Helmet", 1, "Military"),
            ("AK-74", 1, "Military"),
            ("AK-74 Magazine", 3, "Military"),
            ("Frag Grenade", 2, "Military"),
            ("Smersh Backpack", 1, "Military"),
            ("Combat Knife", 1, "Military"),
        )
    if any(w in blob for w in ["contraband", "smuggler", "black market", "trade", "courier", "cartel"]):
        return kit(
            ("Cigarette Pack", 10, "Residential"),
            ("Alcohol Tincture", 5, "Hospital", "Residential"),
            ("Vodka", 4, "Residential"),
            ("Spirit Bottle", 3, "Residential"),
            ("Burlap Sack", 2, "Residential"),
            ("Duct Tape", 2, "Residential"),
        )
    if any(w in blob for w in ["scout", "expedition", "explorer", "travel", "loop"]):
        return kit(
            ("Compass", 1, "Hunting", "Military"),
            ("Map (full)", 1, "Residential"),
            ("Canteen", 1, "Residential", "Hunting"),
            ("Cooking Pot", 1, "Residential"),
            ("Matches", 2, "Residential"),
            ("Roadflare", 2, "Industrial", "Residential"),
            ("Hunting Backpack", 1, "Hunting"),
        )

    # --- Fallback by kind (always returns something) ---
    if kind in {"collection", "scavenge", "loot"}:
        return kit(
            ("Canned Beans", 3, "Residential"),
            ("Bandage", 3, "Residential", "Hospital"),
            ("Rope", 2, "Residential", "Hunting"),
            ("Duct Tape", 2, "Residential", "Industrial"),
            ("Canteen", 1, "Residential"),
            ("Hunting Knife", 1, "Hunting", "Residential"),
        )
    if kind in {"crafting", "craft"}:
        return kit(
            ("Long Wooden Stick", 4, "Forest"),
            ("Rope", 2, "Residential"),
            ("Rag", 4, "Residential"),
            ("Bone Hook", 2, "Coastal", "Hunting"),
            ("Sharpening Stone", 1, "Industrial", "Residential"),
            ("Improvised Knife", 1, "Forest"),
        )
    if kind in {"survival"}:
        return kit(
            ("Canteen", 1, "Residential"),
            ("Matches", 2, "Residential"),
            ("Cooking Pot", 1, "Residential"),
            ("Bandage", 4, "Residential", "Hospital"),
            ("Hunting Knife", 1, "Hunting", "Residential"),
            ("Sewing Kit", 1, "Residential"),
        )
    # Last-ditch fallback so the embed never looks empty.
    return kit(
        ("Bandage", 3, "Residential"),
        ("Rope", 2, "Residential"),
        ("Duct Tape", 2, "Residential"),
        ("Canteen", 1, "Residential"),
    )


def enrich_quest_with_defaults(challenge):
    """If the quest dict has no structured items_needed, inject a sensible
    default kit so even legacy bank quests look meaty. Idempotent.
    Returns the (possibly-mutated) challenge dict for chaining."""
    if not isinstance(challenge, dict):
        return challenge
    existing = challenge.get("items_needed") or []
    has_structured = any(isinstance(it, dict) and (it.get("item") or it.get("name")) for it in existing) if isinstance(existing, list) else False
    if not has_structured:
        challenge["items_needed"] = default_items_for_quest(challenge)
    return challenge


async def open_pve_quest_ticket(interaction, challenge):
    """Create a private channel for a player to start a quest. Only the
    player, admins, and the bot can see it. The quest itself becomes
    locked to this player — no one else can ticket it.

    Returns the created channel or None on failure (with the interaction
    already informed)."""
    guild = interaction.guild
    member = interaction.user
    if not guild or not isinstance(member, discord.Member):
        await interaction.response.send_message(
            "Tickets can only be opened inside a server.", ephemeral=True
        )
        return None

    guild_id = str(guild.id)
    config = guild_configs.setdefault(guild_id, {
        "guild_name": guild.name,
        "admin_roles": DEFAULT_ADMIN_ROLES.copy(),
        "channels": {}
    })

    # 🔒 Quest-locking guard: refuse if another survivor already claimed it.
    if is_quest_claimed(challenge) and str(challenge.get("claimed_by_player_id")) != str(member.id):
        existing_id = challenge.get("claimed_by_player_id")
        existing_label = f"<@{existing_id}>"
        await interaction.response.send_message(
            f"🔒 This quest is already claimed by {existing_label}. "
            "One survivor per quest. Wait for it to be completed/released, "
            "or pick a different one.",
            ephemeral=True,
        )
        return None

    category = await get_or_create_pve_ticket_category(guild, config)

    quest_code = pve_quest_code(challenge)
    ticket_number = next_quest_ticket_number(guild_id)
    member_slug = re.sub(r"[^a-z0-9]+", "-", str(member.display_name).lower()).strip("-")[:18] or "survivor"
    title_words = re.sub(r"[^a-z0-9\s]+", "", str(challenge.get("title", "")).lower()).split()
    quest_slug = "-".join(title_words[:3])[:24] or quest_code.lower()
    # Channel name matches the requested pattern: `<n>-<player>-<questslug>`
    channel_name = f"{ticket_number}-{member_slug}-{quest_slug}"[:95]

    overwrites = {
        guild.default_role: discord.PermissionOverwrite(read_messages=False),
        member: discord.PermissionOverwrite(read_messages=True, send_messages=True, attach_files=True, embed_links=True),
        guild.me: discord.PermissionOverwrite(read_messages=True, send_messages=True, manage_channels=True, embed_links=True),
    }
    # Grant access to anyone with the configured admin roles or the
    # built-in administrator permission.
    admin_role_names = {str(r).lower() for r in config.get("admin_roles", DEFAULT_ADMIN_ROLES)}
    for role in guild.roles:
        if role.permissions.administrator or role.name.lower() in admin_role_names:
            overwrites[role] = discord.PermissionOverwrite(
                read_messages=True, send_messages=True, manage_messages=True, embed_links=True
            )

    try:
        ticket_channel = await guild.create_text_channel(
            channel_name,
            category=category,
            overwrites=overwrites,
            topic=(
                f"Ticket #{ticket_number} – Type: 📨 Start Quest – "
                f"Player: {member} – Quest: {quest_code} {challenge.get('title', '')}"
            )[:1024],
        )
    except discord.Forbidden:
        await interaction.response.send_message(
            "I don't have permission to create ticket channels. Ask an admin to give me **Manage Channels**.",
            ephemeral=True
        )
        return None
    except Exception as err:
        print(f"[PVE TICKET] create_text_channel failed: {err}")
        await interaction.response.send_message(
            f"Could not open ticket: `{err}`", ephemeral=True
        )
        return None

    # 🔒 Lock the quest to this player BEFORE posting the intro so any
    # racing click from another player on the same embed bounces off.
    mark_quest_claimed(
        challenge,
        player_id=member.id,
        ticket_channel_id=ticket_channel.id,
        ticket_number=ticket_number,
    )

    # 🎟️ Campaign chain binding: if this quest belongs to a campaign,
    # bind the WHOLE campaign to this ticket channel so every
    # subsequent part of the story posts here, not in public.
    campaign_id_for_binding = (
        challenge.get("campaign_id")
        or challenge.get("ai_campaign_id")
    )
    if campaign_id_for_binding:
        try:
            gid_str = str(guild.id)
            campaign_block = pve_ai_campaigns.setdefault(gid_str, {})
            campaign = campaign_block.get(campaign_id_for_binding)
            if campaign:
                # Only bind if no one else has already claimed the
                # campaign chain (defence against simultaneous tickets
                # on two different quests of the same campaign).
                existing_bound = campaign.get("bound_player_id")
                if not existing_bound or str(existing_bound) == str(member.id):
                    campaign["bound_ticket_channel_id"] = ticket_channel.id
                    campaign["bound_player_id"] = member.id
                    campaign["bound_at"] = datetime.now(UTC).isoformat()
                    save_pve_ai_campaigns()
        except Exception as err:
            print(f"[PVE TICKET] campaign bind failed: {err}")

    # Auto-enrich legacy bank quests with a default items_needed kit so
    # the player always sees a meaty multi-item briefing inside the ticket.
    try:
        enrich_quest_with_defaults(challenge)
        save_pve_challenges()
    except Exception:
        pass

    welcome = discord.Embed(
        title=f"Welcome to #{channel_name}!",
        description=(
            f"This is the start of the **#{channel_name}** private channel.\n"
            f"**Ticket #{ticket_number}** – Type: 📨 **Start Quest** – "
            f"Created by: {member.mention}\n\n"
            f"**Quest:** `{quest_code}` — {challenge.get('title', 'PVE Quest')}\n"
            f"_{challenge.get('summary', '')[:400]}_"
        ),
        color=0xE67E22,
    )
    welcome.set_footer(text="Wandering Bot Alpha — Quest Ticket System")
    try:
        await ticket_channel.send(content=f"{member.mention}", embed=style_embed(welcome))
    except Exception as err:
        print(f"[PVE TICKET] failed to send welcome: {err}")

    intro = discord.Embed(
        title=f"🎟️ Quest Ticket — {challenge.get('title', 'PVE Quest')}",
        description=(
            f"Your ticket has been created in the Created Channel.\n"
            f"Please provide any additional info you deem relevant to help us answer faster.\n\n"
            f"**Next steps:**\n"
            f"1. Discuss the quest with the admin who claims this ticket.\n"
            f"2. The admin will assign you the right role / share hidden quest info if needed.\n"
            f"3. Submit screenshots, clips, or a written summary of progress.\n"
            f"4. Once done, the admin runs "
            f"`/pvecomplete quest_id:{quest_code} member:@you` and rewards land here."
        ),
        color=0xE67E22
    )
    intro.add_field(name="Quest ID", value=f"`{quest_code}`", inline=True)
    intro.add_field(name="Type", value=challenge.get("kind", "PVE"), inline=True)
    intro.add_field(name="Difficulty", value=challenge.get("difficulty", "Medium"), inline=True)
    if challenge.get("quest_line"):
        intro.add_field(name="Quest Line", value=challenge["quest_line"], inline=False)
    intro.add_field(name="🎯 Objective", value=str(challenge.get("goal", "—"))[:1024], inline=False)

    # Surface the FULL items list inside the ticket — this is the player's
    # private briefing channel, they shouldn't have to hop back to the
    # public feed to see what they're collecting.
    items_needed = challenge.get("items_needed") or []
    if items_needed:
        rendered_items = []
        for it in items_needed[:10]:
            line = format_quest_item_line(it) if isinstance(it, dict) else f"• {str(it)[:80]}"
            if line:
                rendered_items.append(line)
        if rendered_items:
            intro.add_field(
                name="📦 Required Items",
                value="\n".join(rendered_items)[:1024],
                inline=False,
            )

    delivery_target = (challenge.get("delivery_target") or "").strip()
    if delivery_target:
        intro.add_field(name="📍 Delivery / Drop-off", value=delivery_target[:1024], inline=False)

    rules = challenge.get("rules") or []
    if rules:
        intro.add_field(
            name="📜 Rules",
            value="\n".join(f"• {r}" for r in rules[:6])[:1024],
            inline=False,
        )

    risk_factor = challenge.get("risk_factor") or []
    if risk_factor:
        intro.add_field(
            name="⚠️ Risk Factor",
            value="\n".join(f"• {r}" for r in risk_factor[:5])[:1024],
            inline=False,
        )

    pvp_zone = (challenge.get("pvp_zone") or "").strip()
    if pvp_zone:
        intro.add_field(name="⚔️ PvP Zone", value=pvp_zone[:1024], inline=False)

    intro.add_field(name="💰 Reward", value=str(challenge.get("reward", "—"))[:1024], inline=False)
    intro.set_footer(text="Wandering Bot Alpha — PVE Ticket System")

    control_view = QuestTicketControlView(
        quest_code=quest_code,
        ticket_channel_id=ticket_channel.id,
        player_id=member.id,
    )

    try:
        intro_msg = await ticket_channel.send(embed=style_embed(intro), view=control_view)
        try:
            await intro_msg.pin(reason="Quest ticket controls")
        except Exception:
            pass
    except Exception as err:
        print(f"[PVE TICKET] failed to send intro: {err}")

    # 🔁 Edit the public quest embed(s) to show 🔒 CLAIMED + disable Start button.
    try:
        await update_public_quest_posts_with_claim(guild, challenge)
    except Exception as err:
        print(f"[PVE TICKET] could not update public embed: {err}")

    await interaction.response.send_message(
        f"🎟️ Ticket opened: {ticket_channel.mention}. The quest is now locked to you.",
        ephemeral=True
    )
    return ticket_channel


class PVEQuestCompletionView(discord.ui.View):
    """View attached to every newly posted PVE quest. The "Open Ticket /
    Start Quest" button creates a private channel for the clicking
    player so they can chat with admins, get the quest role, and
    receive rewards there. The quest is locked to that player — no one
    else can ticket the same quest.

    `timeout=None` makes the view persistent across bot restarts as long
    as the bot re-registers it on startup (handled at the end of the
    file).
    """

    def __init__(self, quest_code: str, *, disabled: bool = False):
        super().__init__(timeout=None)
        # custom_id encodes the quest code so the bot can find the challenge
        # when the button is pressed days after the embed was posted.
        button = discord.ui.Button(
            label="Open Ticket / Start Quest",
            style=discord.ButtonStyle.success,
            emoji="🎯",
            custom_id=f"pve_submit:{quest_code}",
            disabled=disabled,
        )
        self.add_item(button)


class QuestTicketControlView(discord.ui.View):
    """View pinned inside each quest ticket channel. Gives admins the
    Claim / Close / Reopen / Delete controls (matching the user-supplied
    reference screenshots). All buttons use stable custom_ids so the view
    survives bot restarts."""

    def __init__(self, *, quest_code: str, ticket_channel_id: int, player_id: int):
        super().__init__(timeout=None)
        suffix = f"{quest_code}:{ticket_channel_id}:{player_id}"
        self.add_item(discord.ui.Button(
            label="Claim", style=discord.ButtonStyle.primary, emoji="🎫",
            custom_id=f"pve_ticket_claim:{suffix}",
        ))
        self.add_item(discord.ui.Button(
            label="Close", style=discord.ButtonStyle.secondary, emoji="🔒",
            custom_id=f"pve_ticket_close:{suffix}",
        ))
        self.add_item(discord.ui.Button(
            label="Reopen", style=discord.ButtonStyle.success, emoji="🔓",
            custom_id=f"pve_ticket_reopen:{suffix}",
        ))
        self.add_item(discord.ui.Button(
            label="Delete", style=discord.ButtonStyle.danger, emoji="🗑️",
            custom_id=f"pve_ticket_delete:{suffix}",
        ))


def _member_is_pve_ticket_admin(member, config):
    """True if `member` may use Claim/Close/Reopen/Delete buttons. Falls
    back to the same admin-role set used for permission overwrites in
    open_pve_quest_ticket."""
    if not isinstance(member, discord.Member):
        return False
    if member.guild_permissions.administrator or member.guild_permissions.manage_channels:
        return True
    admin_role_names = {str(r).lower() for r in (config.get("admin_roles") or DEFAULT_ADMIN_ROLES)}
    for role in getattr(member, "roles", []):
        if role.name.lower() in admin_role_names:
            return True
    return False


def _find_challenge_by_ticket_channel(guild_id, ticket_channel_id):
    """Reverse-lookup a PVE challenge from a ticket channel id so we can
    release the quest claim when an admin deletes the ticket."""
    target = int(ticket_channel_id)
    for challenge in pve_challenges.get(str(guild_id), []):
        if int(challenge.get("claimed_ticket_channel_id") or 0) == target:
            return challenge
    return None


async def _handle_pve_ticket_claim(interaction, suffix):
    quest_code, ticket_channel_id, player_id = suffix.split(":", 2)
    config = guild_configs.setdefault(str(interaction.guild.id), {"channels": {}, "admin_roles": DEFAULT_ADMIN_ROLES.copy()})
    if not _member_is_pve_ticket_admin(interaction.user, config):
        await interaction.response.send_message("Only admins can claim tickets.", ephemeral=True)
        return
    await interaction.response.send_message(
        f"{interaction.user.mention} claimed the ticket.",
        allowed_mentions=discord.AllowedMentions.none() if False else None,
    )


async def _handle_pve_ticket_close(interaction, suffix):
    quest_code, ticket_channel_id, player_id = suffix.split(":", 2)
    config = guild_configs.setdefault(str(interaction.guild.id), {"channels": {}, "admin_roles": DEFAULT_ADMIN_ROLES.copy()})
    if not _member_is_pve_ticket_admin(interaction.user, config):
        await interaction.response.send_message("Only admins can close tickets.", ephemeral=True)
        return
    channel = interaction.channel
    try:
        # Revoke the ticket player's read access; admin overwrites remain.
        try:
            target_member = interaction.guild.get_member(int(player_id))
            if target_member:
                await channel.set_permissions(target_member, read_messages=False, reason="Ticket closed")
        except Exception:
            pass
        await interaction.response.send_message(
            f"🔒 Ticket closed by {interaction.user.mention}. Player can no longer view this channel — admins can Reopen.",
        )
    except Exception as err:
        await interaction.response.send_message(f"Could not close ticket: `{err}`", ephemeral=True)


async def _handle_pve_ticket_reopen(interaction, suffix):
    quest_code, ticket_channel_id, player_id = suffix.split(":", 2)
    config = guild_configs.setdefault(str(interaction.guild.id), {"channels": {}, "admin_roles": DEFAULT_ADMIN_ROLES.copy()})
    if not _member_is_pve_ticket_admin(interaction.user, config):
        await interaction.response.send_message("Only admins can reopen tickets.", ephemeral=True)
        return
    channel = interaction.channel
    try:
        target_member = interaction.guild.get_member(int(player_id))
        if target_member:
            await channel.set_permissions(
                target_member,
                read_messages=True, send_messages=True, attach_files=True, embed_links=True,
                reason="Ticket reopened",
            )
        await interaction.response.send_message(
            f"🔓 Ticket reopened by {interaction.user.mention}. Player can post again."
        )
    except Exception as err:
        await interaction.response.send_message(f"Could not reopen ticket: `{err}`", ephemeral=True)


async def _handle_pve_ticket_delete(interaction, suffix):
    quest_code, ticket_channel_id, player_id = suffix.split(":", 2)
    guild_id = str(interaction.guild.id)
    config = guild_configs.setdefault(guild_id, {"channels": {}, "admin_roles": DEFAULT_ADMIN_ROLES.copy()})
    if not _member_is_pve_ticket_admin(interaction.user, config):
        await interaction.response.send_message("Only admins can delete tickets.", ephemeral=True)
        return
    # Release the quest claim so another survivor can ticket it.
    challenge = find_active_pve_quest_by_code(guild_id, quest_code) or _find_challenge_by_ticket_channel(guild_id, ticket_channel_id)
    if challenge:
        release_quest_claim(challenge)
        try:
            await update_public_quest_posts_with_claim(interaction.guild, challenge)  # safe no-op if not claimed
        except Exception:
            pass
    await interaction.response.send_message(
        f"🗑️ {interaction.user.mention} deleted the ticket. Quest released — others may pick it up. "
        "Channel will be removed in a few seconds…"
    )
    try:
        # Give Discord a moment to deliver the response message before we
        # nuke the channel.
        await asyncio.sleep(3)
        await interaction.channel.delete(reason=f"PVE quest ticket deleted by {interaction.user}")
    except Exception as err:
        print(f"[PVE TICKET] delete failed: {err}")


async def _handle_pve_submit_button(interaction: discord.Interaction, quest_code: str):
    """Called from the bot's interaction listener when a player clicks the
    Submit Completion button on a quest embed."""
    if not interaction.guild:
        await interaction.response.send_message("Use this inside a server.", ephemeral=True)
        return
    guild_id = str(interaction.guild.id)
    challenge = find_active_pve_quest_by_code(guild_id, quest_code)
    if not challenge:
        await interaction.response.send_message(
            "This quest is no longer active. Wait for a new one to be posted.",
            ephemeral=True
        )
        return
    await open_pve_quest_ticket(interaction, challenge)


async def post_pve_challenge(guild_id, config, *, manual=False):
    if not server_allows_pve(config):
        return False, "PVE is disabled for this server mode"

    guild = bot.get_guild(int(guild_id)) if str(guild_id).isdigit() else None
    if not guild:
        return False, "Guild not found"

    channels = config.setdefault("channels", {})
    quest_channel = bot.get_channel(channels.get("pve_quests"))
    if not quest_channel:
        if is_channel_key_disabled(config, "pve_quests"):
            return False, "PVE quest channel was deleted by an owner. Run `/pvesetup` or restore the PVE channel pack to recreate it."
        created = await ensure_pve_channels(guild, config)
        quest_channel = created.get("pve_quests")

    if not quest_channel:
        return False, "PVE quest channel missing"

    challenge = generate_pve_challenge(guild_id=guild_id)
    # Auto-enrich legacy bank quests with a structured item kit so the
    # public embed always shows a meaty multi-item collection list.
    enrich_quest_with_defaults(challenge)
    guild_challenges = pve_challenges.setdefault(str(guild_id), [])
    guild_challenges.append(challenge)
    pve_challenges[str(guild_id)] = guild_challenges[-25:]
    save_pve_challenges()

    embed = discord.Embed(
        title=f"🌲 PVE QUEST: {challenge['title']}",
        color=0x2ECC71
    )
    embed.add_field(name="Type", value=challenge["kind"], inline=True)
    embed.add_field(name="Quest ID", value=f"`{pve_quest_code(challenge)}`", inline=True)
    embed.add_field(name="Difficulty", value=challenge.get("difficulty", "Medium"), inline=True)
    embed.add_field(name="Status", value="Manual Post" if manual else "Auto Generated", inline=False)
    embed.add_field(name="🎯 Objective", value=challenge["goal"], inline=False)

    # 📦 Show the structured items list right under the objective.
    bank_items = challenge.get("items_needed") or []
    if bank_items:
        rendered = []
        for it in bank_items[:10]:
            line = format_quest_item_line(it) if isinstance(it, dict) else f"• {str(it)[:80]}"
            if line:
                rendered.append(line)
        if rendered:
            embed.add_field(name="📦 Required Items", value="\n".join(rendered)[:1024], inline=False)

    embed.add_field(name="💰 Reward", value=challenge["reward"], inline=False)
    if challenge.get("target_event"):
        embed.add_field(
            name="Auto Tracking",
            value=f"ADM tracked: `{challenge['target_event']}` events, target `{challenge.get('target_count', 0)}`.",
            inline=False
        )
    else:
        embed.add_field(
            name="🎯 How To Start",
            value=(
                "Click **🎯 Open Ticket / Start Quest** below — the bot will spin up a "
                "private channel just for you and the admins. Discuss the quest there, "
                "submit proof, and rewards drop in your ticket. Admin runs "
                f"`/pvecomplete quest_id:{pve_quest_code(challenge)} member:@you` once done."
            ),
            inline=False
        )
    if challenge.get("quest_line"):
        embed.add_field(name="Quest Line", value=challenge["quest_line"], inline=True)
    embed.add_field(name="💡 Survival Tip", value=challenge["tips"], inline=False)
    embed.set_thumbnail(url=BOT_IMAGE)
    embed.set_footer(text="Wandering Bot Alpha - PVE Mission Board")

    sent_main = await quest_channel.send(embed=style_embed(embed), view=PVEQuestCompletionView(pve_quest_code(challenge)))
    try:
        remember_quest_post_message(challenge, quest_channel.id, sent_main.id)
    except Exception:
        pass

    themed_channel_key = pve_themed_channel_key(challenge)

    if themed_channel_key:
        themed_channel = bot.get_channel(channels.get(themed_channel_key))
        if themed_channel and themed_channel.id != quest_channel.id:
            themed_embed = discord.Embed.from_dict(embed.to_dict())
            sent_themed = await themed_channel.send(embed=style_embed(themed_embed), view=PVEQuestCompletionView(pve_quest_code(challenge)))
            try:
                remember_quest_post_message(challenge, themed_channel.id, sent_themed.id)
            except Exception:
                pass

    return True, challenge["title"]


async def post_pve_themed_challenge(guild_id, config, kind, *, manual=False, difficulty=None):
    if not server_allows_pve(config):
        return False, "PVE is disabled for this server mode"

    guild = bot.get_guild(int(guild_id)) if str(guild_id).isdigit() else None
    if not guild:
        return False, "Guild not found"

    channel_key = pve_channel_for_kind(kind)
    if not channel_key:
        return False, f"No themed PVE channel for {kind}"
    if is_channel_key_disabled(config, channel_key):
        return False, f"PVE channel `{channel_key}` was deleted by an owner. Run `/pvesetup` or restore the PVE channel pack to recreate it."

    difficulty = str(difficulty or random.choice(PVE_SLOT_DIFFICULTIES)).title()

    if not manual and pve_active_quest_for_channel(guild_id, channel_key, difficulty):
        return False, f"Active {difficulty} {kind} quest already exists"

    channels = config.setdefault("channels", {})
    if not channels.get(channel_key):
        await ensure_pve_channels(guild, config)

    challenge = generate_pve_challenge(kind, difficulty, guild_id=guild_id)
    challenge["channel_key"] = channel_key
    challenge["slot_difficulty"] = difficulty
    # Auto-enrich legacy themed bank quests with a structured item kit.
    enrich_quest_with_defaults(challenge)
    channel = bot.get_channel(channels.get(channel_key))
    if not channel:
        return False, "PVE channel missing"

    guild_challenges = pve_challenges.setdefault(str(guild_id), [])
    guild_challenges.append(challenge)
    pve_challenges[str(guild_id)] = guild_challenges[-50:]
    save_pve_challenges()

    quest_code = pve_quest_code(challenge)

    embed = discord.Embed(
        title=f"{challenge['kind'].upper()} QUEST [{quest_code}]: {challenge['title']}",
        color=0x2ECC71
    )
    embed.add_field(name="🆔 Quest ID", value=f"`{quest_code}`", inline=True)
    embed.add_field(name="Quest Slot", value=channel.mention, inline=True)
    embed.add_field(name="Difficulty", value=challenge.get("difficulty", "Medium"), inline=True)
    embed.add_field(name="🎯 Objective", value=challenge["goal"], inline=False)

    # 📦 Always surface a meaty structured item list under the objective.
    themed_items = challenge.get("items_needed") or []
    if themed_items:
        rendered = []
        for it in themed_items[:10]:
            line = format_quest_item_line(it) if isinstance(it, dict) else f"• {str(it)[:80]}"
            if line:
                rendered.append(line)
        if rendered:
            embed.add_field(name="📦 Required Items", value="\n".join(rendered)[:1024], inline=False)

    embed.add_field(name="💰 Reward", value=challenge["reward"], inline=False)
    embed.add_field(
        name="🎯 How To Start",
        value=(
            "Click **🎯 Open Ticket / Start Quest** below — the bot will spin up a "
            "private channel just for you and the admins. Discuss the quest there, "
            "submit proof, and rewards drop in your ticket. Admin runs "
            f"`/pvecomplete quest_id:{quest_code} member:@you` once done."
        ),
        inline=False
    )
    embed.add_field(name="💡 Survival Tip", value=challenge["tips"], inline=False)
    embed.set_thumbnail(url=BOT_IMAGE)
    embed.set_footer(text=f"Wandering Bot Alpha - Channel PVE Quest Feed - {quest_code}")
    sent_themed_msg = await channel.send(embed=style_embed(embed), view=PVEQuestCompletionView(quest_code))
    try:
        remember_quest_post_message(challenge, channel.id, sent_themed_msg.id)
    except Exception:
        pass
    return True, challenge["title"]


async def post_pve_daily_pack(guild_id, config):
    posted = []
    for kind in PVE_THEMED_QUEST_KINDS.values():
        for difficulty in PVE_SLOT_DIFFICULTIES:
            success, title = await post_pve_themed_challenge(guild_id, config, kind, difficulty=difficulty)
            if success:
                posted.append(title)
    return posted


async def ensure_pve_channel_quests(guild_id, config):
    if not server_allows_pve(config):
        return []

    posted = []
    for kind in PVE_THEMED_QUEST_KINDS.values():
        for difficulty in PVE_SLOT_DIFFICULTIES:
            success, title = await post_pve_themed_challenge(guild_id, config, kind, difficulty=difficulty)
            if success:
                posted.append(title)
    return posted


async def send_pve_completion_feed(guild_id, config, player_name, challenge, reward_status):
    channels = config.get("channels", {})
    quest_channel = bot.get_channel(channels.get("pve_quests"))
    themed_channel = bot.get_channel(channels.get(pve_themed_channel_key(challenge)))

    embed = discord.Embed(
        title="🏕️ PVE QUEST COMPLETE",
        description=f"**{player_name}** completed **{challenge.get('title')}**.",
        color=0xF1C40F
    )
    embed.add_field(name="Quest ID", value=f"`{pve_quest_code(challenge)}`", inline=True)
    embed.add_field(name="Type", value=challenge.get("kind", "PVE"), inline=True)
    embed.add_field(name="Difficulty", value=challenge.get("difficulty", "Medium"), inline=True)
    embed.add_field(name="Reward", value=reward_status, inline=False)
    if challenge.get("quest_line"):
        embed.add_field(name="Quest Line", value=challenge["quest_line"], inline=True)
    embed.set_thumbnail(url=BOT_IMAGE)
    embed.set_footer(text="Wandering Bot Alpha - PVE Rewards")

    sent = False
    for channel in [quest_channel, themed_channel]:
        if channel and (not sent or channel.id != quest_channel.id):
            await channel.send(embed=style_embed(discord.Embed.from_dict(embed.to_dict())))
            sent = True


async def process_pve_progress_from_adm(guild_id, config, event_type, line):
    guild_quests = pve_challenges.get(str(guild_id), [])
    if not guild_quests:
        return

    player_name = extract_player_name(line)
    if not player_name or player_name == "Unknown":
        return

    changed = False

    for challenge in guild_quests:
        if challenge.get("status") != "active":
            continue

        target_event = challenge.get("target_event")
        if not target_event or target_event != event_type:
            continue

        target_count = int(challenge.get("target_count", 0) or 0)
        if target_count <= 0:
            continue

        progress = challenge.setdefault("progress", {})
        progress[player_name] = int(progress.get(player_name, 0)) + 1
        changed = True

        if progress[player_name] >= target_count:
            challenge["status"] = "completed"
            challenge["completed_by"] = player_name
            challenge["completed"] = str(datetime.now(UTC))
            paid, reward_status = award_pve_pennies(guild_id, player_name, challenge)
            if not paid:
                reward_status = f"{challenge.get('reward_pennies', 0)} pennies pending. Survivor must link gamertag with `/linkgamer`."
            else:
                guild = bot.get_guild(int(guild_id)) if str(guild_id).isdigit() else None
                if guild:
                    await send_money_feed(
                        guild,
                        config,
                        "PVE REWARD PAID",
                        f"**{int(challenge.get('reward_pennies', 0) or 0)} pennies** paid for completing `{challenge.get('title', 'PVE quest')}`.",
                        [
                            {"name": "Survivor", "value": player_name, "inline": True},
                            {"name": "Quest", "value": challenge.get("title", "PVE quest"), "inline": True},
                            {"name": "Amount", "value": f"{int(challenge.get('reward_pennies', 0) or 0)} pennies", "inline": True},
                        ],
                        color=0x27AE60,
                        footer="Money Feed - PVE Rewards",
                    )
            await send_pve_completion_feed(guild_id, config, player_name, challenge, reward_status)
            channel_key = challenge.get("channel_key") or pve_themed_channel_key(challenge)
            next_kind = PVE_THEMED_QUEST_KINDS.get(channel_key)
            if next_kind:
                await post_pve_themed_challenge(
                    guild_id,
                    config,
                    next_kind,
                    manual=True,
                    difficulty=challenge.get("slot_difficulty") or challenge.get("difficulty")
                )

    if changed:
        save_pve_challenges()


