# =========================================================


async def purge_self_dashboard_messages(channel, limit=10):
    """Delete recent bot-authored messages in a dashboard-style channel.

    Used at the top of dashboard refresh loops (online, heatmap, pve_heatmap,
    leaderboards, restart_alerts) so orphan messages from previous bot
    sessions or stale in-memory `last_*_message_ids` state get cleaned up
    before a new dashboard message is posted.

    Idempotent — safe to call before every post. Tries the fast bulk-purge
    API first, falls back to manual per-message deletion if the bot lacks
    the Manage Messages permission.
    """
    if not channel:
        return
    try:
        # Fast path: requires Manage Messages permission. Bulk-deletes up to
        # `limit` of the most recent bot messages in one API call.
        await channel.purge(limit=limit, check=lambda m: m.author == bot.user)
        return
    except Exception:
        pass
    # Fallback: iterate history and delete one at a time. Works without
    # Manage Messages, but only for messages younger than 14 days.
    try:
        async for old_msg in channel.history(limit=limit):
            if old_msg.author == bot.user:
                try:
                    await old_msg.delete()
                except Exception:
                    pass
    except Exception:
        pass


def build_online_dashboard_embed(guild_id, reason=""):
    ensure_guild_runtime(guild_id)
    guild_online = online_players[guild_id]
    player_text = "\n".join(
        f"🟢 {player}"
        for player in sorted(guild_online)
    ) if guild_online else "No survivors online."

    embed = discord.Embed(
        title=f"✅🎮 LIVE SURVIVORS ONLINE 🎮✅ ({len(guild_online)})",
        description=player_text,
        color=0x2ECC71
    )
    embed.set_thumbnail(url=BOT_IMAGE)
    footer = "Wandering Bot Alpha - Live online display"
    if reason:
        footer = f"{footer} - {reason}"
    embed.set_footer(text=footer)
    embed.timestamp = datetime.now(UTC)
    return embed


def build_online_dashboard_embed(guild_id, reason=""):
    ensure_guild_runtime(guild_id)
    guild_online = sorted(online_players[guild_id])
    online_count = len(guild_online)
    guild_name = str(guild_configs.get(str(guild_id), {}).get("guild_name") or guild_display_name(guild_id))
    now = datetime.now(UTC)

    if online_count >= 20:
        colour = 0xE67E22
        mood = "High Pop"
        pulse = "██████████"
    elif online_count >= 10:
        colour = 0xF1C40F
        mood = "Busy"
        pulse = "███████░░░"
    elif online_count > 0:
        colour = 0x2ECC71
        mood = "Active"
        pulse = "████░░░░░░"
    else:
        colour = 0x5865F2
        mood = "Quiet"
        pulse = "░░░░░░░░░░"

    embed = discord.Embed(
        title="LIVE SURVIVOR BOARD",
        description=(
            f"**{guild_name}**\n"
            f"`{pulse}`  **{online_count} survivor{'s' if online_count != 1 else ''} online**\n"
            f"Status: **{mood}**"
        ),
        color=colour,
    )
    embed.add_field(name="Server", value=guild_name[:1024], inline=True)
    embed.add_field(name="Online", value=f"**{online_count}**", inline=True)
    embed.add_field(name="Last Change", value=str(reason or "Safety refresh")[:1024], inline=True)

    if guild_online:
        shown = guild_online[:24]
        midpoint = (len(shown) + 1) // 2
        left = shown[:midpoint]
        right = shown[midpoint:]
        embed.add_field(
            name="Survivors",
            value="\n".join(f"`{index + 1:02}` {player}" for index, player in enumerate(left))[:1024],
            inline=True,
        )
        if right:
            embed.add_field(
                name="Survivors",
                value="\n".join(f"`{index + midpoint + 1:02}` {player}" for index, player in enumerate(right))[:1024],
                inline=True,
            )
        if online_count > len(shown):
            embed.add_field(
                name="More Online",
                value=f"`{online_count - len(shown)}` more survivor(s) are online. Use `/online` for the full roster.",
                inline=False,
            )
    else:
        embed.add_field(
            name="No Survivors Online",
            value="The server is quiet. The board will update the moment someone connects.",
            inline=False,
        )

    embed.set_thumbnail(url=BOT_IMAGE)
    embed.set_footer(text="Wandering Bot Alpha - one live message, updated on join/leave")
    embed.timestamp = now
    return embed


def build_online_dashboard_view(guild_id, config):
    view = discord.ui.View(timeout=None)
    # Do not expose guild_id in public Discord link buttons. The dashboard
    # still gates all server data behind the private dashboard login.
    view.add_item(
        discord.ui.Button(
            label="Open Dashboard",
            style=discord.ButtonStyle.link,
            url=f"{DASHBOARD_PUBLIC_URL.rstrip('/')}/admin",
        )
    )
    return view


async def find_existing_online_dashboard_message(channel):
    try:
        async for old_msg in channel.history(limit=20):
            if old_msg.author != bot.user or not old_msg.embeds:
                continue
            title = str(getattr(old_msg.embeds[0], "title", "") or "")
            if "LIVE SURVIVORS ONLINE" in title or "ONLINE SURVIVORS" in title:
                return old_msg
    except Exception:
        pass
    return None


async def upsert_online_dashboard_message(guild_id, config, reason="", force=False):
    channels = config.get("channels", {})
    online_channel = bot.get_channel(channels.get("online"))
    if not online_channel:
        return

    ensure_guild_runtime(guild_id)
    snapshot = tuple(sorted(online_players[guild_id]))
    if not force and last_online_dashboard_snapshots.get(guild_id) == snapshot:
        return

    embed = build_online_dashboard_embed(guild_id, reason)
    view = build_online_dashboard_view(guild_id, config)
    message_id = last_online_message_ids.get(guild_id) or config.get("online_dashboard_message_id")
    message = None

    if message_id:
        try:
            message = await online_channel.fetch_message(int(message_id))
        except Exception:
            message = None

    if message is None:
        message = await find_existing_online_dashboard_message(online_channel)

    if message is not None:
        try:
            await message.edit(embed=embed, view=view)
            last_online_message_ids[guild_id] = message.id
            config["online_dashboard_message_id"] = message.id
            last_online_dashboard_snapshots[guild_id] = snapshot
            save_guild_configs()
            return
        except Exception:
            pass

    await purge_self_dashboard_messages(online_channel, limit=10)
    sent_message = await online_channel.send(embed=embed, view=view)
    last_online_message_ids[guild_id] = sent_message.id
    config["online_dashboard_message_id"] = sent_message.id
    last_online_dashboard_snapshots[guild_id] = snapshot
    save_guild_configs()


@tasks.loop(minutes=ONLINE_UPDATE_MINUTES)
async def online_dashboard_loop():

    for guild_id, config in active_guild_config_items():

        try:
            await upsert_online_dashboard_message(guild_id, config, "15 min safety refresh", force=False)
            continue

            channels = config.get("channels", {})

            online_channel = bot.get_channel(
                channels.get("online")
            )

            if not online_channel:
                continue

            ensure_guild_runtime(guild_id)

            guild_online = online_players[guild_id]

            if guild_online:

                player_text = "\n".join([
                    f"🟢 {player}"
                    for player in sorted(guild_online)
                ])

            else:

                player_text = "No survivors online."

            embed = discord.Embed(
                title=f"✅🎮 LIVE SURVIVORS ONLINE 🎮✅ ({len(guild_online)})",
                description=player_text,
                color=0x2ECC71
            )

            embed.set_thumbnail(url=BOT_IMAGE)

            embed.set_footer(
                text="Wandering Bot Alpha - Auto Refresh Every 30 Minutes"
            )

            embed.timestamp = datetime.now(UTC)

            # Defensively purge any stale bot messages in this channel
            # (orphans from previous sessions where the in-memory message
            # ID was lost on bot restart). Then post the fresh dashboard.
            await purge_self_dashboard_messages(online_channel, limit=10)

            sent_message = await online_channel.send(embed=embed)
            last_online_message_ids[guild_id] = sent_message.id

        except Exception as error:
            print(error)

