def normalize_shop_category(value, fallback="General"):
    text = str(value or "").strip()
    if not text:
        return fallback
    compact = re.sub(r"[^a-z0-9]+", "", text.lower())
    lowered = re.sub(r"\s+", " ", text.lower()).strip()
    for key in (lowered, compact):
        if key in SHOP_CATEGORY_ALIASES:
            return SHOP_CATEGORY_ALIASES[key]
    for category in SHOP_CATEGORY_PRESETS:
        if category.lower() == lowered or re.sub(r"[^a-z0-9]+", "", category.lower()) == compact:
            return category
    return text[:40] or fallback


def shop_category_options(existing=None):
    values = list(SHOP_CATEGORY_PRESETS)
    for category in existing or []:
        normalized = normalize_shop_category(category)
        if normalized not in values:
            values.append(normalized)
    return values


def find_types_xml(source_path=None):
    candidates = []

    if source_path:
        source_path = str(source_path).strip().strip('"')
        candidates.append(source_path)

        if not source_path.lower().endswith(".xml"):
            candidates.append(f"{source_path}.xml")

        if os.path.isdir(source_path):
            candidates.append(os.path.join(source_path, "types.xml"))

    candidates.extend(TYPES_XML_CANDIDATES)

    for candidate in candidates:
        if candidate and os.path.exists(candidate):
            return candidate

    search_roots = [
        DATA_ROOT,
        GUILD_DATA_FOLDER,
        os.getcwd(),
        os.path.dirname(os.path.abspath(__file__)),
    ]

    for root in search_roots:
        if not root or not os.path.isdir(root):
            continue

        try:
            for current_root, _, files in os.walk(root):
                for file_name in files:
                    if file_name.lower() == "types.xml":
                        return os.path.join(current_root, file_name)
        except Exception:
            continue

    return None


def guess_shop_category(item_name, xml_category=None, usage=None):
    exact_category = SHOP_CATEGORY_EXACT_OVERRIDES.get(str(item_name or "").strip().lower())
    if exact_category:
        return exact_category

    if xml_category:
        return normalize_shop_category(xml_category)

    lower = item_name.lower()

    if any(word in lower for word in ["animal_", "zmbm_", "zmbf_", "infected"]):
        return "Misc"

    if any(word in lower for word in ["wheel", "hood", "trunk", "door", "battery", "radiator", "sparkplug", "headlight"]):
        return "Vehicle Parts"

    if any(word in lower for word in ["car", "truck", "sedan", "hatchback", "offroad", "ada", "olga", "sarka", "gunter", "humvee", "boat"]):
        return "Vehicles"

    if any(word in lower for word in ["ammo", "mag_", "magazine", "bullet", "cartridge", "shell"]):
        return "Ammunition"

    if any(word in lower for word in ["grenade", "explosive", "mine", "claymore", "ied", "detonator", "plastic_explosive"]):
        return "Explosives"

    if any(word in lower for word in ["rifle", "ak", "m4", "m16", "mosin", "shotgun", "pistol", "magnum", "sks", "svd", "fal", "winchester", "knife", "spear"]):
        return "Weapons"

    if any(word in lower for word in ["jacket", "pants", "boots", "gloves", "helmet", "vest", "backpack", "cap", "armband", "mask", "belt", "holster", "shirt", "shoes"]):
        return "Clothing"

    if any(word in lower for word in ["barrel", "crate", "chest", "case", "container", "drybag", "pouch", "pot", "protectorcase", "sea_chest", "tent"]):
        return "Base Storage"

    if any(word in lower for word in ["nail", "plank", "log", "sheetmetal", "metalwire", "barbedwire", "camo net", "flag_base", "territory", "fence", "watchtower", "generator"]):
        return "Building"

    if any(word in lower for word in ["hammer", "hatchet", "axe", "saw", "shovel", "pickaxe", "wrench", "pliers", "lockpick", "sewingkit", "ducttape", "fishingrod"]):
        return "Tools"

    if any(word in lower for word in ["bandage", "saline", "morphine", "epinephrine", "vitamin", "charcoal", "tetracycline"]):
        return "Medical"

    if any(word in lower for word in ["apple", "beans", "food", "meat", "water", "soda", "zucchini", "seeds", "canteen", "bottle", "rice", "cereal"]):
        return "Food & Drink"

    if usage:
        return normalize_shop_category(usage)

    for category, terms in SHOP_CATEGORY_TERMS:
        if any(term in lower for term in terms):
            return category

    return "General"


def is_shop_sellable_item(item_name, category=""):
    name = str(item_name or "").strip()
    lower = name.lower()
    category_lower = normalize_shop_category(category, "").lower()
    if not name:
        return False
    blocked_prefixes = (
        "animal_",
        "zmb",
        "land_wreck",
        "land_wreck_",
        "land_misc_wreck",
        "wreck_",
        "static_",
    )
    blocked_fragments = (
        "wreck",
        "doors_",
        "door_",
        "hood_",
        "trunk_",
        "wheel_ruined",
        "zombie",
        "infected",
    )
    vehicle_classes = (
        "civilian",
        "civsedan",
        "hatchback",
        "offroadhatchback",
        "sedan",
        "truck",
        "bus",
        "ada",
        "olga",
        "sarka",
        "gunter",
        "humvee",
        "boat",
    )
    if lower.startswith(blocked_prefixes):
        return False
    if any(fragment in lower for fragment in blocked_fragments):
        return False
    if category_lower in {"vehicles", "vehicle", "animals", "infected", "zombies"}:
        return False
    if any(lower.startswith(vehicle) for vehicle in vehicle_classes):
        return False
    return True


def is_shop_item_record(value):
    return isinstance(value, dict) and any(
        key in value
        for key in ("price", "category", "enabled", "daily_limit", "allowed_role_ids", "blocked_user_ids", "type", "bundle_items")
    )


def ensure_curated_shop_backfill(guild_id=None, default_price=100, repair_categories=True):
    target_shop = guild_shop_items(guild_id) if guild_id else shop_items
    try:
        price = int(default_price)
    except Exception:
        price = 100
    if price <= 0:
        price = 100

    added = 0
    repaired = 0
    for item_name, category in CURATED_SHOP_BACKFILL_ITEMS.items():
        if not is_shop_sellable_item(item_name, category):
            continue
        existing = target_shop.get(item_name)
        if not is_shop_item_record(existing):
            target_shop[item_name] = {
                "price": price,
                "category": category,
                "enabled": True,
            }
            added += 1
            continue

        if repair_categories:
            current_category = normalize_shop_category(existing.get("category") or "")
            if current_category != category:
                existing["category"] = category
                repaired += 1

    if added or repaired:
        save_shop()
    return added, repaired


def update_shop_prices_bulk(guild_id, price, category="", name_contains="", enabled=None):
    items = guild_shop_items(guild_id)
    try:
        price = int(price)
    except Exception:
        raise ValueError("Price must be a whole number.")
    if price < 0:
        raise ValueError("Price cannot be negative.")

    raw_category = str(category or "").strip()
    category_filter = ""
    if raw_category and raw_category.lower() not in {"all", "any", "*"}:
        category_filter = normalize_shop_category(raw_category)

    name_terms = [
        term.strip().lower()
        for term in re.split(r"[,;]", str(name_contains or ""))
        if term.strip()
    ]
    if not category_filter and not name_terms:
        raise ValueError("Choose a category or provide name_contains so the bulk edit has a safe scope.")

    updated = 0
    samples = []
    for item_name, data in sorted(items.items(), key=lambda row: str(row[0]).lower()):
        if not is_shop_item_record(data):
            continue
        item_category = normalize_shop_category(data.get("category") or guess_shop_category(item_name))
        if category_filter and item_category != category_filter:
            continue
        lower_name = str(item_name).lower()
        if name_terms and not any(term in lower_name for term in name_terms):
            continue

        data["price"] = price
        if enabled is not None:
            data["enabled"] = bool(enabled)
        updated += 1
        if len(samples) < 10:
            samples.append(str(item_name))

    if updated:
        save_shop()
    return updated, samples, category_filter or "Any", name_terms


def legacy_shop_template():
    template = {}
    for item_name, data in shop_items.items():
        if is_shop_item_record(data):
            template[str(item_name)] = dict(data)
    return template


def guild_shop_items(guild_id):
    guild_id = str(guild_id or "global")
    block = shop_items.get(guild_id)
    if isinstance(block, dict) and not is_shop_item_record(block):
        return block

    block = legacy_shop_template()
    shop_items[guild_id] = block
    save_shop()
    return block


def wallet_key(guild_id, user_id):
    return f"{guild_id}:{user_id}" if guild_id else str(user_id)


def guild_wallet(guild_id, user_id, name=""):
    key = wallet_key(str(guild_id) if guild_id else None, str(user_id))
    wallet = wallets.get(key)
    if isinstance(wallet, dict):
        wallet.setdefault("guild_id", str(guild_id) if guild_id else "")
        wallet.setdefault("user_id", str(user_id))
        wallet.setdefault("name", str(name or wallet.get("name") or ""))
        ensure_wallet_accounts(wallet)
        wallet.setdefault("daily_transactions", 0)
        return wallet

    legacy = wallets.get(str(user_id))
    if not isinstance(legacy, dict):
        legacy = {}

    wallet = {
        "guild_id": str(guild_id) if guild_id else "",
        "user_id": str(user_id),
        "name": str(name or legacy.get("name") or ""),
        "cash_balance": int(legacy.get("cash_balance", legacy.get("balance", 0)) or 0),
        "bank_balance": int(legacy.get("bank_balance", 0) or 0),
        "daily_transactions": int(legacy.get("daily_transactions", 0) or 0),
    }
    ensure_wallet_accounts(wallet)
    wallets[key] = wallet
    return wallet


def faction_wallet_id(faction_name):
    return f"faction:{faction_key(faction_name)}"


def guild_faction_wallet(guild_id, faction_name):
    display_name, faction = find_guild_faction(guild_id, faction_name)
    display_name = display_name or str(faction_name or "").strip()
    wallet_id = faction_wallet_id(display_name)
    key = wallet_key(str(guild_id) if guild_id else None, wallet_id)
    wallet = wallets.get(key)
    if isinstance(wallet, dict):
        wallet.setdefault("guild_id", str(guild_id) if guild_id else "")
        wallet.setdefault("user_id", wallet_id)
        wallet.setdefault("wallet_type", "faction")
        wallet.setdefault("faction_name", display_name)
        wallet.setdefault("name", f"Faction: {display_name}")
        ensure_wallet_accounts(wallet)
        wallet.setdefault("daily_transactions", 0)
        return wallet

    legacy = wallets.get(wallet_id)
    if not isinstance(legacy, dict):
        legacy = {}
    wallet = {
        "guild_id": str(guild_id) if guild_id else "",
        "user_id": wallet_id,
        "wallet_type": "faction",
        "faction_name": display_name,
        "name": f"Faction: {display_name}",
        "cash_balance": int(legacy.get("cash_balance", legacy.get("balance", 0)) or 0),
        "bank_balance": int(legacy.get("bank_balance", 0) or 0),
        "daily_transactions": int(legacy.get("daily_transactions", 0) or 0),
    }
    ensure_wallet_accounts(wallet)
    wallets[key] = wallet
    return wallet


def wallet_int(value, default=0):
    try:
        return int(value)
    except Exception:
        return default


def wallet_bool(value, default=True):
    if isinstance(value, bool):
        return value
    if value is None:
        return default
    return str(value).strip().lower() in {"1", "true", "yes", "on", "enabled"}


def ensure_wallet_accounts(wallet):
    if not isinstance(wallet, dict):
        return wallet

    had_cash = "cash_balance" in wallet
    had_bank = "bank_balance" in wallet
    if not had_cash and not had_bank:
        wallet["cash_balance"] = wallet_int(wallet.get("balance", 0))
        wallet["bank_balance"] = 0
    else:
        wallet["cash_balance"] = wallet_int(wallet.get("cash_balance", 0))
        wallet["bank_balance"] = wallet_int(wallet.get("bank_balance", 0))

    wallet["balance"] = wallet["cash_balance"] + wallet["bank_balance"]
    return wallet


def wallet_cash(wallet):
    ensure_wallet_accounts(wallet)
    return wallet_int((wallet or {}).get("cash_balance", 0))


def wallet_bank(wallet):
    ensure_wallet_accounts(wallet)
    return wallet_int((wallet or {}).get("bank_balance", 0))


def wallet_balance(wallet):
    ensure_wallet_accounts(wallet)
    return wallet_cash(wallet) + wallet_bank(wallet)


def wallet_account_label(account):
    return "Bank" if str(account or "").lower() == "bank" else "Cash"


def wallet_account_value(wallet, account):
    return wallet_bank(wallet) if str(account or "").lower() == "bank" else wallet_cash(wallet)


def wallet_credit(wallet, amount, account="cash"):
    ensure_wallet_accounts(wallet)
    amount = wallet_int(amount)
    if str(account or "").lower() == "bank":
        wallet["bank_balance"] = wallet_bank(wallet) + amount
    else:
        wallet["cash_balance"] = wallet_cash(wallet) + amount
    wallet["balance"] = wallet_cash(wallet) + wallet_bank(wallet)
    wallet["updated_at"] = datetime.now(UTC).isoformat()
    return wallet_balance(wallet)


def wallet_debit(wallet, amount, account="cash", allow_bank_fallback=True):
    ensure_wallet_accounts(wallet)
    amount = wallet_int(amount)
    if amount <= 0:
        return True

    account = str(account or "cash").lower()
    if account == "bank":
        if wallet_bank(wallet) < amount:
            return False
        wallet["bank_balance"] = wallet_bank(wallet) - amount
    else:
        cash = wallet_cash(wallet)
        if cash >= amount:
            wallet["cash_balance"] = cash - amount
        elif allow_bank_fallback and wallet_balance(wallet) >= amount:
            wallet["cash_balance"] = 0
            wallet["bank_balance"] = wallet_bank(wallet) - (amount - cash)
        else:
            return False

    wallet["balance"] = wallet_cash(wallet) + wallet_bank(wallet)
    wallet["updated_at"] = datetime.now(UTC).isoformat()
    return True


def wallet_move(wallet, amount, from_account, to_account):
    if str(from_account or "").lower() == str(to_account or "").lower():
        return True
    if not wallet_debit(wallet, amount, from_account, allow_bank_fallback=False):
        return False
    wallet_credit(wallet, amount, to_account)
    return True


def wallet_balance_lines(wallet):
    ensure_wallet_accounts(wallet)
    return (
        f"Cash: **{wallet_cash(wallet)} pennies**\n"
        f"Bank: **{wallet_bank(wallet)} pennies**\n"
        f"Total: **{wallet_balance(wallet)} pennies**"
    )


def wallet_balance_brief(wallet):
    ensure_wallet_accounts(wallet)
    return f"cash {wallet_cash(wallet)} | bank {wallet_bank(wallet)} | total {wallet_balance(wallet)} pennies"


DEFAULT_ECONOMY_GAME_SETTINGS = {
    "work_enabled": True,
    "work_base": 250,
    "work_min_percent": 35,
    "work_max_percent": 100,
    "work_cooldown_minutes": 60,
    "steal_enabled": True,
    "steal_success_percent": 35,
    "steal_min_percent": 5,
    "steal_max_percent": 20,
    "steal_penalty_percent": 10,
    "steal_cooldown_minutes": 120,
}


def economy_game_settings(guild_id):
    config = guild_configs.setdefault(str(guild_id), {"guild_name": "", "channels": {}})
    settings = config.setdefault("economy_game_settings", {})
    if not isinstance(settings, dict):
        settings = {}
        config["economy_game_settings"] = settings
    for key, value in DEFAULT_ECONOMY_GAME_SETTINGS.items():
        settings.setdefault(key, value)
    settings["work_enabled"] = wallet_bool(settings.get("work_enabled"), True)
    settings["steal_enabled"] = wallet_bool(settings.get("steal_enabled"), True)
    settings["work_base"] = max(1, wallet_int(settings.get("work_base"), 250))
    settings["work_min_percent"] = max(0, min(100, wallet_int(settings.get("work_min_percent"), 35)))
    settings["work_max_percent"] = max(settings["work_min_percent"], min(100, wallet_int(settings.get("work_max_percent"), 100)))
    settings["work_cooldown_minutes"] = max(0, wallet_int(settings.get("work_cooldown_minutes"), 60))
    settings["steal_success_percent"] = max(0, min(100, wallet_int(settings.get("steal_success_percent"), 35)))
    settings["steal_min_percent"] = max(1, min(100, wallet_int(settings.get("steal_min_percent"), 5)))
    settings["steal_max_percent"] = max(settings["steal_min_percent"], min(100, wallet_int(settings.get("steal_max_percent"), 20)))
    settings["steal_penalty_percent"] = max(0, min(100, wallet_int(settings.get("steal_penalty_percent"), 10)))
    settings["steal_cooldown_minutes"] = max(0, wallet_int(settings.get("steal_cooldown_minutes"), 120))
    return settings


def parse_wallet_time(value):
    try:
        text = str(value or "").strip()
        if not text:
            return None
        parsed = datetime.fromisoformat(text.replace("Z", "+00:00"))
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=UTC)
        return parsed.astimezone(UTC)
    except Exception:
        return None


def wallet_cooldown_ready(wallet, key, minutes):
    ensure_wallet_accounts(wallet)
    if minutes <= 0:
        return True, 0
    cooldowns = wallet.setdefault("cooldowns", {})
    last_used = parse_wallet_time(cooldowns.get(key))
    if not last_used:
        return True, 0
    next_allowed = last_used + timedelta(minutes=minutes)
    remaining = int((next_allowed - datetime.now(UTC)).total_seconds())
    return remaining <= 0, max(0, remaining)


def set_wallet_cooldown(wallet, key):
    ensure_wallet_accounts(wallet)
    wallet.setdefault("cooldowns", {})[key] = datetime.now(UTC).isoformat()


def cooldown_text(seconds):
    seconds = max(0, wallet_int(seconds))
    minutes, secs = divmod(seconds, 60)
    hours, mins = divmod(minutes, 60)
    if hours:
        return f"{hours}h {mins}m"
    if mins:
        return f"{mins}m {secs}s"
    return f"{secs}s"


def load_shop_items_from_types_xml(source_path=None, default_price=100, overwrite=False, guild_id=None):
    types_path = find_types_xml(source_path)

    if not types_path:
        return 0, 0, None

    target_shop = guild_shop_items(guild_id) if guild_id else shop_items
    tree = ET.parse(types_path)
    root = tree.getroot()
    added = 0
    updated = 0

    for type_node in root.findall(".//type"):
        item_name = type_node.get("name")

        if not item_name:
            continue

        category_node = type_node.find("category")
        usage_node = type_node.find("usage")
        cost_node = type_node.find("cost")

        xml_category = category_node.get("name") if category_node is not None else None
        usage = usage_node.get("name") if usage_node is not None else None

        try:
            price = int(cost_node.text.strip()) if cost_node is not None and cost_node.text else default_price
        except Exception:
            price = default_price

        if price <= 0:
            price = default_price

        category = guess_shop_category(item_name, xml_category, usage)
        if not is_shop_sellable_item(item_name, category):
            continue

        item_data = {
            "price": price,
            "category": category,
            "enabled": True
        }

        if item_name in target_shop:
            if overwrite:
                target_shop[item_name].update(item_data)
                updated += 1
            continue

        target_shop[item_name] = item_data
        added += 1

    backfill_added, backfill_repaired = ensure_curated_shop_backfill(
        guild_id,
        default_price,
        repair_categories=True,
    )
    added += backfill_added
    updated += backfill_repaired

    if added or updated:
        save_shop()

    return added, updated, types_path


def load_shop():
    global shop_items
    shop_items = load_json(SHOP_FILE)

    if not shop_items:
        load_shop_items_from_types_xml()


def save_shop():
    save_json(SHOP_FILE, shop_items)


def load_wallets():
    global wallets
    wallets = load_json(WALLETS_FILE)


def save_wallets():
    save_json(WALLETS_FILE, wallets)


def load_delivery_queue():
    global delivery_queue, vehicle_rentals_queue

    if os.path.exists(DELIVERY_QUEUE_FILE):

        with open(DELIVERY_QUEUE_FILE, "r", encoding="utf-8") as f:
            loaded = json.load(f)

        if isinstance(loaded, dict):
            delivery_queue = loaded.get("items", [])
            vehicle_rentals_queue = loaded.get("vehicles", [])
        elif isinstance(loaded, list):
            delivery_queue = loaded
            vehicle_rentals_queue = []


def save_delivery_queue():

    save_json(
        DELIVERY_QUEUE_FILE,
        {
            "items": delivery_queue,
            "vehicles": vehicle_rentals_queue
        }
    )


def shop_bundle_items(item_config):
    if not isinstance(item_config, dict) or str(item_config.get("type") or "").lower() != "bundle":
        return []
    rows = []
    for raw in item_config.get("bundle_items", []):
        if not isinstance(raw, dict):
            continue
        item_name = str(raw.get("item") or raw.get("name") or "").strip()
        try:
            quantity = int(raw.get("quantity", 1) or 1)
        except (TypeError, ValueError):
            quantity = 1
        quantity = max(1, min(999, quantity))
        if item_name:
            rows.append({"item": item_name, "quantity": quantity})
    return rows


def queue_entry_for_guild(entry, guild_id):
    if not isinstance(entry, dict):
        return False
    entry_guild_id = str(entry.get("guild_id") or "").strip()
    return not entry_guild_id or entry_guild_id == str(guild_id)


def queue_entries_for_guild(entries, guild_id):
    return [entry for entry in entries if queue_entry_for_guild(entry, guild_id)]


def remove_uploaded_queue_entries(guild_id):
    global delivery_queue, vehicle_rentals_queue
    delivery_queue = [entry for entry in delivery_queue if not queue_entry_for_guild(entry, guild_id)]
    vehicle_rentals_queue = [entry for entry in vehicle_rentals_queue if not queue_entry_for_guild(entry, guild_id)]


