def console_object_spawner_config(config):
    settings = config.setdefault("console_object_spawner", {})
    settings.setdefault("enabled", False)
    settings.setdefault("object_path", CONSOLE_OBJECT_SPAWNER_PATH)
    settings.setdefault("spawner_ref", CONSOLE_OBJECT_SPAWNER_REF)
    settings.setdefault("cfggameplay_path", "")
    settings.setdefault("objects", [])
    if not isinstance(settings.get("objects"), list):
        settings["objects"] = []
    return settings


def next_console_object_id(settings):
    existing_ids = []
    for item in settings.get("objects", []):
        try:
            existing_ids.append(int(item.get("id", 0)))
        except Exception:
            pass
    return (max(existing_ids) if existing_ids else 0) + 1


def dayz_object_record(class_name, x, z, y=0, yaw=0, pitch=0, roll=0, scale=1.0, persistent=False, object_id=None):
    x_value = parse_dayz_map_number(x)
    y_value = parse_dayz_map_number(y)
    z_value = parse_dayz_map_number(z)
    yaw_value = parse_dayz_map_number(yaw)
    pitch_value = parse_dayz_map_number(pitch)
    roll_value = parse_dayz_map_number(roll)
    scale_value = parse_dayz_map_number(scale)

    if not str(class_name or "").strip() or x_value is None or z_value is None:
        return None

    return {
        "id": object_id,
        "name": str(class_name).strip(),
        "pos": [x_value, y_value or 0, z_value],
        "ypr": [yaw_value or 0, pitch_value or 0, roll_value or 0],
        "scale": scale_value or 1.0,
        "enableCEPersistency": bool(persistent),
    }


def build_console_object_spawner_json(objects):
    output = {"Objects": []}
    for item in objects or []:
        record = dayz_object_record(
            item.get("name"),
            (item.get("pos") or [None, None, None])[0] if isinstance(item.get("pos"), list) else item.get("x"),
            (item.get("pos") or [None, None, None])[2] if isinstance(item.get("pos"), list) and len(item.get("pos")) >= 3 else item.get("z"),
            (item.get("pos") or [None, 0, None])[1] if isinstance(item.get("pos"), list) and len(item.get("pos")) >= 2 else item.get("y", 0),
            (item.get("ypr") or [0, 0, 0])[0] if isinstance(item.get("ypr"), list) else item.get("yaw", 0),
            (item.get("ypr") or [0, 0, 0])[1] if isinstance(item.get("ypr"), list) and len(item.get("ypr")) >= 2 else item.get("pitch", 0),
            (item.get("ypr") or [0, 0, 0])[2] if isinstance(item.get("ypr"), list) and len(item.get("ypr")) >= 3 else item.get("roll", 0),
            item.get("scale", 1.0),
            item.get("enableCEPersistency", item.get("persistent", False)),
            item.get("id"),
        )
        if not record:
            continue
        record.pop("id", None)
        output["Objects"].append(record)
    return json.dumps(output, indent=4)


def load_reference_cfggameplay_text(map_key):
    map_key = "livonia" if map_key == "livonia" else "chernarus"
    path = dayz_reference_path(map_key, "cfggameplay.json")
    if path and os.path.exists(path):
        with open(path, "r", encoding="utf-8", errors="ignore") as source:
            return source.read()
    return '{\n    "version": 123,\n    "WorldsData": {\n        "objectSpawnersArr": []\n    }\n}\n'


def update_cfggameplay_object_spawner(cfggameplay_text, spawner_ref):
    data = json.loads(cfggameplay_text or "{}")
    worlds = data.setdefault("WorldsData", {})
    spawners = worlds.setdefault("objectSpawnersArr", [])
    if not isinstance(spawners, list):
        spawners = []
        worlds["objectSpawnersArr"] = spawners

    wanted = str(spawner_ref or CONSOLE_OBJECT_SPAWNER_REF).strip()
    normalized_existing = {str(item).replace("\\", "/").lower() for item in spawners}
    changed = False
    if wanted.replace("\\", "/").lower() not in normalized_existing:
        spawners.append(wanted)
        changed = True

    return json.dumps(data, indent=4), changed


def download_cfggameplay_with_fallback(config, guild_id, requested_path=""):
    paths = []
    if requested_path:
        paths.append(requested_path)
    settings = console_object_spawner_config(config)
    if settings.get("cfggameplay_path"):
        paths.append(settings["cfggameplay_path"])
    paths.extend(CONSOLE_CFGGAMEPLAY_CANDIDATES)

    tried = []
    for path in paths:
        if not path or path in tried:
            continue
        tried.append(path)
        ok, message, content = download_text_file_from_nitrado(config, path)
        if ok and content:
            return True, message, content, path

    map_key = server_map_key(guild_id)
    return False, "Could not download cfggameplay.json; using bundled vanilla template.", load_reference_cfggameplay_text(map_key), (requested_path or settings.get("cfggameplay_path") or CONSOLE_CFGGAMEPLAY_CANDIDATES[0])


def console_mission_folder_for_map(map_key):
    return DAYZ_REFERENCE_MAP_FOLDERS.get(map_key) or DAYZ_REFERENCE_MAP_FOLDERS["chernarus"]


def console_ce_default_paths(guild_id):
    mission_folder = console_mission_folder_for_map(server_map_key(guild_id))
    platform_key = server_platform_key(guild_id)
    if platform_key == "playstation":
        root = "/dayzps_missions"
    elif platform_key == "pc":
        root = "/mpmissions"
    else:
        root = "/dayzxb_missions"
    return {
        "events_path": f"{root}/{mission_folder}/db/events.xml",
        "spawns_path": f"{root}/{mission_folder}/cfgeventspawns.xml",
        "eventgroups_path": f"{root}/{mission_folder}/cfgeventgroups.xml",
        "mapgroupproto_path": f"{root}/{mission_folder}/mapgroupproto.xml",
        "spawnabletypes_path": f"{root}/{mission_folder}/cfgspawnabletypes.xml",
        "cfgenvironment_path": f"{root}/{mission_folder}/cfgenvironment.xml",
        "cfgareaeffects_path": f"{root}/{mission_folder}/cfgareaeffects.xml",
        "cfgeffectarea_path": f"{root}/{mission_folder}/cfgEffectArea.json",
        "cfggameplay_path": f"{root}/{mission_folder}/cfggameplay.json",
    }


def default_delivery_bridge_path(guild_id):
    mission_folder = console_mission_folder_for_map(server_map_key(guild_id))
    platform_key = server_platform_key(guild_id)
    if platform_key == "playstation":
        root = "/dayzps_missions"
    elif platform_key == "pc":
        root = "/mpmissions"
    else:
        root = "/dayzxb_missions"
    return canonical_remote_path(f"{root}/{mission_folder}/custom/deliveries.xml")


def delivery_bridge_path_for_guild(guild_id, config):
    bridge = config.get("dayz_delivery_bridge") if isinstance(config.get("dayz_delivery_bridge"), dict) else {}
    saved = canonical_remote_path(bridge.get("delivery_path") or "")
    legacy_defaults = {
        "/dayzxb/custom/deliveries.xml",
        "/dayzps/custom/deliveries.xml",
        "/dayz/custom/deliveries.xml",
    }
    if saved and saved.lower() not in legacy_defaults:
        return saved
    return default_delivery_bridge_path(guild_id)


def console_ce_path_suffix(key):
    if key == "events_path":
        return "db/events.xml"
    if key == "spawnabletypes_path":
        return "cfgspawnabletypes.xml"
    if key == "eventgroups_path":
        return "cfgeventgroups.xml"
    if key == "mapgroupproto_path":
        return "mapgroupproto.xml"
    if key == "cfgenvironment_path":
        return "cfgenvironment.xml"
    if key == "cfgareaeffects_path":
        return "cfgareaeffects.xml"
    if key == "cfgeffectarea_path":
        return "cfgEffectArea.json"
    if key == "cfggameplay_path":
        return "cfggameplay.json"
    return "cfgeventspawns.xml"


def console_ce_allowed_mission_folders(guild_id):
    map_key = server_map_key(guild_id)
    missions = [console_mission_folder_for_map(map_key)]
    if map_key == "sakhal":
        missions.append("dayzOffline.sakhalplus")
    return [mission for mission in missions if mission]


def console_ce_path_matches_selected_map(guild_id, path):
    clean = canonical_remote_path(path)
    if not clean:
        return False
    normalized = normalize_discord_name(clean)
    known_missions = [mission for mission in DAYZ_REFERENCE_MAP_FOLDERS.values()]
    known_missions.extend(["dayzOffline.sakhalplus", "dayzOffline.namalsk"])
    mentioned = [mission for mission in known_missions if normalize_discord_name(mission) in normalized]
    if not mentioned:
        return True
    allowed_mission_keys = {
        normalize_discord_name(mission)
        for mission in console_ce_allowed_mission_folders(guild_id)
    }
    return any(normalize_discord_name(mission) in allowed_mission_keys for mission in mentioned)


def strip_nitrado_noftp_prefix(config, path):
    clean = canonical_remote_path(path)
    nitrado_user = str(config.get("nitrado_user") or "").strip()
    if nitrado_user:
        for prefix in (f"/games/{nitrado_user}/noftp", f"/games/{nitrado_user}/ftproot"):
            if clean.startswith(prefix + "/"):
                return canonical_remote_path(clean[len(prefix):])
    return clean


def console_ce_mission_base_from_path(config, guild_id, path):
    clean = strip_nitrado_noftp_prefix(config, path)
    if not console_ce_path_matches_selected_map(guild_id, clean):
        return ""
    normalized = normalize_discord_name(clean)
    for mission in console_ce_allowed_mission_folders(guild_id):
        mission_key = normalize_discord_name(mission)
        marker = f"/{mission.lower()}"
        if mission_key not in normalized:
            continue
        lower_clean = clean.lower()
        index = lower_clean.find(marker)
        if index < 0:
            continue
        return canonical_remote_path(clean[:index + len(marker)])
    return ""


def remember_console_ce_mission_base(config, guild_id, path):
    base = console_ce_mission_base_from_path(config, guild_id, path)
    if not base:
        return
    bases = config.get("_console_ce_mission_bases")
    if not isinstance(bases, list):
        bases = []
    bases = [str(item) for item in bases if console_ce_path_matches_selected_map(guild_id, item)]
    if base not in bases:
        bases.insert(0, base)
    config["_console_ce_mission_bases"] = bases[:6]


def discover_console_ce_mission_bases(config, guild_id):
    bases = []

    def add_base(path):
        base = console_ce_mission_base_from_path(config, guild_id, path)
        if base and base not in bases:
            bases.append(base)

    cached = config.get("_console_ce_mission_bases")
    if isinstance(cached, list):
        for path in cached:
            add_base(path)

    settings = console_ce_event_config(config)
    for value in settings.values():
        if isinstance(value, str):
            add_base(value)

    active_mission = str(config.get("active_mission_dir") or "").strip().strip("/")
    if active_mission:
        if "/" in active_mission:
            add_base(active_mission)
        else:
            for root in mission_root_candidates_for_config(config, guild_id):
                add_base(f"{root}/{active_mission}")

    if bases:
        return bases

    try:
        for init_path in discover_init_c_paths(config, max_dirs=36, timeout_seconds=5):
            add_base(init_path)
            if len(bases) >= 4:
                break
    except Exception:
        pass

    return bases


def compact_ce_download_message(message, limit=280):
    text = re.sub(r"\s+", " ", str(message or "")).strip()
    if "Just a moment" in text or "<!DOCTYPE html" in text:
        text = "Nitrado/Cloudflare returned an HTML rate-limit page while probing that path."
    return text[:limit]


def console_ce_download_message_is_rate_limited(message):
    text = str(message or "")
    lowered = text.lower()
    return (
        "just a moment" in lowered
        or "<!doctype html" in lowered
        or "cloudflare" in lowered
        or "rate-limit" in lowered
        or "rate limit" in lowered
    )


def console_ce_download_failure_message(guild_id, key, attempted):
    attempted = attempted if isinstance(attempted, list) else []
    file_name = os.path.basename(console_ce_path_suffix(key))
    mission = console_mission_folder_for_map(server_map_key(guild_id))
    platform = server_platform_key(guild_id)
    tried_paths = []
    last_message = ""
    for path, message in attempted:
        clean = canonical_remote_path(path)
        if clean and clean not in tried_paths:
            tried_paths.append(clean)
        if message:
            last_message = compact_ce_download_message(message)
    sample = ", ".join(f"`{path}`" for path in tried_paths[:6])
    if len(tried_paths) > 6:
        sample += f", +{len(tried_paths) - 6} more"
    return (
        f"Could not download existing `{file_name}` for mission `{mission}` "
        f"while probing `{platform}` CE roots. Tried {len(tried_paths)} path(s)"
        + (f": {sample}." if sample else ".")
        + (f" Last response: {last_message}" if last_message else "")
    )


def console_ce_path_candidates(config, guild_id, key, requested_path="", configured_path="", include_discovery=False):
    candidates = []
    allowed_missions = console_ce_allowed_mission_folders(guild_id)

    def add(path):
        clean = canonical_remote_path(path)
        if clean and not console_ce_path_matches_selected_map(guild_id, clean):
            return
        if clean and clean not in candidates:
            candidates.append(clean)

    add(console_ce_default_paths(guild_id)[key])
    add(requested_path)
    add(configured_path)

    mission_names = []
    configured_mission = str(config.get("active_mission_dir") or "").strip().strip("/")
    if "/" not in configured_mission and configured_mission and console_ce_path_matches_selected_map(guild_id, configured_mission):
        mission_names.append(configured_mission)
    mission_names.extend(allowed_missions)

    suffix = console_ce_path_suffix(key)
    if include_discovery:
        for base in discover_console_ce_mission_bases(config, guild_id):
            add(f"{base}/{suffix}")

    mission_bases = mission_root_candidates_for_config(config, guild_id)
    seen_missions = []
    for mission in mission_names:
        mission = str(mission or "").strip().strip("/")
        if mission and mission not in seen_missions:
            seen_missions.append(mission)
    for base in mission_bases:
        for mission in seen_missions:
            add(f"{base}/{mission}/{suffix}")
    return candidates


def console_ce_event_config(config):
    settings = config.setdefault("console_ce_events", {})
    settings.setdefault("enabled", False)
    settings.setdefault("events_path", "")
    settings.setdefault("spawns_path", "")
    settings.setdefault("eventgroups_path", "")
    settings.setdefault("mapgroupproto_path", "")
    settings.setdefault("spawnabletypes_path", "")
    settings.setdefault("cfgenvironment_path", "")
    settings.setdefault("cfgareaeffects_path", "")
    settings.setdefault("cfgeffectarea_path", "")
    settings.setdefault("cfggameplay_path", "")
    return settings


def clear_console_ce_path_cache(config):
    config.pop("_console_ce_mission_bases", None)
    settings = config.get("console_ce_events")
    if not isinstance(settings, dict):
        return
    for key in (
        "events_path",
        "spawns_path",
        "eventgroups_path",
        "mapgroupproto_path",
        "spawnabletypes_path",
        "cfgenvironment_path",
        "cfgareaeffects_path",
        "cfgeffectarea_path",
    ):
        settings.pop(key, None)


def stack_watch_action(settings):
    action = str((settings or {}).get("action") or "notify").strip().lower()
    return action if action in {"notify", "temp_ban", "perm_ban"} else "notify"


async def apply_stack_watch_configured_action(guild_id, config, settings, player_name):
    action = stack_watch_action(settings)
    if action == "notify":
        return "Notify only; no automatic game ban configured."

    reason = str(settings.get("reason") or "Stack Watch: possible item stacking raid").strip()[:500]
    now_ts = datetime.now(UTC).timestamp()
    player_key = normalize_discord_name(player_name)
    if action == "temp_ban":
        try:
            minutes = max(1, min(525600, int(settings.get("temp_ban_minutes") or 1440)))
        except Exception:
            minutes = 1440
        ok, message = await add_player_to_nitrado_banlist_async(
            guild_id,
            config,
            player_name,
            ban_type="temp",
            reason=reason,
            source="stack_watch_auto",
            minutes=minutes,
        )
        if not ok:
            return f"Automatic game-ban failed: {message}"
        existing = [
            record for record in config.get("nitrado_temp_bans", [])
            if normalize_discord_name(record.get("gamertag")) == player_key and record.get("source") == "stack_watch"
        ]
        if not existing:
            config.setdefault("nitrado_temp_bans", []).append({
                "gamertag": player_name,
                "reason": reason,
                "created_ts": now_ts,
                "until_ts": now_ts + minutes * 60,
                "source": "stack_watch",
            })
        save_guild_configs()
        return f"Temp game-ban queued for {minutes} minute(s). {message} No restart requested."

    ok, message = await add_player_to_nitrado_banlist_async(
        guild_id,
        config,
        player_name,
        ban_type="perm",
        reason=reason,
        source="stack_watch_auto",
    )
    if not ok:
        return f"Automatic game-ban failed: {message}"
    existing = [
        record for record in config.get("nitrado_perm_bans", [])
        if normalize_discord_name(record.get("gamertag")) == player_key and record.get("source") == "stack_watch"
    ]
    if not existing:
        config.setdefault("nitrado_perm_bans", []).append({
            "gamertag": player_name,
            "reason": reason,
            "created_ts": now_ts,
            "source": "stack_watch",
        })
    save_guild_configs()
    return f"Permanent game-ban queued. {message} No restart requested."


CONSOLE_CE_ITEM_CONTAINER_CLASSES = {
    "WoodenCrate",
    "SeaChest",
    "Barrel_Green",
    "Barrel_Blue",
    "Barrel_Red",
    "Barrel_Yellow",
    "SmallProtectorCase",
}


def normalize_console_ce_container_class(class_name):
    wanted = str(class_name or "").strip()
    if wanted in {"StaticObj_Misc_WoodenCrate_5x", "SupplyCrate", "Crate"}:
        return "WoodenCrate"
    return wanted


def ce_event_family_for_record(event_type, class_name=""):
    event_type = str(event_type or "").strip().lower()
    class_name = str(class_name or "").strip()
    container_class = normalize_console_ce_container_class(class_name)
    if event_type == "gas_zone" or class_name.startswith("ContaminatedArea"):
        return "Static"
    if class_name.startswith("Animal_") or event_type == "animal_pack":
        return "Animal"
    if class_name.startswith("Zmb") or event_type == "zombie_horde":
        return "Infected"
    if event_type == "vehicle_spawn":
        return "Vehicle"
    if event_type in {"airdrop", "loot_crate"}:
        if container_class in CONSOLE_CE_ITEM_CONTAINER_CLASSES:
            return "Item"
        if class_name.startswith(("Static", "Land_")):
            return "Static"
        return "Item"
    if class_name.startswith(("Static", "Land_")):
        return "Static"
    return "Static"


def ce_event_name(event, suffix="", family=""):
    event_id = int(event.get("id", 0) or 0)
    kind = normalize_discord_name(event.get("event_type", "event")) or "event"
    tail = f"_{normalize_discord_name(suffix)}" if suffix else ""
    event_family = str(family or ce_event_family_for_record(kind, event.get("class_name"))).strip() or "Static"
    stable_slug = stable_console_event_slug(event)
    if stable_slug:
        return f"{event_family}{CONSOLE_CE_EVENT_MARKER}{stable_slug}{tail}"[:64]
    revision = scenario_event_ce_revision_token(event)
    revision_tail = f"_{revision}" if revision else ""
    return f"{event_family}{CONSOLE_CE_EVENT_MARKER}{event_id}_{kind}{revision_tail}{tail}"[:64]


def scenario_event_ce_revision_token(event):
    event_type = str((event or {}).get("event_type") or "").strip().lower()
    if event_type in STABLE_CONSOLE_EVENT_TYPES:
        return ""
    revision = max(
        safe_int(SCENARIO_CE_SCHEMA_REVISIONS.get(event_type), 0),
        safe_int((event or {}).get("native_ce_revision"), 0),
        safe_int((event or {}).get("ce_revision"), 0),
        safe_int((event or {}).get("upload_revision"), 0),
    )
    if revision > 0:
        return f"r{min(revision, 9999)}"
    seed = str((event or {}).get("updated_at") or (event or {}).get("created_at") or "").strip()
    if not seed:
        return ""
    return hashlib.sha1(seed.encode("utf-8", errors="ignore")).hexdigest()[:5]


def stable_console_event_slug(event):
    event_type = str((event or {}).get("event_type") or "").strip().lower()
    if event_type not in STABLE_CONSOLE_EVENT_TYPES:
        return ""
    preset = normalize_discord_name(
        (event or {}).get("preset")
        or (event or {}).get("spawn_preset")
        or ""
    )
    if not preset or preset in {"custom", "customvehicle"}:
        preset = normalize_discord_name((event or {}).get("class_name") or "")
    if not preset:
        preset = "managed"
    prefix = "animal" if event_type == "animal_pack" else "horde"
    return f"{prefix}_{preset}"[:48]


def vanilla_animal_ce_event_name(class_name):
    text = normalize_discord_name(class_name)
    if not text:
        return ""
    if "ursusarctos" in text or "bear" in text:
        return "AnimalBear"
    if "canislupus" in text or "wolf" in text:
        return "AnimalWolf"
    if "susscrofa" in text or "wildboar" in text or "boar" in text:
        return "AnimalWildBoar"
    if "cervuselaphus" in text or "reddeer" in text:
        return "AnimalDeer"
    if "capreolus" in text or "roedeer" in text:
        return "AnimalRoeDeer"
    if "bostaurus" in text or "cow" in text:
        return "AnimalCow"
    if "caprahircus" in text or "goat" in text:
        return "AnimalGoat"
    if "ovisaries" in text or "sheep" in text:
        return "AnimalSheep"
    if "gallus" in text or "hen" in text or "chicken" in text:
        return "AmbientHen"
    return ""


VANILLA_ANIMAL_CE_EVENT_NAMES = {
    "AmbientHen",
    "AnimalBear",
    "AnimalCow",
    "AnimalDeer",
    "AnimalGoat",
    "AnimalPig",
    "AnimalRoeDeer",
    "AnimalSheep",
    "AnimalWildBoar",
    "AnimalWolf",
}


def ce_event_nominal_count(event, override_count=None):
    try:
        count = int(override_count if override_count is not None else event.get("count", 1))
    except Exception:
        count = 1
    return max(1, min(250, count))


def xml_text_from_root(root):
    try:
        ET.indent(root, space="    ")
    except Exception:
        pass
    return "<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"yes\"?>\n" + ET.tostring(root, encoding="unicode")


def is_xml_comment_node(node):
    return getattr(node, "tag", None) is ET.Comment


def safe_xml_comment_text(text):
    clean = re.sub(r"\s+", " ", str(text or "")).strip()
    clean = clean.replace("--", "-").replace("<", "").replace(">", "")
    return clean[:180]


def wandering_xml_comment(text):
    label = safe_xml_comment_text(text)
    if not label.lower().startswith("wandering bot:"):
        label = f"Wandering Bot: {label}"
    return ET.Comment(f" {label} ")


def append_wandering_xml_comment(parent, text):
    parent.append(wandering_xml_comment(text))


def remove_wandering_xml_comments(parent, contains=""):
    wanted = str(contains or "").strip().lower()
    removed = 0
    for child in list(parent):
        if not is_xml_comment_node(child):
            continue
        text = str(child.text or "").strip().lower()
        if "wandering bot:" not in text:
            continue
        if wanted and wanted not in text:
            continue
        parent.remove(child)
        removed += 1
    return removed


def parse_xml_root_or_new(text, fallback_root):
    text = str(text or "").strip()
    if not text:
        return ET.Element(fallback_root), "Created new template because the source XML was empty."

    try:
        return parse_xml_root_preserving_comments(text), None
    except Exception as error:
        close_tag = f"</{str(fallback_root or '').strip().lower()}>"
        lower_text = text.lower()
        close_index = lower_text.rfind(close_tag) if close_tag != "</>" else -1
        if close_index >= 0:
            recovered_text = text[:close_index + len(close_tag)].strip()
            try:
                return ET.fromstring(recovered_text.encode("utf-8")), None
            except Exception:
                pass
        detail = str(error)
        line_text = ""
        position = getattr(error, "position", None)
        if isinstance(position, tuple) and position:
            line_no = int(position[0] or 0)
            lines = text.splitlines()
            if 1 <= line_no <= len(lines):
                line_text = f" Problem line {line_no}: {lines[line_no - 1][:220]}"
        return ET.Element(fallback_root), f"Created new `{fallback_root}` template because XML parsing failed: {detail}.{line_text}"


def parse_console_ce_xml_source(config, label, text, fallback_root, resolved_path=""):
    root, warning = parse_xml_root_or_new(text, fallback_root)
    if not warning:
        return root, None, None

    backup_path = f"{canonical_remote_path(resolved_path)}.wanderingbot-backup-latest" if resolved_path else ""
    if backup_path:
        ok, backup_message, backup_text = download_text_file_from_nitrado(config, backup_path)
        if ok and str(backup_text or "").strip():
            backup_root, backup_warning = parse_xml_root_or_new(backup_text, fallback_root)
            if not backup_warning:
                return backup_root, (
                    f"{label}: live XML was malformed, so Wandering Bot recovered from "
                    f"`{backup_path}` before merging. Live parse issue: {warning}"
                ), None
            return root, warning, (
                f"{label}: live XML is malformed and backup `{backup_path}` is also invalid. "
                f"Live issue: {warning} Backup issue: {backup_warning}"
            )
        return root, warning, (
            f"{label}: live XML is malformed and backup `{backup_path}` could not be downloaded. "
            f"Live issue: {warning} Backup download: {backup_message}"
        )

    return root, warning, f"{label}: {warning}"


def parse_xml_root_preserving_comments(text):
    try:
        parser = ET.XMLParser(target=ET.TreeBuilder(insert_comments=True))
        return ET.fromstring(str(text or "").encode("utf-8"), parser=parser)
    except TypeError:
        return ET.fromstring(str(text or "").encode("utf-8"))


def remove_wandering_ce_nodes(root):
    removed = 0
    for child in list(root):
        if is_xml_comment_node(child):
            text = str(child.text or "")
            if "wandering bot:" in text.lower():
                root.remove(child)
            continue
        name = str(child.get("name") or "")
        if (
            name in LEGACY_WANDERING_CE_NAMES
            or CONSOLE_CE_EVENT_MARKER in name
            or name.startswith(CONSOLE_CE_EVENT_PREFIX)
            or "wanderingbot" in normalize_discord_name(name)
        ):
            root.remove(child)
            removed += 1
    return removed


def is_wandering_managed_name(value):
    text = str(value or "").strip()
    if not text:
        return False
    return (
        text in LEGACY_WANDERING_CE_NAMES
        or CONSOLE_CE_EVENT_MARKER in text
        or text.startswith(CONSOLE_CE_EVENT_PREFIX)
        or "wanderingbot" in normalize_discord_name(text)
    )


def is_wandering_scope_comment(node):
    return is_xml_comment_node(node) and "wandering bot:" in str(node.text or "").lower()


def is_wandering_scope_node(node):
    for attr in ("name", "path", "usable"):
        if is_wandering_managed_name(node.get(attr)):
            return True
    if "wanderingbot" in normalize_discord_name(ET.tostring(node, encoding="unicode")):
        return True
    return False


def ce_scope_node_key(node, fallback_index):
    for attr in ("name", "path", "usable"):
        value = str(node.get(attr) or "").strip()
        if value:
            return (str(node.tag), attr, value.lower())
    return (str(node.tag), "index", str(fallback_index))


def ce_scope_node_display(node, key):
    tag = str(node.tag)
    for attr in ("name", "path", "usable"):
        value = str(node.get(attr) or "").strip()
        if value:
            return f"<{tag} {attr}=\"{value}\">"
    return f"<{tag}> #{key[-1]}"


def canonical_ce_scope_node_text(node):
    clone = ET.fromstring(ET.tostring(node, encoding="utf-8"))
    try:
        ET.indent(clone, space="    ")
    except Exception:
        pass
    return ET.tostring(clone, encoding="unicode")


def remove_wandering_marked_spawn_children(event_node):
    removed = 0
    pending_managed_spawn_comment = None
    for child in list(event_node):
        if is_xml_comment_node(child):
            text = str(child.text or "").strip().lower()
            if "wandering bot:" in text and "managed spawn position" in text:
                pending_managed_spawn_comment = child
                continue
            pending_managed_spawn_comment = None
            continue
        if pending_managed_spawn_comment is not None and getattr(child, "tag", "") in {"pos", "zone"}:
            event_node.remove(pending_managed_spawn_comment)
            event_node.remove(child)
            removed += 1
        pending_managed_spawn_comment = None
    return removed


def canonical_ce_scope_node_text_without_wandering_spawn_children(node):
    clone = parse_xml_root_preserving_comments(ET.tostring(node, encoding="unicode"))
    remove_wandering_marked_spawn_children(clone)
    try:
        ET.indent(clone, space="    ")
    except Exception:
        pass
    return ET.tostring(clone, encoding="unicode")


def ce_scope_records(root):
    records = {}
    pending_owned_comment = False
    fallback_index = 0
    for child in list(root):
        if is_xml_comment_node(child):
            pending_owned_comment = is_wandering_scope_comment(child)
            continue
        fallback_index += 1
        key = ce_scope_node_key(child, fallback_index)
        if key in records:
            key = (key[0], key[1], key[2], str(fallback_index))
        owned = pending_owned_comment or is_wandering_scope_node(child)
        pending_owned_comment = False
        records[key] = {
            "text": canonical_ce_scope_node_text(child),
            "owned": owned,
            "display": ce_scope_node_display(child, key),
        }
    return records


def validate_managed_ce_xml_scope(label, original_text, merged_text):
    if not str(merged_text or "").strip():
        return True, f"`{label}` snippet scope check skipped because no upload text was generated."
    if not str(original_text or "").strip():
        return False, f"`{label}` snippet scope guard blocked upload because the live source text was empty."
    try:
        original_root = parse_xml_root_preserving_comments(original_text)
        merged_root = parse_xml_root_preserving_comments(merged_text)
    except Exception as error:
        return False, f"`{label}` snippet scope guard could not parse original/merged XML: {error}"
    if str(original_root.tag) != str(merged_root.tag):
        return False, f"`{label}` snippet scope guard blocked root change from <{original_root.tag}> to <{merged_root.tag}>."

    original_records = ce_scope_records(original_root)
    merged_records = ce_scope_records(merged_root)
    changed_unowned = []
    for key in sorted(set(original_records) | set(merged_records), key=str):
        original = original_records.get(key)
        merged = merged_records.get(key)
        if (original or {}).get("text") == (merged or {}).get("text"):
            continue
        owned = bool((original or {}).get("owned") or (merged or {}).get("owned"))
        if not owned and label == "cfgeventspawns.xml":
            original_node = None
            merged_node = None
            for child in list(original_root):
                if not is_xml_comment_node(child) and ce_scope_node_key(child, 0)[:3] == key[:3]:
                    original_node = child
                    break
            for child in list(merged_root):
                if not is_xml_comment_node(child) and ce_scope_node_key(child, 0)[:3] == key[:3]:
                    merged_node = child
                    break
            if (
                original_node is not None
                and merged_node is not None
                and canonical_ce_scope_node_text_without_wandering_spawn_children(original_node)
                == canonical_ce_scope_node_text_without_wandering_spawn_children(merged_node)
            ):
                continue
        if not owned and label == "events.xml":
            original_node = None
            merged_node = None
            for child in list(original_root):
                if not is_xml_comment_node(child) and ce_scope_node_key(child, 0)[:3] == key[:3]:
                    original_node = child
                    break
            for child in list(merged_root):
                if not is_xml_comment_node(child) and ce_scope_node_key(child, 0)[:3] == key[:3]:
                    merged_node = child
                    break
            if vanilla_animal_event_count_patch_is_safe(original_node, merged_node):
                continue
        if not owned:
            changed_unowned.append((merged or original or {}).get("display") or str(key))
    if changed_unowned:
        sample = ", ".join(f"`{item}`" for item in changed_unowned[:8])
        if len(changed_unowned) > 8:
            sample += f", +{len(changed_unowned) - 8} more"
        return False, (
            f"`{label}` snippet scope guard blocked upload because it would change non-WanderingBot "
            f"top-level XML node(s): {sample}. Fix or remove the generated WanderingBot snippet instead."
        )
    return True, f"`{label}` snippet scope guard confirmed only WanderingBot-managed XML nodes changed."


def vanilla_animal_event_count_patch_is_safe(original_node, merged_node):
    if original_node is None or merged_node is None:
        return False
    if getattr(original_node, "tag", None) != "event" or getattr(merged_node, "tag", None) != "event":
        return False
    original_name = str(original_node.get("name") or "").strip()
    merged_name = str(merged_node.get("name") or "").strip()
    if original_name != merged_name or original_name not in VANILLA_ANIMAL_CE_EVENT_NAMES:
        return False
    allowed_tags = {"nominal", "min", "max"}
    original_children = [child for child in list(original_node) if not is_xml_comment_node(child)]
    merged_children = [child for child in list(merged_node) if not is_xml_comment_node(child)]
    if len(original_children) != len(merged_children):
        return False
    changed_allowed = False
    for original_child, merged_child in zip(original_children, merged_children):
        if getattr(original_child, "tag", None) != getattr(merged_child, "tag", None):
            return False
        tag = str(getattr(original_child, "tag", "") or "")
        if tag in allowed_tags:
            if dict(original_child.attrib) != dict(merged_child.attrib):
                return False
            original_text = str(original_child.text or "").strip()
            merged_text = str(merged_child.text or "").strip()
            if original_text != merged_text:
                if not original_text.isdigit() or not merged_text.isdigit():
                    return False
                changed_allowed = True
            continue
        if canonical_ce_scope_node_text(original_child) != canonical_ce_scope_node_text(merged_child):
            return False
    return changed_allowed


def validate_console_ce_upload_scope(built):
    targets = [
        ("events.xml", "events_source_text", "events_text"),
        ("cfgeventspawns.xml", "spawns_source_text", "spawns_text"),
        ("cfgspawnabletypes.xml", "spawnabletypes_source_text", "spawnabletypes_text"),
        ("cfgeventgroups.xml", "eventgroups_source_text", "eventgroups_text"),
        ("mapgroupproto.xml", "mapgroupproto_source_text", "mapgroupproto_text"),
        ("cfgenvironment.xml", "cfgenvironment_source_text", "cfgenvironment_text"),
        ("cfgareaeffects.xml", "cfgareaeffects_source_text", "cfgareaeffects_text"),
    ]
    messages = []
    for label, source_key, text_key in targets:
        merged_text = built.get(text_key)
        if not merged_text:
            continue
        if source_key not in built:
            continue
        ok, message = validate_managed_ce_xml_scope(label, built.get(source_key, ""), merged_text)
        messages.append(message)
        if not ok:
            return False, messages
    return True, messages


def console_ce_needs_spawnabletypes(config):
    # Scenario loot should come from DayZ CE usage/category tags and native class
    # loot config. Do not inject per-item cargo into cfgspawnabletypes.xml.
    return False


def console_ce_has_native_loot_intent(config):
    for event in native_ce_scenario_events(config):
        if event.get("event_type") in {"airdrop", "loot_crate"} and (
            event.get("loot_preset")
            or event.get("loot")
            or event.get("loot_mix")
        ):
            return True
    return False


def normalize_gas_particle_mode(value):
    text = str(value or "").strip().lower()
    if text in {"debug", "red", "red_debug", "debug_red"}:
        return "debug"
    if text in {"normal", "green", "restore", "restore_normal"}:
        return "normal"
    return ""


def console_ce_cfgareaeffects_mode(config):
    modes = []
    for event in native_ce_scenario_events(config):
        if str(event.get("event_type") or "").strip().lower() != "gas_zone":
            continue
        mode = normalize_gas_particle_mode(event.get("gas_particle"))
        if mode:
            modes.append(mode)
    if "debug" in modes:
        return "debug"
    if "normal" in modes:
        return "normal"
    return ""


def _xml_local_name(tag):
    return str(tag or "").rsplit("}", 1)[-1].strip().lower()


def _gas_particle_target(mode):
    return GAS_PARTICLE_DEBUG if normalize_gas_particle_mode(mode) == "debug" else GAS_PARTICLE_NORMAL


def _replace_gas_particle_value(value, target):
    text = str(value or "")
    if "contaminated_area_gas_bigass" not in text:
        return None
    return re.sub(
        r"graphics/particles/contaminated_area_gas_bigass(?:_debug)?",
        target,
        text,
    )


def patch_cfgareaeffects_gas_particle(root, mode):
    target = _gas_particle_target(mode)
    changed = 0
    matched = 0
    for node in root.iter():
        local_name = _xml_local_name(node.tag)
        node_name = str(node.get("name") or node.get("Name") or "").strip().lower()
        if local_name == "particlename" and node.text is not None:
            matched += 1
            replacement = target if "contaminated_area_gas_bigass" in str(node.text) else None
            if replacement and node.text != replacement:
                node.text = replacement
                changed += 1
        elif node_name == "particlename" and "value" in node.attrib:
            matched += 1
            if node.get("value") != target:
                node.set("value", target)
                changed += 1

        for attr, attr_value in list(node.attrib.items()):
            replacement = _replace_gas_particle_value(attr_value, target)
            if replacement is not None:
                matched += 1
                if attr_value != replacement:
                    node.set(attr, replacement)
                    changed += 1
    return changed, matched, target


def cfgspawnabletypes_loot_signature(cargo_node):
    return tuple(sorted(
        str(item.get("name") or "").strip()
        for item in cargo_node.findall("item")
        if str(item.get("name") or "").strip()
    ))


def cfgspawnabletypes_item_signature(group_node):
    return tuple(sorted(
        (
            str(item.get("name") or "").strip(),
            str(item.get("quantmin") or "").strip(),
            str(item.get("quantmax") or "").strip(),
        )
        for item in group_node.findall("item")
        if str(item.get("name") or "").strip()
    ))


def cfgspawnabletypes_damage_is_pristine(type_node):
    damage_nodes = list(type_node.findall("damage"))
    if len(damage_nodes) != 1:
        return False
    damage_node = damage_nodes[0]
    min_damage = str(damage_node.get("min") or "").strip()
    max_damage = str(damage_node.get("max") or "").strip()
    return min_damage in {"0", "0.0", "0.00"} and max_damage in {"0", "0.0", "0.00"}


def find_or_create_spawnable_type(root, class_name):
    wanted = str(class_name or "").strip()
    for type_node in root.findall("type"):
        if str(type_node.get("name") or "").strip().lower() == wanted.lower():
            return type_node, False

    return ET.SubElement(root, "type", {"name": wanted}), True


def scenario_container_class_for_ce(class_name):
    return normalize_console_ce_container_class(class_name)


def scenario_loot_items(event):
    loot = event.get("loot") or []
    if isinstance(loot, str):
        loot = [item.strip() for item in loot.split(",") if item.strip()]
    clean = [
        str(item).strip()
        for item in loot
        if str(item).strip()
    ]
    if clean:
        return clean
    preset_key = str(event.get("loot_preset") or "none").strip()
    return [
        str(item).strip()
        for item in SCENARIO_LOOT_PRESETS.get(preset_key, [])
        if str(item).strip()
    ]


def scenario_event_random(event, salt=""):
    raw = "|".join([
        str((event or {}).get("id") or ""),
        str((event or {}).get("name") or ""),
        str((event or {}).get("x") or ""),
        str((event or {}).get("z") or ""),
        str((event or {}).get("created_at") or ""),
        str((event or {}).get("loot_preset") or ""),
        str(salt or ""),
    ])
    seed = int(hashlib.sha256(raw.encode("utf-8", errors="ignore")).hexdigest()[:16], 16)
    return random.Random(seed)


def scenario_seeded_sample(event, items, minimum, maximum, salt):
    clean = []
    seen = set()
    for item in items or []:
        name = str(item or "").strip()
        key = name.lower()
        if name and key not in seen:
            seen.add(key)
            clean.append(name)
    if len(clean) <= minimum:
        return clean
    rng = scenario_event_random(event, salt)
    rng.shuffle(clean)
    count = min(len(clean), rng.randint(minimum, max(minimum, maximum)))
    return clean[:count]


def scenario_airdrop_ground_loot_items(event):
    loot = scenario_loot_items(event)
    weapons = [item for item in loot if item in SCENARIO_AIRDROP_WEAPON_LOOT or item in SCENARIO_AIRDROP_WEAPON_RECIPES]
    clothing = [item for item in loot if item in SCENARIO_AIRDROP_CLOTHING_LOOT]
    bags = [item for item in loot if item in SCENARIO_AIRDROP_BAG_LOOT]
    field_items = [item for item in loot if item in SCENARIO_AIRDROP_FIELD_LOOT]
    selected = []
    selected.extend(scenario_seeded_sample(event, weapons, 5, 8, "weapons"))
    selected.extend(scenario_seeded_sample(event, clothing, 8, 12, "clothing"))
    selected.extend(scenario_seeded_sample(event, bags, 2, 4, "bags"))
    selected.extend(scenario_seeded_sample(event, field_items, 5, 9, "field"))
    if not selected:
        selected = [item for item in loot if item in SCENARIO_AIRDROP_GROUND_LOOT or item in SCENARIO_AIRDROP_WEAPON_RECIPES]
    seen = set()
    unique = []
    for item in selected:
        key = str(item).lower()
        if key not in seen:
            seen.add(key)
            unique.append(item)
    return unique[:36]


def scenario_airdrop_ammo_box_items(event):
    items = []
    seen = set()

    def add(item_name):
        name = str(item_name or "").strip()
        key = name.lower()
        if name and key.startswith("ammobox_") and key not in seen:
            seen.add(key)
            items.append(name)

    for item in scenario_loot_items(event):
        add(item)
    for weapon in scenario_airdrop_ground_loot_items(event):
        recipe = SCENARIO_AIRDROP_WEAPON_RECIPES.get(weapon, {})
        for item in recipe.get("supplies", []):
            add(item)
    return items


def scenario_airdrop_container_loot_allowed(item_name):
    item_name = str(item_name or "").strip()
    return item_name.lower().startswith("ammobox_")


def scenario_airdrop_container_loot_items(event):
    selected = scenario_airdrop_ground_loot_items(event)
    ammo_boxes = scenario_airdrop_ammo_box_items(event)
    rng = scenario_event_random(event, "crate-cargo")
    cargo = []
    seen = set()

    def add(item_name):
        name = str(item_name or "").strip()
        key = name.lower()
        if name and key not in seen:
            seen.add(key)
            cargo.append(name)

    selected = list(selected)
    rng.shuffle(selected)
    ammo_boxes = list(ammo_boxes)
    rng.shuffle(ammo_boxes)
    for item in selected:
        add(item)
    for item in ammo_boxes:
        add(item)
    return cargo[:42]


def scenario_spawnabletypes_quantity_attrs(item_name):
    lower = str(item_name or "").strip().lower()
    if lower.startswith(("mag_", "ammo_", "ammobox_", "battery")) or lower.endswith("battery") or lower in {"canteen", "waterbottle"}:
        return {"quantmin": "100", "quantmax": "100"}
    return {}


def set_spawnable_type_pristine(type_node):
    if cfgspawnabletypes_damage_is_pristine(type_node):
        return False
    for damage_node in list(type_node.findall("damage")):
        type_node.remove(damage_node)
    damage_node = ET.Element("damage", {"min": "0.0", "max": "0.0"})
    type_node.insert(0, damage_node)
    return True


def scenario_airdrop_pristine_classes(event, class_name):
    seen = set()
    classes = []

    def add(item_name):
        item_name = str(item_name or "").strip()
        key = item_name.lower()
        if item_name and key not in seen:
            seen.add(key)
            classes.append(item_name)

    add(class_name)
    marker_class = str(event.get("marker_class") or SCENARIO_AIRDROP_MARKER_CLASS).strip()
    if event.get("visual_marker") and marker_class:
        add(marker_class)
    if event.get("visual_marker"):
        scene = scenario_airdrop_scene_config(event)
        add(scene.get("marker"))
        for scene_prop in scene.get("props") or []:
            add(scene_prop.get("type"))
    for item_name in scenario_loot_items(event):
        add(item_name)
        recipe = SCENARIO_AIRDROP_WEAPON_RECIPES.get(item_name, {})
        for child_name in recipe.get("attachments", []):
            add(child_name)
        for child_name in recipe.get("supplies", []):
            add(child_name)
    return classes


def add_cfgspawnabletypes_item(parent_node, item_name, chance="1.00"):
    attrs = {
        "name": str(item_name),
        "chance": str(chance),
    }
    attrs.update(scenario_spawnabletypes_quantity_attrs(item_name))
    ET.SubElement(parent_node, "item", attrs)


def replace_spawnabletypes_group(type_node, tag_name, items):
    clean_items = [
        str(item).strip()
        for item in items
        if str(item).strip()
    ]
    if not clean_items:
        return False

    signature = tuple(sorted(
        (
            item,
            scenario_spawnabletypes_quantity_attrs(item).get("quantmin", ""),
            scenario_spawnabletypes_quantity_attrs(item).get("quantmax", ""),
        )
        for item in clean_items
    ))
    for group_node in list(type_node.findall(tag_name)):
        if cfgspawnabletypes_item_signature(group_node) == signature:
            type_node.remove(group_node)

    remove_wandering_xml_comments(type_node, f"managed spawnabletypes {tag_name}")
    append_wandering_xml_comment(
        type_node,
        f"managed spawnabletypes {tag_name} for {type_node.get('name') or 'unknown'}",
    )
    group_node = ET.SubElement(type_node, tag_name, {"chance": "1.00"})
    for item in clean_items:
        add_cfgspawnabletypes_item(group_node, item)
    return True


def remove_spawnabletypes_preset_refs(type_node):
    removed = 0
    for group_tag in ("cargo", "attachments"):
        for group_node in list(type_node.findall(group_tag)):
            if str(group_node.get("preset") or "").strip():
                type_node.remove(group_node)
                removed += 1
    return removed


def sanitize_spawnabletypes_ignored_items(root):
    removed_items = 0
    removed_groups = 0
    for type_node in root.findall("type"):
        for group_tag in ("cargo", "attachments"):
            for group_node in list(type_node.findall(group_tag)):
                touched_group = False
                for item_node in list(group_node.findall("item")):
                    item_key = normalize_discord_name(item_node.get("name") or "")
                    if item_key in INVALID_SPAWNABLETYPE_ITEM_KEYS:
                        group_node.remove(item_node)
                        removed_items += 1
                        touched_group = True
                if touched_group and not group_node.findall("item"):
                    type_node.remove(group_node)
                    removed_groups += 1
    return removed_items, removed_groups


def merge_airdrop_loot_into_spawnabletypes(root, events):
    changed_classes = set()
    cargo_blocks = 0
    preset_refs_removed = 0

    for event in events:
        if event.get("event_type") not in {"airdrop", "vehicle_spawn"}:
            continue

        class_name = scenario_container_class_for_ce(event.get("class_name"))
        loot = scenario_loot_items(event)
        if not class_name or not loot:
            continue

        if event.get("event_type") == "airdrop":
            for pristine_class in scenario_airdrop_pristine_classes(event, class_name):
                pristine_node, _ = find_or_create_spawnable_type(root, pristine_class)
                removed_refs = remove_spawnabletypes_preset_refs(pristine_node)
                if removed_refs:
                    changed_classes.add(pristine_class)
                    preset_refs_removed += removed_refs
                if set_spawnable_type_pristine(pristine_node):
                    changed_classes.add(pristine_class)

        for weapon_name in scenario_airdrop_ground_loot_items(event):
            recipe = SCENARIO_AIRDROP_WEAPON_RECIPES.get(weapon_name, {})
            attachments = recipe.get("attachments", [])
            if not attachments:
                continue
            weapon_node, _ = find_or_create_spawnable_type(root, weapon_name)
            removed_refs = remove_spawnabletypes_preset_refs(weapon_node)
            if removed_refs:
                changed_classes.add(weapon_name)
                preset_refs_removed += removed_refs
            if replace_spawnabletypes_group(weapon_node, "attachments", attachments):
                changed_classes.add(weapon_name)
                cargo_blocks += 1

        type_node, _ = find_or_create_spawnable_type(root, class_name)
        removed_refs = remove_spawnabletypes_preset_refs(type_node)
        if removed_refs:
            changed_classes.add(class_name)
            preset_refs_removed += removed_refs
        loot = scenario_airdrop_container_loot_items(event) if event.get("event_type") == "airdrop" else loot
        if not loot:
            continue
        signature = tuple(sorted(loot))

        for cargo_node in list(type_node.findall("cargo")):
            if cfgspawnabletypes_loot_signature(cargo_node) == signature:
                type_node.remove(cargo_node)

        cargo_node = ET.SubElement(type_node, "cargo", {"chance": "1.00"})
        for item_name in loot:
            add_cfgspawnabletypes_item(cargo_node, item_name)

        changed_classes.add(class_name)
        cargo_blocks += 1

    return sorted(changed_classes), cargo_blocks, preset_refs_removed


def ce_decimal(value, default=0):
    parsed = parse_dayz_map_number(value)
    if parsed is None:
        parsed = default
    return f"{float(parsed):.2f}".rstrip("0").rstrip(".")


def add_console_ce_event_definition(
    root,
    event_name,
    child_type,
    count,
    lifetime,
    restock=0,
    use_eventgroup=False,
    limit_type="child",
    child_lootmin=0,
    child_lootmax=0,
    nominal=None,
    min_count=None,
    max_count=None,
    saferadius=0,
    distanceradius=0,
    cleanupradius=100,
    child_records=None,
    remove_damaged=False,
    empty_children=False,
    secondary="",
):
    append_wandering_xml_comment(root, f"managed event definition {event_name}")
    event_node = ET.SubElement(root, "event", {"name": event_name})
    fields = [
        ("nominal", count if nominal is None else nominal),
        ("min", count if min_count is None else min_count),
        ("max", count if max_count is None else max_count),
        ("lifetime", lifetime),
        ("restock", restock),
        ("saferadius", saferadius),
        ("distanceradius", distanceradius),
        ("cleanupradius", cleanupradius),
    ]
    for tag, value in fields:
        child = ET.SubElement(event_node, tag)
        child.text = str(int(value))

    secondary = str(secondary or "").strip()
    if secondary:
        secondary_node = ET.SubElement(event_node, "secondary")
        secondary_node.text = secondary

    flags = ET.SubElement(event_node, "flags")
    flags.set("deletable", "1")
    flags.set("init_random", "0")
    flags.set("remove_damaged", "1" if remove_damaged else "0")

    position = ET.SubElement(event_node, "position")
    position.text = "fixed"
    limit = ET.SubElement(event_node, "limit")
    limit.text = str(limit_type or "child")
    active = ET.SubElement(event_node, "active")
    active.text = "1"

    children = ET.SubElement(event_node, "children")
    if empty_children:
        return event_node
    child_records = child_records if isinstance(child_records, list) and child_records else [{
        "type": child_type,
        "count": count,
        "lootmin": child_lootmin,
        "lootmax": child_lootmax,
    }]
    for child_record in child_records:
        child_count = max(1, int(child_record.get("count") or count or 1))
        if "max" in child_record:
            child_max = max(0, int(child_record.get("max") or 0))
        elif use_eventgroup:
            child_max = max(1, int(max_count if max_count is not None else child_count))
        else:
            child_max = child_count
        if "min" in child_record:
            child_min = max(0, int(child_record.get("min") or 0))
        elif child_max <= 0:
            child_min = child_count
        else:
            child_min = max(0, min(child_count, child_max))
        ET.SubElement(children, "child", {
            "lootmax": str(int(child_record.get("lootmax", child_lootmax) or 0)),
            "lootmin": str(int(child_record.get("lootmin", child_lootmin) or 0)),
            "max": str(child_max),
            "min": str(child_min),
            "type": str(child_record.get("type") or child_type),
        })
    return event_node


def set_ce_event_text_value(event_node, tag_name, value):
    child = event_node.find(tag_name)
    if child is None:
        child = ET.SubElement(event_node, tag_name)
    wanted = str(int(value))
    if str(child.text or "").strip() == wanted:
        return False
    child.text = wanted
    return True


def patch_existing_console_ce_event_definition(root, record):
    event_name = str(record.get("name") or "").strip()
    if not event_name:
        return False
    event_node = root.find(f"./event[@name='{event_name}']")
    if event_node is None:
        add_console_ce_event_definition(
            root,
            event_name,
            record.get("event_child_type") or record.get("class_name"),
            record.get("count", 1),
            record.get("lifetime", 3600),
            restock=record.get("restock", 0),
            limit_type=record.get("limit_type") or "custom",
            child_lootmin=record.get("child_lootmin", 0),
            child_lootmax=record.get("child_lootmax", 0),
            nominal=record.get("nominal"),
            min_count=record.get("min_count"),
            max_count=record.get("max_count"),
            saferadius=record.get("saferadius", 0),
            distanceradius=record.get("distanceradius", 0),
            cleanupradius=record.get("cleanupradius", 100),
            child_records=record.get("child_records"),
            remove_damaged=bool(record.get("remove_damaged")),
            secondary=record.get("secondary", ""),
        )
        return True
    changed = False
    count = max(1, safe_int(record.get("count"), 1))
    current_max = safe_int(event_node.findtext("max"), count)
    changed |= set_ce_event_text_value(event_node, "nominal", count)
    changed |= set_ce_event_text_value(event_node, "min", count)
    changed |= set_ce_event_text_value(event_node, "max", max(count, current_max))
    return changed


def scenario_airdrop_scene_type(event):
    scene_type = re.sub(r"[^a-z0-9_]+", "_", str((event or {}).get("scene_type") or "compact_crater").strip().lower()).strip("_")
    return scene_type if scene_type in SCENARIO_AIRDROP_SCENES else "compact_crater"


def scenario_airdrop_scene_config(event):
    return SCENARIO_AIRDROP_SCENES[scenario_airdrop_scene_type(event)]


def scenario_airdrop_scene_min_radius(event):
    scene = scenario_airdrop_scene_config(event)
    return max(0, int(scene.get("min_radius") or 0))


def scenario_airdrop_primary_static_child(event, class_name):
    if event.get("visual_marker"):
        marker_class = str(
            scenario_airdrop_scene_config(event).get("marker")
            or event.get("marker_class")
            or ""
        ).strip()
        if marker_class:
            return marker_class
    return str(class_name or "").strip()


def scenario_airdrop_anchor_class(event, class_name):
    class_name = str(class_name or "").strip()
    marker_class = str(
        scenario_airdrop_scene_config(event).get("marker")
        or event.get("marker_class")
        or SCENARIO_AIRDROP_MARKER_CLASS
    ).strip()
    if str(class_name or "").strip().lower() in SCENARIO_AIRDROP_RETIRED_ANCHOR_CLASSES:
        return marker_class or SCENARIO_AIRDROP_MARKER_CLASS
    if event.get("visual_marker") and marker_class:
        return marker_class
    return class_name or marker_class or SCENARIO_AIRDROP_MARKER_CLASS


def scenario_airdrop_child_offsets(index, radius=35, max_spread=None):
    try:
        radius_value = float(radius or 35)
    except Exception:
        radius_value = 35.0
    spread_cap = float(max_spread or 18)
    spread = max(4.0, min(spread_cap, radius_value / 2.5))
    ring = index // 8
    slot = index % 8
    distance = min(spread, 5.5 + (ring * 6.0))
    angle = math.radians((slot * 45) + (ring * 22.5))
    return (math.cos(angle) * distance, math.sin(angle) * distance)


def scenario_airdrop_eventgroup_children(event, class_name):
    children = []

    scene = scenario_airdrop_scene_config(event)
    marker_class = scenario_airdrop_anchor_class(event, class_name)
    loot_count = max(1, min(80, safe_int(event.get("lootmax"), 15)))
    loot_min = max(0, min(loot_count, safe_int(event.get("lootmin"), max(1, loot_count // 2))))
    guard_class = str(event.get("guard_class") or "").strip()
    guard_count = ce_event_nominal_count(event, event.get("guard_count", 0)) if guard_class else 0
    guard_radius = max(5, min(500, safe_int(event.get("guard_radius"), event.get("radius") or 35)))

    def append_guard_children():
        for index in range(max(0, min(80, guard_count))):
            guard_x, guard_z = scenario_airdrop_child_offsets(index, guard_radius, max_spread=guard_radius)
            children.append({
                "type": guard_class,
                "spawnsecondary": "false",
                "x": ce_decimal(guard_x),
                "z": ce_decimal(guard_z),
                "a": "0.0",
                "y": "0.0",
            })

    if event.get("visual_marker") and marker_class:
        children.append({
            "type": marker_class,
            "x": "0.0",
            "z": "0.0",
            "a": "0.0",
            "y": "0.0",
            "min": 1,
            "max": 1,
            "lootmin": loot_min,
            "lootmax": loot_count,
        })
        for scene_prop in scene.get("props") or SCENARIO_AIRDROP_SCENE_PROPS:
            children.append({
                "type": scene_prop["type"],
                "spawnsecondary": "false",
                "x": scene_prop["x"],
                "y": scene_prop["y"],
                "z": scene_prop["z"],
                "a": scene_prop["a"],
            })
        append_guard_children()
        return children

    crate_x, crate_z = scene.get("crate_offset") or ("4.6", "-3.2")
    if not children:
        crate_x, crate_z = "0.0", "0.0"
    children.append({
        "type": class_name,
        "x": crate_x,
        "z": crate_z,
        "a": "0.0",
        "y": "0.0",
        "min": 1,
        "max": 1,
        "lootmin": 0,
        "lootmax": 0,
    })
    append_guard_children()
    return children


def scenario_airdrop_direct_child_records(event, class_name):
    marker_class = scenario_airdrop_anchor_class(event, class_name)
    loot_count = max(1, min(80, safe_int(event.get("lootmax"), 15)))
    loot_min = max(0, min(loot_count, safe_int(event.get("lootmin"), max(1, loot_count // 2))))
    return [{
        "type": marker_class,
        "count": 1,
        "min": 1,
        "max": 1,
        "lootmin": loot_min,
        "lootmax": loot_count,
    }]


def scenario_airdrop_uses_eventgroup(event):
    if not (event or {}).get("visual_marker"):
        return False
    scene = scenario_airdrop_scene_config(event or {})
    return bool(scene.get("props"))


def scenario_airdrop_secondary_infected(event):
    guard_class = str((event or {}).get("guard_class") or "").strip()
    guard_count = ce_event_nominal_count(event or {}, (event or {}).get("guard_count", 0)) if guard_class else 0
    return SCENARIO_AIRDROP_SECONDARY_INFECTED if guard_class and guard_count > 0 else ""


def add_console_ce_event_group(root, group_name, child_type, lootmin=40, lootmax=80, child_records=None):
    append_wandering_xml_comment(root, f"managed eventgroup {group_name}")
    group_node = ET.SubElement(root, "group", {"name": str(group_name)})
    child_records = child_records if isinstance(child_records, list) and child_records else [{
        "type": child_type,
        "lootmin": lootmin,
        "lootmax": lootmax,
        "x": "0.0",
        "z": "0.0",
        "a": "0.0",
        "y": "0.0",
    }]
    for child_record in child_records:
        attrs = {
            "type": str(child_record.get("type") or child_type),
            "x": str(child_record.get("x", "0.0")),
            "z": str(child_record.get("z", "0.0")),
            "a": str(child_record.get("a", "0.0")),
            "y": str(child_record.get("y", "0.0")),
        }
        if str(child_record.get("spawnsecondary") or "").strip():
            attrs["spawnsecondary"] = str(child_record.get("spawnsecondary"))
        else:
            attrs["deloot"] = "1"
            if "min" in child_record:
                attrs["min"] = str(max(0, int(child_record.get("min") or 0)))
            if "max" in child_record:
                attrs["max"] = str(max(0, int(child_record.get("max") or 0)))
            attrs["lootmin"] = str(max(0, int(child_record.get("lootmin", lootmin) or 0)))
            attrs["lootmax"] = str(max(0, int(child_record.get("lootmax", lootmax) or 0)))
        ET.SubElement(group_node, "child", attrs)
    return group_node


STALE_AIRDROP_PROTO_CLASSES = {
    "staticobj_misc_woodencrate_5x",
    "woodencrate",
    "supplycrate",
    "crate",
    "seachest",
    "barrel_green",
}


def mapgroupproto_group_looks_like_legacy_bare_airdrop_proto(group_node):
    if getattr(group_node, "tag", None) != "group":
        return False
    name = str(group_node.get("name") or "").strip().lower()
    if name not in STALE_AIRDROP_PROTO_CLASSES:
        return False
    if group_node.findall("container"):
        return False
    child_tags = {
        str(getattr(child, "tag", "") or "").lower()
        for child in list(group_node)
        if not is_xml_comment_node(child)
    }
    return child_tags.issubset({"usage", "point", "value"})


def mapgroupproto_group_looks_like_old_airdrop_proto(group_node):
    # Only explicit legacy bot fingerprints count as stale. A previous broad
    # lootfloor+categories heuristic also matched community packs like
    # StaticLivoniaRevampLoot and silently deleted their
    # <group name="StaticObj_Misc_WoodenCrate_5x"> on every upload, which left
    # the live RPT spamming:
    #   [CE][SpawnRandomLoot] (StaticLivoniaRevampLoot_NN) :: !!! No group
    #   configured for 'StaticObj_Misc_WoodenCrate_5x', failed to spawn loot
    if mapgroupproto_group_looks_like_legacy_bare_airdrop_proto(group_node):
        return True
    name = str(group_node.get("name") or "").strip().lower()
    if name not in STALE_AIRDROP_PROTO_CLASSES:
        return False
    for value_node in group_node.findall("value"):
        if str(value_node.get("name") or "").strip().lower() == "tier4":
            return True
    return False


def cleanup_stale_mapgroupproto_airdrop_nodes(root, map_key=""):
    removed_groups = 0
    removed_values = 0
    changed = False
    if str(root.tag or "").strip().lower() in {"mapgroupproto", "map"}:
        root.tag = "prototype"
        changed = True

    remove_next_managed_group = False
    for group_node in list(root.findall("group")):
        if "wanderingbot" in normalize_discord_name(group_node.get("name") or ""):
            root.remove(group_node)
            removed_groups += 1
            changed = True

    for child in list(root):
        if is_xml_comment_node(child):
            text = str(child.text or "").strip().lower()
            if "wandering bot:" in text and "managed mapgroupproto group" in text:
                root.remove(child)
                remove_next_managed_group = True
                changed = True
            continue
        if remove_next_managed_group:
            root.remove(child)
            removed_groups += 1
            changed = True
            remove_next_managed_group = False

    return changed, removed_groups, removed_values


