def mapgroupproto_positive_int(value, default=0):
    try:
        return max(0, int(str(value or "").strip() or default))
    except Exception:
        return max(0, int(default or 0))


def mapgroupproto_group_has_usable_loot_container(group_node):
    if group_node is None:
        return False
    for container_node in group_node.findall("container"):
        if mapgroupproto_positive_int(container_node.get("lootmax")) <= 0:
            continue
        if (
            container_node.findall("category")
            and container_node.findall("tag")
            and container_node.findall("point")
        ):
            return True
    return False


def scenario_mapgroupproto_loot_tag_keys(event):
    keys = []

    def add(key):
        key = str(key or "").strip().lower()
        if key and key != "none" and key not in keys:
            keys.append(key)

    add(event.get("loot_preset"))
    mix = event.get("loot_mix")
    if isinstance(mix, dict):
        for key, value in mix.items():
            if safe_int(value, 0) > 0:
                add(key)
    if not keys and event.get("event_type") in {"airdrop", "loot_crate"}:
        add("military")
    return keys


def scenario_mapgroupproto_loot_tags(event):
    usages = []
    values = []
    categories = []

    def add_unique(target, values):
        for value in values or ():
            value = str(value or "").strip()
            if value and value not in target:
                target.append(value)

    for key in scenario_mapgroupproto_loot_tag_keys(event):
        tags = MAPGROUPPROTO_LOOT_TAGS_BY_KEY.get(key, {})
        add_unique(usages, tags.get("usage"))
        add_unique(values, tags.get("value"))
        add_unique(categories, tags.get("category"))
    if not usages:
        usages = ["Military"]
    if not values:
        values = ["Tier3", "Tier4"]
    if not categories:
        categories = list(MAPGROUPPROTO_LOOT_CATEGORIES)
    return {"usage": usages, "value": values, "category": categories}


def mapgroupproto_uses_generic_single_point(container_node):
    points = list(container_node.findall("point")) if container_node is not None else []
    if len(points) != 1:
        return False
    point = points[0]
    return str(point.get("pos") or "").strip() in {"0 0 0", "0.0 0.0 0.0"}


def ensure_mapgroupproto_loot_container(group_node, lootmax=80, tags=None, class_name=""):
    target_lootmax = str(max(1, int(lootmax or 80)))
    tags = tags if isinstance(tags, dict) else {}
    wanted_usages = [str(item).strip() for item in tags.get("usage", []) if str(item).strip()]
    wanted_values = [str(item).strip() for item in tags.get("value", []) if str(item).strip()]
    wanted_categories = [str(item).strip() for item in tags.get("category", []) if str(item).strip()]
    if not wanted_usages:
        wanted_usages = ["Military"]
    if not wanted_values:
        wanted_values = ["Tier3", "Tier4"]
    if not wanted_categories:
        wanted_categories = list(MAPGROUPPROTO_LOOT_CATEGORIES)
    changed = False

    if mapgroupproto_positive_int(group_node.get("lootmax")) <= 0:
        group_node.set("lootmax", target_lootmax)
        changed = True
    wanted_usage_set = {name.lower() for name in wanted_usages}
    for usage_node in list(group_node.findall("usage")):
        if str(usage_node.get("name") or "").strip().lower() not in wanted_usage_set:
            group_node.remove(usage_node)
            changed = True
    if not group_node.findall("usage"):
        for usage_name in wanted_usages:
            ET.SubElement(group_node, "usage", {"name": usage_name})
            changed = True
    wanted_value_set = {name.lower() for name in wanted_values}
    for value_node in list(group_node.findall("value")):
        if str(value_node.get("name") or "").strip().lower() not in wanted_value_set:
            group_node.remove(value_node)
            changed = True
    if not group_node.findall("value"):
        for value_name in wanted_values:
            ET.SubElement(group_node, "value", {"name": value_name})
            changed = True
    for point_node in list(group_node.findall("point")):
        group_node.remove(point_node)
        changed = True

    containers = list(group_node.findall("container"))
    container = next(
        (
            node
            for node in containers
            if str(node.get("name") or "").strip().lower() == "lootfloor"
        ),
        None,
    )
    if container is None:
        container = containers[0] if containers else None
    if container is None:
        container = ET.SubElement(group_node, "container", {"name": "lootFloor", "lootmax": target_lootmax})
        changed = True
    else:
        container_name = str(container.get("name") or "").strip()
        if not container_name or (container_name.lower() == "lootfloor" and container_name != "lootFloor"):
            container.set("name", "lootFloor")
            changed = True
        if mapgroupproto_positive_int(container.get("lootmax")) <= 0:
            container.set("lootmax", target_lootmax)
            changed = True

    if not container.findall("category"):
        for category_name in wanted_categories:
            ET.SubElement(container, "category", {"name": category_name})
        changed = True
    existing_tags = {
        str(tag_node.get("name") or "").strip().lower()
        for tag_node in container.findall("tag")
    }
    if not existing_tags:
        ET.SubElement(container, "tag", {"name": "floor"})
        changed = True
        existing_tags.add("floor")
    if str(class_name or "").strip().lower() == "wreck_mi8_crashed" and "shelves" not in existing_tags:
        ET.SubElement(container, "tag", {"name": "shelves"})
        changed = True

    if not container.findall("point"):
        point_records = SCENARIO_MI8_LOOT_POINTS if str(class_name or "").strip().lower() == "wreck_mi8_crashed" else [{
            "pos": "0 0 0",
            "range": "0.5",
            "height": "0.5",
            "flags": "32",
        }]
        for point_record in point_records:
            attrs = dict(point_record)
            attrs.setdefault("flags", "32")
            ET.SubElement(container, "point", attrs)
        changed = True
    elif str(class_name or "").strip().lower() == "wreck_mi8_crashed" and mapgroupproto_uses_generic_single_point(container):
        for point in list(container.findall("point")):
            container.remove(point)
        for point_record in SCENARIO_MI8_LOOT_POINTS:
            attrs = dict(point_record)
            attrs.setdefault("flags", "32")
            ET.SubElement(container, "point", attrs)
        changed = True
    else:
        for point in container.findall("point"):
            if not str(point.get("flags") or "").strip():
                point.set("flags", "32")
                changed = True
    return changed


def eventgroup_child_needs_mapgroupproto(child_record):
    if not isinstance(child_record, dict):
        return False
    if str(child_record.get("spawnsecondary") or "").strip().lower() == "false":
        return False
    return bool(str(child_record.get("type") or "").strip())


def find_managed_mapgroupproto_group(root, class_name):
    wanted = str(class_name or "").strip().lower()
    pending_managed_comment = False
    for child in list(root):
        if is_xml_comment_node(child):
            text = str(child.text or "").strip().lower()
            pending_managed_comment = "wandering bot:" in text and "managed mapgroupproto group" in text
            continue
        if (
            pending_managed_comment
            and str(getattr(child, "tag", "") or "") == "group"
            and str(child.get("name") or "").strip().lower() == wanted
        ):
            return child
        pending_managed_comment = False
    return None


def find_usable_unmanaged_mapgroupproto_group(root, class_name):
    wanted = str(class_name or "").strip().lower()
    pending_managed_comment = False
    for child in list(root):
        if is_xml_comment_node(child):
            text = str(child.text or "").strip().lower()
            pending_managed_comment = "wandering bot:" in text and "managed mapgroupproto group" in text
            continue
        is_managed = pending_managed_comment
        pending_managed_comment = False
        if (
            not is_managed
            and str(getattr(child, "tag", "") or "") == "group"
            and str(child.get("name") or "").strip().lower() == wanted
            and mapgroupproto_group_has_usable_loot_container(child)
        ):
            return child
    return None


def add_mapgroupproto_loot_group(root, class_name, lootmax=80, tags=None):
    # Non-destructive: unmarked live groups stay byte-for-byte under the
    # snippet scope guard. If WanderingBot needs a proto, append its own marked
    # group at the end and only refresh that marked block on later retries.
    #
    # The appended group seeds a real <container> + canonical categories so
    # DayZ has a loot pool to spawn from.
    wanted = str(class_name or "").strip()
    if not wanted:
        return None, False
    managed_group = find_managed_mapgroupproto_group(root, wanted)
    if managed_group is not None:
        changed = ensure_mapgroupproto_loot_container(managed_group, lootmax=lootmax, tags=tags, class_name=wanted)
        return managed_group, changed
    usable_unmanaged = find_usable_unmanaged_mapgroupproto_group(root, wanted)
    if usable_unmanaged is not None:
        return usable_unmanaged, False

    append_wandering_xml_comment(root, f"managed mapgroupproto group {wanted}")
    group_node = ET.SubElement(root, "group", {"name": wanted})
    ensure_mapgroupproto_loot_container(group_node, lootmax=lootmax, tags=tags, class_name=wanted)
    return group_node, True


def find_or_create_named_child(root, tag_name, name, comment_text=""):
    wanted = str(name or "").strip()
    for child in root.findall(tag_name):
        if str(child.get("name") or "").strip().lower() == wanted.lower():
            return child, False
    if comment_text:
        append_wandering_xml_comment(root, comment_text)
    return ET.SubElement(root, tag_name, {"name": wanted}), True


def console_ce_event_uses_zone_spawn(event_name):
    name = str(event_name or "").strip()
    return name.startswith(CONSOLE_CE_ZONE_SPAWN_FAMILIES)


def console_ce_event_is_static_gas_zone(event_name):
    name = str(event_name or "").strip()
    return (
        name.startswith("Static")
        and CONSOLE_CE_EVENT_MARKER in name
        and "gaszone" in normalize_discord_name(name)
    )


def console_ce_vehicle_spawn_positions(x, z, angle=0, radius=45):
    base_x = parse_dayz_map_number(x)
    base_z = parse_dayz_map_number(z)
    base_angle = parse_dayz_map_number(angle) or 0
    if base_x is None or base_z is None:
        return [(x, z, base_angle)]

    try:
        spread = int(radius or 45)
    except Exception:
        spread = 45
    spread = max(12, min(75, spread or 45))
    diagonal = round(spread * 0.7, 3)
    offsets = [
        (0, 0),
        (spread, 0),
        (-spread, 0),
        (0, spread),
        (0, -spread),
        (diagonal, diagonal),
        (-diagonal, diagonal),
        (diagonal, -diagonal),
        (-diagonal, -diagonal),
    ]
    positions = []
    seen = set()
    for dx, dz in offsets:
        pos_x = round(base_x + dx, 3)
        pos_z = round(base_z + dz, 3)
        key = (pos_x, pos_z)
        if key in seen:
            continue
        seen.add(key)
        positions.append((pos_x, pos_z, base_angle))
    return positions


def console_ce_spread_positions(x, z, angle=0, radius=45, count=1):
    base_x = parse_dayz_map_number(x)
    base_z = parse_dayz_map_number(z)
    base_angle = parse_dayz_map_number(angle) or 0
    count = max(1, min(80, safe_int(count, 1)))
    if base_x is None or base_z is None or count == 1:
        return [(x, z, base_angle)]
    spread = max(6, min(250, safe_int(radius, 45)))
    positions = [(round(base_x, 3), round(base_z, 3), base_angle)]
    for index in range(1, count):
        ring = (index - 1) // 8
        slot = (index - 1) % 8
        distance = min(spread, 8 + (ring * 8))
        pos_angle = (slot * 45) + (ring * 22.5)
        radians = math.radians(pos_angle)
        positions.append((
            round(base_x + (math.cos(radians) * distance), 3),
            round(base_z + (math.sin(radians) * distance), 3),
            round((base_angle + pos_angle) % 360, 3),
        ))
    return positions


def remove_matching_console_ce_spawn_children(event_node, x, z, radius=None, group_name=""):
    target_x = ce_decimal(x)
    target_z = ce_decimal(z)
    target_radius = str(max(1, int(radius or 45))) if radius is not None else ""
    removed = 0
    for child in list(event_node):
        if child.tag not in {"pos", "zone"}:
            continue
        if ce_decimal(child.get("x")) != target_x or ce_decimal(child.get("z")) != target_z:
            continue
        if group_name and str(child.get("group") or "") != str(group_name):
            continue
        if child.tag == "zone" and target_radius and str(child.get("r") or "") != target_radius:
            continue
        event_node.remove(child)
        removed += 1
    return removed


def cleanup_wandering_marked_spawn_children(root):
    removed = 0
    for event_node in root.findall("event"):
        removed += remove_wandering_marked_spawn_children(event_node)
    return removed


def add_console_ce_event_spawn(root, event_name, x, z, angle=0, count=1, radius=45, y=None, group_name="", empty=False):
    event_node, _ = find_or_create_named_child(root, "event", event_name, f"managed spawn block {event_name}")
    if empty:
        return event_node
    count = max(1, int(count or 1))
    radius = max(0, int(radius or 0))
    remove_wandering_marked_spawn_children(event_node)
    remove_matching_console_ce_spawn_children(event_node, x, z, radius, group_name)
    # DayZ samples terrain height for cfgeventspawns positions; forcing y can reject spawns.
    if group_name:
        attrs = {
            "x": ce_decimal(x),
            "z": ce_decimal(z),
            "a": ce_decimal(angle),
            "group": str(group_name),
        }
        append_wandering_xml_comment(event_node, f"managed spawn position {event_name}")
        ET.SubElement(event_node, "pos", attrs)
        return event_node

    if event_name in VANILLA_ANIMAL_CE_EVENT_NAMES:
        for pos_x, pos_z, pos_angle in console_ce_spread_positions(x, z, angle=angle, radius=radius or 45, count=count):
            append_wandering_xml_comment(event_node, f"managed spawn position {event_name}")
            ET.SubElement(event_node, "pos", {
                "x": ce_decimal(pos_x),
                "z": ce_decimal(pos_z),
                "a": ce_decimal(pos_angle),
                "active": "1",
            })
        return event_node

    if console_ce_event_is_static_gas_zone(event_name):
        append_wandering_xml_comment(event_node, f"managed spawn radius {event_name}")
        ET.SubElement(event_node, "zone", {
            "smin": "0",
            "smax": "0",
            "dmin": "1",
            "dmax": str(count),
            "r": str(max(1, radius or 45)),
        })
        append_wandering_xml_comment(event_node, f"managed spawn position {event_name}")
        ET.SubElement(event_node, "pos", {
            "x": ce_decimal(x),
            "z": ce_decimal(z),
            "a": ce_decimal(angle),
        })
        return event_node

    if console_ce_event_uses_zone_spawn(event_name) and not (
        event_name.startswith("Animal") and CONSOLE_CE_EVENT_MARKER in event_name
    ):
        append_wandering_xml_comment(event_node, f"managed spawn position {event_name}")
        ET.SubElement(event_node, "zone", {
            "smin": "1",
            "smax": str(count),
            "dmin": "1",
            "dmax": str(count),
            "x": ce_decimal(x),
            "z": ce_decimal(z),
            "r": str(max(1, radius or 45)),
        })
    if event_name.startswith("Vehicle") and CONSOLE_CE_EVENT_MARKER in event_name:
        for pos_x, pos_z, pos_angle in console_ce_vehicle_spawn_positions(x, z, angle=angle, radius=radius or 45):
            append_wandering_xml_comment(event_node, f"managed spawn position {event_name}")
            ET.SubElement(event_node, "pos", {
                "x": ce_decimal(pos_x),
                "z": ce_decimal(pos_z),
                "a": ce_decimal(pos_angle),
            })
        return event_node
    if event_name.startswith("Animal") and CONSOLE_CE_EVENT_MARKER in event_name:
        for pos_x, pos_z, pos_angle in console_ce_spread_positions(x, z, angle=angle, radius=radius or 45, count=count):
            append_wandering_xml_comment(event_node, f"managed spawn position {event_name}")
            ET.SubElement(event_node, "pos", {
                "x": ce_decimal(pos_x),
                "z": ce_decimal(pos_z),
                "a": ce_decimal(pos_angle),
                "active": "1",
            })
        return event_node
    attrs = {
        "x": ce_decimal(x),
        "z": ce_decimal(z),
        "a": ce_decimal(angle),
    }
    append_wandering_xml_comment(event_node, f"managed spawn position {event_name}")
    ET.SubElement(event_node, "pos", attrs)
    return event_node


ANIMAL_TERRITORY_PROFILES = {
    "Animal_UrsusArctos": {
        "species": "Bear",
        "behavior": "BlissBearGroupBeh",
        "zone": "HuntingGround",
        "color": "4294923520",
    },
    "Animal_CanisLupus_Grey": {
        "species": "Wolf",
        "behavior": "DZWolfGroupBeh",
        "zone": "HuntingGround",
        "color": "4291611852",
    },
    "Animal_CanisLupus_White": {
        "species": "Wolf",
        "behavior": "DZWolfGroupBeh",
        "zone": "HuntingGround",
        "color": "4291611852",
    },
    "Animal_CervusElaphus": {
        "species": "Deer",
        "behavior": "DZDeerGroupBeh",
        "zone": "Graze",
        "color": "4286611584",
    },
    "Animal_SusScrofa": {
        "species": "WildBoar",
        "behavior": "DZDeerGroupBeh",
        "zone": "Graze",
        "color": "4286611584",
    },
}


def animal_territory_profile(class_name):
    class_name = str(class_name or "").strip()
    if class_name in ANIMAL_TERRITORY_PROFILES:
        return dict(ANIMAL_TERRITORY_PROFILES[class_name])
    if "Ursus" in class_name:
        return dict(ANIMAL_TERRITORY_PROFILES["Animal_UrsusArctos"])
    if "CanisLupus" in class_name:
        return dict(ANIMAL_TERRITORY_PROFILES["Animal_CanisLupus_Grey"])
    if "Cervus" in class_name or "Capreolus" in class_name:
        return dict(ANIMAL_TERRITORY_PROFILES["Animal_CervusElaphus"])
    if "SusScrofa" in class_name:
        return dict(ANIMAL_TERRITORY_PROFILES["Animal_SusScrofa"])
    return {
        "species": "Animal",
        "behavior": "DZDeerGroupBeh",
        "zone": "Graze",
        "color": "4286611584",
    }


def remote_mission_base_from_ce_paths(built):
    for key, suffix in (
        ("spawns_path", "/cfgeventspawns.xml"),
        ("events_path", "/db/events.xml"),
        ("cfgenvironment_path", "/cfgenvironment.xml"),
    ):
        path = canonical_remote_path(built.get(key) or "")
        if path.lower().endswith(suffix.lower()):
            return path[:-len(suffix)]
    return ""


def ce_file_slug(value):
    slug = re.sub(r"[^a-z0-9_]+", "_", str(value or "").strip().lower()).strip("_")
    return re.sub(r"_+", "_", slug)


def animal_territory_file_name(record):
    safe = ce_file_slug(record.get("territory_file_key") or record.get("territory_name") or record.get("name") or "animal")
    return f"wanderingbot_{safe}_territories.xml"[:96]


def animal_territory_remote_path(mission_base, record):
    return canonical_remote_path(f"{mission_base}/env/{animal_territory_file_name(record)}")


def animal_territory_usable_name(record):
    return os.path.splitext(animal_territory_file_name(record))[0]


def animal_territory_group_key(record):
    profile = animal_territory_profile(record.get("class_name"))
    species = normalize_discord_name(profile.get("species") or record.get("class_name") or "animal")
    behavior = normalize_discord_name(profile.get("behavior") or record.get("animal_behavior") or "animal")
    return f"{species}_{behavior}"[:60] or "animal"


def group_animal_territory_records(records):
    groups = {}
    for record in records:
        key = ce_file_slug(record.get("territory_file_key") or record.get("territory_name") or record.get("name") or animal_territory_group_key(record))
        if key.startswith("wanderingbot"):
            key = re.sub(r"^wanderingbot_?", "", key)
        if key.startswith("animal") and not key.startswith("animal_") and len(key) > len("animal"):
            key = f"animal_{key[len('animal'):]}"
        elif not key.startswith("animal_"):
            key = f"animal_{key}"
        group = groups.setdefault(key, {
            "territory_file_key": key,
            "territory_name": record.get("territory_name") or f"WanderingBot_{key}",
            "animal_behavior": record.get("animal_behavior"),
            "territory_zone": record.get("territory_zone"),
            "territory_color": record.get("territory_color"),
            "records": [],
            "event_names": [],
        })
        group["records"].append(record)
        group["event_names"].append(str(record.get("name") or ""))
    return list(groups.values())


def remove_wandering_environment_nodes(root):
    territories = root.find("territories") if root.tag != "territories" else root
    if territories is None:
        return 0, 0

    removed_files = 0
    removed_territories = 0
    for child in list(territories):
        if child.tag == "file":
            path = str(child.get("path") or "").lower()
            if "wanderingbot" in normalize_discord_name(path):
                territories.remove(child)
                removed_files += 1
        elif child.tag == "territory":
            name = str(child.get("name") or "").lower()
            usable_names = [
                str(file_node.get("usable") or "").lower()
                for file_node in child.findall("file")
            ]
            if (
                "wanderingbot" in normalize_discord_name(name)
                or any("wanderingbot" in normalize_discord_name(usable) for usable in usable_names)
            ):
                territories.remove(child)
                removed_territories += 1
    return removed_files, removed_territories


def add_animal_environment_entry(root, record):
    territories = root.find("territories") if root.tag != "territories" else root
    if territories is None:
        territories = ET.SubElement(root, "territories")

    usable = animal_territory_usable_name(record)
    file_path = f"env/{animal_territory_file_name(record)}"
    append_wandering_xml_comment(territories, f"managed animal territory file {file_path}")
    ET.SubElement(territories, "file", {"path": file_path})
    append_wandering_xml_comment(territories, f"managed animal territory {record.get('territory_name') or record.get('name')}")
    territory_node = ET.SubElement(territories, "territory", {
        "type": "Herd",
        "name": str(record.get("territory_name") or record.get("name")),
        "behavior": str(record.get("animal_behavior") or "DZDeerGroupBeh"),
    })
    ET.SubElement(territory_node, "file", {"usable": usable})
    records = record.get("records") if isinstance(record.get("records"), list) else [record]
    count = sum(max(1, int(item.get("count") or 1)) for item in records)
    radius = max([max(2, int(item.get("radius") or 20)) for item in records] or [20])
    for name, value in (
        ("globalCountMax", max(count, 1)),
        ("zoneCountMin", count),
        ("zoneCountMax", count),
        ("playerSpawnRadiusNear", 1),
        ("playerSpawnRadiusFar", radius),
    ):
        ET.SubElement(territory_node, "item", {"name": name, "val": str(int(value))})


def build_animal_territory_text(record):
    root = ET.Element("territory-type")
    append_wandering_xml_comment(root, f"managed animal territory zones {record.get('territory_name') or record.get('name')}")
    territory = ET.SubElement(root, "territory", {"color": str(record.get("territory_color") or "4286611584")})
    records = record.get("records") if isinstance(record.get("records"), list) else [record]
    for item in records:
        count = max(1, int(item.get("count") or 1))
        radius = max(1, int(item.get("radius") or 20))
        ET.SubElement(territory, "zone", {
            "name": str(item.get("territory_zone") or record.get("territory_zone") or "Graze"),
            "smin": "0",
            "smax": "0",
            "dmin": str(count),
            "dmax": str(count),
            "x": ce_decimal(item.get("x")),
            "z": ce_decimal(item.get("z")),
            "r": str(radius),
        })
    return xml_text_from_root(root)


def scenario_start_speed_key(event):
    key = normalize_discord_name((event or {}).get("start_speed") or (event or {}).get("spawn_delay") or "fast")
    return key if key in SCENARIO_START_SPEED_OPTIONS else "fast"


def scenario_start_speed_label(event):
    key = scenario_start_speed_key(event)
    return SCENARIO_START_SPEED_OPTIONS.get(key, SCENARIO_START_SPEED_OPTIONS["fast"])


def scenario_speed_defaults(event_type, event, use_eventgroup=False):
    speed = scenario_start_speed_key(event)
    radius = safe_int((event or {}).get("radius"), 70)
    if event_type in {"airdrop", "loot_crate"}:
        normal = {
            "restock": 0,
            "saferadius": 0,
            "distanceradius": 25,
            "cleanupradius": max(100, min(1500, radius * 4)),
        }
    elif event_type == "vehicle_spawn":
        normal = {
            "restock": 0,
            "saferadius": 500,
            "distanceradius": 500,
            "cleanupradius": 200,
        }
    elif event_type in {"zombie_horde", "animal_pack"}:
        normal = {
            "restock": 0,
            "saferadius": 0,
            "distanceradius": 0,
            "cleanupradius": 100,
        }
    else:
        normal = {
            "restock": 3600 if use_eventgroup else 0,
            "saferadius": 0,
            "distanceradius": 1000 if use_eventgroup else 0,
            "cleanupradius": 1500 if use_eventgroup else 100,
        }

    if speed == "normal":
        return normal
    if speed == "slow":
        return {
            **normal,
            "restock": max(normal["restock"], 600),
            "saferadius": max(normal["saferadius"], 250),
            "distanceradius": max(normal["distanceradius"], 750),
        }
    fast = dict(normal)
    fast["restock"] = 0
    fast["saferadius"] = 0
    if event_type == "vehicle_spawn":
        fast["distanceradius"] = 25
    elif event_type in {"zombie_horde", "animal_pack"}:
        fast["distanceradius"] = 0
    elif event_type in {"airdrop", "loot_crate"}:
        fast["distanceradius"] = min(fast["distanceradius"], 25)
    return fast


def console_ce_records_for_event(event):
    event_type = str(event.get("event_type") or "").strip()
    class_name = str(event.get("class_name") or "").strip()
    records = []
    warnings = []

    if event_type in {"vehicle_reset_all", "vehicle_reset_point"}:
        warnings.append(
            f"`{event.get('id')}` is a vehicle reset. Native console XML can add vehicle spawn events, but it cannot delete/reset existing vehicles on command."
        )
        return records, warnings

    if not class_name:
        warnings.append(f"`{event.get('id')}` has no classname, so it was skipped.")
        return records, warnings

    count = ce_event_nominal_count(event)
    lifetime = 3600
    if event_type == "vehicle_spawn":
        count = 1
        lifetime = 3888000
    elif event_type in {"airdrop", "loot_crate"}:
        count = 1
        lifetime = 7200
    elif event_type == "zombie_horde":
        lifetime = 1800
    elif event_type == "animal_pack":
        lifetime = 3600
    elif event_type == "gas_zone":
        count = 1
        lifetime = max(60, min(3888000, safe_int(event.get("gas_lifetime"), 3888000 if event.get("permanent") else 1800)))
    lifetime = max(60, min(3888000, safe_int(event.get("lifetime"), lifetime)))

    if event_type in {"airdrop", "loot_crate"}:
        class_name = scenario_container_class_for_ce(class_name)
        if event_type == "airdrop":
            class_name = scenario_airdrop_anchor_class(event, class_name)
        min_scene_radius = scenario_airdrop_scene_min_radius(event) if event.get("visual_marker") else 0
        if min_scene_radius:
            event["radius"] = max(safe_int(event.get("radius"), 35), min_scene_radius)
    use_eventgroup = False
    eventgroup_children = None
    family = ce_event_family_for_record(event_type, class_name)
    limit_type = "child"
    if event_type == "vehicle_spawn":
        limit_type = "mixed"
    child_lootmin = 0
    child_lootmax = 0
    if event_type == "zombie_horde":
        family = "Infected"
        limit_type = "custom"
        child_lootmax = 5
        mix = event.get("zombie_mix")
        if isinstance(mix, list):
            child_records = []
            total_count = 0
            for item in mix:
                if not isinstance(item, dict):
                    continue
                child_class = str(item.get("class") or item.get("type") or "").strip()
                child_count = ce_event_nominal_count(item)
                if child_class and child_class.startswith(("ZmbM_", "ZmbF_")):
                    child_records.append({
                        "type": child_class,
                        "count": child_count,
                        "min": child_count,
                        "max": 0,
                        "lootmin": 0,
                        "lootmax": 5,
                    })
                    total_count += child_count
            if child_records:
                count = max(1, min(250, total_count))
            else:
                child_records = None
        else:
            child_records = [{
                "type": class_name,
                "count": count,
                "min": count,
                "max": 0,
                "lootmin": 0,
                "lootmax": 5,
            }]
    else:
        child_records = None
    if event_type in {"airdrop", "loot_crate"}:
        family = "Static"
        use_eventgroup = scenario_airdrop_uses_eventgroup(event)
        eventgroup_children = scenario_airdrop_eventgroup_children(event, class_name) if use_eventgroup else None
        child_records = None if use_eventgroup else scenario_airdrop_direct_child_records(event, class_name)
        count = 1
    if event_type == "animal_pack":
        if not class_name.startswith("Animal_"):
            warnings.append(f"`{event.get('id')}` animal pack uses `{class_name}`, but animal events need an `Animal_...` classname.")
            return records, warnings
        vanilla_event_name = vanilla_animal_ce_event_name(class_name)
        if not vanilla_event_name:
            warnings.append(
                f"`{event.get('id')}` animal pack uses `{class_name}`, but no matching vanilla animal CE event is known. "
                "Use bear, wolf, boar, deer, cow, sheep, goat, pig, or hen classes."
            )
            return records, warnings
        family = "Animal"
        limit_type = "custom"
        child_records = None
    if event_type == "gas_zone":
        family = "Static"
        limit_type = "parent"
        child_records = [{
            "type": "ContaminatedArea_Dynamic",
            "count": 1,
            "min": 1,
            "max": 1,
            "lootmin": 0,
            "lootmax": 0,
        }]

    speed_defaults = scenario_speed_defaults(event_type, event, use_eventgroup=use_eventgroup)
    restock = max(0, min(3888000, safe_int(event.get("restock"), speed_defaults["restock"])))
    if event_type in {"airdrop", "loot_crate"} and restock == 3600:
        restock = 0
    saferadius = max(0, min(5000, safe_int(event.get("saferadius"), speed_defaults["saferadius"])))
    distanceradius = max(0, min(30000, safe_int(event.get("distanceradius"), speed_defaults["distanceradius"])))
    cleanupradius = max(0, min(30000, safe_int(event.get("cleanupradius"), speed_defaults["cleanupradius"])))
    if event_type in {"airdrop", "loot_crate"}:
        if distanceradius in {0, 1000}:
            distanceradius = speed_defaults["distanceradius"]
        if cleanupradius == 1500:
            cleanupradius = speed_defaults["cleanupradius"]
    elif event_type == "vehicle_spawn":
        if scenario_start_speed_key(event) != "fast" and distanceradius < speed_defaults["distanceradius"]:
            distanceradius = speed_defaults["distanceradius"]
        if cleanupradius < speed_defaults["cleanupradius"]:
            cleanupradius = speed_defaults["cleanupradius"]

    record_name = vanilla_animal_ce_event_name(class_name) if event_type == "animal_pack" else ce_event_name(event, family=family)
    record = {
        "name": record_name,
        "class_name": class_name,
        "event_child_type": scenario_airdrop_primary_static_child(event, class_name) if use_eventgroup else class_name,
        "count": count,
        "lifetime": lifetime,
        "x": event.get("x"),
        "y": event.get("y"),
        "z": event.get("z"),
        "radius": event.get("radius"),
        "use_eventgroup": use_eventgroup,
        "limit_type": limit_type,
        "child_lootmin": child_lootmin,
        "child_lootmax": child_lootmax,
        "child_records": child_records,
        "secondary": scenario_airdrop_secondary_infected(event) if event_type in {"airdrop", "loot_crate"} else "",
        "eventgroup_children": eventgroup_children,
        # Eventgroup-routed Static events resolve children from cfgeventgroups.xml.
        "empty_event_children": bool(use_eventgroup),
        "nominal": 1 if event_type in {"airdrop", "loot_crate"} else (1 if use_eventgroup else None),
        "min_count": 1 if event_type in {"airdrop", "loot_crate"} else (1 if use_eventgroup else None),
        "max_count": 1 if event_type in {"airdrop", "loot_crate"} else (1 if use_eventgroup else None),
        "restock": restock,
        "saferadius": saferadius,
        "distanceradius": distanceradius,
        "cleanupradius": cleanupradius,
        "start_speed": scenario_start_speed_key(event),
        "remove_damaged": event_type == "vehicle_spawn",
        "stable_definition": event_type in STABLE_CONSOLE_EVENT_TYPES,
        "use_existing_definition": event_type == "animal_pack",
        "patch_existing_definition": event_type == "animal_pack",
        "mapgroupproto_classes": (
            [
                str(child.get("type") or "").strip()
                for child in (eventgroup_children or [])
                if eventgroup_child_needs_mapgroupproto(child)
            ]
            if use_eventgroup
            else ([class_name] if event_type in {"airdrop", "loot_crate"} else [])
        ),
        "mapgroupproto_tags": scenario_mapgroupproto_loot_tags(event) if event_type in {"airdrop", "loot_crate"} or use_eventgroup else {},
    }
    if event_type == "gas_zone":
        gas_radius = max(30, min(1000, safe_int(event.get("radius"), 120)))
        record.update({
            "count": 1,
            "nominal": 1,
            "min_count": 1,
            "max_count": 1,
            "lifetime": lifetime,
            "radius": gas_radius,
            "saferadius": saferadius,
            "distanceradius": max(0, min(30000, safe_int(event.get("distanceradius"), max(50, gas_radius)))),
            "cleanupradius": max(0, min(30000, safe_int(event.get("cleanupradius"), max(100, gas_radius + 100)))),
            "child_lootmin": 0,
            "child_lootmax": 0,
            "child_records": child_records,
            "remove_damaged": False,
        })
        warnings.append(
            f"`{event.get('id')}` creates a fixed contaminated gas zone at X/Z for {lifetime} seconds. "
            "Permanent dashboard mode keeps it in CE XML until the event is deleted."
        )
    if event_type == "animal_pack":
        record.update({"nominal": count, "min_count": count, "max_count": count})
        warnings.append(
            f"`{event.get('id')}` reuses vanilla `{record_name}` with WanderingBot-marked fixed spawn positions. "
            "This avoids custom herd-template names such as `HerdWanderingBot_animal_bear`."
        )
    records.append(record)

    if event_type == "airdrop":
        marker_class = str(scenario_airdrop_scene_config(event).get("marker") or event.get("marker_class") or SCENARIO_AIRDROP_MARKER_CLASS).strip()
        if event.get("visual_marker") and marker_class:
            scene_label = scenario_airdrop_scene_config(event).get("label") or scenario_airdrop_scene_type(event)
            warnings.append(
                f"`{event.get('id')}` requested `{scene_label}` visual object `{marker_class}`. "
                "Native CE will deploy the terrain-aligned scene, direct ground loot, and any infected guards through one fixed Static dynamic event."
            )

        if event.get("loot_preset") and event.get("loot_preset") != "none" and not event.get("loot"):
            warnings.append(
                f"`{event.get('id')}` has loot preset `{event.get('loot_preset')}` but no resolved loot items, so the crate event will spawn without cargo."
            )

    if event_type == "vehicle_spawn" and event.get("vehicle_condition") and event.get("vehicle_condition") != "no_parts":
        warnings.append(
            f"`{event.get('id')}` spawns the vehicle event, but exact fuel/parts condition is not guaranteed by events.xml/cfgeventspawns.xml alone."
        )

    return records, warnings


def console_ce_definition_child_records(record):
    child_records = record.get("child_records")
    if isinstance(child_records, list) and child_records:
        source_records = child_records
    else:
        source_records = [{
            "type": record.get("event_child_type") or record.get("class_name"),
            "count": record.get("count", 1),
            "lootmin": record.get("child_lootmin", 0),
            "lootmax": record.get("child_lootmax", 0),
        }]
    cleaned = []
    for child_record in source_records:
        if not isinstance(child_record, dict):
            continue
        child_type = str(child_record.get("type") or "").strip()
        if not child_type:
            continue
        cleaned.append({
            "type": child_type,
            "count": max(1, safe_int(child_record.get("count"), 1)),
            "min": max(0, safe_int(child_record.get("min"), child_record.get("count", 1))),
            "max": max(0, safe_int(child_record.get("max"), child_record.get("count", 1))),
            "lootmin": max(0, safe_int(child_record.get("lootmin"), record.get("child_lootmin", 0))),
            "lootmax": max(0, safe_int(child_record.get("lootmax"), record.get("child_lootmax", 0))),
        })
    return cleaned


def merge_console_ce_definition_records(records):
    merged = []
    stable_by_name = {}

    for record in records:
        if not isinstance(record, dict):
            continue
        name = str(record.get("name") or "").strip()
        if not name or not record.get("stable_definition"):
            merged.append(record)
            continue
        existing = stable_by_name.get(name.lower())
        if existing is None:
            existing = dict(record)
            existing["child_records"] = console_ce_definition_child_records(record)
            stable_by_name[name.lower()] = existing
            merged.append(existing)
            continue

        existing["count"] = min(250, max(1, safe_int(existing.get("count"), 1)) + max(1, safe_int(record.get("count"), 1)))
        existing["nominal"] = existing["count"]
        existing["min_count"] = existing["count"]
        existing["max_count"] = existing["count"]
        for key in ("lifetime", "restock", "saferadius", "distanceradius", "cleanupradius"):
            existing[key] = max(safe_int(existing.get(key), 0), safe_int(record.get(key), 0))

        child_map = {
            (
                str(child.get("type") or "").lower(),
                safe_int(child.get("lootmin"), 0),
                safe_int(child.get("lootmax"), 0),
                safe_int(child.get("min"), 0),
                safe_int(child.get("max"), 0),
            ): dict(child)
            for child in console_ce_definition_child_records(existing)
        }
        for child in console_ce_definition_child_records(record):
            key = (
                str(child.get("type") or "").lower(),
                safe_int(child.get("lootmin"), 0),
                safe_int(child.get("lootmax"), 0),
                safe_int(child.get("min"), 0),
                safe_int(child.get("max"), 0),
            )
            if key in child_map:
                child_map[key]["count"] = min(250, safe_int(child_map[key].get("count"), 1) + safe_int(child.get("count"), 1))
                child_map[key]["min"] = min(250, safe_int(child_map[key].get("min"), 1) + safe_int(child.get("min"), 1))
            else:
                child_map[key] = dict(child)
        existing["child_records"] = list(child_map.values())

    return merged


def download_console_ce_source(config, guild_id, key, requested_path=""):
    defaults = console_ce_default_paths(guild_id)
    settings = console_ce_event_config(config)
    target_path = requested_path or settings.get(key) or defaults[key]
    attempted = []
    tried = set()
    for candidate_path in console_ce_path_candidates(config, guild_id, key, requested_path, settings.get(key)):
        tried.add(candidate_path)
        ok, message, text = download_text_file_from_nitrado(config, candidate_path)
        attempted.append((candidate_path, message))
        if ok and text:
            remember_console_ce_mission_base(config, guild_id, candidate_path)
            return text, candidate_path, message
        if console_ce_download_message_is_rate_limited(message):
            break

    for candidate_path in console_ce_path_candidates(config, guild_id, key, requested_path, settings.get(key), include_discovery=True):
        if candidate_path in tried:
            continue
        tried.add(candidate_path)
        ok, message, text = download_text_file_from_nitrado(config, candidate_path)
        attempted.append((candidate_path, message))
        if ok and text:
            remember_console_ce_mission_base(config, guild_id, candidate_path)
            return text, candidate_path, message
        if console_ce_download_message_is_rate_limited(message):
            break

    message = (
        console_ce_download_failure_message(guild_id, key, attempted)
        if attempted
        else f"{target_path}: no path candidates were available"
    )

    map_key = server_map_key(guild_id)
    if key == "events_path":
        reference_parts = ("db", "events.xml")
        fallback_root = "events"
    elif key == "spawnabletypes_path":
        reference_parts = ("cfgspawnabletypes.xml",)
        fallback_root = "spawnabletypes"
    elif key == "eventgroups_path":
        reference_parts = ("cfgeventgroups.xml",)
        fallback_root = "eventgroupdef"
    elif key == "mapgroupproto_path":
        reference_parts = ("mapgroupproto.xml",)
        fallback_root = "map"
    elif key == "cfgenvironment_path":
        reference_parts = ("cfgenvironment.xml",)
        fallback_root = "env"
    elif key == "cfgareaeffects_path":
        reference_parts = ("cfgareaeffects.xml",)
        fallback_root = "areaeffects"
    else:
        reference_parts = ("cfgeventspawns.xml",)
        fallback_root = "eventposdef"

    reference_text = load_dayz_reference_text(map_key, *reference_parts)
    if reference_text:
        return reference_text, target_path, f"{message} Using bundled vanilla reference as fallback."

    return f"<{fallback_root}></{fallback_root}>\n", target_path, f"{message} No bundled reference was found, so a minimal template was used."


def console_ce_source_is_fallback(source):
    source_text = str(source or "")
    return "Using bundled vanilla reference as fallback" in source_text or "minimal template" in source_text


def download_console_effect_area_source(config, guild_id, requested_path=""):
    settings = console_ce_event_config(config)
    defaults = console_ce_default_paths(guild_id)
    target_path = requested_path or settings.get("cfgeffectarea_path") or defaults["cfgeffectarea_path"]
    attempted = []
    tried = set()
    for candidate_path in console_ce_path_candidates(config, guild_id, "cfgeffectarea_path", target_path, settings.get("cfgeffectarea_path")):
        tried.add(candidate_path)
        ok, message, text = download_text_file_from_nitrado(config, candidate_path)
        attempted.append((candidate_path, message))
        if ok and text:
            remember_console_ce_mission_base(config, guild_id, candidate_path)
            return text, candidate_path, message
        if console_ce_download_message_is_rate_limited(message):
            break
    for candidate_path in console_ce_path_candidates(config, guild_id, "cfgeffectarea_path", target_path, settings.get("cfgeffectarea_path"), include_discovery=True):
        if candidate_path in tried:
            continue
        tried.add(candidate_path)
        ok, message, text = download_text_file_from_nitrado(config, candidate_path)
        attempted.append((candidate_path, message))
        if ok and text:
            remember_console_ce_mission_base(config, guild_id, candidate_path)
            return text, candidate_path, message
        if console_ce_download_message_is_rate_limited(message):
            break
    return "", target_path, (
        console_ce_download_failure_message(guild_id, "cfgeffectarea_path", attempted)
        if attempted
        else f"{target_path}: no path candidates were available"
    )


def patch_cfgeffectarea_gas_particle(value, mode):
    target = _gas_particle_target(mode)
    matched = 0
    changed = 0

    def walk(node):
        nonlocal matched, changed
        if isinstance(node, dict):
            for key, current in list(node.items()):
                if str(key).lower() == "particlename" and isinstance(current, str):
                    replacement = _replace_gas_particle_value(current, target)
                    if replacement is not None:
                        matched += 1
                        if current != replacement:
                            node[key] = replacement
                            changed += 1
                else:
                    walk(current)
        elif isinstance(node, list):
            for item in node:
                walk(item)

    walk(value)
    return changed, matched, target


def build_console_ce_event_files(guild_id, config, events_path="", spawns_path="", spawnabletypes_path=""):
    events_text, resolved_events_path, events_source = download_console_ce_source(config, guild_id, "events_path", events_path)
    spawns_text, resolved_spawns_path, spawns_source = download_console_ce_source(config, guild_id, "spawns_path", spawns_path)
    source_fallbacks = []
    for label, source in (("events.xml", events_source), ("cfgeventspawns.xml", spawns_source)):
        if console_ce_source_is_fallback(source):
            source_fallbacks.append(f"{label}: {source}")

    warnings = []
    events_root, events_parse_warning, events_parse_blocker = parse_console_ce_xml_source(
        config,
        "events.xml",
        events_text,
        "events",
        resolved_events_path,
    )
    spawns_root, spawns_parse_warning, spawns_parse_blocker = parse_console_ce_xml_source(
        config,
        "cfgeventspawns.xml",
        spawns_text,
        "eventposdef",
        resolved_spawns_path,
    )
    if events_parse_blocker:
        source_fallbacks.append(events_parse_blocker)
    elif events_parse_warning:
        warnings.append(events_parse_warning)
    if spawns_parse_blocker:
        source_fallbacks.append(spawns_parse_blocker)
    elif spawns_parse_warning:
        warnings.append(spawns_parse_warning)

    removed_events = remove_wandering_ce_nodes(events_root)
    removed_spawns = remove_wandering_ce_nodes(spawns_root)
    removed_spawn_children = cleanup_wandering_marked_spawn_children(spawns_root)

    records = []
    for event in native_ce_scenario_events(config):
        event_records, event_warnings = console_ce_records_for_event(event)
        records.extend(event_records)
        warnings.extend(event_warnings)

    records_reusing_existing_definitions = [
        record for record in records
        if record.get("use_existing_definition")
    ]
    definition_records = merge_console_ce_definition_records([
        record for record in records
        if not record.get("use_existing_definition")
    ])
    patched_existing_definitions = 0
    for record in records_reusing_existing_definitions:
        if record.get("patch_existing_definition") and patch_existing_console_ce_event_definition(events_root, record):
            patched_existing_definitions += 1
    for record in definition_records:
        add_console_ce_event_definition(
            events_root,
            record["name"],
            record.get("event_child_type") or record["class_name"],
            record["count"],
            record["lifetime"],
            restock=record.get("restock", 0),
            use_eventgroup=bool(record.get("use_eventgroup")),
            limit_type=record.get("limit_type") or "child",
            child_lootmin=record.get("child_lootmin", 0),
            child_lootmax=record.get("child_lootmax", 0),
            nominal=record.get("nominal"),
            min_count=record.get("min_count"),
            max_count=record.get("max_count"),
            saferadius=record.get("saferadius", 0),
            distanceradius=record.get("distanceradius", 0),
            cleanupradius=record.get("cleanupradius", 100),
            child_records=record.get("child_records"),
            remove_damaged=bool(record.get("remove_damaged")),
            empty_children=bool(record.get("empty_event_children")),
            secondary=record.get("secondary", ""),
        )
    for record in records:
        if record.get("skip_spawn"):
            continue
        add_console_ce_event_spawn(
            spawns_root,
            record["name"],
            record["x"],
            record["z"],
            y=record.get("y"),
            count=record["count"],
            radius=record.get("radius") or 45,
            group_name=record["name"] if record.get("use_eventgroup") else "",
            empty=bool(record.get("empty_spawn")),
        )

    messages = [
        events_source,
        spawns_source,
        f"Removed `{removed_events}` old WanderingBot event definition(s), `{removed_spawns}` old spawn point block(s), and `{removed_spawn_children}` old marked spawn child node(s).",
        f"Generated `{len(records)}` native CE spawn record(s) across `{len(definition_records)}` managed event definition(s).",
    ]
    if patched_existing_definitions:
        messages.append(
            f"Adjusted `{patched_existing_definitions}` reused vanilla animal event definition(s) so selected animal packs have a positive CE count."
        )
    if records_reusing_existing_definitions:
        messages.append(
            "Reused vanilla CE definition(s) for: "
            + ", ".join(f"`{record.get('name')}`" for record in records_reusing_existing_definitions[:8])
        )
    if events_parse_warning:
        messages.append(events_parse_warning)
    if spawns_parse_warning:
        messages.append(spawns_parse_warning)
    messages.extend(warnings)

    output = {
        "events_path": resolved_events_path,
        "events_text": xml_text_from_root(events_root),
        "events_source_text": events_text,
        "spawns_path": resolved_spawns_path,
        "spawns_text": xml_text_from_root(spawns_root),
        "spawns_source_text": spawns_text,
        "eventgroups_path": "",
        "eventgroups_text": "",
        "eventgroups_source_text": "",
        "mapgroupproto_path": "",
        "mapgroupproto_text": "",
        "mapgroupproto_source_text": "",
        "spawnabletypes_path": "",
        "spawnabletypes_text": "",
        "spawnabletypes_source_text": "",
        "cfgenvironment_path": "",
        "cfgenvironment_text": "",
        "cfgenvironment_source_text": "",
        "cfgareaeffects_path": "",
        "cfgareaeffects_text": "",
        "cfgareaeffects_source_text": "",
        "cfgeffectarea_path": "",
        "cfgeffectarea_text": "",
        "animal_territory_files": [],
        "record_count": len(records),
        "messages": messages,
        "source_fallbacks": source_fallbacks,
    }
    mission_base = remote_mission_base_from_ce_paths(output)
    output["mission_base"] = mission_base
    output["mission_folder"] = mission_base.rstrip("/").split("/")[-1] if mission_base else ""
    output["managed_event_names"] = sorted({
        str(record.get("name") or "").strip()
        for record in (definition_records + records_reusing_existing_definitions)
        if str(record.get("name") or "").strip()
    })[:24]
    output["managed_spawn_names"] = sorted({
        str(record.get("name") or "").strip()
        for record in records
        if not record.get("skip_spawn")
        if str(record.get("name") or "").strip()
    })[:24]
    output["restart_required"] = bool(records or config.get("scenario_events_cleanup_pending"))

    animal_records = [record for record in records if record.get("animal_territory")]
    should_cleanup_environment = bool(records) or bool(config.get("scenario_events_cleanup_pending"))
    if should_cleanup_environment:
        if not mission_base:
            output.setdefault("source_fallbacks", []).append(
                "cfgenvironment.xml: could not infer mission folder from resolved CE paths."
            )
        env_path = canonical_remote_path(f"{mission_base}/cfgenvironment.xml") if mission_base else console_ce_default_paths(guild_id)["cfgenvironment_path"]
        env_text, resolved_env_path, env_source = download_console_ce_source(
            config,
            guild_id,
            "cfgenvironment_path",
            env_path
        )
        env_root, env_parse_warning = parse_xml_root_or_new(env_text, "env")
        if env_parse_warning:
            if animal_records:
                output.setdefault("source_fallbacks", []).append(f"cfgenvironment.xml: {env_parse_warning}")
            else:
                output["messages"].append(f"cfgenvironment.xml cleanup skipped: {env_parse_warning}")
        removed_files, removed_territories = remove_wandering_environment_nodes(env_root)
        animal_territory_groups = group_animal_territory_records(animal_records)
        for record in animal_territory_groups:
            add_animal_environment_entry(env_root, record)
            territory_path = animal_territory_remote_path(mission_base, record) if mission_base else ""
            output["animal_territory_files"].append({
                "path": territory_path,
                "text": build_animal_territory_text(record),
                "name": record.get("territory_name"),
                "event_names": record.get("event_names", []),
            })
        if animal_records or removed_files or removed_territories:
            output["cfgenvironment_path"] = resolved_env_path
            output["cfgenvironment_text"] = xml_text_from_root(env_root)
            output["cfgenvironment_source_text"] = env_text
        output["messages"].append(env_source)
        source_text = str(env_source or "")
        if "Using bundled vanilla reference as fallback" in source_text or "minimal template" in source_text:
            if animal_records:
                output.setdefault("source_fallbacks", []).append(f"cfgenvironment.xml: {source_text}")
            else:
                output["messages"].append(f"cfgenvironment.xml cleanup skipped: {source_text}")
        output["messages"].append(
            f"Updated `cfgenvironment.xml` for `{len(animal_records)}` animal territory event(s), removed `{removed_files}` old Wandering Bot file reference(s) and `{removed_territories}` old territory block(s)."
        )
        if env_parse_warning:
            output["messages"].append(env_parse_warning)

    cfgareaeffects_mode = console_ce_cfgareaeffects_mode(config)
    if cfgareaeffects_mode:
        mission_base = remote_mission_base_from_ce_paths(output)
        cfgeffectarea_path = (
            canonical_remote_path(f"{mission_base}/cfgEffectArea.json")
            if mission_base
            else console_ce_default_paths(guild_id)["cfgeffectarea_path"]
        )
        cfgeffectarea_text, resolved_cfgeffectarea_path, cfgeffectarea_source = download_console_effect_area_source(
            config,
            guild_id,
            cfgeffectarea_path,
        )
        if not str(cfgeffectarea_text or "").strip():
            output["messages"].append(
                f"cfgEffectArea.json gas colour skipped: {cfgeffectarea_source}. "
                "Events were still generated; only the red/normal gas particle patch was skipped."
            )
        else:
            try:
                cfgeffectarea_payload = json.loads(cfgeffectarea_text)
            except Exception as error:
                output["messages"].append(
                    f"cfgEffectArea.json gas colour skipped: could not parse `{resolved_cfgeffectarea_path}` as JSON ({error}). "
                    "Events were still generated; only the red/normal gas particle patch was skipped."
                )
            else:
                changed, matched, target_particle = patch_cfgeffectarea_gas_particle(cfgeffectarea_payload, cfgareaeffects_mode)
                if matched <= 0:
                    output["messages"].append(
                        "cfgEffectArea.json gas colour skipped: no `ParticleName` containing "
                        "`graphics/particles/contaminated_area_gas_bigass` was found."
                    )
                else:
                    output["cfgeffectarea_path"] = resolved_cfgeffectarea_path
                    output["cfgeffectarea_text"] = json.dumps(cfgeffectarea_payload, indent=4, ensure_ascii=False) + "\n"
                    output["messages"].append(cfgeffectarea_source)
                    output["messages"].append(
                        f"Updated `cfgEffectArea.json` gas `ParticleName` to `{target_particle}` "
                        f"({changed} changed, {matched} matched). This can affect contaminated-area gas using that particle."
                    )

    eventgroup_records = [record for record in records if record.get("use_eventgroup")]
    mapgroupproto_records = [
        record for record in records
        if record.get("use_eventgroup") or record.get("mapgroupproto_classes")
    ]
    cleanup_pending = bool(config.get("scenario_events_cleanup_pending"))
    should_cleanup_group_files = bool(eventgroup_records or mapgroupproto_records)
    if eventgroup_records or mapgroupproto_records or should_cleanup_group_files:
        eventgroups_text = ""
        resolved_eventgroups_path = console_ce_default_paths(guild_id)["eventgroups_path"]
        eventgroups_source = "cfgeventgroups.xml unchanged; no direct eventgroup-routed event needed."
        eventgroups_root = ET.Element("eventgroupdef")
        eventgroups_parse_warning = ""
        eventgroups_parse_blocker = ""
        if eventgroup_records or cleanup_pending:
            eventgroups_text, resolved_eventgroups_path, eventgroups_source = download_console_ce_source(
                config,
                guild_id,
                "eventgroups_path",
                ""
            )
            eventgroups_root, eventgroups_parse_warning, eventgroups_parse_blocker = parse_console_ce_xml_source(
                config,
                "cfgeventgroups.xml",
                eventgroups_text,
                "eventgroupdef",
                resolved_eventgroups_path,
            )
        mapgroupproto_text, resolved_mapgroupproto_path, mapgroupproto_source = download_console_ce_source(
            config,
            guild_id,
            "mapgroupproto_path",
            ""
        )
        mapgroupproto_root, mapgroupproto_parse_warning = parse_xml_root_or_new(mapgroupproto_text, "prototype")
        if eventgroups_parse_blocker:
            output.setdefault("source_fallbacks", []).append(eventgroups_parse_blocker)
        elif eventgroups_parse_warning:
            output.setdefault("source_fallbacks", []).append(f"cfgeventgroups.xml: {eventgroups_parse_warning}")
        if mapgroupproto_parse_warning:
            output.setdefault("source_fallbacks", []).append(f"mapgroupproto.xml: {mapgroupproto_parse_warning}")
        removed_groups = remove_wandering_ce_nodes(eventgroups_root)
        proto_changed, removed_proto_groups, removed_proto_values = cleanup_stale_mapgroupproto_airdrop_nodes(
            mapgroupproto_root,
            server_map_key(guild_id),
        )
        added_proto = 0
        for record in eventgroup_records:
            eventgroup_children = record.get("eventgroup_children") if isinstance(record.get("eventgroup_children"), list) else None
            add_console_ce_event_group(
                eventgroups_root,
                record["name"],
                record["class_name"],
                lootmin=record.get("child_lootmin", 40) or 40,
                lootmax=record.get("child_lootmax", 80) or 80,
                child_records=eventgroup_children,
            )
        for record in mapgroupproto_records:
            proto_classes = [
                str(item or "").strip()
                for item in (record.get("mapgroupproto_classes") or [])
                if str(item or "").strip()
            ]
            eventgroup_children = record.get("eventgroup_children") if isinstance(record.get("eventgroup_children"), list) else None
            if record.get("use_eventgroup") and not proto_classes:
                proto_classes = [record["class_name"]]
                if eventgroup_children:
                    proto_classes = [
                        str(child.get("type") or "").strip()
                        for child in eventgroup_children
                        if eventgroup_child_needs_mapgroupproto(child)
                        if str(child.get("type") or "").strip()
                    ]
            for proto_class in dict.fromkeys(proto_classes):
                _, created = add_mapgroupproto_loot_group(
                    mapgroupproto_root,
                    proto_class,
                    tags=record.get("mapgroupproto_tags") if proto_class == record["class_name"] else {},
                )
                if created:
                    added_proto += 1
        if removed_groups or eventgroup_records or cleanup_pending:
            output["eventgroups_path"] = resolved_eventgroups_path
            output["eventgroups_text"] = xml_text_from_root(eventgroups_root)
            output["eventgroups_source_text"] = eventgroups_text
        if proto_changed or added_proto or eventgroup_records or cleanup_pending:
            output["mapgroupproto_path"] = resolved_mapgroupproto_path
            output["mapgroupproto_text"] = xml_text_from_root(mapgroupproto_root)
            output["mapgroupproto_source_text"] = mapgroupproto_text
        output["messages"].append(eventgroups_source)
        output["messages"].append(mapgroupproto_source)
        for label, source in (("cfgeventgroups.xml", eventgroups_source), ("mapgroupproto.xml", mapgroupproto_source)):
            source_text = str(source or "")
            if "Using bundled vanilla reference as fallback" in source_text or "minimal template" in source_text:
                output.setdefault("source_fallbacks", []).append(f"{label}: {source_text}")
        output["messages"].append(
            f"Updated `cfgeventgroups.xml` with `{len(eventgroup_records)}` event group(s), removed `{removed_groups}` old Wandering Bot group(s)."
        )
        output["messages"].append(
            f"Updated `mapgroupproto.xml`: removed `{removed_proto_groups}` old Wandering Bot proto group(s), "
            f"left live server proto groups unchanged, and added/repaired `{added_proto}` lootFloor proto group(s)."
        )
        if eventgroups_parse_warning:
            output["messages"].append(eventgroups_parse_warning)
        if mapgroupproto_parse_warning:
            output["messages"].append(mapgroupproto_parse_warning)

    if console_ce_has_native_loot_intent(config):
        output["messages"].append(
            "Native CE loot uses `mapgroupproto.xml` usage/category tags for the selected preset; "
            "`cfgspawnabletypes.xml` per-item cargo tuning is skipped."
        )

    if console_ce_needs_spawnabletypes(config):
        spawnable_text, resolved_spawnable_path, spawnable_source = download_console_ce_source(
            config,
            guild_id,
            "spawnabletypes_path",
            spawnabletypes_path
        )
        if console_ce_source_is_fallback(spawnable_source):
            output["messages"].append(
                "`cfgspawnabletypes.xml` cargo tuning skipped: live source was unavailable through Nitrado/API. "
                "The airdrop event/spawn XML can still upload safely; crate cargo will use the server's existing config until this file can be read."
            )
        else:
            spawnable_root, spawnable_parse_warning = parse_xml_root_or_new(spawnable_text, "spawnabletypes")
            if spawnable_parse_warning:
                output["messages"].append(
                    "`cfgspawnabletypes.xml` cargo tuning skipped: the live source was returned but could not be parsed safely. "
                    "The airdrop event/spawn XML can still upload; no cargo overwrite was attempted."
                )
                output["messages"].append(spawnable_parse_warning)
            else:
                removed_ignored_items, removed_empty_groups = sanitize_spawnabletypes_ignored_items(spawnable_root)
                changed_classes, cargo_blocks, preset_refs_removed = merge_airdrop_loot_into_spawnabletypes(spawnable_root, native_ce_scenario_events(config))
                candidate_spawnable_text = xml_text_from_root(spawnable_root)
                scope_ok, scope_message = validate_managed_ce_xml_scope(
                    "cfgspawnabletypes.xml",
                    spawnable_text,
                    candidate_spawnable_text,
                )
                if not scope_ok:
                    output["messages"].append(spawnable_source)
                    output["messages"].append(
                        "`cfgspawnabletypes.xml` cargo tuning skipped because it would modify existing server item/class definitions. "
                        "Core WanderingBot CE events, spawn points, event groups, and mapgroupproto snippets can still upload safely."
                    )
                    output["messages"].append(scope_message)
                else:
                    output["spawnabletypes_path"] = resolved_spawnable_path
                    output["spawnabletypes_text"] = candidate_spawnable_text
                    output["spawnabletypes_source_text"] = spawnable_text
                    output["messages"].append(spawnable_source)
                    output["messages"].append(
                        f"Updated `cfgspawnabletypes.xml` with `{cargo_blocks}` event cargo block(s) for: "
                        + (", ".join(f"`{item}`" for item in changed_classes) if changed_classes else "none")
                    )
                    if preset_refs_removed:
                        output["messages"].append(
                            f"Removed `{preset_refs_removed}` missing-preset cargo/attachment reference(s) from touched airdrop classes."
                        )
                    if removed_ignored_items:
                        output["messages"].append(
                            f"Removed `{removed_ignored_items}` ignored flare preset item reference(s) from `cfgspawnabletypes.xml` "
                            f"and cleaned `{removed_empty_groups}` empty cargo/attachment group(s)."
                        )
                    if any(str(item).lower() in {"woodencrate", "staticobj_misc_woodencrate_5x"} for item in changed_classes):
                        output["messages"].append(
                            "Note: wooden-crate cargo tuning is class-based, so other CE-spawned crates using that same classname can share that cargo setup."
                        )

    return output


def validate_console_ce_xml_bundle(built, check_scope=True):
    messages = []
    scope_messages = []
    source_fallbacks = built.get("source_fallbacks") if isinstance(built.get("source_fallbacks"), list) else []
    if source_fallbacks:
        return False, [
            "Native CE XML upload blocked because the bot could not download the existing server file(s). "
            "Refusing to upload a fallback/minimal template over a live Nitrado XML file."
        ] + [str(item) for item in source_fallbacks[-6:]]

    if check_scope:
        scope_ok, scope_messages = validate_console_ce_upload_scope(built)
        if not scope_ok:
            return False, scope_messages

    try:
        events_root = ET.fromstring(str(built.get("events_text") or "").encode("utf-8"))
        spawns_root = ET.fromstring(str(built.get("spawns_text") or "").encode("utf-8"))
        eventgroups_root = ET.fromstring(str(built.get("eventgroups_text") or "<eventgroupdef></eventgroupdef>").encode("utf-8"))
        mapgroupproto_root = ET.fromstring(str(built.get("mapgroupproto_text") or "<prototype></prototype>").encode("utf-8"))
        cfgenvironment_root = ET.fromstring(str(built.get("cfgenvironment_text") or "<env><territories /></env>").encode("utf-8"))
        cfgareaeffects_root = ET.fromstring(str(built.get("cfgareaeffects_text") or "<areaeffects></areaeffects>").encode("utf-8"))
        if built.get("cfgeffectarea_text"):
            json.loads(str(built.get("cfgeffectarea_text") or ""))
    except Exception as error:
        return False, scope_messages + [f"CE file validation failed before upload: {error}"]

    territory_files = built.get("animal_territory_files") if isinstance(built.get("animal_territory_files"), list) else []
    for territory_file in territory_files:
        try:
            territory_root = ET.fromstring(str(territory_file.get("text") or "").encode("utf-8"))
        except Exception as error:
            return False, [f"XML validation failed for `{territory_file.get('path')}`: {error}"]
        if territory_root.tag != "territory-type":
            messages.append(f"`{territory_file.get('path')}` must use `<territory-type>` as the root tag.")
        if not territory_root.findall(".//zone"):
            messages.append(f"`{territory_file.get('path')}` has no animal territory `<zone>`.")

    allowed_families = ("Ambient", "Animal", "ContaminatedArea", "Infected", "Item", "Static", "Trajectory", "Vehicle")
    generated_events = {}
    for event_node in events_root.findall("event"):
        name = str(event_node.get("name") or "")
        if not is_wandering_managed_name(name):
            continue
        if not name.startswith(allowed_families):
            messages.append(
                f"`{name}` uses an invalid DayZ CE event prefix. Use one of: {', '.join(allowed_families)}."
            )
        if (event_node.findtext("position") or "").strip() != "fixed":
            messages.append(f"`{name}` must use `<position>fixed</position>` for cfgeventspawns coordinates.")
        limit_text = (event_node.findtext("limit") or "").strip()
        if limit_text not in {"child", "custom", "mixed", "parent"}:
            messages.append(f"`{name}` must use `<limit>child</limit>`, `<limit>custom</limit>`, `<limit>mixed</limit>`, or `<limit>parent</limit>`.")
        if limit_text == "mixed" and not name.startswith("Vehicle"):
            messages.append(f"`{name}` uses `<limit>mixed</limit>`, which is only allowed for vehicle CE events.")
        if (event_node.findtext("active") or "").strip() != "1":
            messages.append(f"`{name}` is not active.")
        children = event_node.find("children")
        child_nodes = list(children.findall("child")) if children is not None else []
        if not child_nodes and not name.startswith("Static"):
            messages.append(f"`{name}` has no `<child>` classname to spawn.")
        for child in child_nodes:
            child_type = str(child.get("type") or "").strip()
            if not child_type:
                messages.append(f"`{name}` has a child with no `type` classname.")
            if child_type.startswith(("ZmbM_", "ZmbF_")) and not (name.startswith("Infected") or name.startswith("Static")):
                messages.append(f"`{name}` spawns infected child `{child_type}` but does not use the `Infected` CE family.")
            if name.startswith("Infected") and child_type.startswith("Animal_"):
                messages.append(f"`{name}` is an infected event but has animal child `{child_type}`.")
            try:
                child_max = int(str(child.get("max") or "0"))
            except Exception:
                child_max = 0
            if child_max <= 0 and not (name.startswith("Infected") and limit_text == "custom"):
                messages.append(f"`{name}` has a child with `max` 0, so CE will disable or ignore the event.")
        generated_events[name] = event_node

    generated_spawns = {
        str(event_node.get("name") or ""): event_node
        for event_node in spawns_root.findall("event")
        if is_wandering_managed_name(event_node.get("name") or "")
    }

    for name in generated_events:
        spawn_node = generated_spawns.get(name)
        if spawn_node is None:
            messages.append(f"`{name}` is in events.xml but missing from cfgeventspawns.xml.")
            continue
        territory_event_names = {
            str(event_name or "")
            for item in territory_files
            for event_name in (
                item.get("event_names")
                if isinstance(item.get("event_names"), list)
                else [item.get("name")]
            )
        }
        is_animal_territory_event = name.startswith("Animal") and name in territory_event_names
        if not spawn_node.findall("pos") and not is_animal_territory_event:
            messages.append(f"`{name}` has no `<pos>` coordinates in cfgeventspawns.xml.")
        has_group_pos = any(str(pos.get("group") or "").strip() for pos in spawn_node.findall("pos"))
        children = event_node.find("children")
        child_nodes = list(children.findall("child")) if children is not None else []
        if name.startswith("Static") and not child_nodes and not has_group_pos:
            messages.append(f"`{name}` has no `<child>` classname to spawn.")
        is_wandering_fixed_animal_event = name.startswith("Animal") and is_wandering_managed_name(name)
        if (
            console_ce_event_uses_zone_spawn(name)
            and not is_wandering_fixed_animal_event
            and not spawn_node.findall("zone")
            and not has_group_pos
            and not is_animal_territory_event
        ):
            messages.append(f"`{name}` has no `<zone>` radius block in cfgeventspawns.xml.")

    for name in generated_spawns:
        if name not in generated_events:
            messages.append(f"`{name}` is in cfgeventspawns.xml but missing from events.xml.")

    generated_groups = {
        str(group_node.get("name") or ""): group_node
        for group_node in eventgroups_root.findall("group")
        if is_wandering_managed_name(group_node.get("name") or "")
    }
    proto_nodes = {
        str(group_node.get("name") or "").strip(): group_node
        for group_node in mapgroupproto_root.findall("group")
    }
    for name, event_node in generated_events.items():
        if not name.startswith("Static"):
            continue
        spawn_node = generated_spawns.get(name)
        has_group_pos = bool(spawn_node is not None and any(
            str(pos.get("group") or "").strip()
            for pos in spawn_node.findall("pos")
        ))
        if has_group_pos:
            continue
        for child in event_node.findall("children/child"):
            child_type = str(child.get("type") or "").strip()
            try:
                child_lootmax = int(str(child.get("lootmax") or "0"))
            except Exception:
                child_lootmax = 0
            if not child_type or child_lootmax <= 0:
                continue
            proto_node = proto_nodes.get(child_type)
            if proto_node is None:
                messages.append(f"`{child_type}` is used by `{name}` but has no mapgroupproto group.")
            elif not mapgroupproto_group_has_usable_loot_container(proto_node):
                messages.append(
                    f"`{child_type}` is used as a direct loot-bearing child by `{name}`, but its "
                    "mapgroupproto group has no usable loot container/point."
                )
    for name, event_node in generated_events.items():
        if not name.startswith("Static"):
            continue
        spawn_node = generated_spawns.get(name)
        has_group_pos = bool(spawn_node is not None and any(
            str(pos.get("group") or "").strip()
            for pos in spawn_node.findall("pos")
        ))
        if not has_group_pos:
            continue
        group_node = generated_groups.get(name)
        if group_node is None:
            messages.append(f"`{name}` is a static crate event but is missing from cfgeventgroups.xml.")
            continue
        child_nodes = group_node.findall("child")
        if not child_nodes:
            messages.append(f"`{name}` has no eventgroup child object.")
        event_child_types = {
            str(child.get("type") or "").strip()
            for child in (event_node.find("children").findall("child") if event_node.find("children") is not None else [])
        }
        if name in event_child_types:
            messages.append(
                f"`{name}` uses its event group name as an events.xml child type; "
                "use the real object classname, such as `WoodenCrate`, and keep the group name only in cfgeventspawns.xml."
            )
        group_child_max_values = []
        for child in child_nodes:
            child_type = str(child.get("type") or "").strip()
            is_static_scene_prop = str(child.get("spawnsecondary") or "").strip().lower() == "false"
            if not child_type:
                messages.append(f"`{name}` has an eventgroup child with no type.")
            elif not is_static_scene_prop and child_type not in proto_nodes:
                messages.append(f"`{child_type}` is used by `{name}` but has no mapgroupproto group.")
            for attr in ("x", "y", "z", "a"):
                if str(child.get(attr) or "").strip() == "":
                    messages.append(f"`{name}` eventgroup child `{child_type or 'unknown'}` is missing `{attr}` placement data.")
            try:
                group_lootmax = int(str(child.get("lootmax") or "0"))
            except Exception:
                group_lootmax = 0
            try:
                group_child_max = int(str(child.get("max") or "0"))
            except Exception:
                group_child_max = 0
            group_child_max_values.append(max(group_lootmax, group_child_max))
            if group_lootmax <= 0 and group_child_max <= 0 and not is_static_scene_prop:
                messages.append(f"`{name}` eventgroup child `{child_type or 'unknown'}` has `lootmax` 0.")
            if group_lootmax > 0 and not is_static_scene_prop and child_type in proto_nodes:
                proto_node = proto_nodes[child_type]
                if not mapgroupproto_group_has_usable_loot_container(proto_node):
                    messages.append(
                        f"`{child_type}` is used as a loot-bearing child by `{name}`, but its "
                        "mapgroupproto group has no usable loot container/point."
                    )
        if child_nodes and max(group_child_max_values or [0]) <= 0:
            messages.append(
                f"`{name}` eventgroup children all have max/lootmax 0. DayZ disables child-limited Static events "
                "in this shape."
            )

    if territory_files:
        territories_node = cfgenvironment_root.find("territories") if cfgenvironment_root.tag != "territories" else cfgenvironment_root
        if territories_node is None:
            messages.append("`cfgenvironment.xml` has no `<territories>` block for animal territory events.")
        else:
            env_paths = {
                str(file_node.get("path") or "").replace("\\", "/").lower()
                for file_node in territories_node.findall("file")
            }
            env_usables = {
                str(file_node.get("usable") or "").lower()
                for territory_node in territories_node.findall("territory")
                for file_node in territory_node.findall("file")
            }
            for territory_file in territory_files:
                path = str(territory_file.get("path") or "")
                file_name = os.path.basename(path).lower()
                expected_path = f"env/{file_name}"
                usable = os.path.splitext(file_name)[0]
                if expected_path not in env_paths:
                    messages.append(f"`cfgenvironment.xml` is missing `<file path=\"{expected_path}\" />`.")
                if usable not in env_usables:
                    messages.append(f"`cfgenvironment.xml` is missing a territory using `{usable}`.")

    if messages:
        return False, scope_messages + messages
    return True, scope_messages + [f"Validated `{len(generated_events)}` Wandering Bot CE event record(s) before upload."]


def verify_uploaded_console_ce_xml_bundle(config, built):
    remote_built = dict(built)
    remote_built["source_fallbacks"] = []
    messages = []
    targets = [
        ("events.xml", "events_path", "events_text"),
        ("cfgeventspawns.xml", "spawns_path", "spawns_text"),
        ("cfgspawnabletypes.xml", "spawnabletypes_path", "spawnabletypes_text"),
        ("cfgeventgroups.xml", "eventgroups_path", "eventgroups_text"),
        ("mapgroupproto.xml", "mapgroupproto_path", "mapgroupproto_text"),
        ("cfgenvironment.xml", "cfgenvironment_path", "cfgenvironment_text"),
        ("cfgareaeffects.xml", "cfgareaeffects_path", "cfgareaeffects_text"),
    ]
    for label, path_key, text_key in targets:
        if not built.get(text_key):
            continue
        path = built.get(path_key)
        if not path:
            return False, [f"`{label}` final bundle check skipped because the remote path was missing."]
        ok, message, text = download_text_file_from_nitrado(config, path)
        if not ok or not str(text or "").strip():
            detail = message
            if ok and not str(text or "").strip():
                detail = f"{message} (download returned empty content)"
            return True, [
                f"Final remote CE bundle re-download warning: `{label}` could not be re-downloaded "
                f"after individual upload verification already passed: {detail}"
            ]
        remote_built[text_key] = text
    validation_ok, validation_messages = validate_console_ce_xml_bundle(remote_built, check_scope=False)
    messages.extend(validation_messages)
    if not validation_ok:
        return False, ["Final remote CE bundle verification failed after upload."] + validation_messages
    return True, ["Final remote CE bundle verified across events.xml, cfgeventspawns.xml, cfgeventgroups.xml and mapgroupproto.xml."]


def successful_native_ce_fallback_message(message):
    text = str(message or "").lower()
    return (
        "api upload failed, so verified ftp live write was used" in text
        and (
            "post-upload re-download matched" in text
            or "verified after upload" in text
        )
    )


def native_ce_failure_summary_messages(messages, limit=4):
    candidates = []
    for message in messages or []:
        text = str(message or "")
        lower = text.lower()
        if successful_native_ce_fallback_message(text):
            continue
        if any(token in lower for token in (
            "blocked",
            "failed",
            "invalid",
            "missing",
            "refusing",
            "exception",
            "error",
            "restore",
        )):
            candidates.append(text)
    fallback = [
        str(message)
        for message in (messages or [])
        if not successful_native_ce_fallback_message(message)
    ]
    return (candidates or fallback)[-limit:]


def native_ce_failed_status_text(messages):
    summary = native_ce_failure_summary_messages(messages)
    return "Native CE XML upload failed: " + (" | ".join(summary) if summary else "no details")


def upload_ce_latest_backup_to_nitrado(config, label, backup_path, text_content):
    valid_upload, validation_message = validate_protected_dayz_xml_upload(backup_path, text_content)
    if not valid_upload:
        return False, validation_message

    ftp_success, ftp_message = upload_text_file_to_nitrado_ftp(config, backup_path, text_content)
    if ftp_success:
        verify_ok, verify_message = verify_remote_protected_dayz_xml(config, label, backup_path)
        if verify_ok:
            return True, f"{ftp_message} {verify_message}"
        return False, f"{ftp_message} Backup verification failed: {verify_message}"

    api_success, api_message = upload_text_file_to_nitrado_api(config, backup_path, text_content)
    if api_success:
        verify_ok, verify_message = verify_remote_protected_dayz_xml(config, label, backup_path)
        if verify_ok:
            return True, f"{api_message} {verify_message}"
        return False, f"{api_message} Backup verification failed: {verify_message}"

    return False, f"FTP backup upload failed: {ftp_message} API backup fallback also failed: {api_message}"


def backup_remote_ce_sources_before_upload(config, built):
    backup_messages = []
    restore_texts = built.setdefault("restore_texts", {})
    required_backups = {"events.xml", "cfgeventspawns.xml", "cfgspawnabletypes.xml"}
    targets = [
        ("events.xml", built.get("events_path")),
        ("cfgeventspawns.xml", built.get("spawns_path")),
        ("cfgspawnabletypes.xml", built.get("spawnabletypes_path") if built.get("spawnabletypes_text") else ""),
        ("cfgeventgroups.xml", built.get("eventgroups_path") if built.get("eventgroups_text") else ""),
        ("mapgroupproto.xml", built.get("mapgroupproto_path") if built.get("mapgroupproto_text") else ""),
        ("cfgenvironment.xml", built.get("cfgenvironment_path") if built.get("cfgenvironment_text") else ""),
        ("cfgareaeffects.xml", built.get("cfgareaeffects_path") if built.get("cfgareaeffects_text") else ""),
        ("cfgEffectArea.json", built.get("cfgeffectarea_path") if built.get("cfgeffectarea_text") else ""),
    ]
    for label, path in targets:
        if not path:
            continue
        ok, message, content = download_text_file_from_nitrado(config, path)
        if not ok or not str(content or "").strip():
            detail = message
            if ok and not str(content or "").strip():
                detail = f"{message} (download returned empty content)"
            if label in required_backups:
                return False, backup_messages + [f"Backup blocked: could not re-download `{label}` from `{path}` before upload: {detail}"]
            backup_messages.append(
                f"`{label}` backup skipped: existing file at `{path}` could not be re-downloaded before upload: {detail}"
            )
            continue
        valid_source, source_message = validate_protected_dayz_xml_upload(path, content)
        if not valid_source:
            if label in required_backups:
                return False, backup_messages + [f"Backup blocked: live `{label}` at `{path}` is not valid before upload: {source_message}"]
            backup_messages.append(f"`{label}` backup skipped: live source at `{path}` is not valid before upload: {source_message}")
            continue
        restore_texts[path] = content
        backup_path = f"{path}.wanderingbot-backup-latest"
        backup_ok, backup_message = upload_ce_latest_backup_to_nitrado(config, label, backup_path, content)
        backup_messages.append(f"`{label}` backup `{backup_path}`: {backup_message}")
        if not backup_ok:
            backup_messages.append(
                f"`{label}` remote latest backup failed verification, so this upload will use the freshly downloaded in-memory restore copy if rollback is needed."
            )
            continue
        deleted, failed = cleanup_wanderingbot_backups_for_path(config, path, keep_paths=[backup_path])
        if deleted:
            backup_messages.append(f"`{label}` old WanderingBot backups removed: {len(deleted)}")
        if failed:
            backup_messages.append(f"`{label}` old backup cleanup skipped for {len(failed)} file(s): {' | '.join(failed[:2])}")
    return True, backup_messages


def verify_remote_protected_dayz_xml(config, label, path):
    spec = dayz_file_spec_for_path(path)
    if not spec:
        return True, f"`{label}` has no protected structured-file verifier."
    ok, message, content = download_text_file_from_nitrado(config, path)
    if not ok:
        return False, f"`{label}` verification failed after upload: {message}"
    valid, validation_message = validate_protected_dayz_xml_upload(path, content)
    if not valid:
        return False, f"`{label}` verification failed after upload: {validation_message}"
    if spec.kind == "json":
        return True, f"`{label}` verified after upload as valid JSON."
    return True, f"`{label}` verified after upload with <{spec.xml_root}> root."


def restore_remote_ce_file_from_text(config, label, path, restore_text, source_label):
    valid, validation_message = validate_protected_dayz_xml_upload(path, restore_text)
    if not valid:
        return False, f"`{label}` restore blocked: {source_label} is not valid for `{path}`: {validation_message}"
    restore_ok, restore_message = upload_text_file_to_nitrado(config, path, restore_text)
    if not restore_ok:
        return False, f"`{label}` restore upload failed from {source_label}: {restore_message}"
    verify_ok, verify_message = verify_remote_protected_dayz_xml(config, label, path)
    if not verify_ok:
        return False, f"`{label}` restore verification failed from {source_label}: {verify_message}"
    return True, f"`{label}` restored from {source_label}. {verify_message}"


def restore_remote_ce_file_from_latest_backup(config, label, path, restore_text=None):
    if str(restore_text or "").strip():
        return restore_remote_ce_file_from_text(config, label, path, restore_text, "in-memory pre-upload copy")

    backup_path = f"{path}.wanderingbot-backup-latest"
    ok, message, backup_text = download_text_file_from_nitrado(config, backup_path)
    if not ok:
        return False, f"`{label}` restore failed: could not download `{backup_path}`: {message}"
    return restore_remote_ce_file_from_text(config, label, path, backup_text, f"`{backup_path}`")


def upload_protected_ce_file_to_nitrado(config, label, path, text_content, restore_text=None):
    upload_ok, upload_message = upload_text_file_to_nitrado(config, path, text_content)
    if not upload_ok:
        live_ok, live_message = verify_remote_protected_dayz_xml(config, label, path)
        if live_ok:
            return False, f"{upload_message} Live `{label}` remained valid after failed upload. {live_message}"
        restore_ok, restore_message = restore_remote_ce_file_from_latest_backup(config, label, path, restore_text=restore_text)
        suffix = f" Restore attempted: {restore_message}" if restore_message else ""
        return False, f"{upload_message} Live verification after failure: {live_message}.{suffix}"
    if dayz_file_spec_for_path(path):
        return True, upload_message
    verify_ok, verify_message = verify_remote_protected_dayz_xml(config, label, path)
    if verify_ok:
        return True, f"{upload_message} {verify_message}"
    restore_ok, restore_message = restore_remote_ce_file_from_latest_backup(config, label, path, restore_text=restore_text)
    return False, f"{verify_message} Restore attempted: {restore_message}"


def upload_console_ce_event_files(guild_id, config, events_path="", spawns_path="", spawnabletypes_path="", consume_restart=False):
    built = build_console_ce_event_files(guild_id, config, events_path, spawns_path, spawnabletypes_path)
    messages = list(built["messages"])
    validation_ok, validation_messages = validate_console_ce_xml_bundle(built)
    messages.extend(validation_messages)
    if not validation_ok:
        return False, built, messages

    backup_ok, backup_messages = backup_remote_ce_sources_before_upload(config, built)
    messages.extend(backup_messages)
    if not backup_ok:
        return False, built, messages

    restore_texts = built.get("restore_texts") if isinstance(built.get("restore_texts"), dict) else {}

    events_ok, events_message = upload_protected_ce_file_to_nitrado(
        config,
        "events.xml",
        built["events_path"],
        built["events_text"],
        restore_text=restore_texts.get(built["events_path"]),
    )
    spawns_ok, spawns_message = upload_protected_ce_file_to_nitrado(
        config,
        "cfgeventspawns.xml",
        built["spawns_path"],
        built["spawns_text"],
        restore_text=restore_texts.get(built["spawns_path"]),
    )
    messages.append(f"`events.xml`: {events_message}")
    messages.append(f"`cfgeventspawns.xml`: {spawns_message}")

    spawnable_ok = True
    if built.get("spawnabletypes_text"):
        spawnable_ok, spawnable_message = upload_protected_ce_file_to_nitrado(
            config,
            "cfgspawnabletypes.xml",
            built["spawnabletypes_path"],
            built["spawnabletypes_text"],
            restore_text=restore_texts.get(built["spawnabletypes_path"]),
        )
        messages.append(f"`cfgspawnabletypes.xml`: {spawnable_message}")

    eventgroups_ok = True
    if built.get("eventgroups_text"):
        eventgroups_ok, eventgroups_message = upload_protected_ce_file_to_nitrado(
            config,
            "cfgeventgroups.xml",
            built["eventgroups_path"],
            built["eventgroups_text"],
            restore_text=restore_texts.get(built["eventgroups_path"]),
        )
        messages.append(f"`cfgeventgroups.xml`: {eventgroups_message}")

    mapgroupproto_ok = True
    if built.get("mapgroupproto_text"):
        mapgroupproto_ok, mapgroupproto_message = upload_protected_ce_file_to_nitrado(
            config,
            "mapgroupproto.xml",
            built["mapgroupproto_path"],
            built["mapgroupproto_text"],
            restore_text=restore_texts.get(built["mapgroupproto_path"]),
        )
        messages.append(f"`mapgroupproto.xml`: {mapgroupproto_message}")

    territory_ok = True
    failed_territory_files = []
    for territory_file in built.get("animal_territory_files") or []:
        path = territory_file.get("path")
        text = territory_file.get("text")
        if not path or not text:
            territory_ok = False
            failed_territory_files.append(territory_file)
            messages.append("Animal territory upload skipped because the target path or content was missing.")
            continue
        one_ok, one_message = upload_text_file_to_nitrado(config, path, text)
        territory_ok = territory_ok and one_ok
        if not one_ok:
            failed_territory_files.append(territory_file)
        messages.append(f"`{os.path.basename(path)}` `{path}`: {one_message}")

    cfgenvironment_ok = True
    if built.get("cfgenvironment_text"):
        cfgenvironment_text = built["cfgenvironment_text"]
        if failed_territory_files:
            try:
                env_root = ET.fromstring(str(cfgenvironment_text or "").encode("utf-8"))
                territories = env_root.find("territories") if env_root.tag != "territories" else env_root
                removed_refs = 0
                if territories is not None:
                    failed_paths = {
                        f"env/{os.path.basename(str(item.get('path') or '')).lower()}"
                        for item in failed_territory_files
                        if str(item.get("path") or "").strip()
                    }
                    failed_usables = {
                        os.path.splitext(os.path.basename(str(item.get("path") or "")).lower())[0]
                        for item in failed_territory_files
                        if str(item.get("path") or "").strip()
                    }
                    for node in list(territories):
                        if node.tag == "file":
                            path_value = str(node.get("path") or "").replace("\\", "/").lower()
                            if path_value in failed_paths:
                                territories.remove(node)
                                removed_refs += 1
                        elif node.tag == "territory":
                            usable_values = {
                                str(file_node.get("usable") or "").lower()
                                for file_node in node.findall("file")
                            }
                            if usable_values & failed_usables:
                                territories.remove(node)
                                removed_refs += 1
                cfgenvironment_text = xml_text_from_root(env_root)
                messages.append(
                    f"`cfgenvironment.xml`: removed `{removed_refs}` reference(s) for animal territory file(s) that did not upload, then uploaded the cleaned environment file."
                )
            except Exception as error:
                cfgenvironment_ok = False
                messages.append(f"`cfgenvironment.xml` cleanup failed after animal territory upload failure: {error}")

        if cfgenvironment_ok:
            cfgenvironment_ok, cfgenvironment_message = upload_protected_ce_file_to_nitrado(
                config,
                "cfgenvironment.xml",
                built["cfgenvironment_path"],
                cfgenvironment_text,
                restore_text=restore_texts.get(built["cfgenvironment_path"]),
            )
            messages.append(f"`cfgenvironment.xml`: {cfgenvironment_message}")

    cfgareaeffects_ok = True
    if built.get("cfgareaeffects_text"):
        cfgareaeffects_ok, cfgareaeffects_message = upload_protected_ce_file_to_nitrado(
            config,
            "cfgareaeffects.xml",
            built["cfgareaeffects_path"],
            built["cfgareaeffects_text"],
            restore_text=restore_texts.get(built["cfgareaeffects_path"]),
        )
        messages.append(f"`cfgareaeffects.xml`: {cfgareaeffects_message}")

    cfgeffectarea_ok = True
    if built.get("cfgeffectarea_text"):
        cfgeffectarea_ok, cfgeffectarea_message = upload_text_file_to_nitrado(
            config,
            built["cfgeffectarea_path"],
            built["cfgeffectarea_text"]
        )
        messages.append(f"`cfgEffectArea.json`: {cfgeffectarea_message}")

    success = events_ok and spawns_ok and spawnable_ok and eventgroups_ok and mapgroupproto_ok and cfgenvironment_ok and cfgareaeffects_ok and cfgeffectarea_ok and territory_ok
    if success:
        final_bundle_ok, final_bundle_messages = verify_uploaded_console_ce_xml_bundle(config, built)
        messages.extend(final_bundle_messages)
        success = success and final_bundle_ok
    if success:
        settings = console_ce_event_config(config)
        settings["enabled"] = True
        settings["events_path"] = built["events_path"]
        settings["spawns_path"] = built["spawns_path"]
        if built.get("eventgroups_path"):
            settings["eventgroups_path"] = built["eventgroups_path"]
        if built.get("mapgroupproto_path"):
            settings["mapgroupproto_path"] = built["mapgroupproto_path"]
        if built.get("spawnabletypes_path"):
            settings["spawnabletypes_path"] = built["spawnabletypes_path"]
        if built.get("cfgenvironment_path"):
            settings["cfgenvironment_path"] = built["cfgenvironment_path"]
        if built.get("cfgareaeffects_path"):
            settings["cfgareaeffects_path"] = built["cfgareaeffects_path"]
        if built.get("cfgeffectarea_path"):
            settings["cfgeffectarea_path"] = built["cfgeffectarea_path"]
        if consume_restart:
            mark_one_time_scenario_events_uploaded(config)
        save_guild_configs()

    return success, built, messages


def _scenario_notice_event_summary(event):
    if not isinstance(event, dict):
        return {}
    return {
        "id": event.get("id", ""),
        "name": event.get("name", ""),
        "type": event.get("event_type", ""),
        "class": event.get("class_name", ""),
        "x": event.get("x", ""),
        "z": event.get("z", ""),
        "radius": event.get("radius", ""),
        "permanent": bool(event.get("permanent")),
        "status": event.get("status", ""),
        "runs": event.get("remaining_restarts", event.get("runs", "")),
    }


def _scenario_notice_type_icon(event_type):
    event_type = str(event_type or "").strip().lower()
    icons = {
        "airdrop": "📦",
        "loot_crate": "📦",
        "zombie_horde": "☠️",
        "animal_pack": "🐾",
        "vehicle_spawn": "🚙",
        "gas_zone": "☣️",
    }
    return icons.get(event_type, "📍")


def _scenario_notice_coord_text(event, guild_id):
    x = event.get("x")
    z = event.get("z")
    if not str(x).strip() or not str(z).strip():
        return "-"
    coord = f"({x}, {z})"
    link = _rpt_world_link(x, z, guild_id)
    return f"[{coord}]({link})" if link else coord


def _scenario_notice_event_line(event, guild_id):
    event_type = str(event.get("type") or "event")
    name = str(event.get("name") or event.get("id") or "event")
    class_name = str(event.get("class") or "-")
    radius = str(event.get("radius") or "").strip()
    mode = "permanent" if event.get("permanent") else f"{event.get('runs') or 1} run(s)"
    radius_text = f" · r{radius}m" if radius else ""
    return (
        f"- {_scenario_notice_type_icon(event_type)} **{name}** `{event_type}` / `{class_name}` "
        f"at {_scenario_notice_coord_text(event, guild_id)}{radius_text} · {mode}"
    )[:260]


def queue_scenario_event_discord_notice(config, success, built=None, messages=None, events=None, source="Dashboard"):
    if not isinstance(config, dict):
        return False
    summaries = [_scenario_notice_event_summary(event) for event in (events or [])]
    summaries = [summary for summary in summaries if summary]
    mission_base, mission_folder, managed_names = native_ce_upload_metadata_from_built(built or {})
    notices = config.setdefault("scenario_event_discord_notices", [])
    if not isinstance(notices, list):
        notices = []
    notice = {
        "id": f"{datetime.now(UTC).timestamp()}-{len(notices)}",
        "created_at": datetime.now(UTC).isoformat(),
        "source": str(source or "Dashboard")[:80],
        "success": bool(success),
        "mission_base": mission_base,
        "mission_folder": mission_folder,
        "managed_event_names": managed_names,
        "events_path": str((built or {}).get("events_path") or ""),
        "spawns_path": str((built or {}).get("spawns_path") or ""),
        "eventgroups_path": str((built or {}).get("eventgroups_path") or ""),
        "mapgroupproto_path": str((built or {}).get("mapgroupproto_path") or ""),
        "spawnabletypes_path": str((built or {}).get("spawnabletypes_path") or ""),
        "cfgenvironment_path": str((built or {}).get("cfgenvironment_path") or ""),
        "cfgareaeffects_path": str((built or {}).get("cfgareaeffects_path") or ""),
        "cfgeffectarea_path": str((built or {}).get("cfgeffectarea_path") or ""),
        "bridge_delivery_path": str((built or {}).get("bridge_delivery_path") or ""),
        "territory_paths": [
            str(item.get("path") or "")
            for item in ((built or {}).get("animal_territory_files") or [])
            if isinstance(item, dict) and str(item.get("path") or "").strip()
        ][:8],
        "messages": [str(message)[:320] for message in (messages or [])[-10:]],
        "events": summaries[:10],
    }
    notices.append(notice)
    config["scenario_event_discord_notices"] = notices[-8:]
    return True


async def post_scenario_event_discord_notice(guild_id, config, notice):
    guild = bot.get_guild(int(guild_id))
    if not guild:
        return False
    channel = await get_or_create_rpt_admin_channel(guild, config)
    if not channel:
        return False
    state = rpt_event_tracker.setdefault(str(guild_id), {
        "events": [], "last_restart_ts": 0, "last_rpt_size": 0,
        "enabled": True, "embed_message_id": None, "channel_id": None,
        "restart_marker_count": 0,
    })
    state["channel_id"] = channel.id
    tracker_status = ""
    try:
        tracker_status = await refresh_rpt_event_tracker(guild_id, config)
    except Exception as tracker_error:
        tracker_status = f"Tracker refresh failed: {tracker_error}"
    tracker_status_text = str(tracker_status or "")
    tracker_has_new_rpt = (
        "No change in RPT since last pull." not in tracker_status_text
        and "unchanged since last tracker pull" not in tracker_status_text
    )
    success = bool(notice.get("success"))
    bridge_delivery_path = str(notice.get("bridge_delivery_path") or "").strip()
    success_status = "Bridge XML uploaded - restart once for new spawns" if bridge_delivery_path else "CE XML uploaded - restart once for new spawns"
    embed = discord.Embed(
        title="🛰️ LIVE EVENT DEPLOYMENT" if success else "⚠️ LIVE EVENT DEPLOYMENT FAILED",
        description=(
            f"Source: **{notice.get('source') or 'Dashboard'}**\n"
            f"Server: **{guild.name}**\n"
            f"Status: **{success_status if success else 'needs attention before it can spawn'}**\n"
            f"Tracker: {tracker_status or 'waiting for next .RPT pull'}"
        ),
        color=0x2ECC71 if success else 0xE74C3C,
    )
    event_lines = []
    for event in notice.get("events") or []:
        event_lines.append(_scenario_notice_event_line(event, guild.id))
    if event_lines:
        embed.add_field(name="Queued dashboard event(s)", value="\n".join(event_lines)[:1024], inline=False)

    target_lines = []
    if notice.get("mission_folder"):
        target_lines.append(f"- **Mission** `{notice.get('mission_folder')}`")
    if notice.get("mission_base"):
        target_lines.append(f"- **Remote base** `{notice.get('mission_base')}`")
    managed_names = [str(name) for name in (notice.get("managed_event_names") or []) if str(name).strip()]
    if managed_names:
        target_lines.append(f"- **Managed CE definition(s)** `{', '.join(managed_names[:5])}`")
        if len(managed_names) > 5:
            target_lines.append(f"- +{len(managed_names) - 5} more managed definition(s)")
    if target_lines:
        embed.add_field(name="CE target", value="\n".join(target_lines)[:1024], inline=False)

    live_events = list((rpt_event_tracker.get(str(guild_id), {}) or {}).get("events") or [])
    if live_events:
        now_ts = datetime.now(UTC).timestamp()
        live_lines = []
        for ev in live_events[:8]:
            link = _rpt_world_link(ev.get("x"), ev.get("z"), guild.id)
            coord = f"({int(ev.get('x', 0))}, {int(ev.get('z', 0))})"
            if link:
                coord = f"[{coord}]({link})"
            first_seen_ts = int(float(ev.get("first_seen_ts", now_ts)))
            age_s = int(now_ts - first_seen_ts)
            live_lines.append(f"- **{ev.get('type', 'Unknown')}** at {coord} | seen <t:{first_seen_ts}:R> | age {format_duration_seconds(age_s)}")
        if len(live_events) > 8:
            live_lines.append(f"- +{len(live_events) - 8} more live tracked spawn(s)")
        live_title = "Currently visible in latest RPT" if tracker_has_new_rpt else "Latest tracker state"
        if not tracker_has_new_rpt:
            live_lines.insert(0, "- Latest `.RPT` file is unchanged since the previous tracker parse; this remains the current tracker state until the next post-restart RPT update.")
        embed.add_field(name=live_title, value="\n".join(live_lines)[:1024], inline=False)

    path_lines = []
    for label, key in (
        ("events.xml", "events_path"),
        ("cfgeventspawns.xml", "spawns_path"),
        ("eventgroups.xml", "eventgroups_path"),
        ("mapgroupproto.xml", "mapgroupproto_path"),
        ("cfgspawnabletypes.xml", "spawnabletypes_path"),
        ("cfgenvironment.xml", "cfgenvironment_path"),
        ("cfgareaeffects.xml", "cfgareaeffects_path"),
        ("cfgEffectArea.json", "cfgeffectarea_path"),
        ("deliveries.xml", "bridge_delivery_path"),
    ):
        value = str(notice.get(key) or "").strip()
        if value:
            path_lines.append(f"- **{label}** `{value}`")
    for value in notice.get("territory_paths") or []:
        value = str(value or "").strip()
        if value:
            path_lines.append(f"- **animal territory** `{value}`")
    if path_lines:
        embed.add_field(name="Uploaded CE files", value="\n".join(path_lines)[:1024], inline=False)

    diagnostics = list((rpt_event_tracker.get(str(guild_id), {}) or {}).get("diagnostics") or [])
    warning_lines = []
    if tracker_has_new_rpt:
        for item in diagnostics[:6]:
            kind = str(item.get("kind") or "Warning")
            name = str(item.get("name") or "RPT")
            message = str(item.get("message") or "Check the latest RPT.")
            warning_lines.append(f"- **{kind}** `{name}`: {message}"[:240])
    elif diagnostics:
        warning_lines.append("- RPT warnings are from the latest parsed `.RPT`; the next post-restart RPT update will confirm this upload.")
    messages = [str(message) for message in (notice.get("messages") or []) if str(message).strip()]
    for message in messages[-6:]:
        warning_lines.append(f"- {message}"[:260])
    if warning_lines:
        embed.add_field(name="Spawn / upload details", value="\n".join(warning_lines)[-1024:], inline=False)

    embed.add_field(
        name="What happens next",
        value="Restart the server. The pinned live spawn tracker will update from the next `.RPT` pull and will show what actually spawned, where, and any warnings the parser can see.",
        inline=False,
    )
    embed.set_footer(text=f"Wandering Bot live events · Posted {datetime.now(UTC).strftime('%Y-%m-%d %H:%M UTC')}")
    try:
        await channel.send(embed=style_embed(embed), allowed_mentions=discord.AllowedMentions.none())
        return True
    except Exception as err:
        print(f"[SCENARIO NOTICE] Discord post failed for {guild_id}: {err}")
        return False


async def process_scenario_event_discord_notices(guild_id, config):
    notices = config.get("scenario_event_discord_notices") or []
    if not isinstance(notices, list) or not notices:
        return False
    remaining = []
    changed = False
    for notice in notices:
        if not isinstance(notice, dict):
            changed = True
            continue
        if await post_scenario_event_discord_notice(guild_id, config, notice):
            changed = True
        else:
            remaining.append(notice)
    config["scenario_event_discord_notices"] = remaining[-8:]
    return changed


def native_ce_upload_metadata_from_built(built):
    built = built if isinstance(built, dict) else {}
    mission_base = str(built.get("mission_base") or "").strip()
    if not mission_base:
        mission_base = remote_mission_base_from_ce_paths(built)
    mission_folder = str(built.get("mission_folder") or "").strip()
    if not mission_folder and mission_base:
        mission_folder = mission_base.rstrip("/").split("/")[-1]
    managed_names = []
    for value in (built.get("managed_event_names") or built.get("managed_spawn_names") or []):
        text = str(value or "").strip()
        if text and text not in managed_names:
            managed_names.append(text)
    return mission_base, mission_folder, managed_names[:24]


def scenario_event_has_confirmed_native_upload(event):
    return isinstance(event, dict) and bool(str(event.get("native_ce_uploaded_at") or "").strip())


def scenario_event_uses_delivery_bridge(event, config=None):
    return scenario_event_bridge_enabled(event, config)


def scenario_event_has_confirmed_bridge_upload(event):
    return isinstance(event, dict) and bool(str(event.get("bridge_uploaded_at") or "").strip())


def scenario_event_has_confirmed_upload(event):
    return scenario_event_has_confirmed_native_upload(event) or scenario_event_has_confirmed_bridge_upload(event)


def scenario_event_needs_native_redeploy_after_bridge(event):
    return (
        isinstance(event, dict)
        and str(event.get("event_type") or "").strip().lower() in DELIVERY_BRIDGE_SCENARIO_TYPES
        and not scenario_event_uses_delivery_bridge(event)
        and scenario_event_has_confirmed_bridge_upload(event)
        and not scenario_event_has_confirmed_native_upload(event)
    )


def scenario_event_upload_needs_resolution(event):
    if not isinstance(event, dict):
        return False
    upload_status = str(event.get("upload_status") or "waiting_for_bot_upload").strip().lower()
    status_text = str(event.get("status") or "").strip().lower()
    return (
        upload_status in {"", "waiting_for_bot_upload", "failed", "queued", "uploading", "starting"}
        or "upload requested" in status_text
        or "upload starting" in status_text
        or "waiting for bot upload" in status_text
    )


def remember_native_ce_upload_warning(event, warning, now_text=None):
    warnings = event.get("native_ce_upload_warnings")
    if not isinstance(warnings, list):
        warnings = []
    warning_text = str(warning or "").strip()
    if warning_text:
        warnings.append({
            "at": now_text or datetime.now(UTC).isoformat(),
            "message": warning_text[:500],
        })
    event["native_ce_upload_warnings"] = warnings[-5:]
    event["upload_status"] = "uploaded"
    event["status"] = "XML uploaded to Nitrado; restart once, then wait for the next RPT tracker pull"
    event.pop("upload_error", None)


def apply_native_ce_upload_metadata(event, built, messages, now_text, upload_status="uploaded", status_text=None):
    mission_base, mission_folder, managed_names = native_ce_upload_metadata_from_built(built)
    event["native_ce_uploaded_at"] = now_text
    event["native_ce_events_path"] = built.get("events_path", "")
    event["native_ce_spawns_path"] = built.get("spawns_path", "")
    event["native_ce_eventgroups_path"] = built.get("eventgroups_path", "")
    event["native_ce_mapgroupproto_path"] = built.get("mapgroupproto_path", "")
    event["native_ce_spawnabletypes_path"] = built.get("spawnabletypes_path", "")
    event["native_ce_cfgenvironment_path"] = built.get("cfgenvironment_path", "")
    event["native_ce_mission_base"] = mission_base
    event["native_ce_mission_folder"] = mission_folder
    event["native_ce_managed_event_names"] = managed_names
    event["native_ce_restart_required"] = bool(built.get("restart_required", True))
    event["native_ce_territory_paths"] = [
        str(item.get("path") or "")
        for item in (built.get("animal_territory_files") or [])
        if isinstance(item, dict) and str(item.get("path") or "").strip()
    ][:8]
    event["native_ce_upload_messages"] = [str(message)[:320] for message in messages[-8:]]
    event["upload_status"] = upload_status
    event["status"] = status_text or "XML uploaded to Nitrado; restart once, then wait for the next RPT tracker pull"
    event.pop("upload_error", None)


def apply_bridge_upload_metadata(event, delivery_path, messages, now_text, upload_status="uploaded", status_text=None):
    event["use_delivery_bridge"] = True
    event["bridge_uploaded_at"] = now_text
    event["bridge_delivery_path"] = str(delivery_path or "")
    event["bridge_upload_messages"] = [str(message)[:320] for message in (messages or [])[-8:]]
    event["native_ce_restart_required"] = True
    event["upload_status"] = upload_status
    event["status"] = status_text or "Bridge XML uploaded to Nitrado; restart once for the server bridge to spawn it"
    event.pop("upload_error", None)


def upload_delivery_bridge_scenario_events(guild_id, config, events, source="Dashboard"):
    delivery_path = delivery_bridge_path_for_guild(guild_id, config)
    events = [event for event in (events or []) if scenario_event_uses_delivery_bridge(event, config)]
    if not events:
        return False, delivery_path, ["No bridge-compatible live events were queued."]
    try:
        upload_success, xml_output_path = write_and_upload_delivery_xml(
            guild_id,
            config,
            datetime.now(UTC),
            scenario_events_override=events,
            consume_scenario_events=False,
        )
    except Exception as error:
        trace = compact_exception_leaf_trace(error)
        return False, delivery_path, [
            f"Bridge delivery XML upload failed: {type(error).__name__}: {error}. Leaf trace: {trace[:800]}"
        ]
    if upload_success:
        config["scenario_events_cleanup_pending"] = True
    event_labels = ", ".join(str(event.get("id") or event.get("name") or event.get("class_name") or "?") for event in events[:8])
    messages = [
        f"Bridge delivery XML {'uploaded' if upload_success else 'failed'} for {len(events)} live event(s): {event_labels}.",
        f"Delivery XML target `{delivery_path}`; local file `{xml_output_path}`.",
        "This route uses the installed Wandering Bot deliveries.xml bridge for direct event spawning.",
    ]
    return upload_success, delivery_path, messages


def native_ce_source_blocked_messages(messages):
    combined = " | ".join(
        str(message or "")
        for message in (messages or [])
        if not successful_native_ce_fallback_message(message)
    )
    lowered = combined.lower()
    return (
        "native ce xml upload blocked because the bot could not download" in lowered
        or "no bundled reference was found, so a minimal template was used" in lowered
        or "refusing to upload a fallback/minimal template" in lowered
    )


def native_ce_nitrado_response_blocked_messages(messages):
    combined = " | ".join(
        str(message or "")
        for message in (messages or [])
        if not successful_native_ce_fallback_message(message)
    )
    lowered = combined.lower()
    return (
        "returned non-json response" in lowered
        or "<empty response body>" in lowered
        or "empty/non-json response" in lowered
        or "cloudflare" in lowered
        or "rate-limit" in lowered
        or "rate limit" in lowered
    )


def native_ce_upload_blocked_messages(messages):
    return native_ce_source_blocked_messages(messages) or native_ce_nitrado_response_blocked_messages(messages)


def native_ce_source_required_status(messages=None):
    detail = ""
    for message in messages or []:
        if successful_native_ce_fallback_message(message):
            continue
        text = str(message or "").strip()
        lowered = text.lower()
        if "could not download existing" in lowered:
            detail = " " + text[:320]
            break
        if "rate-limit" in lowered or "cloudflare" in lowered:
            detail = " " + text[:320]
            break
    return (
        "Native CE source required: the bot could not download the existing CE XML through Nitrado/API access, "
        "so upload is blocked to avoid overwriting live events.xml/cfgeventspawns.xml. "
        "This does not mean the DayZ server cannot read its own events.xml."
        + detail
    )


def native_ce_nitrado_response_status(messages=None):
    detail = ""
    for message in messages or []:
        if successful_native_ce_fallback_message(message):
            continue
        text = str(message or "").strip()
        lowered = text.lower()
        if (
            "returned non-json response" in lowered
            or "<empty response body>" in lowered
            or "empty/non-json response" in lowered
            or "cloudflare" in lowered
            or "rate-limit" in lowered
            or "rate limit" in lowered
        ):
            detail = " " + text[:320]
            break
    return (
        "Native CE upload blocked: Nitrado returned an empty/non-JSON response while the bot was reading or uploading CE XML. "
        "This is a Nitrado/API response problem, not a valid DayZ XML result, so auto-retry has been stopped."
        + detail
    )


def compact_exception_leaf_trace(error, limit=8):
    frames = traceback.extract_tb(getattr(error, "__traceback__", None))[-limit:]
    parts = []
    for frame in frames:
        file_name = os.path.basename(frame.filename)
        line = (frame.line or "").strip()
        parts.append(f"{file_name}:{frame.lineno} in {frame.name}" + (f": {line}" if line else ""))
    return " | ".join(parts)


def native_ce_upload_blocked_status(messages=None):
    if native_ce_source_blocked_messages(messages):
        return native_ce_source_required_status(messages)
    return native_ce_nitrado_response_status(messages)


def mark_native_ce_source_required(config, event, messages, now_text):
    status_text = native_ce_upload_blocked_status(messages)
    event["upload_attempts"] = max(3, int(event.get("upload_attempts") or 0))
    event["upload_status"] = "blocked"
    event["upload_error"] = status_text
    event["status"] = "Native CE source required" if native_ce_source_blocked_messages(messages) else "Nitrado API response blocked"
    event["updated_at"] = now_text
    event["native_ce_upload_messages"] = [str(message)[:320] for message in (messages or [])[-8:]]
    settings = console_ce_event_config(config)
    settings["source_blocked_at"] = now_text
    settings["source_blocked_reason"] = status_text[:1000]
    settings["source_blocked_platform"] = normalize_server_platform(config.get("server_platform") or config.get("platform"))
    settings["source_blocked_map"] = str(config.get("server_map") or config.get("map") or "")


def dashboard_upload_console_ce_event_files(guild_id):
    guild_id = str(guild_id)
    try:
        load_guild_configs()
        config = guild_configs.get(guild_id)
        if not isinstance(config, dict):
            return {"ok": False, "built": {}, "messages": [f"No guild config found for {guild_id}."]}
        active_dashboard_events = [
            event
            for event in scenario_events_for_config(config)
            if (
                isinstance(event, dict)
                and str(event.get("created_by") or "") == "dashboard"
                and event.get("enabled", True)
                and not is_file_vehicle_reset_event(event)
                and scenario_event_upload_needs_resolution(event)
            )
        ]
        bridge_events = [
            event
            for event in active_dashboard_events
            if scenario_event_uses_delivery_bridge(event, config) and not scenario_event_has_confirmed_bridge_upload(event)
        ]
        native_events = [
            event
            for event in active_dashboard_events
            if not scenario_event_uses_delivery_bridge(event, config) and not scenario_event_has_confirmed_native_upload(event)
        ]
        if bridge_events:
            now_text = datetime.now(UTC).isoformat()
            bridge_success, delivery_path, bridge_messages = upload_delivery_bridge_scenario_events(
                guild_id,
                config,
                bridge_events,
                "Dashboard upload",
            )
            for event in bridge_events:
                event["upload_attempts"] = int(event.get("upload_attempts") or 0) + 1
                event["updated_at"] = now_text
                if bridge_success:
                    apply_bridge_upload_metadata(event, delivery_path, bridge_messages, now_text)
                else:
                    event["upload_status"] = "failed"
                    event["upload_error"] = "Bridge delivery XML upload failed: " + (" | ".join(bridge_messages[-4:]) if bridge_messages else "no details")
                    event["status"] = "Bridge XML upload failed"
            try:
                queue_scenario_event_discord_notice(
                    config,
                    bridge_success,
                    {
                        "bridge_delivery_path": delivery_path,
                        "bridge_event_ids": [safe_int(event.get("id"), 0) for event in bridge_events],
                        "restart_required": True,
                    },
                    bridge_messages,
                    bridge_events,
                    "Dashboard bridge upload",
                )
            except Exception as notice_error:
                bridge_messages.append(f"Discord notice queue skipped after bridge upload state update: {type(notice_error).__name__}: {notice_error}")
            save_guild_configs()
            if not native_events and not bool(config.get("scenario_events_cleanup_pending")):
                return {
                    "ok": bridge_success,
                    "built": {
                        "bridge_delivery_path": delivery_path,
                        "bridge_event_ids": [safe_int(event.get("id"), 0) for event in bridge_events],
                        "restart_required": True,
                    },
                    "messages": bridge_messages,
                }
        success, built, messages = upload_console_ce_event_files(
            guild_id,
            config,
            "",
            "",
            "",
            False,
        )
    except Exception as error:
        success = False
        built = {}
        trace = compact_exception_leaf_trace(error)
        messages = [f"Native CE upload exception: {type(error).__name__}: {error}. Leaf trace: {trace[:1000]}"]
        config = guild_configs.get(guild_id)
        if not isinstance(config, dict):
            return {"ok": False, "built": built, "messages": messages}
    source_blocked = native_ce_upload_blocked_messages(messages)
    status_text = (
        f"Native CE XML uploaded to {built.get('events_path')} and {built.get('spawns_path')}"
        if success
        else native_ce_upload_blocked_status(messages)
        if source_blocked
        else native_ce_failed_status_text(messages)
    )
    now_text = datetime.now(UTC).isoformat()
    changed = False
    affected_events = []
    cleanup_pending = bool(config.get("scenario_events_cleanup_pending"))
    if success and cleanup_pending:
        config["scenario_events_cleanup_pending"] = False
        config["scenario_events_cleanup_completed_at"] = now_text
        config.pop("scenario_events_cleanup_error", None)
        changed = True
    elif cleanup_pending:
        config["scenario_events_cleanup_error"] = status_text
        changed = True
    native_event_ids = {str(event.get("id") or "") for event in native_events if isinstance(event, dict)}
    for event in native_events:
        if not isinstance(event, dict):
            continue
        affected_events.append(event)
        if success:
            apply_native_ce_upload_metadata(event, built, messages, now_text)
            event["updated_at"] = now_text
            changed = True
        elif scenario_event_upload_needs_resolution(event):
            if scenario_event_has_confirmed_native_upload(event):
                remember_native_ce_upload_warning(event, status_text, now_text)
                event["updated_at"] = now_text
                changed = True
                continue
            if source_blocked:
                mark_native_ce_source_required(config, event, messages, now_text)
                changed = True
                continue
            attempts = int(event.get("upload_attempts") or 0) + 1
            event["upload_attempts"] = attempts
            event["upload_status"] = "failed"
            event["upload_error"] = status_text
            event["status"] = "Native CE XML upload failed"
            event["updated_at"] = now_text
            changed = True
    if changed:
        try:
            queue_events = affected_events if affected_events else [
                event for event in scenario_events_for_config(config)
                if isinstance(event, dict) and str(event.get("id") or "") in native_event_ids
            ]
            queue_scenario_event_discord_notice(config, success, built, messages, queue_events, "Dashboard upload")
        except Exception as notice_error:
            messages.append(f"Discord notice queue skipped after upload state update: {type(notice_error).__name__}: {notice_error}")
        save_guild_configs()
    return {"ok": success, "built": built, "messages": messages}


def scenario_location_from_choice(location_key, x=None, z=None, y=0, map_key="chernarus"):
    presets = scenario_location_presets_for_map(map_key)
    location = presets.get(str(location_key or "").lower())
    if not location:
        location = presets.get("custom", SCENARIO_LOCATION_PRESETS["custom"])

    if location_key == "custom":
        x_value = parse_dayz_map_number(x)
        z_value = parse_dayz_map_number(z)
        y_value = parse_dayz_map_number(y) if y is not None else 0
        if x_value is None or z_value is None:
            return None, "Custom location needs numeric `x` and `z` coordinates."
        return {
            "name": "Custom Coordinates",
            "x": x_value,
            "y": y_value or 0,
            "z": z_value,
        }, None

    return dict(location), None


def build_scenario_event_xml(event):
    x = parse_dayz_map_number(event.get("x"))
    y = parse_dayz_map_number(event.get("y", 0))
    z = parse_dayz_map_number(event.get("z"))
    class_name = str(event.get("class_name") or "").strip()
    event_type = str(event.get("event_type") or "").strip()
    if x is None or z is None:
        return None

    if event_type == "vehicle_reset_all":
        if str(event.get("reset_method") or "").lower() in {"cfgignorelist", "economy_xml"}:
            return None
        excluded = event.get("exclude") or []
        if isinstance(excluded, str):
            excluded = [item.strip() for item in excluded.split(",") if item.strip()]
        exclude_attr = "|".join(str(item).strip() for item in excluded if str(item).strip())
        radius = max(1000, min(30000, int(event.get("radius", 22000) or 22000)))
        return (
            f'<object action="reset_all_vehicles" name="ALL_VEHICLES" '
            f'pos="{x} {y or 0} {z}" radius="{radius}" '
            f'exclude="{safe_xml_attr(exclude_attr)}" event_id="{safe_xml_attr(event.get("id", ""))}" />'
        )

    if event_type == "vehicle_reset_point":
        if not class_name:
            return None
        radius = max(5, min(250, int(event.get("radius", 35) or 35)))
        return (
            f'<object action="reset_vehicle" name="{safe_xml_attr(class_name)}" '
            f'pos="{x} {y or 0} {z}" radius="{radius}" '
            f'event_id="{safe_xml_attr(event.get("id", ""))}" />'
        )

    if not class_name:
        return None

    count = max(1, min(250, int(event.get("count", 1) or 1)))
    radius = max(0, min(2000, int(event.get("radius", 0) or 0)))
    loot = event.get("loot") or []
    if isinstance(loot, str):
        loot = [item.strip() for item in loot.split(",") if item.strip()]
    resolved_loot = scenario_loot_items(event)
    loot_attr = "|".join(str(item).strip() for item in resolved_loot if str(item).strip())

    if event_type in {"airdrop", "loot_crate"}:
        lines = []

        def fmt_pos(px, py, pz):
            return f"{ce_decimal(px)} {ce_decimal(py)} {ce_decimal(pz)}"

        def add_spawn_line(action, name, px, py, pz, extra_attrs=""):
            name = str(name or "").strip()
            if not name:
                return
            suffix = f" {extra_attrs.strip()}" if str(extra_attrs or "").strip() else ""
            lines.append(
                f'<object action="{safe_xml_attr(action)}" name="{safe_xml_attr(name)}" '
                f'pos="{fmt_pos(px, py, pz)}"{suffix} />'
            )

        scene = scenario_airdrop_scene_config(event)
        base_y = y or 0
        crate_x = x
        crate_z = z
        if event.get("visual_marker"):
            marker_class = str(scene.get("marker") or event.get("marker_class") or SCENARIO_AIRDROP_MARKER_CLASS).strip()
            add_spawn_line("spawn_item", marker_class, x, base_y, z)
            for scene_prop in scene.get("props") or SCENARIO_AIRDROP_SCENE_PROPS:
                offset_x = parse_dayz_map_number(scene_prop.get("x")) or 0
                offset_y = parse_dayz_map_number(scene_prop.get("y")) or 0
                offset_z = parse_dayz_map_number(scene_prop.get("z")) or 0
                add_spawn_line("spawn_item", scene_prop.get("type"), x + offset_x, base_y + offset_y, z + offset_z)
            crate_offset = scene.get("crate_offset") or ("0", "0")
            crate_x += parse_dayz_map_number(crate_offset[0]) or 0
            crate_z += parse_dayz_map_number(crate_offset[1]) or 0

        ground_loot = scenario_airdrop_ground_loot_items(event) if event_type == "airdrop" else []
        ground_spread = int(scene.get("ground_spread") or max(12, min(35, radius or 18)))
        for index, item_name in enumerate(ground_loot[:36]):
            offset_x, offset_z = scenario_airdrop_child_offsets(index, ground_spread, max_spread=ground_spread)
            add_spawn_line("spawn_item", item_name, x + offset_x, base_y, z + offset_z)

        crate_loot = list(scenario_airdrop_ammo_box_items(event)) if event_type == "airdrop" else list(resolved_loot)
        seen_crate_loot = {str(item).lower() for item in crate_loot}
        for weapon_name in ground_loot:
            recipe = SCENARIO_AIRDROP_WEAPON_RECIPES.get(weapon_name, {})
            for child_name in list(recipe.get("attachments", [])) + list(recipe.get("supplies", [])):
                child_key = str(child_name).lower()
                if child_name and child_key not in seen_crate_loot:
                    seen_crate_loot.add(child_key)
                    crate_loot.append(child_name)
        if not crate_loot and resolved_loot:
            crate_loot = list(resolved_loot[:20])
        crate_loot_attr = "|".join(str(item).strip() for item in crate_loot[:48] if str(item).strip())
        crate_radius = 0 if count <= 1 else max(1, min(12, radius))

        extra_attrs = {
            "event_type": event.get("event_type", ""),
            "loot_preset": event.get("loot_preset", ""),
            "guard_class": event.get("guard_class", ""),
            "guard_count": event.get("guard_count", ""),
            "guard_radius": event.get("guard_radius", ""),
            "visual_marker": "1" if event.get("visual_marker") else "",
        }
        extra_text = " ".join(
            f'{key}="{safe_xml_attr(value)}"'
            for key, value in extra_attrs.items()
            if str(value or "").strip()
        )
        if extra_text:
            extra_text = " " + extra_text
        lines.append(
            f'<object action="spawn_event" name="{safe_xml_attr(class_name)}" '
            f'pos="{fmt_pos(crate_x, base_y, crate_z)}" count="{count}" radius="{crate_radius}" '
            f'loot="{safe_xml_attr(crate_loot_attr)}" event_id="{safe_xml_attr(event.get("id", ""))}"{extra_text} />'
        )
        return "\n".join(lines)

    extra_attrs = {
        "event_type": event.get("event_type", ""),
        "loot_preset": event.get("loot_preset", ""),
        "vehicle_condition": event.get("vehicle_condition", ""),
        "vehicle_cargo_mode": event.get("vehicle_cargo_mode", ""),
        "guard_class": event.get("guard_class", ""),
        "guard_count": event.get("guard_count", ""),
        "guard_radius": event.get("guard_radius", ""),
        "gas_lifetime": event.get("gas_lifetime", ""),
        "marker_class": event.get("marker_class", ""),
        "visual_marker": "1" if event.get("visual_marker") else "",
    }
    extra_text = " ".join(
        f'{key}="{safe_xml_attr(value)}"'
        for key, value in extra_attrs.items()
        if str(value or "").strip()
    )
    if extra_text:
        extra_text = " " + extra_text

    return (
        f'<object action="spawn_event" name="{safe_xml_attr(class_name)}" '
        f'pos="{x} {y or 0} {z}" count="{count}" radius="{radius}" '
        f'loot="{safe_xml_attr(loot_attr)}" event_id="{safe_xml_attr(event.get("id", ""))}"{extra_text} />'
    )


def scenario_event_mode_text(event):
    if event.get("permanent"):
        return "forever"

    remaining = event.get("remaining_restarts")
    if remaining is None:
        return "one-time"

    try:
        remaining = int(remaining)
    except Exception:
        return "one-time"

    if remaining <= 0:
        return "forever"

    return f"{remaining} restart(s)"


async def auto_push_scenario_events_xml(guild_id, config):
    """Push merged events.xml / cfgeventspawns.xml / cfgspawnabletypes.xml to
    Nitrado right after an admin creates a new scenario event.

    Returns a tuple (success, status_text) where `status_text` is a human-
    readable string suitable for embed descriptions. Does NOT consume the
    event's restart counter — the normal restart processor handles that on
    the actual server restart.
    """
    try:
        delivery_events = delivery_bridge_scenario_events(config)
        if delivery_events:
            upload_success, delivery_path, upload_messages = await asyncio.to_thread(
                upload_delivery_bridge_scenario_events,
                guild_id,
                config,
                delivery_events,
                "Immediate event upload",
            )
            now_text = datetime.now(UTC).isoformat()
            for event in delivery_events:
                if upload_success:
                    apply_bridge_upload_metadata(event, delivery_path, upload_messages, now_text)
                else:
                    event["upload_status"] = "failed"
                    event["upload_error"] = "Bridge delivery XML upload failed: " + (" | ".join(upload_messages[-4:]) if upload_messages else "no details")
                    event["status"] = "Bridge XML upload failed"
            save_guild_configs()
            if upload_success and not native_ce_scenario_events(config):
                return True, "Bridge XML uploaded to Nitrado. Event will spawn through the DayZ bridge after the next server restart."

        native_events = native_ce_scenario_events(config)
        if not native_events:
            return bool(delivery_events), (
                "Bridge XML uploaded to Nitrado. Event will spawn through the DayZ bridge after the next server restart."
                if delivery_events
                else "No live event XML upload was needed."
            )

        upload_success, _, upload_messages = await asyncio.to_thread(
            upload_console_ce_event_files,
            guild_id,
            config,
            "",
            "",
            "",
            False,
        )
    except Exception as upload_error:
        return False, (
            "⚠️ Event created but auto-upload to Nitrado FAILED — it will NOT appear "
            f"on the server until you run `/events uploadce`. Reason: {upload_error}"
        )

    if upload_success:
        return True, (
            "✅ XML uploaded to Nitrado. Event will appear after the next server restart."
        )

    last_msg = upload_messages[-1] if upload_messages else "no message"
    return False, (
        "⚠️ Event created but auto-upload to Nitrado FAILED — it will NOT appear "
        f"on the server until you run `/events uploadce`. Reason: {last_msg}"
    )


def restart_count_fields(restarts=1):
    try:
        restarts = int(restarts or 1)
    except Exception:
        restarts = 1

    if restarts <= 0:
        return {"permanent": True, "remaining_restarts": 0}

    return {"permanent": False, "remaining_restarts": max(1, min(365, restarts))}


def mark_one_time_scenario_events_uploaded(config, require_native_upload=False):
    events = scenario_events_for_config(config)
    kept = []
    changed = False
    now_text = datetime.now(UTC).isoformat()

    for event in events:
        if not event.get("enabled", True):
            kept.append(event)
            continue

        if is_file_vehicle_reset_event(event):
            kept.append(event)
            continue

        if event.get("permanent"):
            kept.append(event)
            continue

        if require_native_upload and not scenario_event_has_confirmed_upload(event):
            kept.append(event)
            continue

        if "remaining_restarts" not in event:
            changed = True
            continue

        try:
            remaining = int(event.get("remaining_restarts", 1) or 1)
        except Exception:
            remaining = 1

        remaining -= 1
        if remaining > 0:
            event["remaining_restarts"] = remaining
            event["status"] = f"Completed one restart cycle; {remaining} restart(s) left"
            event["updated_at"] = now_text
            kept.append(event)
        changed = True

    config["scenario_events"] = kept
    return changed


def mark_scenario_event_completed(config, event_id):
    event_id = str(event_id)
    events = scenario_events_for_config(config)
    kept = []
    for event in events:
        if str(event.get("id")) != event_id:
            kept.append(event)
            continue
        method_label = "cfgignorelist vehicle-only reset" if is_cfgignorelist_vehicle_reset_event(event) else "economy reset"
        if event.get("permanent"):
            event["status"] = f"Completed one {method_label} cycle; waiting for next scheduled run"
            kept.append(event)
            continue
        try:
            remaining = int(event.get("remaining_restarts", 1) or 1)
        except Exception:
            remaining = 1
        remaining -= 1
        if remaining > 0:
            event["remaining_restarts"] = remaining
            event["status"] = f"Completed one {method_label} cycle"
            kept.append(event)
    config["scenario_events"] = kept


def vehicle_reset_exclusions(config):
    excluded = config.setdefault("vehicle_reset_exclusions", [])
    if not isinstance(excluded, list):
        excluded = []
        config["vehicle_reset_exclusions"] = excluded
    return [str(item) for item in excluded if str(item).strip()]


def known_vehicle_classes(limit=None):
    classes = DEFAULT_VEHICLE_RESET_CLASSES.copy()

    for item_name, data in shop_items.items():
        if str(data.get("category", "")).lower() == "vehicles":
            classes.append(str(item_name))

    deduped = []
    seen = set()
    for item_name in sorted(classes):
        key = normalize_discord_name(item_name)
        if not key or key in seen:
            continue
        deduped.append(item_name)
        seen.add(key)

    if limit:
        return deduped[:limit]
    return deduped


def cfgignorelist_path_candidates(guild_id, config):
    configured = str(config.get("vehicle_reset_cfgignorelist_path") or "").strip()
    paths = [configured] if configured else []
    roots = [
        "/dayzxb/mpmissions",
        "/dayzxb_missions",
        "/dayzps/mpmissions",
        "/dayzps_missions",
        "/dayz/mpmissions",
        "/dayz_missions",
        "/mpmissions",
    ]

    for mission in map_mission_folder_names(server_map_key(guild_id)):
        for root in roots:
            paths.append(f"{root}/{mission}/cfgignorelist.xml")
            paths.append(f"{root}/{mission}/db/cfgignorelist.xml")

    deduped = []
    for path in paths:
        path = str(path or "").replace("\\", "/").strip()
        if path and path not in deduped:
            deduped.append(path)
    return deduped


def empty_cfgignorelist_xml():
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<ignore />\n'


def download_cfgignorelist_for_vehicle_reset(guild_id, config):
    messages = []
    candidates = cfgignorelist_path_candidates(guild_id, config)
    for path in candidates:
        ok, message, text = download_text_file_from_nitrado(config, path)
        messages.append(f"{path}: {message}")
        if ok and text is not None:
            config["vehicle_reset_cfgignorelist_path"] = path
            return True, path, message, text

    path = candidates[0] if candidates else ""
    if path:
        config["vehicle_reset_cfgignorelist_path"] = path
        return True, path, "cfgignorelist.xml was not found; a vehicle-only file will be created.", empty_cfgignorelist_xml()

    return False, "", "Could not resolve a cfgignorelist.xml path. Tried: " + " | ".join(messages[-6:]), ""


def vehicle_reset_cfgignorelist_classes(config):
    excluded = {normalize_discord_name(item) for item in vehicle_reset_exclusions(config)}
    classes = []
    for item_name in known_vehicle_classes(limit=None):
        key = normalize_discord_name(item_name)
        if key and key not in excluded:
            classes.append(item_name)
    return classes


def build_vehicle_cfgignorelist_xml(original_text, vehicle_classes):
    try:
        root = ET.fromstring(original_text or empty_cfgignorelist_xml())
    except ET.ParseError:
        root = ET.Element("ignore")

    existing = {
        normalize_discord_name(node.get("name"))
        for node in root.findall(".//item")
        if node.get("name")
    }
    added = 0
    for item_name in vehicle_classes:
        key = normalize_discord_name(item_name)
        if not key or key in existing:
            continue
        item = ET.SubElement(root, "item")
        item.set("name", str(item_name))
        existing.add(key)
        added += 1

    try:
        ET.indent(root, space="    ")
    except Exception:
        pass

    xml_body = ET.tostring(root, encoding="unicode")
    xml_text = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n' + xml_body + "\n"
    return True, f"Prepared cfgignorelist.xml with {len(vehicle_classes)} vehicle class(es), adding {added}.", xml_text


def scheduled_vehicle_reset_preflight_seconds(config):
    try:
        minutes = int(config.get("vehicle_reset_preflight_minutes", 15) or 15)
    except Exception:
        minutes = 15
    return max(2, min(120, minutes)) * 60


def scheduled_damage_settings_preflight_seconds(config):
    try:
        minutes = int(config.get("damage_preflight_minutes", config.get("vehicle_reset_preflight_minutes", 15)) or 15)
    except Exception:
        minutes = 15
    return max(2, min(120, minutes)) * 60


def normalized_damage_state(value):
    return "off" if str(value or "").strip().lower() == "off" else "on"


def damage_state_to_cfggameplay_disabled(value):
    return normalized_damage_state(value) != "on"


def update_cfggameplay_damage_settings(cfggameplay_text, base_state, container_state):
    data = json.loads(cfggameplay_text or "{}")
    if not isinstance(data, dict):
        raise ValueError("cfggameplay.json root must be a JSON object.")
    general = data.setdefault("GeneralData", {})
    if not isinstance(general, dict):
        general = {}
        data["GeneralData"] = general

    disable_base = damage_state_to_cfggameplay_disabled(base_state)
    disable_container = damage_state_to_cfggameplay_disabled(container_state)
    changed = (
        general.get("disableBaseDamage") is not disable_base
        or general.get("disableContainerDamage") is not disable_container
    )
    general["disableBaseDamage"] = disable_base
    general["disableContainerDamage"] = disable_container
    flags = {
        "disableBaseDamage": disable_base,
        "disableContainerDamage": disable_container,
    }
    return json.dumps(data, indent=2, ensure_ascii=False) + "\n", changed, flags


def download_live_cfggameplay_source(config, guild_id):
    settings = console_ce_event_config(config)
    attempted = []
    tried = set()
    for include_discovery in (False, True):
        for candidate_path in console_ce_path_candidates(
            config,
            guild_id,
            "cfggameplay_path",
            "",
            settings.get("cfggameplay_path"),
            include_discovery=include_discovery,
        ):
            if candidate_path in tried:
                continue
            tried.add(candidate_path)
            ok, message, text = download_text_file_from_nitrado(config, candidate_path)
            attempted.append((candidate_path, message))
            if ok and str(text or "").strip():
                remember_console_ce_mission_base(config, guild_id, candidate_path)
                settings["cfggameplay_path"] = candidate_path
                return True, message, text, candidate_path
            if console_ce_download_message_is_rate_limited(message):
                break

    if attempted:
        tried_text = "; ".join(
            f"{path}: {compact_ce_download_message(message, 120)}"
            for path, message in attempted[-5:]
        )
        return False, f"Could not download live cfggameplay.json. Tried {len(attempted)} path(s): {tried_text}", None, ""
    return False, "Could not download live cfggameplay.json because no path candidates were available.", None, ""


def read_cfggameplay_damage_flags(text):
    data = json.loads(text or "{}")
    if not isinstance(data, dict):
        raise ValueError("cfggameplay.json root must be a JSON object.")
    general = data.get("GeneralData")
    if not isinstance(general, dict):
        general = {}
    return {
        "disableBaseDamage": bool(general.get("disableBaseDamage", False)),
        "disableContainerDamage": bool(general.get("disableContainerDamage", False)),
    }


def upload_cfggameplay_damage_settings(guild_id, config, base_state, container_state):
    ok, message, source_text, path = download_live_cfggameplay_source(config, guild_id)
    if not ok:
        return False, message, "", {}

    try:
        updated_text, changed, wanted_flags = update_cfggameplay_damage_settings(source_text, base_state, container_state)
    except Exception as error:
        return False, f"Could not parse live cfggameplay.json from `{path}`: {error}", path, {}

    if not changed:
        return True, f"`cfggameplay.json` already has raid damage flags staged at `{path}`.", path, wanted_flags

    backup_path = f"{path}.wanderingbot-backup-latest"
    backup_ok, backup_message = upload_text_file_to_nitrado(config, backup_path, source_text)
    if not backup_ok:
        return False, f"Backup blocked before cfggameplay upload: {backup_message}", path, wanted_flags

    upload_ok, upload_message = upload_text_file_to_nitrado(config, path, updated_text)
    if not upload_ok:
        verify_ok, verify_message, verify_text = download_text_file_from_nitrado(config, path)
        restore_note = ""
        try:
            if not verify_ok or read_cfggameplay_damage_flags(verify_text) != read_cfggameplay_damage_flags(source_text):
                restore_ok, restore_message = upload_text_file_to_nitrado(config, path, source_text)
                restore_note = f" Restore attempted: {restore_message}" if restore_message else ""
                if not restore_ok:
                    restore_note = f" Restore failed: {restore_message}"
        except Exception as error:
            restore_ok, restore_message = upload_text_file_to_nitrado(config, path, source_text)
            restore_note = f" Restore after verification error `{error}`: {restore_message}"
        return False, f"{upload_message} Live verification after failed upload: {verify_message}.{restore_note}", path, wanted_flags

    verify_ok, verify_message, verify_text = download_text_file_from_nitrado(config, path)
    if not verify_ok:
        return False, f"{upload_message} Verification download failed after cfggameplay upload: {verify_message}", path, wanted_flags
    try:
        live_flags = read_cfggameplay_damage_flags(verify_text)
    except Exception as error:
        restore_ok, restore_message = upload_text_file_to_nitrado(config, path, source_text)
        return False, f"cfggameplay verification parse failed after upload: {error}. Restore attempted: {restore_message}", path, wanted_flags
    if live_flags != wanted_flags:
        restore_ok, restore_message = upload_text_file_to_nitrado(config, path, source_text)
        return False, f"cfggameplay verification mismatch after upload. Restore attempted: {restore_message}", path, wanted_flags

    return True, f"{upload_message} Verified `{path}` with disableBaseDamage={wanted_flags['disableBaseDamage']} and disableContainerDamage={wanted_flags['disableContainerDamage']}.", path, wanted_flags


def scheduled_vehicle_reset_restore_delay_seconds(config):
    try:
        seconds = int(config.get("vehicle_reset_post_restart_restore_delay_seconds", 300) or 300)
    except Exception:
        seconds = 300
    return max(60, min(3600, seconds))


def cfgignorelist_vehicle_reset_backup_path(path):
    path = str(path or "").replace("\\", "/").strip()
