def download_economy_xml_for_vehicle_reset(guild_id, config):
    messages = []
    for path in economy_xml_path_candidates(guild_id, config):
        ok, message, text = download_text_file_from_nitrado(config, path)
        messages.append(f"{path}: {message}")
        if ok and text:
            config["vehicle_reset_economy_path"] = path
            return True, path, message, text

    return False, "", "Could not download economy.xml. Tried: " + " | ".join(messages[-6:]), ""


def set_vehicle_economy_init(economy_xml_text, init_value):
    try:
        root = ET.fromstring(economy_xml_text)
    except ET.ParseError as error:
        return False, f"economy.xml parse failed: {error}", economy_xml_text

    wanted = str(init_value)
    changed = 0
    matched = 0
    for node in root.iter():
        tag = str(node.tag or "").split("}", 1)[-1].lower()
        if tag in {"vehicles", "vehicle"}:
            matched += 1
            if node.get("init") != wanted:
                node.set("init", wanted)
                changed += 1

    if matched <= 0:
        return False, "No vehicle economy init entries were found.", economy_xml_text
    if changed <= 0:
        return True, f"Vehicle economy init was already {wanted}.", economy_xml_text

    return (
        True,
        f"Changed {changed} vehicle economy init entr{'y' if changed == 1 else 'ies'} to {wanted}.",
        ET.tostring(root, encoding="unicode"),
    )


async def run_economy_vehicle_reset_workflow(guild_id, config, event):
    workflow = config.setdefault("vehicle_reset_economy_workflow", {})
    if workflow.get("running"):
        return False, "Economy vehicle reset is already running for this guild."

    event_id = str(event.get("id") or "")
    workflow.update({
        "running": True,
        "event_id": event_id,
        "started_at": datetime.now(UTC).isoformat(),
        "stage": "download_economy_xml",
    })
    event["status"] = "Economy XML reset running: preparing economy.xml"
    save_guild_configs()

    path = ""
    original_text = ""
    restored = False

    try:
        ok, path, message, original_text = await asyncio.to_thread(
            download_economy_xml_for_vehicle_reset,
            guild_id,
            config,
        )
        if not ok:
            event["status"] = message
            return False, message

        ok, message, wipe_text = set_vehicle_economy_init(original_text, "0")
        if not ok:
            event["status"] = message
            return False, message

        workflow["stage"] = "upload_init_0"
        event["status"] = message
        save_guild_configs()
        upload_ok, upload_message = await asyncio.to_thread(
            upload_text_file_to_nitrado,
            config,
            path,
            wipe_text,
        )
        if not upload_ok:
            event["status"] = f"Failed to upload vehicle init 0 economy.xml: {upload_message}"
            return False, event["status"]

        workflow["stage"] = "restart_with_init_0"
        event["status"] = "Vehicles init set to 0; restarting server for wipe cycle"
        save_guild_configs()
        restart_ok, restart_message = await asyncio.to_thread(nitrado_gameserver_action, config, "restart")
        record = append_restart_history(
            guild_id,
            config,
            "vehicle_reset",
            "requested" if restart_ok else "failed",
            f"Economy vehicle reset restart: {restart_message}",
            "vehicle reset workflow",
        )
        save_guild_configs()
        await publish_restart_history(guild_id, config, record)
        if not restart_ok:
            event["status"] = restart_message
            return False, restart_message

        await asyncio.sleep(max(30, int(config.get("vehicle_reset_wipe_wait_seconds", 120) or 120)))

        workflow["stage"] = "stop_for_restore"
        event["status"] = "Stopping server so vehicles init can be restored to 1"
        save_guild_configs()
        stop_ok, stop_message = await asyncio.to_thread(nitrado_gameserver_action, config, "stop")
        if not stop_ok:
            event["status"] = stop_message
            return False, stop_message

        await asyncio.sleep(max(10, int(config.get("vehicle_reset_restore_wait_seconds", 30) or 30)))

        ok, message, restore_text = set_vehicle_economy_init(original_text, "1")
        if not ok:
            event["status"] = message
            return False, message

        workflow["stage"] = "upload_init_1"
        event["status"] = message
        save_guild_configs()
        upload_ok, upload_message = await asyncio.to_thread(
            upload_text_file_to_nitrado,
            config,
            path,
            restore_text,
        )
        if not upload_ok:
            event["status"] = f"Failed to restore vehicle init 1 economy.xml: {upload_message}"
            return False, event["status"]
        restored = True

        workflow["stage"] = "start_with_init_1"
        event["status"] = "Vehicles init restored to 1; starting server"
        save_guild_configs()
        start_ok, start_message = await asyncio.to_thread(nitrado_gameserver_action, config, "start")
        if not start_ok:
            event["status"] = start_message
            return False, start_message

        workflow["stage"] = "complete"
        workflow["last_completed_at"] = datetime.now(UTC).isoformat()
        workflow["last_path"] = path
        event["status"] = "Economy XML vehicle reset complete"
        mark_scenario_event_completed(config, event_id)
        return True, "Economy XML vehicle reset complete."

    finally:
        if original_text and path and not restored:
            try:
                ok, _, restore_text = set_vehicle_economy_init(original_text, "1")
                if ok:
                    await asyncio.to_thread(upload_text_file_to_nitrado, config, path, restore_text)
                    workflow["restore_attempted_at"] = datetime.now(UTC).isoformat()
            except Exception as restore_error:
                workflow["restore_error"] = str(restore_error)
                print(f"ECONOMY VEHICLE RESET RESTORE FAILED {guild_id}: {restore_error}")

        workflow["running"] = False
        workflow["finished_at"] = datetime.now(UTC).isoformat()
        save_guild_configs()


async def process_economy_vehicle_reset_events(guild_id, config):
    processed = []
    for event in list(active_economy_vehicle_reset_events(config)):
        ok, message = await run_economy_vehicle_reset_workflow(guild_id, config, event)
        processed.append((ok, message))
        if not ok:
            break
    return processed


async def run_scheduled_cfgignorelist_vehicle_reset_workflow(guild_id, config, event):
    workflow = config.setdefault("vehicle_reset_cfgignorelist_workflow", {})
    event_id = str(event.get("id") or "")
    now = datetime.now(UTC)
    stage = str(event.get("cfgignorelist_stage") or "pending_prepare").strip().lower()
    target_restart = _parse_schedule_datetime(
        event.get("target_restart_utc")
        or event.get("queued_for_restart_utc")
        or event.get("created_at")
    )

    if stage in {"waiting_for_restart", "waiting_to_restore"}:
        restore_after = _parse_schedule_datetime(event.get("cfgignorelist_restore_after_utc"))
        if not restore_after:
            if target_restart:
                restore_after = target_restart + timedelta(seconds=scheduled_vehicle_reset_restore_delay_seconds(config))
            else:
                restore_after = now + timedelta(seconds=scheduled_vehicle_reset_restore_delay_seconds(config))
            event["cfgignorelist_restore_after_utc"] = restore_after.isoformat()

        if now < restore_after:
            event["cfgignorelist_stage"] = "waiting_to_restore" if target_restart and now >= target_restart else "waiting_for_restart"
            event["status"] = (
                "Vehicle-only cfgignorelist prepared; waiting for scheduled restart "
                f"at {format_reset_time(target_restart.isoformat() if target_restart else '')} "
                f"then restore after {format_reset_time(restore_after.isoformat())}."
            )
            save_guild_configs()
            return True, event["status"]

        stage = "restore_original_cfgignorelist"
        event["cfgignorelist_stage"] = stage

    if stage == "pending_prepare":
        if workflow.get("running"):
            return False, "cfgignorelist vehicle reset is already running for this guild."

        workflow.update({
            "running": True,
            "event_id": event_id,
            "started_at": now.isoformat(),
            "stage": "prepare_before_scheduled_restart",
        })
        event["reset_method"] = "cfgignorelist"
        event["status"] = "Preparing vehicle-only cfgignorelist before the scheduled restart"
        save_guild_configs()

        try:
            vehicle_classes = vehicle_reset_cfgignorelist_classes(config)
            if not vehicle_classes:
                event["status"] = "No vehicle classes were found for cfgignorelist reset."
                return False, event["status"]

            ok, path, message, original_text = await asyncio.to_thread(
                download_cfgignorelist_for_vehicle_reset,
                guild_id,
                config,
            )
            if not ok:
                event["status"] = message
                return False, message

            backup_path = cfgignorelist_vehicle_reset_backup_path(path)
            if backup_path:
                backup_ok, backup_message = await asyncio.to_thread(
                    upload_text_file_to_nitrado,
                    config,
                    backup_path,
                    original_text or empty_cfgignorelist_xml(),
                )
                if not backup_ok:
                    event["status"] = f"Failed to save cfgignorelist restore backup: {backup_message}"
                    return False, event["status"]
            else:
                backup_message = "No backup path could be resolved."

            ok, message, wipe_text = build_vehicle_cfgignorelist_xml(original_text, vehicle_classes)
            if not ok:
                event["status"] = message
                return False, message

            upload_ok, upload_message = await asyncio.to_thread(
                upload_text_file_to_nitrado,
                config,
                path,
                wipe_text,
            )
            if not upload_ok:
                event["status"] = f"Failed to upload vehicle-only cfgignorelist.xml: {upload_message}"
                return False, event["status"]

            restore_after = (
                target_restart + timedelta(seconds=scheduled_vehicle_reset_restore_delay_seconds(config))
                if target_restart
                else datetime.now(UTC) + timedelta(seconds=scheduled_vehicle_reset_restore_delay_seconds(config))
            )
            event.update({
                "cfgignorelist_stage": "waiting_for_restart",
                "cfgignorelist_path": path,
                "cfgignorelist_backup_path": backup_path,
                "cfgignorelist_vehicle_class_count": len(vehicle_classes),
                "cfgignorelist_prepared_at": datetime.now(UTC).isoformat(),
                "cfgignorelist_restore_after_utc": restore_after.isoformat(),
                "status": (
                    f"Vehicle-only cfgignorelist prepared with {len(vehicle_classes)} vehicle class(es); "
                    f"waiting for scheduled restart at {format_reset_time(target_restart.isoformat() if target_restart else '')}."
                ),
            })
            workflow.update({
                "stage": "waiting_for_scheduled_restart",
                "vehicle_class_count": len(vehicle_classes),
                "last_path": path,
                "backup_path": backup_path,
            })
            save_guild_configs()
            await post_vehicle_reset_status(
                guild_id,
                config,
                "Vehicle Reset Prepared",
                (
                    f"The bot uploaded a vehicle-only cfgignorelist before the scheduled restart.\n\n"
                    f"Path: `{path}`\n"
                    f"Backup: `{backup_path or 'none'}`\n"
                    f"Vehicle classes: `{len(vehicle_classes)}`\n"
                    f"Restart target: `{format_reset_time(target_restart.isoformat() if target_restart else '')}`\n"
                    f"Restore due after: `{format_reset_time(restore_after.isoformat())}`\n\n"
                    f"{backup_message}"
                ),
                0xF1C40F,
            )
            return True, event["status"]

        finally:
            workflow["running"] = False
            workflow["finished_at"] = datetime.now(UTC).isoformat()
            save_guild_configs()

    if stage == "restore_original_cfgignorelist":
        if workflow.get("running"):
            return False, "cfgignorelist vehicle reset restore is already running for this guild."

        path = str(event.get("cfgignorelist_path") or config.get("vehicle_reset_cfgignorelist_path") or "").strip()
        backup_path = str(event.get("cfgignorelist_backup_path") or cfgignorelist_vehicle_reset_backup_path(path)).strip()
        if not path or not backup_path:
            event["status"] = "Cannot restore cfgignorelist because the live path or backup path is missing."
            save_guild_configs()
            return False, event["status"]

        workflow.update({
            "running": True,
            "event_id": event_id,
            "started_at": now.isoformat(),
            "stage": "restore_after_scheduled_restart",
            "last_path": path,
            "backup_path": backup_path,
        })
        event["status"] = "Restoring original cfgignorelist after the scheduled vehicle reset"
        save_guild_configs()

        try:
            wait_ok, wait_message = await wait_for_nitrado_gameserver_online(config)
            workflow["server_online_wait"] = wait_message
            if not wait_ok:
                workflow["server_online_wait_warning"] = wait_message

            backup_ok, backup_message, original_text = await asyncio.to_thread(
                download_text_file_from_nitrado,
                config,
                backup_path,
            )
            if not backup_ok or original_text is None:
                event["status"] = f"Could not download cfgignorelist restore backup: {backup_message}"
                return False, event["status"]

            restore_ok, restore_message = await asyncio.to_thread(
                upload_text_file_to_nitrado,
                config,
                path,
                original_text or empty_cfgignorelist_xml(),
            )
            if not restore_ok:
                event["status"] = f"Failed to restore original cfgignorelist.xml: {restore_message}"
                return False, event["status"]

            restart_ok, restart_message = await asyncio.to_thread(nitrado_gameserver_action, config, "restart")
            record = append_restart_history(
                guild_id,
                config,
                "vehicle_reset",
                "requested" if restart_ok else "failed",
                f"Scheduled cfgignorelist vehicle reset restore restart: {restart_message}",
                "vehicle reset workflow",
            )
            save_guild_configs()
            await publish_restart_history(guild_id, config, record)
            if not restart_ok:
                event["status"] = f"Original cfgignorelist restored, but restore restart failed: {restart_message}"
                return False, event["status"]

            workflow["stage"] = "complete"
            workflow["last_completed_at"] = datetime.now(UTC).isoformat()
            event["cfgignorelist_stage"] = "complete"
            event["status"] = "cfgignorelist vehicle-only reset complete; original ignore list restored and restart requested"
            mark_scenario_event_completed(config, event_id)
            save_guild_configs()
            await post_vehicle_reset_status(
                guild_id,
                config,
                "Vehicle Reset Restored",
                (
                    "The scheduled vehicle reset cycle finished.\n\n"
                    f"Restored: `{path}`\n"
                    f"Backup used: `{backup_path}`\n"
                    f"Server wait: `{wait_message}`\n"
                    f"Restore restart: `{restart_message}`"
                ),
                0x2ECC71,
            )
            return True, "cfgignorelist vehicle-only reset complete; restore restart requested."

        finally:
            workflow["running"] = False
            workflow["finished_at"] = datetime.now(UTC).isoformat()
            save_guild_configs()

    event["status"] = f"Unknown cfgignorelist reset stage `{stage}`."
    save_guild_configs()
    return False, event["status"]


async def run_cfgignorelist_vehicle_reset_workflow(guild_id, config, event):
    if is_scheduled_cfgignorelist_vehicle_reset(event):
        return await run_scheduled_cfgignorelist_vehicle_reset_workflow(guild_id, config, event)

    workflow = config.setdefault("vehicle_reset_cfgignorelist_workflow", {})
    if workflow.get("running"):
        return False, "cfgignorelist vehicle reset is already running for this guild."

    event_id = str(event.get("id") or "")
    workflow.update({
        "running": True,
        "event_id": event_id,
        "started_at": datetime.now(UTC).isoformat(),
        "stage": "download_cfgignorelist",
    })
    event["reset_method"] = "cfgignorelist"
    event["status"] = "cfgignorelist vehicle-only reset running: preparing vehicle list"
    save_guild_configs()

    path = ""
    original_text = ""
    restored = False

    try:
        vehicle_classes = vehicle_reset_cfgignorelist_classes(config)
        if not vehicle_classes:
            event["status"] = "No vehicle classes were found for cfgignorelist reset."
            return False, event["status"]

        ok, path, message, original_text = await asyncio.to_thread(
            download_cfgignorelist_for_vehicle_reset,
            guild_id,
            config,
        )
        if not ok:
            event["status"] = message
            return False, message

        ok, message, wipe_text = build_vehicle_cfgignorelist_xml(original_text, vehicle_classes)
        if not ok:
            event["status"] = message
            return False, message

        workflow["stage"] = "upload_vehicle_cfgignorelist"
        workflow["vehicle_class_count"] = len(vehicle_classes)
        event["status"] = message
        save_guild_configs()
        upload_ok, upload_message = await asyncio.to_thread(
            upload_text_file_to_nitrado,
            config,
            path,
            wipe_text,
        )
        if not upload_ok:
            event["status"] = f"Failed to upload vehicle-only cfgignorelist.xml: {upload_message}"
            return False, event["status"]

        workflow["stage"] = "restart_with_vehicle_cfgignorelist"
        event["status"] = "Vehicle-only cfgignorelist.xml uploaded; restarting server for reset cycle"
        save_guild_configs()
        restart_ok, restart_message = await asyncio.to_thread(nitrado_gameserver_action, config, "restart")
        record = append_restart_history(
            guild_id,
            config,
            "vehicle_reset",
            "requested" if restart_ok else "failed",
            f"cfgignorelist vehicle reset restart: {restart_message}",
            "vehicle reset workflow",
        )
        save_guild_configs()
        await publish_restart_history(guild_id, config, record)
        if not restart_ok:
            event["status"] = restart_message
            return False, restart_message

        await asyncio.sleep(max(30, int(config.get("vehicle_reset_wipe_wait_seconds", 120) or 120)))

        workflow["stage"] = "stop_for_cfgignorelist_restore"
        event["status"] = "Stopping server so the original cfgignorelist.xml can be restored"
        save_guild_configs()
        stop_ok, stop_message = await asyncio.to_thread(nitrado_gameserver_action, config, "stop")
        if not stop_ok:
            event["status"] = stop_message
            return False, stop_message

        await asyncio.sleep(max(10, int(config.get("vehicle_reset_restore_wait_seconds", 30) or 30)))

        workflow["stage"] = "restore_original_cfgignorelist"
        event["status"] = "Restoring original cfgignorelist.xml"
        save_guild_configs()
        restore_ok, restore_message = await asyncio.to_thread(
            upload_text_file_to_nitrado,
            config,
            path,
            original_text or empty_cfgignorelist_xml(),
        )
        if not restore_ok:
            event["status"] = f"Failed to restore original cfgignorelist.xml: {restore_message}"
            return False, event["status"]
        restored = True

        workflow["stage"] = "start_after_cfgignorelist_restore"
        event["status"] = "Original cfgignorelist.xml restored; starting server"
        save_guild_configs()
        start_ok, start_message = await asyncio.to_thread(nitrado_gameserver_action, config, "start")
        if not start_ok:
            event["status"] = start_message
            return False, start_message

        workflow["stage"] = "complete"
        workflow["last_completed_at"] = datetime.now(UTC).isoformat()
        workflow["last_path"] = path
        event["status"] = "cfgignorelist vehicle-only reset complete"
        mark_scenario_event_completed(config, event_id)
        return True, "cfgignorelist vehicle-only reset complete."

    finally:
        if original_text and path and not restored:
            try:
                await asyncio.to_thread(upload_text_file_to_nitrado, config, path, original_text)
                workflow["restore_attempted_at"] = datetime.now(UTC).isoformat()
            except Exception as restore_error:
                workflow["restore_error"] = str(restore_error)
                print(f"CFGIGNORELIST VEHICLE RESET RESTORE FAILED {guild_id}: {restore_error}")

        workflow["running"] = False
        workflow["finished_at"] = datetime.now(UTC).isoformat()
        save_guild_configs()


async def process_cfgignorelist_vehicle_reset_events(guild_id, config):
    processed = []
    for event in list(active_cfgignorelist_vehicle_reset_events(config)):
        ok, message = await run_cfgignorelist_vehicle_reset_workflow(guild_id, config, event)
        processed.append((ok, message))
        if not ok:
            break
    return processed


def queue_all_vehicle_reset(guild_id, config, requested_by):
    map_width, map_height = server_map_size(guild_id)
    center_x = map_width / 2
    center_y = map_height / 2
    radius = int(max(map_width, map_height) * 1.5)
