@bot.command()
async def shop(ctx):
    guild_id = str(ctx.guild.id) if ctx.guild else None
    items = guild_shop_items(guild_id)

    if not items:

        await ctx.send("Shop is currently empty.")
        return

    lines = []

    for item_name, data in items.items():

        lines.append(
            f"• {item_name} — {data.get('price', 0)} pennies 🪙"
        )

    embed = discord.Embed(
        title="🛒 BLACK MARKET SHOP",
        description="Items are grouped by server shop category. Use `/buy item_name x y` to order for next restart delivery.",
        color=0x9B59B6
    )

    categories = defaultdict(list)
    for item_name, data in items.items():
        if not isinstance(data, dict):
            data = {}
        is_bundle = str(data.get("type") or "").lower() == "bundle"
        category = normalize_shop_category(data.get("category") or ("Bundles" if is_bundle else guess_shop_category(item_name)))
        if not is_bundle and not is_shop_sellable_item(item_name, category):
            continue
        if not data.get("enabled", True):
            continue
        bundle_items = shop_bundle_items(data)
        bundle_note = ""
        if bundle_items:
            shown = ", ".join(f"{row['quantity']}x {row['item']}" for row in bundle_items[:4])
            more = f" +{len(bundle_items) - 4} more" if len(bundle_items) > 4 else ""
            bundle_note = f" ({shown}{more})"
        categories[category].append(f"- `{item_name}` - {data.get('price', 0)} pennies{bundle_note}")

    field_count = 0
    for category in shop_category_options(categories.keys()):
        rows = categories.get(category, [])
        if not rows:
            continue
        if field_count >= 25:
            break
        value = "\n".join(rows[:10])
        if len(rows) > 10:
            value += f"\n...and {len(rows) - 10} more"
        embed.add_field(name=f"Category: {category}", value=value[:1024], inline=False)
        field_count += 1

    if not embed.fields:
        embed.description = "Shop is currently empty or all items are disabled."

    embed.set_thumbnail(url=BOT_IMAGE)

    embed.set_footer(
        text="Wandering Bot Alpha • Black Market"
    )

    await ctx.send(embed=style_embed(embed))


@bot.command()
async def buy(ctx, item_name: str, x: str, y: str):

    user_id = str(ctx.author.id)
    guild_id = str(ctx.guild.id)
    x_value = parse_dayz_map_number(x)
    y_value = parse_dayz_map_number(y)

    if x_value is None or y_value is None:
        await ctx.send("Use numeric map coordinates, for example `/buy NailBox 7500 8400`.")
        return

    items = guild_shop_items(guild_id)

    if item_name not in items:

        await ctx.send("That item does not exist in the shop.")
        return

    item_config = items.get(item_name, {})
    bundle_items = shop_bundle_items(item_config)
    is_bundle = bool(bundle_items)

    if not is_bundle and not is_shop_sellable_item(item_name, item_config.get("category")):
        await ctx.send("That class is not allowed in the player shop.")
        return

    if not items[item_name].get("enabled", True):

        await ctx.send("❌ That item is currently disabled.")
        return

    if is_bundle:
        invalid_items = [row["item"] for row in bundle_items if not is_shop_sellable_item(row["item"], "")]
        if invalid_items:
            await ctx.send("That bundle contains a class that is not allowed in the player shop.")
            return

    blocked_user_ids = {str(uid) for uid in item_config.get("blocked_user_ids", []) if uid}
    if user_id in blocked_user_ids:
        await ctx.send("You are restricted from buying that item.")
        return

    allowed_role_ids = {str(rid) for rid in item_config.get("allowed_role_ids", []) if rid}
    if allowed_role_ids:
        member_role_ids = {str(getattr(role, "id", "")) for role in getattr(ctx.author, "roles", [])}
        if not member_role_ids.intersection(allowed_role_ids):
            await ctx.send("That item is restricted to a specific Discord role.")
            return

    wallet = guild_wallet(guild_id, user_id, str(ctx.author))

    limit = DEFAULT_DAILY_TRANSACTION_LIMIT
    item_daily_limit = int(item_config.get("daily_limit", 0) or 0)
    if item_daily_limit > 0:
        limit = min(limit, item_daily_limit)

    if wallet["daily_transactions"] >= limit:

        await ctx.send("❌ Daily delivery limit reached.")
        return

    price = items[item_name].get("price", 0)

    if wallet_balance(wallet) < price:

        await ctx.send("❌ Not enough pennies.")
        return

    wallet_debit(wallet, price, "cash")
    wallet["daily_transactions"] += 1

    created_at = str(datetime.now(UTC))
    if is_bundle:
        bundle_id = f"bundle-{guild_id}-{user_id}-{int(datetime.now(UTC).timestamp())}"
        for row in bundle_items:
            for _ in range(row["quantity"]):
                delivery_queue.append({
                    "guild_id": guild_id,
                    "delivery_type": "bundle_item",
                    "bundle_id": bundle_id,
                    "bundle_name": item_name,
                    "spawn_ready": False,
                    "player": str(ctx.author),
                    "discord_id": user_id,
                    "item": row["item"],
                    "x": str(x_value),
                    "y": str(y_value),
                    "status": "queued",
                    "created": created_at
                })
    else:
        delivery_queue.append({
            "guild_id": guild_id,
            "delivery_type": "item",
            "spawn_ready": False,
            "player": str(ctx.author),
            "discord_id": user_id,
            "item": item_name,
            "x": str(x_value),
            "y": str(y_value),
            "status": "queued",
            "created": created_at
        })

    save_wallets()
    save_delivery_queue()

    map_link = build_izurvive_link(f"{x_value},{y_value}", guild_id) or f"https://dayz.ginfo.gg/#location={x_value};{y_value}"

    embed = discord.Embed(
        title="📦 DELIVERY QUEUED",
        description=(
            f"Your order has been added to the next restart delivery queue."
        ),
        color=0x3498DB
    )

    embed.add_field(
        name="📦 Item",
        value=item_name,
        inline=True
    )

    embed.add_field(
        name="💰 Cost",
        value=f"{price} pennies 🪙",
        inline=True
    )

    embed.add_field(
        name="📍 Delivery Location",
        value=f"[🔵 Open Map](<{map_link}>)",
        inline=False
    )

    embed.add_field(
        name="⏰ Delivery ETA",
        value="Next server restart",
        inline=False
    )

    embed.set_thumbnail(url=BOT_IMAGE)

    embed.set_footer(
        text="Wandering Bot Alpha • Black Market Delivery"
    )

    await ctx.send(embed=style_embed(embed))

    # ================= PURCHASE LOG =================

    guild_id = str(ctx.guild.id)

    config = guild_configs.get(guild_id, {})

    await send_money_feed(
        ctx.guild,
        config,
        "BLACK MARKET PURCHASE",
        f"{ctx.author.mention} spent **{price} pennies**.",
        [
            {"name": "Survivor", "value": ctx.author.mention, "inline": True},
            {"name": "Item", "value": item_name, "inline": True},
            {"name": "Cost", "value": f"{price} pennies", "inline": True},
            {"name": "Balance After", "value": wallet_balance_brief(wallet), "inline": True},
            {"name": "Delivery Location", "value": f"[Open Map](<{map_link}>)", "inline": False},
        ],
        color=0x9B59B6,
        footer="Money Feed - Shop",
    )

    purchase_log_channel = bot.get_channel(
        config.get("channels", {}).get("purchase_logs")
    )

    if purchase_log_channel:

        log_embed = discord.Embed(
            title="💳 NEW BLACK MARKET PURCHASE",
            color=0x9B59B6
        )

        log_embed.add_field(
            name="👤 Survivor",
            value=ctx.author.mention,
            inline=True
        )

        log_embed.add_field(
            name="📦 Item",
            value=item_name,
            inline=True
        )

        log_embed.add_field(
            name="💰 Price",
            value=f"{price} pennies 🪙",
            inline=True
        )

        log_embed.add_field(
            name="📍 Delivery Location",
            value=f"[🔵 Open Map](<{map_link}>)",
            inline=False
        )

        log_embed.set_thumbnail(url=BOT_IMAGE)

        log_embed.set_footer(
            text="Wandering Bot Alpha • Purchase Logs"
        )

        await purchase_log_channel.send(
            embed=style_embed(log_embed)
        )


