class VehicleResetExcludeSelect(discord.ui.Select):
    def __init__(self, guild_id, config):
        self.guild_id = str(guild_id)
        self.config = config
        vehicle_classes = known_vehicle_classes()
        excluded = set(vehicle_reset_exclusions(config))
        options = [
            discord.SelectOption(
                label=item_name[:100],
                value=item_name[:100],
                default=item_name in excluded
            )
            for item_name in vehicle_classes[:25]
        ]

        super().__init__(
            placeholder="Choose vehicle classes to exclude from the all-vehicle reset",
            min_values=0,
            max_values=max(1, len(options)),
            options=options
        )

    async def callback(self, interaction: discord.Interaction):
        if not has_interaction_admin_power(interaction):
            await interaction.response.send_message("Admin only.", ephemeral=True)
            return

        self.config["vehicle_reset_exclusions"] = list(self.values)
        save_guild_configs()
        excluded = vehicle_reset_exclusions(self.config)
        text = ", ".join(f"`{item}`" for item in excluded) or "None"
        await interaction.response.send_message(
            f"Vehicle reset exclusions updated: {text}",
            ephemeral=True
        )


class QueueAllVehicleResetButton(discord.ui.Button):
    def __init__(self, guild_id, config):
        super().__init__(
            label="Queue All-Vehicle Reset",
            style=discord.ButtonStyle.danger
        )
        self.guild_id = str(guild_id)
        self.config = config

    async def callback(self, interaction: discord.Interaction):
        if not has_interaction_admin_power(interaction):
            await interaction.response.send_message("Admin only.", ephemeral=True)
            return

        entry = queue_all_vehicle_reset(self.guild_id, self.config, interaction.user)
        excluded = entry.get("exclude", [])
        excluded_text = ", ".join(f"`{item}`" for item in excluded) or "None"
        await interaction.response.send_message(
            "All-vehicle reset queued for the next restart delivery run.\n"
            f"Excluded classes: {excluded_text}\n\n"
            "This requires `/installdayzbridge install:true` with the v5 bridge and a server restart before the in-game cleanup happens.",
            ephemeral=True
        )


class VehicleResetExcludeView(discord.ui.View):
    def __init__(self, guild_id, config):
        super().__init__(timeout=900)
        if known_vehicle_classes():
            self.add_item(VehicleResetExcludeSelect(guild_id, config))
        self.add_item(QueueAllVehicleResetButton(guild_id, config))


# =========================================================
# RESTART DELIVERY PROCESSOR
# =========================================================

@tasks.loop(minutes=1)
async def restart_delivery_processor():

    now = datetime.now(UTC)

    for guild_id, config in active_guild_config_items():

        try:

            applied_damage = apply_due_damage_schedule(guild_id, config, now)
            if applied_damage:
                for damage_result in applied_damage:
                    status = "APPLIED" if damage_result.get("ok") else "FAILED"
                    print(
                        f"SCHEDULED DAMAGE SETTINGS {status} "
                        f"{guild_id}: schedule={damage_result.get('schedule_label') or 'damage'} "
                        f"base={damage_result.get('base_damage_state')} "
                        f"container={damage_result.get('container_damage_state')} "
                        f"path={damage_result.get('cfggameplay_path') or 'unknown'} "
                        f"{damage_result.get('message') or ''}"
                    )

            queued_reset = queue_due_vehicle_reset_schedule(guild_id, config, now)
            if queued_reset:
                print(f"SCHEDULED VEHICLE RESET QUEUED {guild_id}: {queued_reset.get('id')}")

            cfgignorelist_results = await process_cfgignorelist_vehicle_reset_events(guild_id, config)
            if cfgignorelist_results:
                for ok, message in cfgignorelist_results:
                    print(f"CFGIGNORELIST VEHICLE RESET {guild_id}: ok={ok} {message}")
                continue

            economy_results = await process_economy_vehicle_reset_events(guild_id, config)
            if economy_results:
                for ok, message in economy_results:
                    print(f"ECONOMY VEHICLE RESET {guild_id}: ok={ok} {message}")

            if await process_dashboard_scenario_xml_upload(guild_id, config):
                save_guild_configs()

            restart_interval = config.get(
                "restart_interval_hours",
                DEFAULT_RESTART_INTERVAL_HOURS
            )

            restart_offset = config.get(
                "restart_start_hour",
                0
            )
            local_tz = restart_timezone_for_config(config)
            local_now = now.astimezone(local_tz)

            if local_now.minute != 0:
                continue

            if (
                local_now.hour >= restart_offset
                and ((local_now.hour - restart_offset) % restart_interval == 0)
            ):
                normal_scenario_events = bridge_scenario_events(config)
                delivery_scenario_events = delivery_bridge_scenario_events(config)
                native_scenario_events = native_ce_scenario_events(config)
                console_ce_enabled = console_ce_event_config(config).get("enabled")
                has_delivery_work = queue_entries_for_guild(delivery_queue, guild_id) or queue_entries_for_guild(vehicle_rentals_queue, guild_id)
                if has_delivery_work or (normal_scenario_events and not console_ce_enabled) or (delivery_scenario_events and console_ce_enabled):
                    await asyncio.to_thread(
                        write_and_upload_delivery_xml,
                        guild_id,
                        config,
                        now,
                        delivery_scenario_events if console_ce_enabled else None,
                        not console_ce_enabled,
                    )

                if native_scenario_events and console_ce_enabled:
                    success, built, messages = await asyncio.to_thread(
                        upload_console_ce_event_files,
                        guild_id,
                        config,
                        "",
                        "",
                        "",
                        True
                    )
                    queue_scenario_event_discord_notice(config, success, built, messages, native_scenario_events, "Scheduled restart")
                    await process_scenario_event_discord_notices(guild_id, config)
                    if not success:
                        print(f"CONSOLE CE EVENT UPLOAD FAILED {guild_id}: {' | '.join(messages[-4:])}")

                pending_files = config.get("pending_server_file_changes") or []
                if "messages.xml" in pending_files:
                    ok, message = await asyncio.to_thread(upload_messages_xml_to_nitrado, config)
                    print(f"MESSAGES XML UPLOAD {guild_id}: ok={ok} {message}")

        except Exception as error:
            print(f"DELIVERY XML SCHEDULE ERROR {guild_id}: {error}")


def pending_dashboard_scenario_xml_events(config):
    pending_events = []
    for event in scenario_events_for_config(config):
        if not isinstance(event, dict):
            continue
        if not event.get("enabled", True):
            continue
        if str(event.get("created_by") or "") != "dashboard":
            continue
        if is_file_vehicle_reset_event(event):
            continue
        needs_native_redeploy = scenario_event_needs_native_redeploy_after_bridge(event)
        if scenario_event_has_confirmed_upload(event) and not needs_native_redeploy:
            continue
        upload_status = str(event.get("upload_status") or "waiting_for_bot_upload")
        if upload_status != "waiting_for_bot_upload" and not needs_native_redeploy:
            continue
        if int(event.get("upload_attempts") or 0) >= 3 and not needs_native_redeploy:
            continue
        if needs_native_redeploy:
            event.pop("bridge_uploaded_at", None)
            event.pop("bridge_surface_fixed_at", None)
            event.pop("bridge_delivery_path", None)
            event.pop("bridge_upload_messages", None)
            event["use_delivery_bridge"] = False
            event["delivery_route"] = "native_ce"
            event["force_native_ce"] = True
            event["upload_status"] = "waiting_for_bot_upload"
            event["status"] = "Native CE XML redeploy requested after bridge route did not run"
            event["upload_attempts"] = 0
        pending_events.append(event)
    return pending_events


async def process_dashboard_scenario_xml_upload(guild_id, config):
    pending_events = pending_dashboard_scenario_xml_events(config)
    cleanup_pending = bool(config.get("scenario_events_cleanup_pending"))
    bridge_events = [
        event
        for event in pending_events
        if scenario_event_uses_delivery_bridge(event, config) and not scenario_event_has_confirmed_bridge_upload(event)
    ]
    native_events = [
        event
        for event in pending_events
        if not scenario_event_uses_delivery_bridge(event, config) and not scenario_event_has_confirmed_native_upload(event)
    ]
    if not pending_events and not cleanup_pending:
        return False

    changed = False
    if bridge_events:
        now_text = datetime.now(UTC).isoformat()
        bridge_success, delivery_path, bridge_messages = await asyncio.to_thread(
            upload_delivery_bridge_scenario_events,
            guild_id,
            config,
            bridge_events,
            "Dashboard worker",
        )
        for event in bridge_events:
            event["upload_attempts"] = int(event.get("upload_attempts") or 0) + 1
            event["updated_at"] = now_text
            if bridge_success:
                apply_bridge_upload_metadata(event, delivery_path, bridge_messages, now_text)
            else:
                event["upload_status"] = "failed"
                event["upload_error"] = "Bridge delivery XML upload failed: " + (" | ".join(bridge_messages[-4:]) if bridge_messages else "no details")
                event["status"] = "Bridge XML upload failed"
        try:
            queue_scenario_event_discord_notice(
                config,
                bridge_success,
                {
                    "bridge_delivery_path": delivery_path,
                    "bridge_event_ids": [safe_int(event.get("id"), 0) for event in bridge_events],
                    "restart_required": True,
                },
                bridge_messages,
                bridge_events,
                "Dashboard bridge worker",
            )
        except Exception as notice_error:
            bridge_messages.append(f"Discord notice queue skipped after bridge upload state update: {type(notice_error).__name__}: {notice_error}")
        changed = True
        cleanup_pending = bool(config.get("scenario_events_cleanup_pending"))

    pending_events = native_events
    if not pending_events and not cleanup_pending:
        print(f"DASHBOARD SCENARIO BRIDGE UPLOAD {guild_id}: processed={len(bridge_events)}")
        return changed

    try:
        upload_success, built, messages = await asyncio.to_thread(
            upload_console_ce_event_files,
            guild_id,
            config,
            "",
            "",
            "",
            False,
        )
        source_blocked = native_ce_upload_blocked_messages(messages)
        status_text = (
            f"Native CE XML uploaded to {built.get('events_path')} and {built.get('spawns_path')}"
            if upload_success
            else native_ce_upload_blocked_status(messages)
            if source_blocked
            else native_ce_failed_status_text(messages)
        )
    except Exception as ce_error:
        upload_success = False
        built = {}
        messages = [f"{type(ce_error).__name__}: {ce_error}"]
        source_blocked = False
        status_text = f"Native CE XML upload failed: {type(ce_error).__name__}: {ce_error}"

    now_text = datetime.now(UTC).isoformat()
    if upload_success and cleanup_pending:
        config["scenario_events_cleanup_pending"] = False
        config["scenario_events_cleanup_completed_at"] = now_text
        config.pop("scenario_events_cleanup_error", None)
    elif cleanup_pending:
        config["scenario_events_cleanup_error"] = status_text
    for event in pending_events:
        attempts = int(event.get("upload_attempts") or 0) + 1
        event["upload_attempts"] = attempts
        event["updated_at"] = now_text
        if upload_success:
            apply_native_ce_upload_metadata(event, built, messages, now_text)
        else:
            if scenario_event_has_confirmed_native_upload(event):
                remember_native_ce_upload_warning(event, status_text, now_text)
                continue
            if source_blocked:
                mark_native_ce_source_required(config, event, messages, now_text)
                continue
            event["upload_status"] = "failed"
            event["upload_error"] = status_text
            event["status"] = "Native CE XML upload failed"
    try:
        queue_scenario_event_discord_notice(config, upload_success, built, messages, pending_events, "Dashboard worker")
    except Exception as notice_error:
        messages.append(f"Discord notice queue skipped after upload state update: {type(notice_error).__name__}: {notice_error}")
    print(f"DASHBOARD SCENARIO NATIVE CE UPLOAD {guild_id}: success={upload_success} {status_text}")
    return True


@tasks.loop(minutes=1)
async def dashboard_scenario_upload_loop():
    changed = False
    for guild_id, config in active_guild_config_items():
        try:
            if await process_dashboard_scenario_xml_upload(guild_id, config):
                changed = True
            if await process_scenario_event_discord_notices(guild_id, config):
                changed = True
        except Exception as error:
            print(f"DASHBOARD SCENARIO XML LOOP ERROR {guild_id}: {error}")
    if changed:
        save_guild_configs()


