@bot.command()
@commands.check(lambda ctx: has_staff_permissions(ctx))
async def editshopitem(
    ctx,
    item_name: str,
    price: int = None,
    category: str = None
):

    items = guild_shop_items(str(ctx.guild.id) if ctx.guild else None)

    if item_name not in items:

        await ctx.send("❌ Item not found in shop.")
        return

    if price is not None:
        items[item_name]["price"] = price

    if category is not None:
        normalized_category = guess_shop_category(item_name, category)
        if not is_shop_sellable_item(item_name, normalized_category):
            await ctx.send("That category/class combination is not allowed in the player shop.")
            return
        items[item_name]["category"] = normalized_category

    save_shop()

    embed = discord.Embed(
        title="✏️ SHOP ITEM UPDATED",
        description=f"Updated `{item_name}` successfully.",
        color=0x3498DB
    )

    embed.set_thumbnail(url=BOT_IMAGE)

    await ctx.send(embed=style_embed(embed))


@bot.command()
@commands.check(lambda ctx: has_staff_permissions(ctx))
async def toggleshopitem(ctx, item_name: str):

    items = guild_shop_items(str(ctx.guild.id) if ctx.guild else None)

    if item_name not in items:

        await ctx.send("❌ Item not found.")
