@bot.tree.command(name="adminban", description="Admin: ban a Discord member and post a public reason")
@app_commands.default_permissions(ban_members=True)
@app_commands.describe(member="Member to ban", reason="Reason shown in Wandering in Shame", delete_message_days="Delete recent message history, 0-7 days")
async def adminban(interaction: discord.Interaction, member: discord.Member, reason: str, delete_message_days: int = 0):
    if not interaction.user.guild_permissions.ban_members:
        await interaction.response.send_message("You need Ban Members permission.", ephemeral=True)
        return

    if member.id == interaction.user.id or member.id == bot.user.id:
        await interaction.response.send_message("That member cannot be banned by this command.", ephemeral=True)
        return

    delete_message_days = max(0, min(7, int(delete_message_days or 0)))
    guild_id = str(interaction.guild.id)
    config = guild_configs.setdefault(guild_id, {"guild_name": interaction.guild.name, "channels": {}})

    await member.ban(reason=f"{reason} - banned by {interaction.user}", delete_message_days=delete_message_days)
    await send_public_shame_notice(
        interaction.guild,
        config,
        "MEMBER BANNED",
        f"{member.mention}\n`{member}`",
        interaction.user,
        reason,
        "permanent"
    )

    await interaction.response.send_message(f"Banned `{member}` and posted the reason in Wandering in Shame.", ephemeral=True)


@bot.tree.command(name="admintempban", description="Admin: temporarily ban a Discord member and post a public reason")
@app_commands.default_permissions(ban_members=True)
@app_commands.describe(member="Member to temp-ban", duration="Example: 30m, 2h, 3d, or 1d 6h", reason="Reason shown in Wandering in Shame")
async def admintempban(interaction: discord.Interaction, member: discord.Member, duration: str, reason: str):
    if not interaction.user.guild_permissions.ban_members:
        await interaction.response.send_message("You need Ban Members permission.", ephemeral=True)
        return

    if member.id == interaction.user.id or member.id == bot.user.id:
        await interaction.response.send_message("That member cannot be banned by this command.", ephemeral=True)
        return

    seconds = parse_duration_to_seconds(duration)
    if not seconds or seconds < 60:
        await interaction.response.send_message("Duration must be at least 1 minute. Use examples like `30m`, `2h`, `3d`, or `1d 6h`.", ephemeral=True)
        return

    guild_id = str(interaction.guild.id)
    config = guild_configs.setdefault(guild_id, {"guild_name": interaction.guild.name, "channels": {}})
    until_ts = datetime.now(UTC).timestamp() + seconds
    duration_text = format_duration_seconds(seconds)

    config.setdefault("temp_bans", []).append({
        "user_id": str(member.id),
        "user_name": str(member),
        "moderator_id": str(interaction.user.id),
        "reason": reason,
        "until_ts": until_ts,
        "created": str(datetime.now(UTC)),
    })
    save_guild_configs()

    await member.ban(reason=f"Temp ban {duration_text}: {reason} - banned by {interaction.user}", delete_message_days=0)
    await send_public_shame_notice(
        interaction.guild,
        config,
        "TEMP BAN ISSUED",
        f"{member.mention}\n`{member}`",
        interaction.user,
        reason,
        duration_text
    )

    await interaction.response.send_message(f"Temp-banned `{member}` for {duration_text} and posted the reason.", ephemeral=True)


@bot.tree.command(name="adminunban", description="Admin: unban a Discord user ID and post a public reason")
@app_commands.default_permissions(ban_members=True)
@app_commands.describe(user_id="Discord user ID to unban", reason="Reason shown in Wandering in Shame")
async def adminunban(interaction: discord.Interaction, user_id: str, reason: str = "Appeal accepted"):
    if not interaction.user.guild_permissions.ban_members:
        await interaction.response.send_message("You need Ban Members permission.", ephemeral=True)
        return

    if not str(user_id).isdigit():
        await interaction.response.send_message("User ID must be numeric.", ephemeral=True)
        return

    guild_id = str(interaction.guild.id)
    config = guild_configs.setdefault(guild_id, {"guild_name": interaction.guild.name, "channels": {}})
    user = await bot.fetch_user(int(user_id))
    await interaction.guild.unban(user, reason=f"{reason} - unbanned by {interaction.user}")
    config["temp_bans"] = [
        ban for ban in config.get("temp_bans", [])
        if str(ban.get("user_id")) != str(user_id)
    ]
    save_guild_configs()

    await send_public_shame_notice(
        interaction.guild,
        config,
        "MEMBER UNBANNED",
        f"`{user}` (`{user_id}`)",
        interaction.user,
        reason,
        None
    )

    await interaction.response.send_message(f"Unbanned `{user}` and posted the reason.", ephemeral=True)


translation_group = app_commands.Group(
    name="translation",
    description="Multi-rule translation config (add/list/remove/clear rules)",
)
bot.tree.add_command(translation_group)


@translation_group.command(name="config", description="Admin: configure automatic translation")
@app_commands.describe(
    mode="same posts translations in the same chat, channel forwards them, off disables translation",
    target_language="Target language code, example: en, es, fr, de",
    source_language="Source language code or auto",
    source_channel="Optional source channel. Blank means all channels.",
    target_channel="Required for channel mode"
)
@app_commands.choices(mode=[
    app_commands.Choice(name="same - translate beside the original message", value="same"),
    app_commands.Choice(name="channel - forward translations to a target channel", value="channel"),
    app_commands.Choice(name="off - disable automatic translation", value="off"),
])
async def translationconfig(
    interaction: discord.Interaction,
    mode: str = "same",
    target_language: str = "en",
    source_language: str = "auto",
    source_channel: discord.TextChannel = None,
    target_channel: discord.TextChannel = None
):

    if not has_interaction_admin_power(interaction):
        await interaction.response.send_message("Admin only.", ephemeral=True)
        return

    mode = mode.lower().strip()

    if mode not in ["off", "same", "channel"]:
        await interaction.response.send_message("Mode must be `off`, `same`, or `channel`.", ephemeral=True)
        return

    if mode == "channel" and not target_channel:
        await interaction.response.send_message(
            "`channel` mode means translations are posted into another channel, so choose `target_channel`. Use `same` if you want translations posted beside the original message.",
            ephemeral=True
        )
        return

    guild_id = str(interaction.guild.id)
    if guild_id not in guild_configs:
        guild_configs[guild_id] = {
            "guild_name": interaction.guild.name,
            "admin_roles": DEFAULT_ADMIN_ROLES.copy(),
            "channels": {}
        }

    # ── Multi-rule storage ───────────────────────────────────────
    # Each call to /translation config now appends a rule
    # in `translations` rather than overwriting the whole config.
    # That makes it possible to set up multiple directions, e.g.
    #   • Channel A (EN→ES) → Channel B
    #   • Channel B (ES→EN) → Channel A
    # at the same time. Older configs that still have the legacy
    # singleton `translation` dict are migrated on first edit.
    guild_cfg = guild_configs[guild_id]
    legacy = guild_cfg.pop("translation", None)
    rules = guild_cfg.get("translations")
    if not isinstance(rules, list):
        rules = []
        if isinstance(legacy, dict) and legacy.get("enabled"):
            rules.append(legacy)

    if mode == "off":
        # `/translation config mode:off` with no source_channel clears EVERY
        # rule. With a source_channel, it only disables matching rules.
        if source_channel:
            removed = 0
            new_rules = []
            for existing in rules:
                if existing.get("source_channel_id") == source_channel.id:
                    removed += 1
                    continue
                new_rules.append(existing)
            rules = new_rules
            guild_cfg["translations"] = rules
            save_guild_configs()
            await interaction.response.send_message(
                f"Removed {removed} translation rule(s) for {source_channel.mention}.",
                ephemeral=True
            )
        else:
            guild_cfg["translations"] = []
            save_guild_configs()
            await interaction.response.send_message(
                "All translation rules removed for this server.",
                ephemeral=True
            )
        return

    new_rule = {
        "enabled": True,
        "mode": mode,
        "target_language": normalize_translation_language(target_language, "en"),
        "source_language": normalize_translation_language(source_language, "auto"),
        "source_channel_id": source_channel.id if source_channel else None,
        "target_channel_id": target_channel.id if target_channel else None,
    }

    # Append every rule. Admins may intentionally stack many rules for the
    # same channel, language, or target when running multilingual servers.
    rules.append(new_rule)
    guild_cfg["translations"] = rules

    save_guild_configs()

    # ── Live verification ────────────────────────────────────────
    # Run an actual translation right now so the admin instantly sees
    # whether the backend is reachable, or gets a clear error to act on.
    verification = ""
    if mode != "off":
        try:
            sample = "Hello, this is a translation test."
            sample_translated = await translate_text(
                sample,
                normalize_translation_language(target_language, "en"),
                normalize_translation_language(source_language, "auto"),
            )
            if sample_translated:
                verification = (
                    f"✅ **Live test passed.**\n"
                    f"`Hello, this is a translation test.` → `{sample_translated[:200]}`"
                )
            else:
                verification = (
                    "⚠️ **Live test failed** — the translation backend (MyMemory) "
                    "did not return a result. Common causes:\n"
                    "• Daily free quota exhausted (5000 chars/day per Railway IP — "
                    "comes back tomorrow)\n"
                    "• Outbound HTTPS blocked by your host\n"
                    "• Invalid language code (use 2-letter ISO, e.g. `en`, `es`, `fr`)\n"
                    "Check the Railway logs for `[TRANSLATE]` lines for the exact error."
                )
        except Exception as test_err:
            verification = f"⚠️ Live test crashed: `{test_err}`"

    embed = discord.Embed(
        title="Translation Rule Added",
        description=(
            "Translation rules **stack** — every call to `/translation config` "
            "adds a new rule rather than replacing your previous setup. "
            "Use `/translation list` to see all rules, `/translation remove` to "
            "delete one, and `/translation clear` to wipe them all.\n\n"
            "`same` posts translations in the same chat.\n"
            "`channel` forwards translations into the target channel.\n"
            "`off` disables / removes translation rules."
        ),
        color=0x1ABC9C
    )
    embed.add_field(name="Mode", value=mode, inline=True)
    embed.add_field(name="Source", value=source_channel.mention if source_channel else "All channels", inline=True)
    embed.add_field(name="Target", value=target_channel.mention if target_channel else "Same channel", inline=True)
    embed.add_field(name="Language", value=f"{source_language} -> {target_language}", inline=False)
    embed.add_field(
        name="Active Rules",
        value=f"This server now has **{len(rules)}** translation rule(s).",
        inline=False,
    )
    if verification:
        embed.add_field(name="Live Verification", value=verification, inline=False)
    embed.add_field(
        name="Heads-up",
        value=(
            "Translations only fire when **Message Content Intent** is enabled "
            "in the Discord Developer Portal under your bot's settings. "
            "If you see no translations even after this passes the live test, "
            "double-check that toggle is ON."
        ),
        inline=False,
    )
    await interaction.response.send_message(embed=style_embed(embed), ephemeral=True)


@translation_group.command(name="list", description="Admin: list all configured translation rules for this server")
async def translationlist(interaction: discord.Interaction):
    if not has_interaction_admin_power(interaction):
        await interaction.response.send_message("Admin only.", ephemeral=True)
        return

    guild_id = str(interaction.guild.id)
    config = guild_configs.get(guild_id, {})
    rules = _get_translation_rules(config)

    if not rules:
        await interaction.response.send_message(
            "No translation rules configured. Use `/translation config` to add one.",
            ephemeral=True,
        )
        return

    stats = translation_runtime_stats.get(guild_id, {})
    page_size = 15
    pages = [rules[i:i + page_size] for i in range(0, len(rules), page_size)]

    async def send_page(page_index, page_rules):
        embed = discord.Embed(
            title=f"Active Translation Rules ({page_index + 1}/{len(pages)})",
            description=(
                f"This server has **{len(rules)}** translation rule(s). "
                "Rules are stored as a list with no bot-side cap; Discord only paginates the display."
            ),
            color=0x1ABC9C,
        )
        lines = []
        base = page_index * page_size
        for offset, rule in enumerate(page_rules, start=1):
            index = base + offset
            src_id = rule.get("source_channel_id")
            tgt_id = rule.get("target_channel_id")
            src = f"<#{src_id}>" if src_id else "All channels"
            tgt = f"<#{tgt_id}>" if tgt_id else "Same channel"
            mode = rule.get("mode", "same")
            src_lang = normalize_translation_language(rule.get("source_language"), "auto")
            tgt_lang = normalize_translation_language(rule.get("target_language"), "en")
            enabled = "on" if rule.get("enabled", True) else "off"
            lines.append(f"`#{index}` **{src_lang}->{tgt_lang}** `{mode}` `{enabled}` | {src} -> {tgt}")
        embed.add_field(name="Rules", value="\n".join(lines)[:3900], inline=False)
        if stats:
            embed.add_field(
                name="Runtime stats since bot start",
                value=(
                    f"Seen: `{stats.get('seen', 0)}` | Posted: `{stats.get('posted', 0)}` | "
                    f"Skipped: `{stats.get('skipped', 0)}` | Failed: `{stats.get('failed', 0)}`\n"
                    f"Last note: `{stats.get('last_error') or stats.get('last_success') or 'none yet'}`"
                )[:1024],
                inline=False,
            )
        return style_embed(embed)

    await interaction.response.send_message(embed=await send_page(0, pages[0]), ephemeral=True)
    for page_index, page_rules in enumerate(pages[1:], start=1):
        await interaction.followup.send(embed=await send_page(page_index, page_rules), ephemeral=True)


@translation_group.command(name="remove", description="Admin: remove a specific translation rule by number")
@app_commands.describe(rule_number="The rule number shown in /translation list (1, 2, 3, ...)")
async def translationremove(interaction: discord.Interaction, rule_number: int):
    if not has_interaction_admin_power(interaction):
        await interaction.response.send_message("Admin only.", ephemeral=True)
        return

    guild_id = str(interaction.guild.id)
    config = guild_configs.setdefault(guild_id, {
        "guild_name": interaction.guild.name,
        "admin_roles": DEFAULT_ADMIN_ROLES.copy(),
        "channels": {}
    })

    # Migrate legacy single-rule config to list before edit
    legacy = config.pop("translation", None)
    rules = config.get("translations")
    if not isinstance(rules, list):
        rules = []
        if isinstance(legacy, dict) and legacy.get("enabled"):
            rules.append(legacy)

    if not rules:
        await interaction.response.send_message(
            "No translation rules to remove. Use `/translation list` to see them.",
            ephemeral=True
        )
        return

    if rule_number < 1 or rule_number > len(rules):
        await interaction.response.send_message(
            f"Rule number must be between 1 and {len(rules)}. Use `/translation list`.",
            ephemeral=True
        )
        return

    removed = rules.pop(rule_number - 1)
    config["translations"] = rules
    save_guild_configs()

    src_id = removed.get("source_channel_id")
    tgt_id = removed.get("target_channel_id")
    src = f"<#{src_id}>" if src_id else "All channels"
    tgt = f"<#{tgt_id}>" if tgt_id else "Same channel"
    await interaction.response.send_message(
        f"Removed rule #{rule_number}: {src} → {tgt} "
        f"({removed.get('source_language', 'auto')} → {removed.get('target_language', 'en')}). "
        f"{len(rules)} rule(s) remain.",
        ephemeral=True
    )


@translation_group.command(name="clear", description="Admin: remove ALL translation rules for this server")
async def translationclear(interaction: discord.Interaction):
    if not has_interaction_admin_power(interaction):
        await interaction.response.send_message("Admin only.", ephemeral=True)
        return

    guild_id = str(interaction.guild.id)
    config = guild_configs.setdefault(guild_id, {
        "guild_name": interaction.guild.name,
        "admin_roles": DEFAULT_ADMIN_ROLES.copy(),
        "channels": {}
    })
    config.pop("translation", None)  # drop legacy
    cleared = len(_get_translation_rules(config))
    config["translations"] = []
    save_guild_configs()

    await interaction.response.send_message(
        f"Cleared {cleared} translation rule(s). The bot will no longer auto-translate "
        f"messages until you set up new rules with `/translation config`.",
        ephemeral=True
    )


