@bot.event
async def on_interaction(interaction: discord.Interaction):
    """Route persistent button clicks (component interactions) by custom_id.

    The PVE quest "Submit Completion" buttons use a `pve_submit:<quest_code>`
    custom_id so we can re-resolve them even after a bot restart without
    needing to re-register every per-quest View instance.
    """
    try:
        if interaction.type == discord.InteractionType.component:
            custom_id = (interaction.data or {}).get("custom_id", "")
            if custom_id.startswith("pve_submit:"):
                quest_code = custom_id.split(":", 1)[1]
                await _handle_pve_submit_button(interaction, quest_code)
            elif custom_id.startswith("pve_ticket_claim:"):
                await _handle_pve_ticket_claim(interaction, custom_id.split(":", 1)[1])
            elif custom_id.startswith("pve_ticket_close:"):
                await _handle_pve_ticket_close(interaction, custom_id.split(":", 1)[1])
            elif custom_id.startswith("pve_ticket_reopen:"):
                await _handle_pve_ticket_reopen(interaction, custom_id.split(":", 1)[1])
            elif custom_id.startswith("pve_ticket_delete:"):
                await _handle_pve_ticket_delete(interaction, custom_id.split(":", 1)[1])
            elif custom_id.startswith("stackwatch:"):
                await _handle_stack_watch_action(interaction, custom_id)
    except Exception as err:
        print(f"[ON_INTERACTION] handler error: {err}")



@bot.event
async def on_member_remove(member):
    guild = getattr(member, "guild", None)
    if not guild or getattr(member, "bot", False):
        return

    guild_id = str(guild.id)
    config = guild_configs.setdefault(guild_id, {"guild_name": guild.name, "channels": {}})
    linked = linked_players.get(str(member.id), {})
    public_channel = await get_or_create_feed_channel(
        guild,
        config,
        "member_leaves",
        DEFAULT_CHANNEL_NAMES["member_leaves"],
        private=False
    )
    if public_channel:
        title = random.choice(["FARE THEE WELL", "SURVIVOR LEFT CAMP", "RADIO SIGNAL LOST"])
        description = random.choice([
            f"`{member}` has left the Discord. The campfire is one voice quieter.",
            f"`{member.display_name}` wandered out of range. Typical apocalypse behaviour.",
            f"`{member.display_name}` has departed. Someone check they did not take the good beans.",
        ])
        embed = discord.Embed(title=title, description=description, color=0x95A5A6)
        if linked_player_gamertags(linked):
            embed.add_field(name="Linked Gamertags", value=linked_player_gamertag_summary(linked), inline=True)
        embed.set_thumbnail(url=BOT_IMAGE)
        embed.set_footer(text="Wandering Bot Alpha - Fare Thee Well")
        await public_channel.send(embed=style_embed(embed))

    audit_channel = await get_or_create_feed_channel(
        guild,
        config,
        "link_audit",
        DEFAULT_CHANNEL_NAMES["link_audit"],
        private=True
    )
    if audit_channel:
        role_names = [role.name for role in getattr(member, "roles", []) if role.name != "@everyone"]
        audit = discord.Embed(
            title="MEMBER LEFT DISCORD",
            description="Private departure audit for staff.",
            color=0xE67E22
        )
        audit.add_field(name="Discord", value=f"`{member}`", inline=False)
        audit.add_field(name="Discord ID", value=f"`{member.id}`", inline=True)
        audit.add_field(name="Linked Gamertags", value=linked_player_gamertag_summary(linked), inline=True)
        audit.add_field(name="Joined Discord", value=str(getattr(member, "joined_at", None) or "Unknown"), inline=False)
        audit.add_field(name="Roles", value=", ".join(role_names[:30]) or "None", inline=False)
        audit.set_thumbnail(url=BOT_IMAGE)
        audit.set_footer(text="Wandering Bot Alpha - Private Member Audit")
        await audit_channel.send(embed=style_embed(audit))

@bot.event
async def on_ready():

    print(f"LOGGED IN AS {bot.user}")
    print(f"DATA ROOT: {os.path.abspath(DATA_ROOT)}")

    ensure_folder(DATA_ROOT)
    ensure_folder(GUILD_DATA_FOLDER)

    load_guild_configs()
    load_processed_adm_lines()
    load_online_players()
    bootstrap_runtime_from_connected_guilds()
    await repair_display_names_for_active_guilds()
    await ensure_pve_channels_for_active_guilds()
    load_player_stats()
    load_heatmap()
    load_swear_jar()
    load_linked_players()
    load_support_tickets()
    load_factions()
    load_pve_challenges()
    load_pve_ai_campaigns()
    load_pve_workshop_schedules()
    load_factions()
    load_wages()
    load_seen_players()
    load_longshot_records()
    load_first_blood()
    load_daily_recap()
    load_bounties()
    load_survival_streaks()
    load_recap_posted()
    load_achievements()
    load_nemesis()
    load_alive_streaks()
    load_daily_kill_tracker()
    load_manhunts()
    load_daily_challenges()
    load_wandering_emojis()
    print(f"WANDERING EMOJIS LOADED: {len(wandering_emojis)}")
    load_shop()
    load_wallets()
    load_delivery_queue()

    await publish_bot_updates_for_active_guilds()

    for guild_id, config in active_guild_config_items():
        try:
            if server_allows_pve(config) and pve_config(config).get("enabled", True):
                posted = await ensure_pve_channel_quests(guild_id, config)
                if posted:
                    print(f"PVE QUEST SLOTS SEEDED {guild_display_name(guild_id)}: {len(posted)}")
        except Exception as error:
            print(f"PVE QUEST SLOT SEED ERROR {guild_id}: {error}")

    active_count = len(list(active_guild_config_items()))
    active_names = [
        guild_configs[guild_id].get("guild_name", guild_id)
        for guild_id, _ in active_guild_config_items()
    ]
    print(f"ACTIVE CONFIGURED GUILDS LOADED: {active_count}/{len(guild_configs)}")
    print(f"ACTIVE GUILDS: {', '.join(active_names) if active_names else 'none'}")

    await start_background_tasks()

    print("[ADM STARTUP] Starting ADM startup protocol for active guilds.")
    startup_results = await refresh_adm_feeds()
    log_adm_protocol_results(startup_results, "ADM STARTUP")

    for guild in bot.guilds:
        await sync_slash_commands_for_guild(guild)

    try:
        global_synced = await bot.tree.sync()
        print(f"GLOBAL SLASH COMMANDS SYNCED: {len(global_synced)}")
        print(f"GLOBAL SLASH COMMAND NAMES: {', '.join(command.name for command in global_synced)}")
    except Exception as sync_error:
        print(f"GLOBAL SLASH SYNC ERROR: {sync_error}")

